@dataclass(frozen=True)
class CaptureOptions:
    mouse: bool = True
    keyboard: bool = False
    gamepad: bool = False
    audio: bool = False

    @classmethod
    def from_profile(cls, profile=None):
        value = profile if isinstance(profile, dict) else {}
        return cls(
            mouse=bool(value.get("mouse_enabled", True)),
            keyboard=bool(value.get("keyboard_enabled", False)),
            gamepad=bool(value.get("gamepad_enabled", False)),
            audio=bool(value.get("sound_enabled", False)),
        )

    def to_dict(self):
        return {"mouse": self.mouse, "keyboard": self.keyboard, "gamepad": self.gamepad, "audio": self.audio}

    def apply_profile(self, profile=None):
        value = dict(profile) if isinstance(profile, dict) else {}
        value.update(
            {
                "mouse_enabled": self.mouse,
                "keyboard_enabled": self.keyboard,
                "gamepad_enabled": self.gamepad,
                "sound_enabled": self.audio,
            }
        )
        required = [
            name
            for name, enabled in (
                ("mouse", self.mouse),
                ("keyboard", self.keyboard),
                ("gamepad", self.gamepad),
                ("sound", self.audio),
            )
            if enabled
        ]
        required.append("vision")
        value["required_input_modalities"] = list(dict.fromkeys(required))
        value["capture_options_schema_version"] = 1
        return value


