def iter_rows(cursor, batch_size=256):
    size = max(1, int(batch_size))
    while True:
        rows = cursor.fetchmany(size)
        if not rows:
            break
        yield from rows


def interruptible_wait(stop_event, seconds):
    duration = max(0.0, float(seconds))
    if stop_event is None:
        if duration:
            time.sleep(duration)
        return False
    return bool(stop_event.wait(duration))


class BoundedTTLMap:
    def __init__(self, maximum=64, ttl_seconds=3600.0, clock=time.monotonic):
        self.maximum = max(1, int(maximum))
        self.ttl_seconds = max(0.05, float(ttl_seconds))
        self.clock = clock
        self.lock = threading.RLock()
        self.values = OrderedDict()

    def _prune_locked(self, now=None):
        current = self.clock() if now is None else float(now)
        expired = [key for key, (created, _) in self.values.items() if current - created > self.ttl_seconds]
        for key in expired:
            self.values.pop(key, None)
        while len(self.values) > self.maximum:
            self.values.popitem(last=False)

    def __setitem__(self, key, value):
        token = str(key)
        with self.lock:
            self.values.pop(token, None)
            self.values[token] = (self.clock(), value)
            self._prune_locked()

    def __getitem__(self, key):
        token = str(key)
        with self.lock:
            self._prune_locked()
            created, value = self.values[token]
            self.values.move_to_end(token)
            return value

    def get(self, key, default=None):
        try:
            return self[key]
        except KeyError:
            return default

    def pop(self, key, default=None):
        with self.lock:
            item = self.values.pop(str(key), None)
        return default if item is None else item[1]

    def clear(self):
        with self.lock:
            self.values.clear()

    def __len__(self):
        with self.lock:
            self._prune_locked()
            return len(self.values)


def freeze_ui_payload(value, depth=0):
    if depth > 8:
        return repr(value)
    if value is None or isinstance(value, (str, int, float, bool, bytes)):
        return value
    if isinstance(value, Path):
        return str(value)
    if isinstance(value, dict):
        return tuple(sorted((str(key), freeze_ui_payload(item, depth + 1)) for key, item in value.items()))
    if isinstance(value, (list, tuple, deque, set, frozenset)):
        return tuple(freeze_ui_payload(item, depth + 1) for item in value)
    return repr(value)


@dataclass(frozen=True, slots=True)
class UiEvent:
    kind: str
    generation: int
    session_id: str
    payload: tuple = ()


class UiDispatcher:
    TERMINATION_KINDS = frozenset({"escape_stop", "mode_result", "shutdown"})
    CRITICAL_KINDS = frozenset(
        {
            "mode_result",
            "escape_stop",
            "ai_worker_failed",
            "writer_status",
            "directory_prepare_finished",
            "directory_commit",
            "model_switch",
            "shutdown",
        }
    )

    def __init__(self, critical_capacity=32, normal_capacity=128, callback_capacity=256):
        self.termination = queue.Queue(maxsize=8)
        self.critical = queue.Queue(maxsize=max(4, int(critical_capacity)))
        self.normal = queue.Queue(maxsize=max(8, int(normal_capacity)))
        self.callback_capacity = max(16, int(callback_capacity))
        self.lock = threading.RLock()
        self.callbacks = OrderedDict()
        self.coalesced = OrderedDict()
        self.generations = defaultdict(int)
        self.counter = 0
        self.dropped = Counter()

    def next_generation(self, scope):
        token = str(scope or "global")
        with self.lock:
            self.generations[token] += 1
            return self.generations[token]

    def current_generation(self, scope):
        with self.lock:
            return self.generations.get(str(scope or "global"), 0)

    def _register_callback(self, callback):
        with self.lock:
            self.counter += 1
            token = "cb:" + str(self.counter)
            self.callbacks[token] = callback
            while len(self.callbacks) > self.callback_capacity:
                stale, _ = self.callbacks.popitem(last=False)
                self.dropped["callback_registry"] += 1
                for key, event in list(self.coalesced.items()):
                    if event.payload and event.payload[0] == stale:
                        self.coalesced.pop(key, None)
            return token

    def post_callback(self, callback, key=None, generation=0, session_id="", critical=None):
        if not callable(callback):
            raise TypeError("UI回调必须可调用")
        token = self._register_callback(callback)
        event = UiEvent(str(key or "callback"), int(generation), str(session_id or ""), freeze_ui_payload((token,)))
        is_critical = event.kind in self.CRITICAL_KINDS if critical is None else bool(critical)
        self.post(event, coalesce_key=None if is_critical else event.kind, critical=is_critical)
        return token

    def post(self, event, coalesce_key=None, critical=False):
        if not isinstance(event, UiEvent):
            raise TypeError("UI队列只接受不可变UiEvent")
        if critical:
            destination = self.termination if event.kind in self.TERMINATION_KINDS else self.critical
            try:
                destination.put_nowait(event)
                return True
            except queue.Full:
                try:
                    displaced = destination.get_nowait()
                    self._discard_callback(displaced)
                except queue.Empty:
                    pass
                key = "termination_oldest" if destination is self.termination else "critical_oldest"
                self.dropped[key] += 1
                destination.put_nowait(event)
                return True
        if coalesce_key:
            with self.lock:
                key = str(coalesce_key)
                old = self.coalesced.pop(key, None)
                if old is not None:
                    self._discard_callback(old)
                    self.dropped["coalesced"] += 1
                self.coalesced[key] = event
                while len(self.coalesced) > self.normal.maxsize:
                    _, stale = self.coalesced.popitem(last=False)
                    self._discard_callback(stale)
                    self.dropped["coalesced_oldest"] += 1
            return True
        try:
            self.normal.put_nowait(event)
            return True
        except queue.Full:
            self._discard_callback(event)
            self.dropped["normal_newest"] += 1
            return False

    def _discard_callback(self, event):
        if isinstance(event, UiEvent) and event.payload:
            token = event.payload[0]
            if isinstance(token, str) and token.startswith("cb:"):
                with self.lock:
                    self.callbacks.pop(token, None)

    def drain(self, maximum=256):
        result = []
        for source in (self.termination, self.critical, self.normal):
            while len(result) < max(1, int(maximum)):
                try:
                    result.append(source.get_nowait())
                except queue.Empty:
                    break
        with self.lock:
            while self.coalesced and len(result) < max(1, int(maximum)):
                _, event = self.coalesced.popitem(last=False)
                result.append(event)
        return result

    def resolve_callback(self, event):
        if not isinstance(event, UiEvent) or not event.payload:
            return None
        token = event.payload[0]
        if not isinstance(token, str) or not token.startswith("cb:"):
            return None
        with self.lock:
            return self.callbacks.pop(token, None)

    def clear(self):
        for event in self.drain(100000):
            self._discard_callback(event)
        with self.lock:
            self.callbacks.clear()
            self.coalesced.clear()


class ManagedTask:
    def __init__(self, name, target, stop_callback=None, force_callback=None):
        self.name = str(name)
        self.target = target
        self.stop_event = threading.Event()
        self.stop_callback = stop_callback
        self.force_callback = force_callback
        self.thread = None
        self.error = None

    def start(self):
        if self.thread is not None and self.thread.is_alive():
            return self

        def runner():
            try:
                self.target(self.stop_event)
            except (UserCancelled, InputStopped):
                pass
            except Exception as error:
                self.error = error

        self.thread = threading.Thread(target=runner, name=self.name, daemon=True)
        self.thread.start()
        return self

    def request_stop(self):
        self.stop_event.set()
        if self.stop_callback is not None:
            self.stop_callback()

    def join(self, deadline):
        thread = self.thread
        if thread is None or not thread.is_alive():
            return True
        remaining = (
            max(0.0, float(deadline) - time.monotonic()) if float(deadline) > 1000 else max(0.0, float(deadline))
        )
        if thread is not threading.current_thread() and remaining > 0:
            thread.join(remaining)
        return not thread.is_alive()

    def force_close(self):
        self.request_stop()
        if self.force_callback is not None:
            return bool(self.force_callback())
        return not self.is_alive()

    def is_alive(self):
        return bool(self.thread and self.thread.is_alive())


