@dataclass(frozen=True, slots=True)
class RuntimePlanSet:
    collect: RuntimePlan
    ai: RuntimePlan
    upgrade: RuntimePlan
    numeric: RuntimePlan

    def for_mode(self, value):
        mode = normalize_mode_id(value)
        if mode == ModeId.COLLECT.value:
            return self.collect
        if mode == ModeId.UPGRADE.value:
            return self.upgrade
        if mode == ModeId.NUMERIC.value:
            return self.numeric
        return self.ai

