        return {
            ModeId.COLLECT.value: self.collect.to_dict(),
            ModeId.AI.value: self.ai.to_dict(),
            ModeId.UPGRADE.value: self.upgrade.to_dict(),
            ModeId.NUMERIC.value: self.numeric.to_dict(),
        }


