MODEL_TIER_SPECS = {
    "Tiny": ModelTierSpec("Tiny", 192, 128, 5, 32, 3, 24, 1.0, (224, 126), 1.0),
    "Base": ModelTierSpec("Base", 384, 256, 5, 64, 6, 48, 1.5, (320, 180), 1.35),
    "Large": ModelTierSpec("Large", 512, 512, 7, 128, 16, 72, 2.0, (384, 216), 1.6),
}


def normalize_model_tier(value):
    token = str(value or "").strip().casefold()
    if token == "large":
        return "Large"
    if token == "base":
        return "Base"
    return "Tiny"


def model_tier_spec(value=None):
    if isinstance(value, RuntimePlan):
        name = value.model_tier
    elif isinstance(value, dict):
        name = value.get("model_tier", value.get("capability_tier", "Tiny"))
    else:
        name = value
    return MODEL_TIER_SPECS[normalize_model_tier(name)]


def select_model_tier(
    backend,
    end_to_end_p95_ms,
    score_ms=None,
    free_vram=None,
    available_ram=None,
    total_vram=None,
    tested_peak_vram=None,
    vram_test_passed=False,
    maximum_peak_ratio=0.72,
):
    family = str(backend or "").casefold()
    latency = float(end_to_end_p95_ms or score_ms or 9999.0)
    score = float(score_ms or latency)
    accelerated = "nvidia" in family or "directml" in family
    vram_known = free_vram is not None and int(free_vram) >= 0
    ram_known = available_ram is not None and int(available_ram) > 0
    total_known = total_vram is not None and int(total_vram) > 0
    peak_known = tested_peak_vram is not None and int(tested_peak_vram) >= 0
    usable_vram = int(total_vram) if total_known else int(free_vram) + int(tested_peak_vram or 0) if vram_known else 0
    peak_ratio = int(tested_peak_vram) / max(1, usable_vram) if peak_known and usable_vram > 0 else 1.0
    large_vram_safe = bool(
        accelerated
        and vram_known
        and peak_known
        and bool(vram_test_passed)
        and int(free_vram) >= 3 * 1024**3
        and peak_ratio <= max(0.5, min(0.75, float(maximum_peak_ratio)))
    )
    if large_vram_safe and latency <= 42.0 and score <= 85.0:
        return "Large"
    base_memory_safe = bool(accelerated or ram_known and int(available_ram) >= 8 * 1024**3)
    if latency <= 80.0 and score <= 160.0 and base_memory_safe:
        return "Base"
    return "Tiny"


def classify_accelerator_fault(error):
    message = (type(error).__name__ + ":" + str(error)).casefold()
    oom = any(token in message for token in ("out of memory", "cuda oom", "e_outofmemory", "显存不足"))
    removed = any(token in message for token in ("device removed", "dxgi_error_device_removed", "device lost"))
    reset = any(token in message for token in ("device reset", "dxgi_error_device_reset", "driver reset", "tdr"))
    directml = any(token in message for token in ("directml", "privateuseone", "dml"))
    cuda = any(token in message for token in ("cuda", "cudnn", "cublas", "nvidia"))
    unsupported = any(
        token in message
        for token in ("not implemented", "unsupported operator", "operator is not supported")
    )
    return {
        "accelerator_fault": bool(oom or removed or reset or (directml or cuda) and not unsupported),
        "oom": bool(oom),
        "device_removed": bool(removed),
        "device_reset": bool(reset),
        "directml": bool(directml),
        "cuda": bool(cuda),
        "signature": hashlib.sha256(message.encode("utf-8", "replace")).hexdigest(),
    }


class WindowsGpuTelemetry:
    def __init__(self):
        self.lock = threading.RLock()
        self.cache = {}

    def _performance_counters(self, pid):
        if os.name != "nt":
            return {}
        command = (
            r"$p=@('\\GPU Engine(*)\\Utilization Percentage',"
            r"'\\GPU Adapter Memory(*)\\Dedicated Usage',"
            r"'\\GPU Adapter Memory(*)\\Shared Usage',"
            r"'\\GPU Process Memory(*)\\Dedicated Usage','\\GPU Process Memory(*)\\Shared Usage');"
            "$s=(Get-Counter -Counter $p -MaxSamples 1 -ErrorAction Stop).CounterSamples;"
            "$s|Select-Object Path,CookedValue|ConvertTo-Json -Compress"
        )
        try:
            output = subprocess.check_output(
                ["powershell.exe", "-NoProfile", "-NonInteractive", "-Command", command],
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=6,
                creationflags=0x08000000,
                stderr=subprocess.DEVNULL,
            ).strip()
            rows = json.loads(output) if output else []
            if isinstance(rows, dict):
                rows = [rows]
            utilization = []
            dedicated = []
            shared = []
            process_dedicated = []
            process_shared = []
            pid_token = "pid_" + str(int(pid)) + "_"
            for row in rows if isinstance(rows, list) else []:
                path = str(row.get("Path", "")).casefold()
                value = max(0.0, safe_float(row.get("CookedValue"), 0.0))
                if "utilization percentage" in path:
                    utilization.append(value)
                elif "gpu process memory" in path and "dedicated usage" in path and pid_token in path:
                    process_dedicated.append(value)
                elif "gpu process memory" in path and "shared usage" in path and pid_token in path:
                    process_shared.append(value)
                elif "gpu adapter memory" in path and "dedicated usage" in path:
                    dedicated.append(value)
                elif "gpu adapter memory" in path and "shared usage" in path:
                    shared.append(value)
            return {
                "gpu_utilization": min(100.0, sum(utilization)),
                "dedicated_vram_used": int(max(dedicated) if dedicated else 0),
                "shared_vram_used": int(max(shared) if shared else 0),
                "process_dedicated_vram": int(sum(process_dedicated)),
                "process_shared_vram": int(sum(process_shared)),
                "performance_counter_source": True,
            }
        except (OSError, ValueError, TypeError, subprocess.SubprocessError, json.JSONDecodeError):
            return {}

    def _nvml(self, pid):
        handled = RECOVERABLE_ERRORS
        try:
            import pynvml
            handled = handled + (getattr(pynvml, "NVMLError", RuntimeError),)
            pynvml.nvmlInit()
            best = None
            for index in range(pynvml.nvmlDeviceGetCount()):
                handle = pynvml.nvmlDeviceGetHandleByIndex(index)
                memory = pynvml.nvmlDeviceGetMemoryInfo(handle)
                utilization = pynvml.nvmlDeviceGetUtilizationRates(handle)
                process_bytes = 0
                process_getters = (
                    "nvmlDeviceGetComputeRunningProcesses_v3",
                    "nvmlDeviceGetComputeRunningProcesses_v2",
                    "nvmlDeviceGetComputeRunningProcesses",
                    "nvmlDeviceGetGraphicsRunningProcesses_v3",
                    "nvmlDeviceGetGraphicsRunningProcesses_v2",
                    "nvmlDeviceGetGraphicsRunningProcesses",
                )
                for name in process_getters:
                    getter = getattr(pynvml, name, None)
                    if getter is None:
                        continue
                    try:
                        for process in getter(handle):
                            if safe_int(getattr(process, "pid", 0), 0) == int(pid):
                                used = getattr(process, "usedGpuMemory", 0)
                                if isinstance(used, int) and used > 0:
                                    process_bytes += used
                    except handled:
                        pass
                row = {
                    "gpu_utilization": float(utilization.gpu),
                    "total_vram": int(memory.total),
                    "free_vram": int(memory.free),
                    "dedicated_vram_used": int(memory.used),
                    "process_dedicated_vram": int(process_bytes),
                    "source": "nvml",
                }
                if best is None or row["process_dedicated_vram"] > best["process_dedicated_vram"]:
                    best = row
            return best or {}
        except handled:
            return {}
        finally:
            try:
                pynvml.nvmlShutdown()
            except handled:
                pass

    def _nvidia_smi(self, pid):
        try:
            output = subprocess.check_output(
                [
                    "nvidia-smi",
                    "--query-gpu=utilization.gpu,memory.total,memory.free,memory.used",
                    "--format=csv,noheader,nounits",
                ],
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=4,
                creationflags=0x08000000 if os.name == "nt" else 0,
                stderr=subprocess.DEVNULL,
            ).strip()
            values = [item.strip() for item in output.splitlines()[0].split(",")]
            process_bytes = 0
            try:
                process_output = subprocess.check_output(
                    ["nvidia-smi", "--query-compute-apps=pid,used_memory", "--format=csv,noheader,nounits"],
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=4,
                    creationflags=0x08000000 if os.name == "nt" else 0,
                    stderr=subprocess.DEVNULL,
                )
                for line in process_output.splitlines():
                    parts = [item.strip() for item in line.split(",")]
                    if len(parts) >= 2 and safe_int(parts[0], -1) == int(pid):
                        process_bytes += int(float(parts[1]) * 1024 * 1024)
            except (OSError, ValueError, subprocess.SubprocessError) as error:
                record_cleanup_error("NVIDIA_PROCESS_TELEMETRY_FAILED", error)
            return {
                "gpu_utilization": max(0.0, min(100.0, float(values[0]))),
                "total_vram": int(float(values[1]) * 1024 * 1024),
                "free_vram": int(float(values[2]) * 1024 * 1024),
                "dedicated_vram_used": int(float(values[3]) * 1024 * 1024),
                "process_dedicated_vram": process_bytes,
                "source": "nvidia_smi_fallback",
            }
        except RECOVERABLE_ERRORS:
            return {}

    def sample(self, backend, process_pid=None, cache_seconds=2.0):
        if os.name != "nt":
            return {}
        pid = safe_int(process_pid, os.getpid(), 1)
        key = (str(backend), pid)
        now = time.monotonic()
        with self.lock:
            cached = self.cache.get(key)
            if cached is not None and now - cached[0] <= max(0.25, float(cache_seconds)):
                return dict(cached[1])
        family = str(backend or "").casefold()
        counters = self._performance_counters(pid)
        if "nvidia" in family:
            result = self._nvml(pid) or self._nvidia_smi(pid)
            dxgi = DXGI_VIDEO_MEMORY_TELEMETRY.sample(backend)
            for key_name, value in dxgi.items():
                result.setdefault(key_name, value)
        elif "directml" in family:
            result = DXGI_VIDEO_MEMORY_TELEMETRY.sample(backend)
        else:
            result = {}
        for key_name, value in counters.items():
            process_keys = {
                "process_dedicated_vram",
                "process_shared_vram",
            }
            if (
                key_name in process_keys
                or key_name not in result
                or result.get(key_name) in {None, 0}
            ):
                result[key_name] = value
        result.setdefault("source", "windows_performance_counters")
        with self.lock:
            self.cache[key] = (now, dict(result))
        return result



WINDOWS_GPU_TELEMETRY = WindowsGpuTelemetry()


def resource_integer(value, default, minimum, maximum):
    try:
        number = int(value)
    except (TypeError, ValueError, OverflowError):
        number = int(default)
    return max(int(minimum), min(int(maximum), number))


def resource_number(value, default):
    try:
        number = float(value)
    except (TypeError, ValueError, OverflowError):
        number = float(default)
    return number if math.isfinite(number) else float(default)


class ResourceGovernor:
    def __init__(self, window_seconds=30):
        self.window_seconds = max(10, min(30, int(window_seconds)))
        self.lock = threading.RLock()
        self.history = deque(maxlen=self.window_seconds)
        self.state = ResourceState.NORMAL
        cores = physical_core_count()
        self.benchmark_profile = {
            "backend": "windows-x64-cpu",
            "vision_batch": 8,
            "policy_batch": 24,
            "capture_fps": 30,
            "motion_capture_fps": 30,
            "semantic_interval": 4,
            "ocr_interval": 6,
            "precision": "fp32",
            "torch_threads": cores,
            "model_tier": "Tiny",
        }
        self._local = threading.local()
        self.accelerator_faults = deque(maxlen=64)
        self.backend_fault_counts = Counter()
        self.backend_blacklist = set()
        self.last_accelerator_fault_at = None
        self.accelerator_self_tests = {}
        self._fault_counter_baseline = {"removed": 0, "reset": 0, "oom": 0}
        self._fault_force_cpu = False
        self.plans = self._plans_for_state(ResourceState.NORMAL, "windows-x64-cpu")
        self.plan = self.plans.ai
        self.recovery_since = None
        self.thread = None
        self.stop_event = threading.Event()
        self.queue_reports = {}
        self.disk_writes = deque(maxlen=256)
        self._system_cpu_previous = None
        self._process_cpu_previous = (time.monotonic(), time.process_time())
        self._gpu_cache = (0.0, None, None)
        self._last_snapshot = HardwareSnapshot(
            cpu_percent=0.0,
            process_cpu_percent=0.0,
            available_ram=0,
            process_rss=0,
            gpu_backend="windows-x64-cpu",
            gpu_utilization=None,
            free_vram=None,
            capture_p95_ms=0.0,
            queue_ratio=0.0,
            queue_oldest_ms=0.0,
            disk_write_p95_ms=0.0,
        )

    def apply_benchmark_profile(self, profile):
        value = dict(profile) if isinstance(profile, dict) else {}
        if not value:
            return self.current_plan()
        with self.lock:
            self.benchmark_profile.update(
                {
                    "backend": str(
                        value.get("backend", self.benchmark_profile.get("backend", "windows-x64-cpu"))
                    ),
                    "vision_batch": max(
                        1,
                        safe_int(
                            value.get("vision_batch"),
                            self.benchmark_profile.get("vision_batch", 8),
                            1,
                            1024,
                        ),
                    ),
                    "policy_batch": max(
                        1,
                        safe_int(
                            value.get("policy_batch"),
                            self.benchmark_profile.get("policy_batch", 24),
                            1,
                            4096,
                        ),
                    ),
                    "capture_fps": max(
                        5,
                        safe_int(
                            value.get("capture_fps"),
                            self.benchmark_profile.get("capture_fps", 30),
                            5,
                            120,
                        ),
                    ),
                    "motion_capture_fps": max(
                        5,
                        safe_int(
                            value.get("motion_capture_fps", value.get("capture_fps")),
                            self.benchmark_profile.get("motion_capture_fps", 30),
                            5,
                            120,
                        ),
                    ),
                    "semantic_interval": max(
                        1,
                        safe_int(
                            value.get("semantic_interval"),
                            self.benchmark_profile.get("semantic_interval", 4),
                            1,
                            60,
                        ),
                    ),
                    "ocr_interval": max(
                        1,
                        safe_int(
                            value.get("ocr_interval"),
                            value.get("semantic_interval", 4) + 2,
                            1,
                            120,
                        ),
                    ),
                    "precision": str(value.get("precision", self.benchmark_profile.get("precision", "fp32"))),
                    "model_tier": normalize_model_tier(
                        value.get("model_tier", self.benchmark_profile.get("model_tier", "Tiny"))
                    ),
                    "torch_threads": max(
                        1,
                        min(
                            physical_core_count(),
                            safe_int(value.get("torch_threads"), physical_core_count(), 1, 256),
                        ),
                    ),
                }
            )
            for key in (
                "resolution_tier",
                "fast_visual_size",
                "semantic_visual_size",
                "ocr_roi_scale",
                "policy_state_size",
                "policy_hidden_size",
                "policy_ensemble_size",
                "temporal_context_length",
                "world_model_horizon",
                "object_slot_count",
                "vision_width_multiplier",
                "vision_backend",
                "policy_backend",
                "world_model_backend",
                "free_vram",
                "total_vram",
                "tested_peak_vram",
                "vram_test_passed",
                "large_model_validated",
                "vram_status",
            ):
                if key in value:
                    self.benchmark_profile[key] = value.get(key)
            self.plans = self._plans_for_state(self.state, self.benchmark_profile["backend"])
            self.plan = self.plans.ai
            return self.current_plan()

    def ensure_started(self):
        with self.lock:
            if self.thread is not None and self.thread.is_alive():
                return self
            self.stop_event.clear()
            self.thread = threading.Thread(target=self._run, name="UniversalGameAI-ResourceGovernor", daemon=True)
            self.thread.start()
        return self

    def stop(self, timeout=1.5):
        self.stop_event.set()
        thread = self.thread
        if thread is not None and thread.is_alive() and thread is not threading.current_thread():
            thread.join(max(0.0, float(timeout)))
        return not bool(thread and thread.is_alive())

    def report_queue(self, name, depth, capacity, oldest_ms=0.0):
        maximum = max(1, int(capacity))
        ratio = max(0.0, min(1.5, float(depth) / maximum))
        with self.lock:
            self.queue_reports[str(name)] = (ratio, max(0.0, float(oldest_ms)), time.monotonic())
        RUNTIME_METRICS.observe("queue_ratio", ratio)
        RUNTIME_METRICS.observe("queue_oldest_ms", max(0.0, float(oldest_ms)))
        return ratio

    def report_disk_write(self, milliseconds):
        value = max(0.0, float(milliseconds))
        with self.lock:
            self.disk_writes.append((time.monotonic(), value))
        RUNTIME_METRICS.observe("disk_write_ms", value)

    def report_gpu_queue_wait(self, milliseconds):
        RUNTIME_METRICS.observe("gpu_queue_wait_ms", max(0.0, float(milliseconds)))

    def report_cpu_to_gpu_copy(self, milliseconds):
        RUNTIME_METRICS.observe("cpu_to_gpu_copy_ms", max(0.0, float(milliseconds)))

    def _persist_backend_fault_state(self):
        store = APP_CONTEXT.store
        if store is None or not getattr(store, "base", None):
            return
        payload = {
            "schema_version": 1,
            "updated": time.time(),
            "run_id": str(os.getpid()) + "|" + str(int(time.time())),
            "blacklisted_backends": sorted(self.backend_blacklist),
            "fault_counts": dict(self.backend_fault_counts),
            "last_fault_monotonic": self.last_accelerator_fault_at,
            "events": list(self.accelerator_faults)[-32:],
            "cpu_safe_backend_retained": True,
        }
        try:
            _atomic_json_write(Path(store.base) / "audit" / "runtime_backend_blacklist.json", payload)
        except (OSError, ValueError, TypeError) as persist_error:
            record_cleanup_error("GPU_FAULT_STATE_PERSIST_FAILED", persist_error)

    def _record_accelerator_fault_locked(self, backend, details, now):
        family = str(backend or "windows-x64-cpu")
        kinds = [name for name in ("oom", "device_removed", "device_reset") if details.get(name)]
        if not kinds:
            return
        event = {
            "created": time.time(),
            "monotonic": float(now),
            "backend": family,
            "kinds": kinds,
            "signature": str(details.get("signature", "")),
        }
        self.accelerator_faults.append(event)
        self.last_accelerator_fault_at = float(now)
        self.accelerator_self_tests.pop(family, None)
        self.backend_fault_counts[family] += 1
        recent_same_backend = [
            item
            for item in self.accelerator_faults
            if item.get("backend") == family and now - safe_float(item.get("monotonic"), 0.0) <= 120.0
        ]
        if len(recent_same_backend) >= 2 and ("nvidia" in family.casefold() or "directml" in family.casefold()):
            self.backend_blacklist.add(family)
            self._fault_force_cpu = True

    def report_accelerator_fault(self, error):
        details = classify_accelerator_fault(error)
        if details["device_removed"]:
            RUNTIME_METRICS.increment("gpu_device_removed")
        if details["device_reset"]:
            RUNTIME_METRICS.increment("gpu_device_reset")
        if details["oom"]:
            RUNTIME_METRICS.increment("gpu_oom")
        if details.get("accelerator_fault"):
            now = time.monotonic()
            backend = self._manifest_backend()
            with self.lock:
                self._record_accelerator_fault_locked(backend, details, now)
                self.state = ResourceState.RED
                self.recovery_since = None
                self._fault_counter_baseline = {
                    "removed": int(RUNTIME_METRICS.counters.get("gpu_device_removed", 0)),
                    "reset": int(RUNTIME_METRICS.counters.get("gpu_device_reset", 0)),
                    "oom": int(RUNTIME_METRICS.counters.get("gpu_oom", 0)),
                }
                self.plans = self._plans_for_state(ResourceState.RED, backend)
                self.plan = self.plans.ai
            self._persist_backend_fault_state()
        details["backend_blacklisted"] = self.is_backend_blacklisted(self._manifest_backend())
        return details

    def mark_accelerator_self_test(self, backend, passed, total_vram=None, tested_peak_vram=None):
        family = str(backend or "")
        now = time.monotonic()
        with self.lock:
            matching_faults = [
                safe_float(item.get("monotonic"), 0.0)
                for item in self.accelerator_faults
                if item.get("backend") == family
            ]
            last_fault = max(matching_faults or [0.0])
            valid = bool(passed and family not in self.backend_blacklist and now >= last_fault)
            self.accelerator_self_tests[family] = {
                "passed": valid,
                "monotonic": now,
                "total_vram": None if total_vram is None else int(total_vram),
                "tested_peak_vram": None if tested_peak_vram is None else int(tested_peak_vram),
            }
            if valid:
                self.benchmark_profile["vram_test_passed"] = True
                self.benchmark_profile["large_model_validated"] = bool(
                    total_vram is not None
                    and tested_peak_vram is not None
                    and int(tested_peak_vram) <= int(total_vram) * 0.72
                )
                self.benchmark_profile["total_vram"] = total_vram
                self.benchmark_profile["tested_peak_vram"] = tested_peak_vram
                self.benchmark_profile["vram_status"] = "known" if total_vram is not None else "unknown"
                self.recovery_since = None
            self.plans = self._plans_for_state(self.state, family or self.benchmark_profile.get("backend"))
            self.plan = self.plans.ai
        self._persist_backend_fault_state()
        return valid

    def blacklist_backend_for_run(self, backend, reason="repeated_accelerator_fault"):
        family = str(backend or "")
        if not family:
            return False
        with self.lock:
            self.backend_blacklist.add(family)
            self._fault_force_cpu = True
            self.backend_fault_counts[family + "|blacklist"] += 1
            self.plans = self._plans_for_state(ResourceState.RED, family)
            self.plan = self.plans.ai
        self._persist_backend_fault_state()
        return True

    def is_backend_blacklisted(self, backend):
        family = str(backend or "")
        with self.lock:
            return family in self.backend_blacklist

    @staticmethod
    def _filetime_value(value):
        return (int(value.dwHighDateTime) << 32) | int(value.dwLowDateTime)

    def _cpu_values(self):
        now = time.monotonic()
        process_now = time.process_time()
        old_wall, old_process = self._process_cpu_previous
        self._process_cpu_previous = (now, process_now)
        process_percent = 100.0 * max(0.0, process_now - old_process) / max(1e-6, now - old_wall)
        process_percent /= max(1, os.cpu_count() or 1)
        if os.name != "nt":
            try:
                load = os.getloadavg()[0]
                total = 100.0 * load / max(1, os.cpu_count() or 1)
            except (AttributeError, OSError):
                total = process_percent
            return max(0.0, min(100.0, total)), max(0.0, min(100.0, process_percent))
        try:
            kernel = ctypes.WinDLL("kernel32", use_last_error=True)
            idle = wintypes.FILETIME()
            kernel_time = wintypes.FILETIME()
            user = wintypes.FILETIME()
            if not kernel.GetSystemTimes(ctypes.byref(idle), ctypes.byref(kernel_time), ctypes.byref(user)):
                raise OSError(ctypes.get_last_error())
            current = (self._filetime_value(idle), self._filetime_value(kernel_time), self._filetime_value(user))
            previous = self._system_cpu_previous
            self._system_cpu_previous = current
            if previous is None:
                total = process_percent
            else:
                idle_delta = current[0] - previous[0]
                total_delta = current[1] - previous[1] + current[2] - previous[2]
                total = 100.0 * max(0, total_delta - idle_delta) / max(1, total_delta)
            return max(0.0, min(100.0, total)), max(0.0, min(100.0, process_percent))
        except (OSError, AttributeError, ValueError):
            return max(0.0, min(100.0, process_percent)), max(0.0, min(100.0, process_percent))

    @staticmethod
    def _memory_values():
        if os.name == "nt":
            class MEMORYSTATUSEX(ctypes.Structure):
                _fields_ = [
                    ("dwLength", wintypes.DWORD),
                    ("dwMemoryLoad", wintypes.DWORD),
                    ("ullTotalPhys", ctypes.c_ulonglong),
                    ("ullAvailPhys", ctypes.c_ulonglong),
                    ("ullTotalPageFile", ctypes.c_ulonglong),
                    ("ullAvailPageFile", ctypes.c_ulonglong),
                    ("ullTotalVirtual", ctypes.c_ulonglong),
                    ("ullAvailVirtual", ctypes.c_ulonglong),
                    ("ullAvailExtendedVirtual", ctypes.c_ulonglong),
                ]
            class PROCESS_MEMORY_COUNTERS(ctypes.Structure):
                _fields_ = [
                    ("cb", wintypes.DWORD),
                    ("PageFaultCount", wintypes.DWORD),
                    ("PeakWorkingSetSize", ctypes.c_size_t),
                    ("WorkingSetSize", ctypes.c_size_t),
                    ("QuotaPeakPagedPoolUsage", ctypes.c_size_t),
                    ("QuotaPagedPoolUsage", ctypes.c_size_t),
                    ("QuotaPeakNonPagedPoolUsage", ctypes.c_size_t),
                    ("QuotaNonPagedPoolUsage", ctypes.c_size_t),
                    ("PagefileUsage", ctypes.c_size_t),
                    ("PeakPagefileUsage", ctypes.c_size_t),
                ]
            try:
                status = MEMORYSTATUSEX()
                status.dwLength = ctypes.sizeof(status)
                kernel = ctypes.WinDLL("kernel32", use_last_error=True)
                if not kernel.GlobalMemoryStatusEx(ctypes.byref(status)):
                    raise OSError(ctypes.get_last_error())
                counters = PROCESS_MEMORY_COUNTERS()
                counters.cb = ctypes.sizeof(counters)
                psapi = ctypes.WinDLL("psapi", use_last_error=True)
                handle = kernel.GetCurrentProcess()
                if not psapi.GetProcessMemoryInfo(handle, ctypes.byref(counters), counters.cb):
                    raise OSError(ctypes.get_last_error())
                return int(status.ullAvailPhys), int(counters.WorkingSetSize)
            except (OSError, AttributeError, ValueError):
                return 0, 0
        try:
            page = int(os.sysconf("SC_PAGE_SIZE"))
            available = int(os.sysconf("SC_AVPHYS_PAGES")) * page
        except (AttributeError, OSError, ValueError):
            available = 0
        try:
            import resource
            rss = int(resource.getrusage(resource.RUSAGE_SELF).ru_maxrss)
            rss = rss if sys.platform == "darwin" else rss * 1024
        except (ImportError, AttributeError, ValueError):
            rss = 0
        return available, rss

    @staticmethod
    def _manifest_backend():
        runtime = APP_CONTEXT.vision_runtime
        try:
            if runtime is not None:
                status = getattr(getattr(runtime, "worker", None), "status", {})
                manifest = status.get("runtime_manifest", {}) if isinstance(status, dict) else {}
                if isinstance(manifest, dict) and (
                    manifest.get("effective_runtime_family") or manifest.get("runtime_family")
                ):
                    return str(
                        manifest.get("effective_runtime_family") or manifest.get("runtime_family")
                    )
                value = runtime.manifest() if getattr(runtime, "active_game", "") else {}
                fingerprint = value.get("runtime_fingerprint", {}) if isinstance(value, dict) else {}
                backend = str(fingerprint.get("gpu_backend", ""))
                if backend:
                    return backend
        except (RuntimeError, ValueError, TypeError, AttributeError):
            pass
        return "windows-x64-cpu"

    def _gpu_values(self, backend):
        family = str(backend).casefold()
        counter_values = WINDOWS_GPU_TELEMETRY.sample(backend)
        if "nvidia" not in family:
            return (
                counter_values.get("gpu_utilization"),
                None,
                counter_values.get("dedicated_vram_used"),
                counter_values.get("shared_vram_used"),
            )
        now = time.monotonic()
        cached_at, utilization, free_vram = self._gpu_cache
        if now - cached_at >= 5.0:
            try:
                creationflags = 0x08000000 if os.name == "nt" else 0
                output = subprocess.check_output(
                    ["nvidia-smi", "--query-gpu=utilization.gpu,memory.free", "--format=csv,noheader,nounits"],
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=3,
                    creationflags=creationflags,
                    stderr=subprocess.DEVNULL,
                )
                first = output.strip().splitlines()[0].split(",")
                utilization = max(0.0, min(100.0, float(first[0].strip())))
                free_vram = max(0, int(float(first[1].strip()) * 1024 * 1024))
            except (OSError, ValueError, IndexError, subprocess.SubprocessError):
                utilization = counter_values.get("gpu_utilization")
                free_vram = None
            self._gpu_cache = (now, utilization, free_vram)
        return (
            utilization,
            free_vram,
            counter_values.get("dedicated_vram_used"),
            counter_values.get("shared_vram_used"),
        )

    @staticmethod
    def _series_p95(name):
        return max(0.0, float(RUNTIME_METRICS.percentile(str(name), 0.95, 0.75)))

    def _queue_values(self):
        now = time.monotonic()
        with self.lock:
            stale = [name for name, value in self.queue_reports.items() if now - value[2] > 3.0]
            for name in stale:
                self.queue_reports.pop(name, None)
            values = list(self.queue_reports.values())
        if not values:
            return 0.0, 0.0
        return max(value[0] for value in values), max(value[1] for value in values)

    def _disk_p95(self):
        now = time.monotonic()
        with self.lock:
            while self.disk_writes and now - self.disk_writes[0][0] > self.window_seconds:
                self.disk_writes.popleft()
            values = sorted(value for _, value in self.disk_writes)
        if not values:
            return self._series_p95("disk_write_ms")
        return values[min(len(values) - 1, int(round((len(values) - 1) * 0.95)))]

    def _base_sample_once_strict(self):
        cpu, process_cpu = self._cpu_values()
        available_ram, process_rss = self._memory_values()
        backend = self._manifest_backend()
        gpu_utilization, free_vram, dedicated_vram_used, shared_vram_used = self._gpu_values(backend)
        queue_ratio, queue_oldest = self._queue_values()
        perception_p95 = self._series_p95("end_to_end_perception_ms")
        decision_p95 = self._series_p95("end_to_end_decision_ms")
        end_to_end_p95 = max(perception_p95, decision_p95)
        end_to_end_p99 = max(
            RUNTIME_METRICS.percentile("end_to_end_perception_ms", 0.99, 0.75),
            RUNTIME_METRICS.percentile("end_to_end_decision_ms", 0.99, 0.75),
        )
        now = time.monotonic()
        counts = {
            "removed": int(RUNTIME_METRICS.counters.get("gpu_device_removed", 0)),
            "reset": int(RUNTIME_METRICS.counters.get("gpu_device_reset", 0)),
            "oom": int(RUNTIME_METRICS.counters.get("gpu_oom", 0)),
        }
        with self.lock:
            deltas = {
                key: max(0, counts[key] - safe_int(self._fault_counter_baseline.get(key), 0))
                for key in counts
            }
            self._fault_counter_baseline = dict(counts)
            if any(deltas.values()):
                details = {
                    "oom": deltas["oom"] > 0,
                    "device_removed": deltas["removed"] > 0,
                    "device_reset": deltas["reset"] > 0,
                    "signature": hashlib.sha256(canonical_bytes({"backend": backend, "counts": counts})).hexdigest(),
                }
                self._record_accelerator_fault_locked(backend, details, now)
            last_fault = self.last_accelerator_fault_at
            fault_age = None if last_fault is None else max(0.0, now - last_fault)
            self_test = self.accelerator_self_tests.get(str(backend), {})
            self_test_passed = bool(
                self_test.get("passed")
                and safe_float(self_test.get("monotonic"), 0.0) >= safe_float(last_fault, 0.0)
            )
            backend_blacklisted = str(backend) in self.backend_blacklist
            total_vram = self.benchmark_profile.get("total_vram")
            tested_peak_vram = self.benchmark_profile.get("tested_peak_vram")
        snapshot = HardwareSnapshot(
            cpu_percent=round(cpu, 3),
            process_cpu_percent=round(process_cpu, 3),
            available_ram=int(available_ram),
            process_rss=int(process_rss),
            gpu_backend=str(backend),
            gpu_utilization=gpu_utilization,
            free_vram=free_vram,
            capture_p95_ms=round(self._series_p95("capture_latency_ms"), 3),
            queue_ratio=round(queue_ratio, 5),
            queue_oldest_ms=round(queue_oldest, 3),
            disk_write_p95_ms=round(self._disk_p95(), 3),
            end_to_end_p95_ms=round(end_to_end_p95, 3),
            end_to_end_p99_ms=round(end_to_end_p99, 3),
            dedicated_vram_used=dedicated_vram_used,
            shared_vram_used=shared_vram_used,
            gpu_queue_wait_p95_ms=round(self._series_p95("gpu_queue_wait_ms"), 3),
            cpu_to_gpu_copy_p95_ms=round(self._series_p95("cpu_to_gpu_copy_ms"), 3),
            device_removed_count=counts["removed"],
            device_reset_count=counts["reset"],
            gpu_oom_count=counts["oom"],
            device_removed_delta=deltas["removed"],
            device_reset_delta=deltas["reset"],
            gpu_oom_delta=deltas["oom"],
            last_accelerator_fault_monotonic=last_fault,
            accelerator_fault_age_seconds=fault_age,
            accelerator_self_test_passed=self_test_passed,
            backend_blacklisted=backend_blacklisted,
            available_ram_known=int(available_ram) > 0,
            free_vram_known=free_vram is not None,
            total_vram=None if total_vram is None else safe_int(total_vram, 0, 0),
            tested_peak_vram=None if tested_peak_vram is None else safe_int(tested_peak_vram, 0, 0),
        )
        with self.lock:
            self.history.append(snapshot)
            self._last_snapshot = snapshot
            self._update_state_locked(now)
        if any(deltas.values()) or backend_blacklisted:
            self._persist_backend_fault_state()
        store = APP_CONTEXT.store
        if store is not None and getattr(store, "base", None) and snapshot.end_to_end_p95_ms > 0:
            update_hardware_profile_health(store.base, snapshot.end_to_end_p95_ms)
        return snapshot

    def sample_once(self):
        implementation = globals().get("_strict_governor_sample_once")
        if implementation is None:
            return self._base_sample_once_strict()
        return implementation(self)

    def _base_update_state_locked_strict(self, now):
        recent = list(self.history)
        current = recent[-1]
        last_five = recent[-5:]
        queue_yellow = len(last_five) >= 5 and all(item.queue_ratio > 0.70 for item in last_five)
        queue_red = len(recent) >= 2 and all(item.queue_ratio > 0.90 for item in recent[-2:])
        thresholds = RUNTIME_THRESHOLDS
        accelerator = "nvidia" in current.gpu_backend.casefold() or "directml" in current.gpu_backend.casefold()
        new_fault = bool(current.device_removed_delta or current.device_reset_delta or current.gpu_oom_delta)
        fault_age = current.accelerator_fault_age_seconds
        fault_red = bool(
            accelerator
            and (
                current.backend_blacklisted
                or new_fault
                or fault_age is not None and fault_age <= 30.0 and not current.accelerator_self_test_passed
            )
        )
        fault_yellow = bool(
            accelerator
            and not fault_red
            and fault_age is not None
            and not current.accelerator_self_test_passed
        )
        severe = bool(
            fault_red
            or queue_red
            or current.available_ram_known and current.available_ram < thresholds.ram_red_bytes
            or current.capture_p95_ms > thresholds.capture_red_ms
            or current.end_to_end_p95_ms > thresholds.end_to_end_red_p95_ms
            or current.disk_write_p95_ms > 180.0
            or current.cpu_percent > 97.0
            or current.gpu_utilization is not None and current.gpu_utilization > 98.0
            or current.free_vram_known and current.free_vram < thresholds.free_vram_red_bytes
            or current.gpu_queue_wait_p95_ms > 40.0
            or current.cpu_to_gpu_copy_p95_ms > 30.0
        )
        warning = bool(
            severe
            or fault_yellow
            or queue_yellow
            or current.capture_p95_ms > thresholds.capture_yellow_ms
            or current.end_to_end_p95_ms > thresholds.end_to_end_yellow_p95_ms
            or current.available_ram_known and current.available_ram < thresholds.ram_yellow_bytes
            or current.disk_write_p95_ms > 80.0
            or current.cpu_percent > 88.0
            or current.process_cpu_percent > 85.0
            or current.gpu_utilization is not None and current.gpu_utilization > 94.0
            or current.free_vram_known and current.free_vram < thresholds.free_vram_yellow_bytes
            or current.gpu_queue_wait_p95_ms > 18.0
            or current.cpu_to_gpu_copy_p95_ms > 12.0
            or current.shared_vram_used is not None and current.shared_vram_used > 2 * 1024**3
        )
        desired = ResourceState.RED if severe else ResourceState.YELLOW if warning else ResourceState.NORMAL
        previous_state = self.state
        if fault_red:
            self.state = ResourceState.RED
            self.recovery_since = None
        elif (
            previous_state is ResourceState.RED
            and fault_age is not None
            and fault_age > 30.0
            and not current.accelerator_self_test_passed
        ):
            self.state = ResourceState.YELLOW
            self.recovery_since = now
        elif current.accelerator_self_test_passed and not severe:
            self.state = ResourceState.YELLOW if warning else ResourceState.NORMAL
            self.recovery_since = None
        else:
            rank = {ResourceState.NORMAL: 0, ResourceState.YELLOW: 1, ResourceState.RED: 2}
            if rank[desired] > rank[self.state]:
                self.state = desired
                self.recovery_since = None
            elif rank[desired] < rank[self.state]:
                if self.recovery_since is None:
                    self.recovery_since = now
                elif now - self.recovery_since >= 30.0:
                    self.state = desired
                    self.recovery_since = None
            else:
                self.recovery_since = None
        self.plans = self._plans_for_state(self.state, current.gpu_backend)
        self.plan = self.plans.ai
        if (
            self.state is ResourceState.RED
            and current.available_ram_known
            and current.available_ram < thresholds.ram_red_bytes
        ):
            FEATURE_ENGINE.clear_frames()
            cache = globals().get("POLICY_TRAINING_CACHE")
            if cache is not None:
                cache.clear()
            collect_garbage("resource_red", 30.0, previous_state is not ResourceState.RED)

    def _update_state_locked(self, now):
        implementation = globals().get("_strict_governor_update_state")
        if implementation is None:
            return self._base_update_state_locked_strict(now)
        return implementation(self, now)

    def plan_envelope(self):
        implementation = globals().get("_strict_plan_envelope")
        if implementation is None:
            plan = self.current_plan(ModeId.AI.value)
            return {"plan_version": 1, "plan_reason": "startup", "requested_backend": str(plan.backend), "requested_model_tier": normalize_model_tier(plan.model_tier), "worker_ack_version": 0, "applied_backend": "", "applied_model_tier": "Tiny", "resource_state": self.state.value, "red_duration_seconds": 0.0, "plan": plan.to_dict()}
        return implementation(self)

    def acknowledge_worker(self, value):
        implementation = globals().get("_strict_ack_worker")
        if implementation is None:
            return safe_int((value or {}).get("worker_ack_version", (value or {}).get("plan_version", 0)), 0) if isinstance(value, dict) else 0
        return implementation(self, value)

    def plan_envelope(self):
        return _strict_plan_envelope(self)

    def acknowledge_worker(self, value):
        return _strict_ack_worker(self, value)

    @staticmethod
    def _size_pair(value, default, minimum=(32, 18), maximum=(1024, 1024)):
        if isinstance(value, (list, tuple)) and len(value) >= 2:
            width = resource_integer(value[0], default[0], minimum[0], maximum[0])
            height = resource_integer(value[1], default[1], minimum[1], maximum[1])
            return width, height
        return int(default[0]), int(default[1])

    def _plan_for_state(self, state, backend, purpose=ModeId.AI.value):
        profile = self.benchmark_profile
        mode = normalize_mode_id(purpose)
        cores = physical_core_count()
        threads = resource_integer(profile.get("torch_threads"), cores, 1, cores)
        capture = resource_integer(profile.get("capture_fps"), 30, 5, 120)
        motion_capture = resource_integer(profile.get("motion_capture_fps"), capture, 5, 120)
        semantic_interval = resource_integer(profile.get("semantic_interval"), 4, 1, 120)
        ocr_interval = resource_integer(profile.get("ocr_interval"), semantic_interval + 2, 1, 240)
        vision_batch = resource_integer(profile.get("vision_batch"), 8, 1, 1024)
        policy_batch = resource_integer(profile.get("policy_batch"), 24, 1, 4096)
        precision = str(profile.get("precision", "fp32"))
        tier = str(profile.get("resolution_tier", "low"))
        tier_defaults = {
            "low": ((64, 36), (224, 126), 1.0),
            "medium": ((128, 72), (320, 180), 1.35),
            "high": ((160, 90), (384, 216), 1.6),
        }
        if tier not in tier_defaults:
            tier = "low"
        fast_default, semantic_default, scale_default = tier_defaults[tier]
        fast_w, fast_h = self._size_pair(profile.get("fast_visual_size"), fast_default)
        semantic_w, semantic_h = self._size_pair(profile.get("semantic_visual_size"), semantic_default)
        ocr_scale = max(0.5, min(3.0, resource_number(profile.get("ocr_roi_scale"), scale_default)))
        requested_model = normalize_model_tier(profile.get("model_tier", "Tiny"))
        if state is ResourceState.YELLOW and requested_model == "Large":
            requested_model = "Base"
        if state is ResourceState.RED:
            requested_model = "Tiny"
        spec = model_tier_spec(requested_model)
        state_size = resource_integer(profile.get("policy_state_size"), spec.state_size, 64, 2048)
        hidden_size = resource_integer(profile.get("policy_hidden_size"), spec.hidden_size, 32, 2048)
        ensemble_size = resource_integer(profile.get("policy_ensemble_size"), spec.ensemble_size, 1, 15)
        temporal = resource_integer(profile.get("temporal_context_length"), spec.temporal_context, 8, 512)
        horizon = resource_integer(profile.get("world_model_horizon"), spec.planning_horizon, 1, 64)
        slots = resource_integer(profile.get("object_slot_count"), spec.object_slots, 8, 256)
        width_multiplier = resource_number(
            profile.get("vision_width_multiplier"), spec.vision_width_multiplier
        )
        width_multiplier = max(0.5, min(4.0, width_multiplier))
        family = str(backend or "windows-x64-cpu")
        accelerated = "nvidia" in family.casefold() or "directml" in family.casefold()
        force_cpu = bool(
            self._fault_force_cpu
            or family in self.backend_blacklist
            or state is ResourceState.RED and accelerated
        )
        vision_backend = str(profile.get("vision_backend", family if accelerated else "windows-x64-cpu"))
        policy_backend = str(profile.get("policy_backend", family if accelerated else "windows-x64-cpu"))
        world_backend = str(profile.get("world_model_backend", "windows-x64-cpu" if accelerated else family))
        if force_cpu:
            family = "windows-x64-cpu"
            vision_backend = family
            policy_backend = family
            world_backend = family
            precision = "int8"
        if mode == ModeId.COLLECT.value:
            capture = max(capture, motion_capture)
            semantic_interval = max(semantic_interval, 6)
            ocr_interval = max(ocr_interval, 12)
            training_batch = 0
            vision_batch = max(1, min(vision_batch, 4))
            policy_batch = max(1, min(policy_batch, 8))
        elif mode == ModeId.UPGRADE.value:
            capture = max(5, min(capture, 12))
            motion_capture = capture
            semantic_interval = max(semantic_interval, 8)
            ocr_interval = max(ocr_interval, 16)
            training_batch = policy_batch
            vision_batch = max(vision_batch, 8)
        elif mode == ModeId.NUMERIC.value:
            capture = max(8, min(capture, 20))
            motion_capture = capture
            semantic_interval = 1
            ocr_interval = 1
            training_batch = 0
            semantic_w = max(semantic_w, 320)
            semantic_h = max(semantic_h, 180)
            ocr_scale = max(ocr_scale, 1.35)
            policy_batch = max(1, min(policy_batch, 8))
        else:
            training_batch = 0
            capture = max(15, capture)
            semantic_interval = max(1, semantic_interval)
            ocr_interval = max(2, ocr_interval)
        if state is ResourceState.YELLOW:
            capture = max(12, capture * 4 // 5)
            motion_capture = min(motion_capture, capture)
            semantic_interval = max(2, semantic_interval * 3 // 2)
            ocr_interval = max(3, ocr_interval * 3 // 2)
            vision_batch = max(1, vision_batch // 2)
            policy_batch = max(1, policy_batch // 2)
            training_batch = max(0, training_batch // 2)
            ensemble_size = max(1, ensemble_size - 2)
            horizon = max(1, horizon // 2)
        elif state is ResourceState.RED:
            capture = max(10, min(capture, 18))
            motion_capture = min(motion_capture, capture)
            semantic_interval = max(4, semantic_interval * 2)
            ocr_interval = max(6, ocr_interval * 2)
            training_batch = 0
            vision_batch = 1
            policy_batch = max(1, min(policy_batch, 4))
            threads = max(1, threads // 3)
            fast_w, fast_h = min(fast_w, 64), min(fast_h, 36)
            semantic_w, semantic_h = min(semantic_w, 224), min(semantic_h, 126)
            state_size = min(state_size, 192)
            hidden_size = min(hidden_size, 128)
            ensemble_size = min(ensemble_size, 3)
            temporal = min(temporal, 32)
            horizon = min(horizon, 3)
            slots = min(slots, 24)
            width_multiplier = min(width_multiplier, 1.0)
        return RuntimePlan(
            capture_fps=int(capture),
            semantic_frame_interval=int(semantic_interval),
            ocr_frame_interval=int(ocr_interval),
            training_batch_size=int(training_batch),
            torch_threads=int(threads),
            prototype_limit=(
                160
                if state is ResourceState.RED
                else 240 if state is ResourceState.YELLOW else MAX_PROTOTYPES
            ),
            backend=family,
            vision_batch_size=int(vision_batch),
            policy_batch_size=int(policy_batch),
            precision=precision,
            fast_vision_width=int(fast_w),
            fast_vision_height=int(fast_h),
            semantic_width=int(semantic_w),
            semantic_height=int(semantic_h),
            ocr_roi_scale=float(ocr_scale),
            motion_capture_fps=int(motion_capture),
            resolution_tier=tier,
            model_tier=spec.name,
            policy_state_size=int(state_size),
            policy_hidden_size=int(hidden_size),
            policy_ensemble_size=int(ensemble_size),
            temporal_context_length=int(temporal),
            world_model_horizon=int(horizon),
            object_slot_count=int(slots),
            vision_width_multiplier=float(width_multiplier),
            purpose=mode,
            vision_backend=vision_backend,
            policy_backend=policy_backend,
            world_model_backend=world_backend,
            vram_status=str(profile.get("vram_status", "unknown")),
            large_model_validated=bool(profile.get("large_model_validated", False)),
        )

    def _plans_for_state(self, state, backend):
        return RuntimePlanSet(
            collect=self._plan_for_state(state, backend, ModeId.COLLECT.value),
            ai=self._plan_for_state(state, backend, ModeId.AI.value),
            upgrade=self._plan_for_state(state, backend, ModeId.UPGRADE.value),
            numeric=self._plan_for_state(state, backend, ModeId.NUMERIC.value),
        )

    @contextmanager
    def plan_scope(self, mode):
        previous = getattr(self._local, "mode", None)
        self._local.mode = normalize_mode_id(mode)
        try:
            yield self.current_plan(self._local.mode)
        finally:
            if previous is None:
                try:
                    del self._local.mode
                except AttributeError:
                    pass
            else:
                self._local.mode = previous

    def _run(self):
        while not self.stop_event.is_set():
            started = time.monotonic()
            try:
                self.sample_once()
            except RECOVERABLE_ERRORS as error:
                record_cleanup_error("RESOURCE_GOVERNOR_SAMPLE_FAILED", error)
            self.stop_event.wait(max(0.05, 1.0 - (time.monotonic() - started)))

    def current_plan(self, mode=None):
        self.ensure_started()
        selected = normalize_mode_id(mode or getattr(self._local, "mode", ModeId.AI.value))
        with self.lock:
            return self.plans.for_mode(selected)

    def current_snapshot(self):
        self.ensure_started()
        with self.lock:
            return self._last_snapshot

    def status(self):
        self.ensure_started()
        with self.lock:
            return {
                "state": self.state.value,
                "plan": self.plan,
                "plans": self.plans.to_dict(),
                "snapshot": self._last_snapshot,
                "backend_blacklist": sorted(self.backend_blacklist),
                "accelerator_faults": list(self.accelerator_faults)[-16:],
            }

    def sample_production_allowed(self):
        snapshot = self.current_snapshot()
        return snapshot.queue_ratio <= 0.90 and self.current_plan(ModeId.UPGRADE.value).training_batch_size > 0


RESOURCE_GOVERNOR = ResourceGovernor(30)
_TORCH_INTEROP_CONFIGURED = False


def configure_torch_runtime(torch_module, plan=None):
    global _TORCH_INTEROP_CONFIGURED
    value = plan or RESOURCE_GOVERNOR.current_plan()
    try:
        torch_module.set_num_threads(max(1, min(physical_core_count(), int(value.torch_threads))))
    except (RuntimeError, AttributeError, TypeError, ValueError):
        pass
    if not _TORCH_INTEROP_CONFIGURED:
        try:
            torch_module.set_num_interop_threads(1)
            _TORCH_INTEROP_CONFIGURED = True
        except (RuntimeError, AttributeError, TypeError, ValueError):
            pass
    precision = str(getattr(value, "precision", "fp32")).casefold()
    try:
        if hasattr(torch_module.backends, "cuda") and hasattr(torch_module.backends.cuda, "matmul"):
            allow_tf32 = precision in {"tf32", "fp16", "mixed_fp16", "fp16_tf32"}
            torch_module.backends.cuda.matmul.allow_tf32 = allow_tf32
        if hasattr(torch_module.backends, "cudnn"):
            torch_module.backends.cudnn.allow_tf32 = precision in {"tf32", "fp16", "mixed_fp16", "fp16_tf32"}
        if hasattr(torch_module, "set_float32_matmul_precision"):
            matmul_precision = (
                "high"
                if precision in {"tf32", "fp16", "mixed_fp16", "fp16_tf32"}
                else "highest"
            )
            torch_module.set_float32_matmul_precision(matmul_precision)
    except (RuntimeError, AttributeError, TypeError, ValueError):
        pass
    return value


def torch_inference_context(torch_module, device, plan=None):
    value = plan or RESOURCE_GOVERNOR.current_plan()
    precision = str(getattr(value, "precision", "fp32")).casefold()
    device_type = str(getattr(device, "type", device)).casefold()
    if device_type == "cuda" and precision in {"fp16", "mixed_fp16", "fp16_tf32"}:
        try:
            return torch_module.autocast(device_type="cuda", dtype=torch_module.float16)
        except (RuntimeError, AttributeError, TypeError):
            return nullcontext()
    return nullcontext()


def _atomic_json_write(path, value):
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    temporary = target.with_suffix(target.suffix + ".tmp")
    temporary.write_text(
        json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":")),
        encoding="utf-8",
    )
    os.replace(temporary, target)


def _total_physical_ram():
    try:
        import psutil

        return int(psutil.virtual_memory().total)
    except (ImportError, AttributeError, TypeError, ValueError):
        pass
    if os.name == "nt":
        class MEMORYSTATUSEX(ctypes.Structure):
            _fields_ = [
                ("dwLength", wintypes.DWORD),
                ("dwMemoryLoad", wintypes.DWORD),
                ("ullTotalPhys", ctypes.c_ulonglong),
                ("ullAvailPhys", ctypes.c_ulonglong),
                ("ullTotalPageFile", ctypes.c_ulonglong),
                ("ullAvailPageFile", ctypes.c_ulonglong),
                ("ullTotalVirtual", ctypes.c_ulonglong),
                ("ullAvailVirtual", ctypes.c_ulonglong),
                ("ullAvailExtendedVirtual", ctypes.c_ulonglong),
            ]

        try:
            status = MEMORYSTATUSEX()
            status.dwLength = ctypes.sizeof(status)
            if ctypes.WinDLL("kernel32", use_last_error=True).GlobalMemoryStatusEx(ctypes.byref(status)):
                return int(status.ullTotalPhys)
        except (OSError, AttributeError, ValueError):
            pass
    try:
        return int(os.sysconf("SC_PHYS_PAGES")) * int(os.sysconf("SC_PAGE_SIZE"))
    except (AttributeError, OSError, ValueError):
        return 0


def _cpu_model_name():
    values = [platform.processor(), platform.machine()]
    if os.name == "nt":
        try:
            import winreg

            with winreg.OpenKey(
                winreg.HKEY_LOCAL_MACHINE,
                r"HARDWARE\DESCRIPTION\System\CentralProcessor\0",
            ) as key:
                values.insert(0, str(winreg.QueryValueEx(key, "ProcessorNameString")[0]))
        except (ImportError, OSError, ValueError):
            pass
    return next((value.strip() for value in values if str(value).strip()), "unknown")


def _display_topology():
    if os.name != "nt":
        return {"count": 0, "virtual_rect": [], "primary": []}
    try:
        user32 = ctypes.WinDLL("user32", use_last_error=True)
        return {
            "count": int(user32.GetSystemMetrics(80)),
            "virtual_rect": [
                int(user32.GetSystemMetrics(76)),
                int(user32.GetSystemMetrics(77)),
                int(user32.GetSystemMetrics(78)),
                int(user32.GetSystemMetrics(79)),
            ],
            "primary": [int(user32.GetSystemMetrics(0)), int(user32.GetSystemMetrics(1))],
        }
    except (OSError, AttributeError, ValueError):
        return {"count": 0, "virtual_rect": [], "primary": []}


def _power_profile():
    result = {"ac_line": "unknown", "active_scheme": "unknown"}
    if os.name != "nt":
        return result
    class SYSTEM_POWER_STATUS(ctypes.Structure):
        _fields_ = [
            ("ACLineStatus", ctypes.c_ubyte),
            ("BatteryFlag", ctypes.c_ubyte),
            ("BatteryLifePercent", ctypes.c_ubyte),
            ("SystemStatusFlag", ctypes.c_ubyte),
            ("BatteryLifeTime", wintypes.DWORD),
            ("BatteryFullLifeTime", wintypes.DWORD),
        ]
    try:
        status = SYSTEM_POWER_STATUS()
        if ctypes.WinDLL("kernel32", use_last_error=True).GetSystemPowerStatus(ctypes.byref(status)):
            result["ac_line"] = {0: "battery", 1: "ac"}.get(int(status.ACLineStatus), "unknown")
            result["battery_percent"] = int(status.BatteryLifePercent)
    except (OSError, AttributeError, ValueError):
        pass
    try:
        output = subprocess.check_output(
            ["powercfg", "/getactivescheme"],
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=2,
            creationflags=0x08000000,
            stderr=subprocess.DEVNULL,
        )
        result["active_scheme"] = " ".join(output.split())[:500]
    except (OSError, subprocess.SubprocessError):
        pass
    return result


def _directml_version():
    try:
        import importlib.metadata

        return str(importlib.metadata.version("torch-directml"))
    except (ImportError, importlib.metadata.PackageNotFoundError, ValueError):
        return ""


def _windows_gpu_inventory():
    if os.name != "nt":
        return []
    command = [
        "powershell.exe",
        "-NoProfile",
        "-NonInteractive",
        "-Command",
        (
            "Get-CimInstance Win32_VideoController | Select-Object "
            "Name,PNPDeviceID,DriverVersion,AdapterRAM | ConvertTo-Json -Compress"
        ),
    ]
    try:
        output = subprocess.check_output(
            command,
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=4,
            creationflags=0x08000000,
            stderr=subprocess.DEVNULL,
        ).strip()
        payload = json.loads(output) if output else []
        rows = payload if isinstance(payload, list) else [payload]
    except (OSError, subprocess.SubprocessError, json.JSONDecodeError, TypeError, ValueError):
        rows = []
    result = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        pnp = str(row.get("PNPDeviceID", ""))
        vendor = re.search(r"VEN_([0-9A-F]{4})", pnp, re.IGNORECASE)
        device = re.search(r"DEV_([0-9A-F]{4})", pnp, re.IGNORECASE)
        result.append(
            {
                "name": str(row.get("Name", "")),
                "vendor_id": vendor.group(1).upper() if vendor else "",
                "device_id": device.group(1).upper() if device else "",
                "driver": str(row.get("DriverVersion", "")),
                "vram_total": safe_int(row.get("AdapterRAM"), 0, 0),
                "pnp": pnp[:500],
            }
        )
    return sorted(result, key=lambda value: (value["vendor_id"], value["device_id"], value["name"]))


def runtime_hardware_fingerprint(torch_module=None, device=None, backend="windows-x64-cpu"):
    gpu_rows = _windows_gpu_inventory()
    target_device = str(device or "")
    cuda_row = {}
    if torch_module is not None and target_device.startswith("cuda"):
        try:
            properties = torch_module.cuda.get_device_properties(device)
            cuda_row = {
                "name": str(properties.name),
                "vendor_id": "10DE",
                "device_id": str(getattr(properties, "uuid", "")),
                "driver": str(getattr(torch_module.version, "cuda", "")),
                "vram_total": int(properties.total_memory),
            }
        except (RuntimeError, AttributeError, TypeError, ValueError):
            cuda_row = {}
    primary = cuda_row or (gpu_rows[0] if gpu_rows else {})
    fingerprint = {
        "schema_version": HARDWARE_PROFILE_SCHEMA_VERSION,
        "cpu_model": _cpu_model_name(),
        "physical_cores": physical_core_count(),
        "logical_cores": max(1, int(os.cpu_count() or 1)),
        "ram_total": _total_physical_ram(),
        "gpu_vendor_id": str(primary.get("vendor_id", "")),
        "gpu_device_id": str(primary.get("device_id", "")),
        "gpu_name": str(primary.get("name", "")),
        "gpu_driver": str(primary.get("driver", "")),
        "vram_total": safe_int(primary.get("vram_total"), 0, 0),
        "gpu_inventory": gpu_rows,
        "runtime_family": str(backend),
        "torch_version": str(getattr(torch_module, "__version__", "")),
        "directml_version": _directml_version(),
        "wheel_lock_checksum": RUNTIME_LOCK_MANIFEST_SHA256,
        "power_profile": _power_profile(),
        "display_topology": _display_topology(),
        "platform": sys.platform,
        "platform_version": platform.version(),
        "python": list(sys.version_info[:3]),
    }
    return fingerprint


def _hardware_health_path(base):
    return Path(base) / "audit" / "hardware_profile_health.json"


def mark_hardware_rebenchmark_required(base, reason):
    path = _hardware_health_path(base)
    try:
        value = json.loads(path.read_text(encoding="utf-8")) if path.is_file() else {}
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        value = {}
    reasons = [str(item) for item in value.get("reasons", []) if str(item)]
    reasons.append(str(reason))
    value.update(
        {
            "schema_version": 1,
            "rebenchmark_required": True,
            "reasons": list(dict.fromkeys(reasons))[-16:],
            "updated": time.time(),
        }
    )
    _atomic_json_write(path, value)
    return True


def update_hardware_profile_health(base, latency_ms=None, gpu_oom=False, driver_reset=False, manual=False):
    root = Path(base)
    profile_path = root / "audit" / "hardware_profile.json"
    health_path = _hardware_health_path(root)
    try:
        profile = json.loads(profile_path.read_text(encoding="utf-8")) if profile_path.is_file() else {}
        health = json.loads(health_path.read_text(encoding="utf-8")) if health_path.is_file() else {}
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        profile, health = {}, {}
    reasons = [str(item) for item in health.get("reasons", []) if str(item)]
    consecutive = safe_int(health.get("consecutive_latency_regressions"), 0, 0, 1000)
    baseline = safe_float(profile.get("end_to_end_p95_ms"), 0.0, 0.0)
    observed = safe_float(latency_ms, 0.0, 0.0)
    if baseline > 0 and observed > baseline * RUNTIME_THRESHOLDS.latency_regression_ratio:
        consecutive += 1
    elif observed > 0:
        consecutive = 0
    if consecutive >= RUNTIME_THRESHOLDS.latency_regression_runs:
        reasons.append("three_consecutive_latency_regressions_over_30_percent")
    if gpu_oom:
        reasons.append("gpu_oom")
    if driver_reset:
        reasons.append("gpu_driver_reset")
    if manual:
        reasons.append("manual_rebenchmark")
    required = bool(reasons)
    value = {
        "schema_version": 1,
        "rebenchmark_required": required,
        "reasons": list(dict.fromkeys(reasons))[-16:],
        "consecutive_latency_regressions": consecutive,
        "last_latency_ms": observed,
        "baseline_latency_ms": baseline,
        "updated": time.time(),
    }
    _atomic_json_write(health_path, value)
    return value


def hardware_profile_rebenchmark_requested(base):
    path = _hardware_health_path(base)
    if not path.is_file():
        return False
    try:
        return bool(json.loads(path.read_text(encoding="utf-8")).get("rebenchmark_required"))
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        return True


def current_hardware_training_profile(base):
    path = Path(base) / "audit" / "hardware_profile.json"
    try:
        value = json.loads(path.read_text(encoding="utf-8")) if path.is_file() else {}
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        value = {}
    fingerprint_fields = {
        key: value.get(key)
        for key in (
            "fingerprint", "cpu_model", "physical_cores", "logical_cores", "ram_total",
            "gpu_vendor_id", "gpu_device_id", "gpu_name", "gpu_driver", "vram_total",
            "runtime_family", "torch_version", "directml_version", "wheel_lock_checksum",
            "power_profile", "display_topology",
        )
        if value.get(key) not in (None, "")
    }
    return {
        "hardware_profile_schema_version": safe_int(value.get("schema_version"), 0),
        "hardware_fingerprint": fingerprint_fields,
        "hardware_fingerprint_checksum": str(value.get("fingerprint", "")),
        "hardware_tier": str(value.get("resolution_tier", "unknown")),
        "backend": str(value.get("backend", value.get("runtime_family", "unknown"))),
        "precision": str(value.get("precision", "fp32")),
        "fast_visual_size": list(value.get("fast_visual_size", [])),
        "semantic_visual_size": list(value.get("semantic_visual_size", [])),
        "capture_fps": safe_int(value.get("capture_fps"), 0, 0),
        "end_to_end_p50_ms": safe_float(value.get("end_to_end_p50_ms"), 0.0, 0.0),
        "end_to_end_p95_ms": safe_float(value.get("end_to_end_p95_ms"), 0.0, 0.0),
        "end_to_end_p99_ms": safe_float(value.get("end_to_end_p99_ms"), 0.0, 0.0),
        "benchmark_timing_contract": str(value.get("benchmark_timing_contract", "")),
    }


def cuda_median_ms(operation, torch_module, repetitions=10, device=None):
    values = []
    repetitions = max(1, int(repetitions))
    for _ in range(repetitions):
        start = torch_module.cuda.Event(enable_timing=True)
        end = torch_module.cuda.Event(enable_timing=True)
        torch_module.cuda.synchronize(device)
        start.record()
        operation()
        end.record()
        torch_module.cuda.synchronize(device)
        values.append(float(start.elapsed_time(end)))
    return statistics.median(values)


def synchronized_wall_samples(operation, repetitions=7, synchronize=None):
    values = []
    for _ in range(max(1, int(repetitions))):
        if synchronize is not None:
            synchronize()
        started = time.perf_counter()
        operation()
        if synchronize is not None:
            synchronize()
        values.append((time.perf_counter() - started) * 1000.0)
    return values


def _percentile(values, fraction):
    ordered = sorted(float(value) for value in values)
    if not ordered:
        return 0.0
    index = min(len(ordered) - 1, max(0, int(round((len(ordered) - 1) * float(fraction)))))
    return ordered[index]


def _manual_feature_from_rgb(rgb, previous_rgb=None):
    source = rgb_bytes(rgb)
    if source is None:
        raise CaptureUnavailable("RGB画面尺寸无效")
    previous = rgb_bytes(previous_rgb)
    luminance = bytearray(PIXELS)
    chroma_b = bytearray(PIXELS)
    chroma_r = bytearray(PIXELS)
    motion = bytearray(PIXELS)
    for pixel in range(PIXELS):
        index = pixel * 3
        red, green, blue = source[index], source[index + 1], source[index + 2]
        luminance[pixel] = (red * 77 + green * 150 + blue * 29) >> 8
        chroma_b[pixel] = max(0, min(255, 128 + ((-43 * red - 85 * green + 128 * blue) >> 8)))
        chroma_r[pixel] = max(0, min(255, 128 + ((128 * red - 107 * green - 21 * blue) >> 8)))
        if previous is not None:
            motion[pixel] = (
                abs(red - previous[index])
                + abs(green - previous[index + 1])
                + abs(blue - previous[index + 2])
            ) // 3
    edges = bytearray(PIXELS)
    for y in range(FEATURE_H):
        for x in range(FEATURE_W):
            index = y * FEATURE_W + x
            right = luminance[index + 1] if x + 1 < FEATURE_W else luminance[index]
            down = luminance[index + FEATURE_W] if y + 1 < FEATURE_H else luminance[index]
            edges[index] = min(255, abs(int(right) - int(luminance[index])) + abs(int(down) - int(luminance[index])))
    return bytes(luminance) + bytes(chroma_b) + bytes(chroma_r) + bytes(edges) + bytes(motion)


def run_startup_microbenchmark(
    base,
    torch_module=None,
    device=None,
    backend="windows-x64-cpu",
    force=False,
    runtime_instance=None,
):
    root = Path(base)
    audit_dir = root / "audit"
    audit_dir.mkdir(parents=True, exist_ok=True)
    path = audit_dir / "hardware_profile.json"
    fingerprint = runtime_hardware_fingerprint(torch_module, device, backend)
    fingerprint_hash = hashlib.sha256(canonical_bytes(fingerprint)).hexdigest()
    requested = hardware_profile_rebenchmark_requested(root)
    if path.is_file() and not force and not requested:
        try:
            cached = json.loads(path.read_text(encoding="utf-8"))
            if (
                cached.get("fingerprint") == fingerprint_hash
                and safe_int(cached.get("schema_version"), 0) == HARDWARE_PROFILE_SCHEMA_VERSION
            ):
                RESOURCE_GOVERNOR.apply_benchmark_profile(cached)
                return cached
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            pass

    physical = physical_core_count()
    runtime_manifest = validate_runtime_manifest(root, False, False) or {}
    candidate_benchmark = runtime_manifest.get("backend_benchmark", {}) if isinstance(runtime_manifest, dict) else {}
    profile = {
        **fingerprint,
        "fingerprint": fingerprint_hash,
        "created": time.time(),
        "vision_batch": 8,
        "policy_batch": 24,
        "capture_fps": 20,
        "motion_capture_fps": 20,
        "semantic_interval": 5,
        "ocr_interval": 8,
        "precision": str(candidate_benchmark.get("precision", "fp32")),
        "torch_threads": physical,
        "vision_latency_ms": 0.0,
        "vision_throughput_fps": 0.0,
        "training_step_ms": 0.0,
        "free_vram": None,
        "total_vram": None,
        "tested_peak_vram": None,
        "vram_status": "unknown",
        "vram_test_passed": False,
        "large_model_validated": False,
        "capture_training_interference_ratio": 1.0,
        "capture_training_interference_tested": False,
        "benchmark_timing_contract": "per_iteration_device_synchronization_cuda_events",
        "end_to_end_pipeline": [
            "capture_or_synthetic_frame_source",
            "color_conversion_and_resize",
            "fast_visual_channel",
            "global_semantic_channel",
            "changed_roi_ocr_preparation",
            "object_detection_and_scene_graph",
            "policy_state_encoding",
            "ood_risk_and_candidate_ranking_preparation",
        ],
        "resolution_tier": "low",
        "candidate_backend_composite_score_ms": safe_float(candidate_benchmark.get("score_ms"), 0.0),
        "candidate_backend_score_components": (
            dict(candidate_benchmark.get("score_components", {}))
            if isinstance(candidate_benchmark.get("score_components"), dict)
            else {}
        ),
    }

    def median_ms(callable_value, repetitions=3):
        values = synchronized_wall_samples(callable_value, repetitions)
        return statistics.median(values)

    if torch_module is not None:
        torch = torch_module
        target_device = device if device is not None else torch.device("cpu")
        is_cuda = bool(str(target_device).startswith("cuda") and torch.cuda.is_available())
        synchronize = (lambda: torch.cuda.synchronize(target_device)) if is_cuda else None
        measure = (
            lambda operation, repetitions=3: cuda_median_ms(
                operation,
                torch,
                repetitions,
                target_device,
            )
            if is_cuda
            else median_ms(operation, repetitions)
        )
        candidate_precision = str(profile.get("precision", "fp32")).casefold()
        if is_cuda:
            profile["precision"] = (
                candidate_precision
                if candidate_precision in {"fp16", "fp16_tf32", "tf32", "fp32"}
                else "fp16_tf32"
            )
        elif str(backend) == "windows-x64-directml":
            profile["precision"] = candidate_precision if candidate_precision in {"fp16", "fp32"} else "fp32"
        else:
            profile["precision"] = (
                candidate_precision
                if candidate_precision.startswith("int8_onnx")
                else "int8_onnx_policy_fp32_vision"
            )
        if is_cuda:
            try:
                free_vram, total_vram = torch.cuda.mem_get_info(target_device)
                profile["free_vram"] = int(free_vram)
                profile["total_vram"] = int(total_vram)
                profile["vram_total_runtime"] = int(total_vram)
                profile["vram_status"] = "known"
                torch.cuda.reset_peak_memory_stats(target_device)
            except (RuntimeError, AttributeError, TypeError):
                profile["free_vram"] = None
                profile["total_vram"] = None
                profile["vram_status"] = "unknown"
        if str(target_device) == "cpu":
            thread_candidates = sorted(set([1, 2, 4, 6, 8, physical, max(1, physical // 2)]))
            thread_candidates = [value for value in thread_candidates if value <= physical]
            thread_timings = {}
            left = torch.randn((384, 384), dtype=torch.float32)
            right = torch.randn((384, 384), dtype=torch.float32)
            for threads in thread_candidates:
                try:
                    torch.set_num_threads(threads)
                    _ = left @ right
                    timing = median_ms(lambda: left @ right, 3)
                    thread_timings[str(threads)] = timing
                except (RuntimeError, ValueError, TypeError):
                    continue
            if thread_timings:
                optimal = min(thread_timings, key=lambda key: thread_timings[key])
                profile["torch_threads"] = max(1, min(physical, int(optimal)))
                profile["thread_benchmark_ms"] = thread_timings
                try:
                    torch.set_num_threads(profile["torch_threads"])
                except (RuntimeError, ValueError, TypeError):
                    pass
        try:
            vision = (
                runtime_instance._build_model()
                if runtime_instance is not None and hasattr(runtime_instance, "_build_model")
                else torch.nn.Sequential(
                    torch.nn.Conv2d(3, 32, 3, padding=1, bias=False),
                    torch.nn.Hardswish(),
                    torch.nn.Conv2d(32, 32, 3, padding=1, groups=32, bias=False),
                    torch.nn.Hardswish(),
                    torch.nn.Conv2d(32, 64, 1, bias=False),
                    torch.nn.Hardswish(),
                    torch.nn.AdaptiveAvgPool2d(1),
                )
            ).to(target_device).eval()
            batch_candidates = [1, 4, 8, 16, 24, 32, 48, 64, 96, 128]
            if not is_cuda:
                batch_candidates = [1, 2, 4, 8, 12, 16, 24, 32]
            timings = {}
            best_batch = 1
            for batch in batch_candidates:
                try:
                    tensor = torch.randn((batch, 3, FEATURE_H, FEATURE_W), device=target_device)
                    with torch.inference_mode():
                        _ = vision(tensor)
                        if synchronize is not None:
                            synchronize()
                        timing = measure(lambda: vision(tensor), 5)
                    timings[str(batch)] = timing
                    per_frame = timing / batch
                    if timing <= 180.0 and per_frame <= 35.0:
                        best_batch = batch
                    del tensor
                except RuntimeError as error:
                    message = str(error).casefold()
                    if "out of memory" in message and is_cuda:
                        update_hardware_profile_health(root, gpu_oom=True)
                        torch.cuda.empty_cache()
                        break
                    if "device lost" in message or "driver" in message and "reset" in message:
                        update_hardware_profile_health(root, driver_reset=True)
                    continue
            profile["vision_batch"] = best_batch
            selected_timing = safe_float(timings.get(str(best_batch)), 0.0)
            profile["vision_latency_ms"] = selected_timing / max(1, best_batch)
            profile["vision_throughput_fps"] = 1000.0 * best_batch / max(0.001, selected_timing)
            profile["vision_batch_benchmark_ms"] = timings

            dense_type = OfflinePolicyModelBuilder._dense_network_type(torch)
            policy_members = [
                OfflinePolicyModelBuilder._create_networks(dense_type, target_device)
                for _ in range(POLICY_ENSEMBLE_SIZE)
            ]
            training_member = policy_members[0]
            policy_parameters = list(training_member.parameters)
            optimizer = torch.optim.AdamW(policy_parameters, lr=0.001)

            def policy_training_objective(tensor, target_state):
                state = tensor[:, :POLICY_INPUT_SIZE]
                action = tensor[:, POLICY_INPUT_SIZE:]
                objective = torch.zeros((), device=target_device)
                for member in (training_member,):
                    encoded = member.encoder(state)
                    pair = torch.cat([encoded, action], dim=1)
                    objective = objective + member.q1(pair).pow(2).mean()
                    objective = objective + member.q2(pair).pow(2).mean()
                    objective = objective + member.value(encoded).pow(2).mean()
                    objective = objective + member.policy(pair).pow(2).mean()
                    objective = objective + member.risk(pair).pow(2).mean()
                    objective = objective + member.outcome(pair).pow(2).mean()
                    objective = objective + (member.dynamics(pair) - target_state).pow(2).mean()
                return objective
            policy_timings = {}
            policy_batch = 8
            candidates = [8, 16, 32, 64, 96, 128, 192, 256]
            if not is_cuda:
                candidates = [8, 16, 24, 32, 48]
            for batch in candidates:
                try:
                    tensor = torch.randn((batch, POLICY_INPUT_SIZE + LATENT_ACTION_SIZE), device=target_device)
                    target = torch.randn((batch, POLICY_INPUT_SIZE), device=target_device)

                    def training_step():
                        optimizer.zero_grad(set_to_none=True)
                        loss = policy_training_objective(tensor, target)
                        loss.backward()
                        optimizer.step()

                    training_step()
                    if synchronize is not None:
                        synchronize()
                    timing = measure(training_step, 2)
                    policy_timings[str(batch)] = timing
                    if timing <= 120.0:
                        policy_batch = batch
                    del tensor, target
                except RuntimeError as error:
                    message = str(error).casefold()
                    if "out of memory" in message and is_cuda:
                        update_hardware_profile_health(root, gpu_oom=True)
                        torch.cuda.empty_cache()
                        break
                    if "device lost" in message or "driver" in message and "reset" in message:
                        update_hardware_profile_health(root, driver_reset=True)
                    continue
            profile["policy_batch"] = policy_batch
            profile["training_step_ms"] = safe_float(policy_timings.get(str(policy_batch)), 0.0)
            profile["policy_batch_benchmark_ms"] = policy_timings

            current_rgb = bytes((index * 17 + 29) & 0xFF for index in range(PIXELS * 3))
            previous_rgb = bytes((index * 13 + 11) & 0xFF for index in range(PIXELS * 3))
            preview_width, preview_height = 320, 180
            preview_rgb = resize_rgb(current_rgb, FEATURE_W, FEATURE_H, preview_width, preview_height)
            preview_previous = resize_rgb(previous_rgb, FEATURE_W, FEATURE_H, preview_width, preview_height)

            def full_pipeline_operation():
                feature = _manual_feature_from_rgb(current_rgb, previous_rgb)
                with torch.inference_mode():
                    tensor = torch.frombuffer(bytearray(current_rgb), dtype=torch.uint8).reshape(
                        FEATURE_H,
                        FEATURE_W,
                        3,
                    )
                    tensor = tensor.permute(2, 0, 1).unsqueeze(0).to(target_device, dtype=torch.float32) / 255.0
                    encoded = vision(tensor)
                    if not is_cuda and str(target_device) != "cpu":
                        encoded = encoded.to("cpu")
                frame = {
                    "f": feature,
                    "raw_f": feature,
                    "rgb": current_rgb,
                    "preview_rgb": preview_rgb,
                    "preview_width": preview_width,
                    "preview_height": preview_height,
                    "changed_regions": changed_roi_regions(
                        preview_previous,
                        preview_rgb,
                        preview_width,
                        preview_height,
                    ),
                    "semantic_targets": [],
                    "semantic_backbone_tokens": [],
                    "time": time.monotonic(),
                }
                frame["semantic_targets"] = detect_semantic_targets(frame, 24)
                frame["scene_graph"] = build_scene_graph(frame["semantic_targets"])
                frame["visual_pyramid"] = build_hybrid_visual_state(frame, [])
                observation = DEFAULT_OBSERVATION_ENCODER.encode(
                    frame,
                    {
                        "recent_actions": [],
                        "recent_action_results": [],
                        "recent_frame_deltas": [0.0, 0.0, 0.0],
                        "task_phase": "benchmark",
                        "modality_mask": {"rgb": True, "motion": True},
                    },
                    {"task_id": "benchmark", "goal": "benchmark"},
                )
                state_vector = _policy_state_vector(observation.to_dict(), "benchmark")
                state_tensor = torch.tensor(
                    [state_vector],
                    dtype=torch.float32,
                    device=target_device,
                )
                candidate_vectors = torch.tensor(
                    [
                        _policy_action_vector("benchmark_action_" + str(index))
                        for index in range(96)
                    ],
                    dtype=torch.float32,
                    device=target_device,
                )
                policy_outputs = []
                for member in policy_members:
                    policy_state = member.encoder(state_tensor)
                    expanded_state = policy_state.expand(candidate_vectors.shape[0], -1)
                    pairs = torch.cat([expanded_state, candidate_vectors], dim=1)
                    policy_outputs.append(
                        torch.stack(
                            [
                                member.q1(pairs).squeeze(1),
                                member.q2(pairs).squeeze(1),
                                member.policy(pairs).squeeze(1),
                                torch.sigmoid(member.risk(pairs).squeeze(1)),
                                torch.softmax(member.outcome(pairs), dim=1)[:, 1],
                            ],
                            dim=1,
                        )
                    )
                stacked = torch.stack(policy_outputs, dim=0)
                stacked.mean(dim=0) - stacked.std(dim=0, unbiased=False)
                return encoded

            full_values = synchronized_wall_samples(full_pipeline_operation, 9, synchronize)
            profile["end_to_end_p50_ms"] = round(_percentile(full_values, 0.50), 6)
            profile["end_to_end_p95_ms"] = round(_percentile(full_values, 0.95), 6)
            profile["end_to_end_p99_ms"] = round(_percentile(full_values, 0.99), 6)
            profile["end_to_end_samples_ms"] = [round(value, 6) for value in full_values]
            e2e_p95 = profile["end_to_end_p95_ms"]
            e2e_p99 = profile["end_to_end_p99_ms"]
            jitter_penalty = max(0.0, e2e_p99 - e2e_p95)
            memory_penalty = (
                max(
                    0.0,
                    (768 * 1024**2 - safe_float(profile.get("free_vram"), 0.0))
                    / (256 * 1024**2),
                )
                * 4.0
                if profile.get("free_vram")
                else 0.0
            )
            training_penalty = (
                max(
                    0.0,
                    safe_float(profile.get("capture_training_interference_ratio"), 1.0) - 1.0,
                )
                * e2e_p95
            )
            driver_penalty = 25.0 * (
                safe_int(RUNTIME_METRICS.counters.get("gpu_device_removed"), 0)
                + safe_int(RUNTIME_METRICS.counters.get("gpu_device_reset"), 0)
            )
            profile["score_components"] = {
                "p95_end_to_end_latency_ms": round(e2e_p95, 6),
                "p99_jitter_penalty_ms": round(jitter_penalty, 6),
                "memory_pressure_penalty_ms": round(memory_penalty, 6),
                "training_interference_penalty_ms": round(training_penalty, 6),
                "driver_instability_penalty_ms": round(driver_penalty, 6),
            }
            profile["composite_score_ms"] = round(
                e2e_p95 + 0.75 * jitter_penalty + memory_penalty + training_penalty + driver_penalty,
                6,
            )
            if e2e_p95 <= 22.0 and e2e_p99 <= 30.0:
                profile["capture_fps"] = 45
                profile["semantic_interval"] = 2
            elif e2e_p95 <= 33.0 and e2e_p99 <= 45.0:
                profile["capture_fps"] = 30
                profile["semantic_interval"] = 3
            else:
                profile["capture_fps"] = 20
                profile["semantic_interval"] = 5
            profile["ocr_interval"] = max(profile["semantic_interval"] + 2, 4)
            profile["motion_capture_fps"] = max(15, min(60, profile["capture_fps"] + (10 if e2e_p95 <= 33.0 else 0)))
            gpu_family = str(backend).startswith("windows-x64-nvidia") or str(backend) == "windows-x64-directml"
            if gpu_family and e2e_p95 <= 30.0:
                profile["resolution_tier"] = "high"
            elif e2e_p95 <= 45.0:
                profile["resolution_tier"] = "medium"
            else:
                profile["resolution_tier"] = "low"

            probe = torch.randn((1, 3, FEATURE_H, FEATURE_W), device=target_device)
            with torch.inference_mode():
                baseline = measure(lambda: vision(probe), 5)
            stop = threading.Event()
            training_tensor = torch.randn(
                (max(8, min(policy_batch, 64)), POLICY_INPUT_SIZE + LATENT_ACTION_SIZE),
                device=target_device,
            )
            training_target = torch.zeros(
                (training_tensor.shape[0], POLICY_INPUT_SIZE),
                device=target_device,
            )

            def background_training():
                while not stop.is_set():
                    optimizer.zero_grad(set_to_none=True)
                    loss = policy_training_objective(training_tensor, training_target)
                    loss.backward()
                    optimizer.step()
                    if is_cuda:
                        torch.cuda.synchronize(target_device)

            worker = threading.Thread(target=background_training, daemon=True)
            worker.start()
            interruptible_wait(None, 0.05)
            with torch.inference_mode():
                interfered = measure(lambda: vision(probe), 5)
            stop.set()
            worker.join(1.0)
            profile["capture_training_interference_ratio"] = interfered / max(0.001, baseline)
            profile["capture_training_interference_tested"] = True
            training_penalty = (
                max(0.0, profile["capture_training_interference_ratio"] - 1.0)
                * safe_float(profile.get("end_to_end_p95_ms"), 0.0)
            )
            profile["score_components"]["training_interference_penalty_ms"] = round(
                training_penalty,
                6,
            )
            profile["composite_score_ms"] = round(
                safe_float(profile.get("end_to_end_p95_ms"), 0.0)
                + 0.75 * safe_float(profile["score_components"].get("p99_jitter_penalty_ms"), 0.0)
                + safe_float(profile["score_components"].get("memory_pressure_penalty_ms"), 0.0)
                + training_penalty
                + safe_float(profile["score_components"].get("driver_instability_penalty_ms"), 0.0),
                6,
            )
            if profile["capture_training_interference_ratio"] > 1.5:
                profile["policy_batch"] = max(8, profile["policy_batch"] // 2)
                profile["capture_fps"] = max(15, profile["capture_fps"] - 5)
                profile["resolution_tier"] = "medium" if profile["resolution_tier"] == "high" else "low"
            optimizer.zero_grad(set_to_none=True)
            if is_cuda:
                try:
                    peak_vram = int(torch.cuda.max_memory_allocated(target_device))
                    total_vram = profile.get("total_vram")
                    profile["tested_peak_vram"] = peak_vram
                    profile["vram_test_passed"] = bool(
                        total_vram is not None and int(total_vram) > 0 and peak_vram <= int(total_vram) * 0.72
                    )
                    profile["large_model_validated"] = bool(profile["vram_test_passed"])
                    profile["vram_headroom_ratio"] = round(1.0 - peak_vram / max(1, int(total_vram)), 6)
                except (RuntimeError, AttributeError, TypeError, ValueError):
                    profile["tested_peak_vram"] = None
                    profile["vram_test_passed"] = False
                    profile["large_model_validated"] = False
            optimizer.zero_grad(set_to_none=True)
            del vision, policy_members, optimizer, probe, training_tensor, training_target
            if is_cuda:
                torch.cuda.empty_cache()
        except (RuntimeError, AttributeError, TypeError, ValueError) as error:
            message = str(error).casefold()
            if "out of memory" in message:
                update_hardware_profile_health(root, gpu_oom=True)
            if "device lost" in message or "driver" in message and "reset" in message:
                update_hardware_profile_health(root, driver_reset=True)
            profile["benchmark_error"] = type(error).__name__ + ":" + str(error)
    else:
        numpy_module = FEATURE_ENGINE.optional_numpy()
        if numpy_module is not None:
            left = numpy_module.random.default_rng(7).standard_normal((256, 256), dtype=numpy_module.float32)
            right = numpy_module.random.default_rng(11).standard_normal((256, 256), dtype=numpy_module.float32)
            profile["numpy_matrix_ms"] = median_ms(lambda: left @ right, 5)
            profile["vision_batch"] = 4
            profile["policy_batch"] = 16
            profile["capture_fps"] = 20
            profile["semantic_interval"] = 5
            profile["ocr_interval"] = 8
            profile["resolution_tier"] = "low"
            profile["end_to_end_p50_ms"] = profile["numpy_matrix_ms"]
            profile["end_to_end_p95_ms"] = profile["numpy_matrix_ms"]
            profile["end_to_end_p99_ms"] = profile["numpy_matrix_ms"]

    tier_shapes = {
        "low": ([64, 36], [224, 126], 1.0),
        "medium": ([128, 72], [320, 180], 1.35),
        "high": ([160, 90], [384, 216], 1.60),
    }
    fast_size, semantic_size, ocr_scale = tier_shapes.get(
        str(profile.get("resolution_tier", "low")),
        tier_shapes["low"],
    )
    profile["fast_visual_size"] = fast_size
    profile["semantic_visual_size"] = semantic_size
    profile["ocr_roi_scale"] = ocr_scale
    profile["model_tier"] = select_model_tier(
        backend,
        profile.get("end_to_end_p95_ms"),
        profile.get("composite_score_ms"),
        profile.get("free_vram"),
        _total_physical_ram() or None,
        profile.get("total_vram"),
        profile.get("tested_peak_vram"),
        profile.get("vram_test_passed", False),
    )
    selected_model_spec = model_tier_spec(profile["model_tier"])
    profile.setdefault("policy_state_size", selected_model_spec.state_size)
    profile.setdefault("policy_hidden_size", selected_model_spec.hidden_size)
    profile.setdefault("policy_ensemble_size", selected_model_spec.ensemble_size)
    profile.setdefault("temporal_context_length", selected_model_spec.temporal_context)
    profile.setdefault("world_model_horizon", selected_model_spec.planning_horizon)
    profile.setdefault("object_slot_count", selected_model_spec.object_slots)
    profile.setdefault("vision_width_multiplier", selected_model_spec.vision_width_multiplier)
    accelerated_backend = "nvidia" in str(backend).casefold() or "directml" in str(backend).casefold()
    profile["vision_backend"] = str(backend) if accelerated_backend else "windows-x64-cpu"
    profile["policy_backend"] = (
        str(backend)
        if accelerated_backend and profile.get("free_vram") is not None and int(profile.get("free_vram")) >= 2 * 1024**3
        else "windows-x64-cpu"
    )
    profile["world_model_backend"] = "windows-x64-cpu"
    profile["policy_benchmark_architecture"] = (
        "five_member_real_inference_and_sequential_real_member_training"
    )
    profile["configuration_version"] = RUNTIME_THRESHOLDS.version
    profile["runtime_thresholds"] = RUNTIME_THRESHOLDS.to_dict()
    profile["checksum"] = hashlib.sha256(
        canonical_bytes({key: value for key, value in profile.items() if key != "checksum"})
    ).hexdigest()
    _atomic_json_write(path, profile)
    _atomic_json_write(
        _hardware_health_path(root),
        {
            "schema_version": 1,
            "rebenchmark_required": False,
            "reasons": [],
            "consecutive_latency_regressions": 0,
            "last_latency_ms": 0.0,
            "baseline_latency_ms": safe_float(profile.get("end_to_end_p95_ms"), 0.0),
            "updated": time.time(),
        },
    )
    RESOURCE_GOVERNOR.apply_benchmark_profile(profile)
    return profile


def wait_for_runtime_training_plan(stop_event=None):
    RESOURCE_GOVERNOR.ensure_started()
    while True:
        try:
            plan = RESOURCE_GOVERNOR.current_plan(ModeId.UPGRADE.value)
        except TypeError:
            plan = RESOURCE_GOVERNOR.current_plan()
        if plan.training_batch_size > 0:
            return plan
        FEATURE_ENGINE.clear_frames()
        cache = globals().get("POLICY_TRAINING_CACHE")
        if cache is not None:
            cache.clear()
        collect_garbage("training_plan_wait", 30.0)
        if stop_event is not None:
            if stop_event.wait(1.0):
                raise InputStopped("资源不足，训练已停止")
        else:
            interruptible_wait(None, 1.0)


def torch_training_device(torch_module):
    runtime = APP_CONTEXT.vision_runtime
    if runtime is not None and getattr(runtime, "ready", False) and not getattr(runtime, "builtin", True):
        device = getattr(runtime, "device", None)
        if device is not None:
            return device
    return torch_module.device("cpu")


def torch_device_is_cuda(torch_module, device):
    try:
        return str(getattr(device, "type", device)).casefold() == "cuda" and bool(torch_module.cuda.is_available())
    except RECOVERABLE_ERRORS:
        return False


def torch_grad_scaler(torch_module, enabled):
    if not enabled:
        return None
    try:
        return torch_module.amp.GradScaler("cuda", enabled=True)
    except (AttributeError, TypeError):
        return torch_module.cuda.amp.GradScaler(enabled=True)


def release_torch_training_resources(torch_module):
    try:
        if bool(torch_module.cuda.is_available()):
            torch_module.cuda.empty_cache()
            torch_module.cuda.ipc_collect()
    except (RuntimeError, AttributeError) as error:
        record_cleanup_error("TORCH_RESOURCE_RELEASE_FAILED", error)
    collect_garbage("torch_training_release", 10.0)


EMERGENCY_CLEANUP_ERRORS = deque(maxlen=256)


def cleanup_error_code(code, error):
    value = str(code or "")
    if value and value != "BEST_EFFORT_EXCEPTION":
        return value
    name = type(error).__name__
    message = str(error).casefold()
    if name == "InputStopped":
        return "USER_CANCELLED"
    if name == "TargetUnavailable":
        return "WINDOW_DISAPPEARED"
    if isinstance(error, FileNotFoundError):
        return "FILE_NOT_FOUND"
    if isinstance(error, sqlite3.OperationalError) and ("busy" in message or "locked" in message):
        return "SQLITE_BUSY"
    if isinstance(error, AssertionError):
        return "INVARIANT_VIOLATION"
    if isinstance(error, OSError):
        return "RESOURCE_CLOSE_FAILED"
    return "UNEXPECTED_CLEANUP_ERROR"


def error_location(error):
    try:
        frames = traceback.extract_tb(error.__traceback__) if getattr(error, "__traceback__", None) is not None else []
        frame = frames[-1] if frames else traceback.extract_stack(limit=3)[0]
        return {"file": Path(frame.filename).name, "line": int(frame.lineno), "function": str(frame.name)}
    except RECOVERABLE_ERRORS:
        return None


def record_cleanup_error(code, error, details=None):
    normalized = cleanup_error_code(code, error)
    payload = dict(details) if isinstance(details, dict) else {}
    payload.pop("line", None)
    location = error_location(error)
    if location is not None:
        payload.setdefault("location", location)
    if normalized != str(code):
        payload.setdefault("source_code", str(code))
    record = {"created": time.time(), "code": normalized, "error": str(error), "details": payload}
    EMERGENCY_CLEANUP_ERRORS.append(record)
    store = APP_CONTEXT.store
    logger = getattr(store, "logger", None) if store is not None else None
    if logger is not None:
        try:
            logger.write(normalized, error, payload)
        except (OSError, ValueError, TypeError) as nested:
            EMERGENCY_CLEANUP_ERRORS.append(
                {
                    "created": time.time(),
                    "code": "CLEANUP_LOG_WRITE_FAILED",
                    "error": str(nested),
                    "details": {"source": normalized, "location": error_location(nested)},
                }
            )
    return record


def best_effort_cleanup(code, callback, expected=(FileNotFoundError,)):
    try:
        return True, callback()
    except expected:
        return True, None
    except OSError as error:
        record_cleanup_error(code, error, {"category": "os_error"})
    except RECOVERABLE_ERRORS as error:
        record_cleanup_error(code, error, {"category": "unexpected"})
    return False, None


def sample_retention_budget(family_count, session_count):
    families = max(1, safe_int(family_count, 1, 1, 64)) if "safe_int" in globals() else max(1, int(family_count or 1))
    sessions = max(1, safe_int(session_count, 1, 1, 64)) if "safe_int" in globals() else max(1, int(session_count or 1))
    return min(MAX_SAMPLES, max(DEFAULT_SAMPLE_BUDGET, 400 + families * 180 + sessions * 120))


def native_windows_architecture():
    machine = ""
    if os.name == "nt":
        try:
            kernel = ctypes.WinDLL("kernel32", use_last_error=True)
            function = getattr(kernel, "IsWow64Process2", None)
            if function is not None:
                process_machine = wintypes.USHORT()
                native_machine = wintypes.USHORT()
                function.argtypes = [wintypes.HANDLE, ctypes.POINTER(wintypes.USHORT), ctypes.POINTER(wintypes.USHORT)]
                function.restype = wintypes.BOOL
                if function(kernel.GetCurrentProcess(), ctypes.byref(process_machine), ctypes.byref(native_machine)):
                    if int(native_machine.value) == 0xAA64:
                        return RUNTIME_ARCH_ARM64
                    if int(native_machine.value) == 0x8664:
                        return RUNTIME_ARCH_X64
        except RECOVERABLE_ERRORS:
            machine = ""
        machine = str(
            os.environ.get("PROCESSOR_ARCHITEW6432") or os.environ.get("PROCESSOR_ARCHITECTURE") or ""
        ).lower()
    else:
        try:
            import platform

            machine = platform.machine().lower()
        except RECOVERABLE_ERRORS:
            machine = ""
    if "arm64" in machine or "aarch64" in machine:
        return RUNTIME_ARCH_ARM64
    if "amd64" in machine or "x86_64" in machine or "x64" in machine:
        return RUNTIME_ARCH_X64
    raise RuntimeError("仅支持Windows 11 x64或ARM64原生架构")


def embedded_runtime_lock(architecture=None):
    arch = str(architecture or native_windows_architecture())
    if arch != RUNTIME_ARCH_X64:
        raise RuntimeError("ARM64尚无完整wheel锁和Windows 11实机验收证据，不宣称严格支持")
    key = arch + "|builtin_cpu"
    source = runtime_lock_manifest()["locks"].get(key)
    if not isinstance(source, list) or not source:
        raise RuntimeError("当前架构缺少内嵌运行库wheel锁：" + arch)
    entries = [dict(item) for item in source]
    required = ("name", "version", "filename", "url", "sha256", "size", "python_abi", "architecture", "backend")
    seen = set()
    for entry in entries:
        if any(field not in entry for field in required):
            raise RuntimeError("内嵌wheel锁字段不完整")
        parsed = urllib.parse.urlsplit(str(entry["url"]))
        if parsed.scheme.lower() != "https" or parsed.hostname not in RUNTIME_ALLOWED_DOWNLOAD_HOSTS:
            raise RuntimeError("内嵌wheel锁URL不受信任")
        name = str(entry["name"]).strip().lower().replace("_", "-")
        if name in seen:
            raise RuntimeError("内嵌wheel锁项目重复：" + name)
        seen.add(name)
        filename = str(entry["filename"])
        digest = str(entry["sha256"]).lower()
        if (
            not str(entry["version"]).strip()
            or not filename
            or urllib.parse.unquote(Path(parsed.path).name) != filename
            or parsed.query
            or parsed.fragment
        ):
            raise RuntimeError("内嵌wheel锁文件名、版本或URL不一致")
        if (
            len(digest) != 64
            or any(value not in "0123456789abcdef" for value in digest)
            or safe_int(entry["size"], 0, 1, 1024 * 1024 * 1024) <= 0
            or str(entry["python_abi"]) != "cp312"
            or str(entry["architecture"]) != arch
            or str(entry["backend"]) != "builtin_cpu"
        ):
            raise RuntimeError("内嵌wheel锁内容无效")
    entries = sorted(entries, key=lambda item: (str(item["name"]).casefold(), str(item["filename"])))
    if not runtime_lock_is_complete(entries):
        raise RuntimeError("内嵌运行库wheel锁不完整")
    return entries, hashlib.sha256(canonical_bytes(entries)).hexdigest(), key


def runtime_family_lock_key(architecture, family):
    arch = str(architecture or native_windows_architecture())
    value = str(family or "windows-x64-cpu")
    if arch != RUNTIME_ARCH_X64:
        return ""
    return str(RUNTIME_BACKEND_LOCK_KEYS.get(value, ""))


def runtime_backend_lock_entries(architecture, family):
    key = runtime_family_lock_key(architecture, family)
    source = runtime_lock_manifest().get("locks", {}).get(key)
    if not key or not isinstance(source, list) or not source:
        return None
    entries = [dict(item) for item in source]
    required = ("name", "version", "filename", "url", "sha256", "size", "python_abi", "architecture", "backend")
    seen = set()
    for entry in entries:
        if any(field not in entry for field in required):
            raise RuntimeError("后端wheel锁字段不完整：" + str(family))
        parsed = urllib.parse.urlsplit(str(entry["url"]))
        name = str(entry["name"]).strip().lower().replace("_", "-")
        digest = str(entry["sha256"]).lower()
        if (
            parsed.scheme.lower() != "https"
            or parsed.hostname not in RUNTIME_ALLOWED_DOWNLOAD_HOSTS
            or name in seen
            or len(digest) != 64
            or any(value not in "0123456789abcdef" for value in digest)
            or safe_int(entry.get("size"), 0, 1, 1024 * 1024 * 1024) <= 0
            or str(entry.get("python_abi")) != "cp312"
            or str(entry.get("architecture")) != str(architecture)
        ):
            raise RuntimeError("后端wheel锁无效：" + str(family))
        seen.add(name)
    entries.sort(key=lambda item: (str(item["name"]).casefold(), str(item["filename"])))
    if not runtime_backend_lock_is_complete(entries):
        raise RuntimeError("后端wheel锁依赖闭包不完整：" + str(family))
    return entries


def runtime_backend_lock_is_complete(entries):
    if not isinstance(entries, list) or not entries:
        return False
    names = {}
    for item in entries:
        if not isinstance(item, dict):
            return False
        name = str(item.get("name", "")).strip().lower().replace("_", "-")
        version = str(item.get("version", "")).strip()
        if not name or not version or name in names:
            return False
        names[name] = version
    if not runtime_required_projects().issubset(set(names)):
        return False
    for project, contract in runtime_dependency_contracts().items():
        if project not in names:
            return False
        for dependency in contract.get("requires", set()):
            provider = runtime_dependency_providers().get(dependency, dependency)
            if provider not in names:
                return False
    return True


def runtime_lock_matches_key(entries, lock_key):
    source = runtime_lock_manifest().get("locks", {}).get(str(lock_key), [])
    return bool(source and list(entries or []) == list(source) and runtime_backend_lock_is_complete(entries))


def runtime_backend_candidates(architecture, hardware=None):
    adapters = list((hardware or {}).get("adapters", [])) if isinstance(hardware, dict) else []
    usable = []
    for item in adapters:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name", "")).strip()
        status = str(item.get("status", "")).strip().casefold()
        lowered = name.casefold()
        software = any(
            marker in lowered
            for marker in ("microsoft basic render", "remote display", "虚拟显示", "basic display")
        )
        if name and not software and status in {"", "ok", "正常"}:
            usable.append(item)
    names = " ".join(str(item.get("name", "")) for item in usable).casefold()
    result = []
    for family in RUNTIME_BACKEND_FAMILIES:
        hardware_eligible = family == "windows-x64-cpu"
        hardware_reason = ""
        if family == "windows-x64-nvidia-cu130":
            hardware_eligible = "nvidia" in names
            if not hardware_eligible:
                hardware_reason = "未检测到状态正常且可用于CUDA实测的NVIDIA适配器"
        elif family == "windows-x64-directml":
            hardware_eligible = bool(usable)
            if not hardware_eligible:
                hardware_reason = "未检测到状态正常且可用于DirectML实测的硬件适配器"
        lock = runtime_backend_lock_entries(architecture, family)
        lock_reason = "" if lock is not None else "当前main.py未内嵌该后端的完整SHA-256 wheel锁"
        reason = "；".join(value for value in (hardware_reason, lock_reason) if value)
        result.append(
            {
                "family": family,
                "lock_key": runtime_family_lock_key(architecture, family),
                "lock_available": lock is not None,
                "hardware_eligible": hardware_eligible,
                "reason": reason,
            }
        )
    return result


def normalized_project_name(value):
    return str(value or "").strip().lower().replace("_", "-")


def runtime_lock_dependency_closure_is_complete(entries):
    if not isinstance(entries, list) or not entries:
        return False
    versions = {}
    for item in entries:
        if not isinstance(item, dict):
            return False
        name = normalized_project_name(item.get("name"))
        version = str(item.get("version", "")).strip()
        if not name or not version or name in versions:
            return False
        versions[name] = version
    if set(versions) != runtime_locked_projects() or versions != runtime_lock_project_versions():
        return False
    for project, contract in runtime_dependency_contracts().items():
        if project not in versions:
            return False
        for dependency in contract.get("requires", set()):
            provider = runtime_dependency_providers().get(dependency, dependency)
            if provider not in versions:
                return False
    return True


def runtime_lock_is_complete(entries):
    names = {normalized_project_name(item.get("name")) for item in entries if isinstance(item, dict)}
    return runtime_required_projects().issubset(names) and runtime_lock_dependency_closure_is_complete(entries)


def tree_size(path):
    root = Path(path)
    if not root.exists():
        return 0
    if root.is_file():
        try:
            return int(root.stat().st_size)
        except OSError:
            return 0
    total = 0
    for item in root.rglob("*"):
        if item.is_file():
            try:
                total += int(item.stat().st_size)
            except OSError:
                pass
    return total


def authoritative_data_size(base):
    root = Path(base)
    total = sum(tree_size(root / name) for name in AUTHORITATIVE_DATA_PATHS)
    for item in root.glob("recovery_*"):
        total += tree_size(item)
    for item in root.iterdir() if root.exists() else []:
        if item.is_file() and item.name not in {
            "universal_game_ai.db",
            "universal_game_ai.db-wal",
            "universal_game_ai.db-shm",
        }:
            total += tree_size(item)
    return total


def required_migration_space(source_base=None):
    source_size = authoritative_data_size(source_base) if source_base is not None else 0
    database_reserve = max(64 * 1024 * 1024, source_size // 8)
    safety = max(128 * 1024 * 1024, (source_size + database_reserve) // 5)
    return max(MIN_DATA_OPERATION_RESERVE, source_size * 2 + database_reserve + safety)


def required_runtime_space(base, wheel_bytes=0):
    root = Path(base)
    current = tree_size(root / "runtime.current")
    data = authoritative_data_size(root)
    wheels = max(0, int(wheel_bytes))
    installed = max(current, int(wheels * 3.5), 2 * 1024 * 1024 * 1024 if not current and not wheels else 0)
    staging = wheels + installed
    rollback = current
    reserve = max(512 * 1024 * 1024, data // 5)
    safety = max(256 * 1024 * 1024, (staging + rollback + reserve) // 5)
    return staging + rollback + reserve + safety


def ensure_free_space(path, required, label):
    root = Path(path)
    probe = root if root.exists() else root.parent
    probe.mkdir(parents=True, exist_ok=True)
    free = int(shutil.disk_usage(probe).free)
    need = max(0, int(required))
    if free < need:
        raise RuntimeError(
            str(label)
            + "需要约"
            + str(round(need / 1024 / 1024 / 1024, 2))
            + "GB可用空间，当前约"
            + str(round(free / 1024 / 1024 / 1024, 2))
            + "GB"
        )
    return free


@dataclass(frozen=True, slots=True)
class RuntimeThresholds:
    version: int = 4
    ram_red_bytes: int = 1536 * 1024 * 1024
    ram_yellow_bytes: int = 2560 * 1024 * 1024
    free_vram_red_bytes: int = 384 * 1024 * 1024
    free_vram_yellow_bytes: int = 768 * 1024 * 1024
    capture_red_ms: float = 70.0
    capture_yellow_ms: float = 35.0
    end_to_end_red_p95_ms: float = 85.0
    end_to_end_yellow_p95_ms: float = 45.0
    maximum_ood: float = 0.70
    minimum_success_probability: float = 0.55
    risk_reject_probability: float = 0.50
    confirmation_frames: int = 3
    active_learning_trigger_streak: int = 8
    minimum_ai_success_lower: float = 0.80
    human_noninferiority_margin: float = 0.05
    online_acceptance_minimum_episodes: int = 30
    online_acceptance_target_episodes: int = 40
    online_acceptance_maximum_episodes: int = 50
    world_model_horizon: int = 16
    latency_regression_ratio: float = 1.30
    latency_regression_runs: int = 3

    def to_dict(self):
        return {
            name: getattr(self, name)
            for name in self.__dataclass_fields__
        }


RUNTIME_THRESHOLDS = RuntimeThresholds()


class VersionedThresholdConfig:
    version = 3
    required_sessions = 2
    review_min_holdout = 150
    review_min_accepted = 150
    ordinary_min_positive = 20
    ordinary_min_sessions = 2
    basic_safe_min_positive = 12
    basic_safe_min_consistency = 0.95
    dangerous_min_positive = 50
    dangerous_min_negative = 50
    dangerous_min_sessions = 4
    capture_min_holdout = 20
    capture_min_accuracy = 0.80
    capture_max_errors = 0
    scene_min_holdout = 10
    scene_min_accuracy = 0.75
    scene_max_errors = 0
    minimum_coverage = 0.80
    maximum_error_upper_95 = 0.02
    minimum_overall_accuracy = 0.80
    maximum_dangerous_false = 0
    maximum_uncovered_false_accept = 0
    candidate_full_limit = 18
    content_aspect_tolerance = 0.015

    @classmethod
    def snapshot(cls):
        result = {
            key: value
            for key, value in vars(cls).items()
            if not key.startswith("_") and isinstance(value, (int, float, str, bool))
        }
        result["runtime"] = RUNTIME_THRESHOLDS.to_dict()
        return result


def current_build_hash():
    try:
        source = Path(__file__)
        stat = source.stat()
        key = (int(stat.st_size), int(stat.st_mtime_ns))
        with RUNTIME_REPOSITORY.lock:
            if not RUNTIME_REPOSITORY.build_hash or RUNTIME_REPOSITORY.build_hash_key != key:
                RUNTIME_REPOSITORY.build_hash = hashlib.sha256(source.read_bytes()).hexdigest()
                RUNTIME_REPOSITORY.build_hash_key = key
            return RUNTIME_REPOSITORY.build_hash
    except RECOVERABLE_ERRORS:
        return ""


def compatibility_signature():
    return {
        "format_version": FORMAT_VERSION,
        "model_schema_version": MODEL_SCHEMA_VERSION,
        "feature_algorithm_version": FEATURE_ALGORITHM_VERSION,
        "action_algorithm_version": ACTION_ALGORITHM_VERSION,
        "feature_size": [FEATURE_W, FEATURE_H, FEATURE_CHANNELS],
        "coarse_size": [COARSE_W, COARSE_H, FEATURE_CHANNELS],
        "window_rule_version": WINDOW_RULE_VERSION,
        "capture_backend_version": CAPTURE_BACKEND_VERSION,
        "thresholds": VersionedThresholdConfig.snapshot(),
    }


def compatibility_signature_from_item(item):
    if not isinstance(item, dict):
        return None
    direct = item.get("compatibility_signature")
    if isinstance(direct, dict):
        return direct
    snapshot = item.get("algorithm_snapshot")
    if not isinstance(snapshot, dict):
        return None
    nested = snapshot.get("compatibility_signature")
    if isinstance(nested, dict):
        return nested
    legacy = {
        key: snapshot.get(key)
        for key in (
            "format_version",
            "feature_algorithm_version",
            "action_algorithm_version",
            "feature_size",
            "coarse_size",
            "window_rule_version",
            "capture_backend_version",
            "thresholds",
        )
    }
    legacy["model_schema_version"] = MODEL_SCHEMA_VERSION
    return legacy


def normalized_compatibility_signature(value):
    if not isinstance(value, dict):
        return None
    result = dict(value)
    result["model_schema_version"] = safe_int(
        result.get("model_schema_version", MODEL_SCHEMA_VERSION), MODEL_SCHEMA_VERSION
    )
    thresholds = dict(result.get("thresholds")) if isinstance(result.get("thresholds"), dict) else {}
    legacy_defaults = {
        "required_sessions": 2,
        "capture_min_holdout": 20,
        "capture_min_accuracy": 0.80,
        "capture_max_errors": 0,
        "scene_min_holdout": 10,
        "scene_min_accuracy": 0.75,
        "scene_max_errors": 0,
        "maximum_dangerous_false": 0,
        "maximum_uncovered_false_accept": 0,
    }
    for key, default in legacy_defaults.items():
        thresholds.setdefault(key, default)
    current = VersionedThresholdConfig.snapshot()
    comparable = dict(thresholds)
    comparable["version"] = current["version"]
    if comparable == current:
        thresholds = current
    result["thresholds"] = thresholds
    return result


def algorithm_snapshot():
    return {"compatibility_signature": compatibility_signature(), "source_build_hash": current_build_hash()}


def evaluate_validation_thresholds(
    split_complete,
    session_count,
    holdout_count,
    accepted,
    coverage,
    overall_accuracy,
    error_upper_95,
    dangerous_false,
    uncovered_false_accept,
):
    enough = bool(
        split_complete
        and int(session_count) >= VersionedThresholdConfig.required_sessions
        and int(holdout_count) >= VersionedThresholdConfig.review_min_holdout
        and int(accepted) >= VersionedThresholdConfig.review_min_accepted
    )
    global_pass = bool(
        float(coverage) >= VersionedThresholdConfig.minimum_coverage
        and float(overall_accuracy) >= VersionedThresholdConfig.minimum_overall_accuracy
        and float(error_upper_95) <= VersionedThresholdConfig.maximum_error_upper_95
        and int(dangerous_false) <= VersionedThresholdConfig.maximum_dangerous_false
        and int(uncovered_false_accept) <= VersionedThresholdConfig.maximum_uncovered_false_accept
    )
    return enough, global_pass


def own_injected_event(flags, extra_info, mask):
    return bool(int(flags) & int(mask) and int(extra_info) == INPUT_EXTRA_INFO)


def normalized_rect(rect, container):
    x, y, w, h = [float(value) for value in rect]
    cx, cy, cw, ch = [float(value) for value in container]
    if min(cw, ch, w, h) <= 0:
        raise ValueError("矩形尺寸无效")
    left = max(0.0, min(1.0, (x - cx) / cw))
    top = max(0.0, min(1.0, (y - cy) / ch))
    right = max(left, min(1.0, (x + w - cx) / cw))
    bottom = max(top, min(1.0, (y + h - cy) / ch))
    if right - left < 0.02 or bottom - top < 0.02:
        raise ValueError("内容区域过小")
    return [round(left, 8), round(top, 8), round(right - left, 8), round(bottom - top, 8)]


def apply_normalized_rect(container, norm):
    cx, cy, cw, ch = [int(value) for value in container]
    if not isinstance(norm, (list, tuple)) or len(norm) != 4:
        norm = [0.0, 0.0, 1.0, 1.0]
    left = max(0.0, min(1.0, safe_float(norm[0], 0.0)))
    top = max(0.0, min(1.0, safe_float(norm[1], 0.0)))
    width = max(0.02, min(1.0 - left, safe_float(norm[2], 1.0)))
    height = max(0.02, min(1.0 - top, safe_float(norm[3], 1.0)))
    x = cx + round(left * cw)
    y = cy + round(top * ch)
    right = cx + round((left + width) * cw)
    bottom = cy + round((top + height) * ch)
    return x, y, max(2, right - x), max(2, bottom - y)


def visual_perceptual_hash(feature):
    source = feature_bytes(feature)
    plane = source[:PIXELS]
    values = []
    for oy in range(8):
        sy = min(FEATURE_H - 1, (2 * oy + 1) * FEATURE_H // 16)
        row = []
        for ox in range(9):
            sx = min(FEATURE_W - 1, (2 * ox + 1) * FEATURE_W // 18)
            row.append(plane[sy * FEATURE_W + sx])
        values.extend(1 if row[index + 1] >= row[index] else 0 for index in range(8))
    value = 0
    for bit in values:
        value = (value << 1) | bit
    return format(value, "016x")


def perceptual_hash_hamming(first, second):
    try:
        return (int(str(first), 16) ^ int(str(second), 16)).bit_count()
    except (TypeError, ValueError):
        return 64


def normalized_policy_score_weights(value=None):
    source = value if isinstance(value, dict) else {}
    return {
        name: safe_float(source.get(name, default), default, 0.0, 500.0)
        for name, default in DEFAULT_POLICY_SCORE_WEIGHTS.items()
    }


def policy_experience_row(experience_model, state_hash, cluster_id, task_id=None):
    if not isinstance(experience_model, dict):
        return {}
    tid = normalized_identifier(task_id or experience_model.get("default_task_id"), "default", 96)
    state_action = experience_model.get("state_action")
    if isinstance(state_action, dict):
        for key in (tid + "|" + str(state_hash) + "|" + str(cluster_id), str(state_hash) + "|" + str(cluster_id)):
            row = state_action.get(key)
            if isinstance(row, dict):
                return row
        priors = experience_model.get("action_prior", {})
        if isinstance(priors, dict):
            for key in (tid + "|" + str(cluster_id), str(cluster_id)):
                row = priors.get(key)
                if isinstance(row, dict):
                    return row
        return {}
    for key in (tid + "|" + str(state_hash) + "|" + str(cluster_id), str(state_hash) + "|" + str(cluster_id)):
        row = experience_model.get(key)
        if isinstance(row, dict):
            return row
    return {}


def summarize_episode_metrics(experiences):
    by_episode = defaultdict(list)
    for item in experiences or []:
        if isinstance(item, dict):
            key = (
                str(item.get("game_id") or "legacy"),
                normalized_identifier(item.get("task_id"), "default", 96),
                str(item.get("episode_id") or item.get("session") or "legacy"),
            )
            by_episode[key].append(item)
    rows = []
    for (game_id, task_id, episode), items in by_episode.items():
        ordered = sorted(items, key=lambda item: safe_int(item.get("step_id"), 0))
        rows.append(
            {
                "game_id": game_id,
                "task_id": task_id,
                "episode_id": episode,
                "steps": len(ordered),
                "reward": sum(safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0) for item in ordered),
                "success": any(bool(item.get("success")) for item in ordered),
                "failure": any(bool(item.get("failure")) for item in ordered),
                "human_overrides": sum(1 for item in ordered if item.get("human_override")),
                "duration": (
                    max(
                        0.0,
                        safe_float(ordered[-1].get("created_t", 0.0), 0.0)
                        - safe_float(ordered[0].get("created_t", 0.0), 0.0),
                    )
                    if ordered
                    else 0.0
                ),
            }
        )
    total = len(rows)
    task_rows = defaultdict(list)
    for row in rows:
        task_rows[row["task_id"]].append(row)
    by_task = {}
    for task_id, items in task_rows.items():
        by_task[task_id] = {
            "episodes": len(items),
            "success_rate": sum(1 for item in items if item["success"]) / max(1, len(items)),
            "failure_rate": sum(1 for item in items if item["failure"]) / max(1, len(items)),
            "average_actions": sum(item["steps"] for item in items) / max(1, len(items)),
            "human_override_count": sum(item["human_overrides"] for item in items),
        }
    return {
        "episodes": total,
        "task_success_rate": sum(1 for row in rows if row["success"]) / max(1, total),
        "failure_rate": sum(1 for row in rows if row["failure"]) / max(1, total),
        "average_actions": sum(row["steps"] for row in rows) / max(1, total),
        "average_completion_time": sum(row["duration"] for row in rows if row["success"])
        / max(1, sum(1 for row in rows if row["success"])),
        "human_override_count": sum(row["human_overrides"] for row in rows),
        "mean_episode_reward": sum(row["reward"] for row in rows) / max(1, total),
        "by_task": by_task,
    }


def visual_scene_key(item):
    feature = feature_bytes(item.get("f"))
    plane = feature[:PIXELS]
    mean = sum(plane) / max(1, len(plane))
    edges = feature[3 * PIXELS : 4 * PIXELS]
    edge_mean = sum(edges) / max(1, len(edges))
    context = temporal_from_context(item.get("context", {}))
    motion = sum(context.get("recent_frame_deltas", [])) / max(1, len(context.get("recent_frame_deltas", [])))
    return (
        "L"
        + str(min(5, int(mean // 43)))
        + "|E"
        + str(min(5, int(edge_mean // 43)))
        + "|M"
        + str(min(5, int(motion // 120)))
    )


def calculate_sequence_penalty(history, cluster_id, sequence_model, task_id=None):
    if not isinstance(sequence_model, dict):
        return 0.0
    values = [str(value) for value in history] if isinstance(history, (list, tuple, deque)) else [str(history)]
    prefixes = []
    if task_id not in (None, ""):
        prefixes.append(normalized_identifier(task_id, "default", 96) + "|")
    prefixes.append("")
    choices = {}
    depth = 0
    for prefix in prefixes:
        for size in range(min(4, len(values)), 0, -1):
            key = prefix + str(size) + "|" + "|".join(values[-size:])
            candidate = sequence_model.get(key, {})
            if isinstance(candidate, dict) and candidate:
                choices = candidate
                depth = size
                break
        if choices:
            break
    if not choices:
        suffix = str(values[-1] if values else "<START>")
        for prefix in prefixes:
            candidate = sequence_model.get(prefix + suffix, {})
            if isinstance(candidate, dict) and candidate:
                choices = candidate
                break
    if not isinstance(choices, dict) or not choices:
        return 0.0
    total = sum(max(0.0, safe_float(value, 0.0)) for value in choices.values())
    probability = max(0.0, safe_float(choices.get(str(cluster_id), 0.0), 0.0)) / max(1e-9, total)
    return (1.0 - probability) * (18.0 + depth * 3.0)


class TaskAgentPolicy:
    def __init__(self, profile):
        self.profile = dict(profile) if isinstance(profile, dict) else {}
        self.allowed = set(str(value) for value in self.profile.get("allowed_families", []))
        self.max_failures = max(1, safe_int(self.profile.get("max_consecutive_failures", 3), 3, 1, 20))
        self.failures = 0
        self.history = deque(maxlen=128)
        self.game_id = str(self.profile.get("game_id", ""))
        self.perception_key = str(self.profile.get("perception_key", "")).strip()
        self.task_id = normalized_identifier(
            self.profile.get("task_id") or self.profile.get("default_task_id"), "default", 96
        )
        self.success_states = frozenset(str(value) for value in self.profile.get("success_states", []))
        self.failure_states = frozenset(str(value) for value in self.profile.get("failure_states", []))
        self.success_hash_distance = safe_int(self.profile.get("success_hash_distance", 6), 6, 0, 32)
        self.failure_hash_distance = safe_int(self.profile.get("failure_hash_distance", 6), 6, 0, 32)
        self.terminal_confirm_frames = safe_int(self.profile.get("terminal_confirm_frames", 2), 2, 1, 8)
        self._terminal_candidate = ""
        self._terminal_streak = 0
        self.last_classification = {
            "state": "neutral",
            "success_probability": 0.0,
            "failure_probability": 0.0,
            "progress_score": 0.0,
            "confirmed": False,
        }

    def allowed_action(self, action):
        family = action_family_key(action)
        return bool(family and family in self.allowed)

    def state_hash(self, feature):
        return visual_perceptual_hash(feature)

    def _hash_probability(self, value, states, threshold):
        if not states:
            return 0.0, 64
        distance = min(perceptual_hash_hamming(value, item) for item in states)
        scale = max(1, threshold + 2)
        return max(0.0, min(1.0, 1.0 - distance / scale)), distance

    def classify(self, feature):
        fused = TerminalEvidenceFusion.classify(self, feature)
        candidate = str(fused.get("candidate", ""))
        if candidate and candidate == self._terminal_candidate:
            self._terminal_streak += 1
        elif candidate:
            self._terminal_candidate = candidate
            self._terminal_streak = 1
        else:
            self._terminal_candidate = ""
            self._terminal_streak = 0
        confirmed = bool(candidate and self._terminal_streak >= self.terminal_confirm_frames)
        state = candidate if confirmed else "neutral"
        reward = (
            safe_float(self.profile.get("success_reward", 1.0), 1.0)
            if state == "success"
            else (
                safe_float(self.profile.get("failure_reward", -1.0), -1.0)
                if state == "failure"
                else max(-0.25, min(0.25, safe_float(fused.get("progress_score"), 0.0) * 0.25))
            )
        )
        self.last_classification = {
            "state": state,
            "candidate": candidate,
            "success_probability": round(safe_float(fused.get("success_probability"), 0.0), 6),
            "failure_probability": round(safe_float(fused.get("failure_probability"), 0.0), 6),
            "reset_probability": round(safe_float(fused.get("reset_probability"), 0.0), 6),
            "progress_probability": round(safe_float(fused.get("progress_probability"), 0.0), 6),
            "stalled_probability": round(safe_float(fused.get("stalled_probability"), 0.0), 6),
            "progress_score": round(safe_float(fused.get("progress_score"), 0.0), 6),
            "confirmed": confirmed,
            "conflict": bool(fused.get("conflict")),
            "requires_guidance": bool(fused.get("requires_guidance")),
            "confirmation_streak": self._terminal_streak,
            "confirmation_required": self.terminal_confirm_frames,
            "confidence": round(safe_float(fused.get("reward_confidence"), 0.0), 6),
            "evidence": list(fused.get("evidence", [])),
            "learned_evidence": dict(fused.get("learned_evidence", {})),
            "hash_evidence": dict(fused.get("hash_evidence", {})),
            "terminal_fusion": "auditable_rules+temporal_sequence_model+conflict_guidance_gate",
        }
        return state, reward

    def register(self, before, action, after, changed):
        before_hash = self.state_hash(before)
        after_hash = self.state_hash(after) if after is not None else ""
        state, reward = self.classify(after if after is not None else before)
        if state == "failure" or not changed:
            self.failures += 1
        else:
            self.failures = 0
        record = {
            "before": before_hash,
            "action": action_signature(action),
            "after": after_hash,
            "state": state,
            "reward": reward,
            "changed": bool(changed),
        }
        record.update(self.last_classification)
        exploitation = reward_exploitation_signal(self.history, record)
        record["reward_exploitation"] = exploitation
        if (
            exploitation.get("detected")
            or self.last_classification.get("conflict")
            or safe_float(self.last_classification.get("stalled_probability"), 0.0) >= 0.82
        ):
            self.failures += 1
        self.history.append(record)
        return {
            "state": state,
            "reward": reward,
            "failures": self.failures,
            "stop": self.failures >= self.max_failures or exploitation.get("detected", False),
            "reward_exploitation": exploitation,
            **self.last_classification,
        }

    def sequence_penalty(self, history, cluster_id, sequence_model):
        return calculate_sequence_penalty(history, cluster_id, sequence_model, self.task_id)


def profile_checksum(profile):
    value = dict(profile) if isinstance(profile, dict) else {}
    value.pop("updated", None)
    return hashlib.sha256(canonical_bytes(value)).hexdigest()


def model_binding_from_samples(samples):
    paths = set()
    classes = set()
    norms = set()
    aspects = []
    dpis = []
    methods = set()
    sizes = []
    for item in samples:
        context = item.get("context", {}) if isinstance(item, dict) else {}
        path = os.path.normcase(str(context.get("process_path", "")))
        window_class = str(context.get("window_class", ""))
        norm = context.get("content_rect_norm")
        aspect = context.get("content_aspect")
        dpi = context.get("dpi")
        rect = context.get("content_rect") or context.get("client_rect")
        method = str(item.get("capture_method") or context.get("capture_method") or "")
        if path:
            paths.add(path)
        if window_class:
            classes.add(window_class)
        if isinstance(norm, (list, tuple)) and len(norm) == 4:
            norms.add(tuple(round(safe_float(value, 0.0), 6) for value in norm))
        if finite_number(aspect) and float(aspect) > 0:
            aspects.append(float(aspect))
        if finite_number(dpi) and int(dpi) > 0:
            dpis.append(int(dpi))
        if isinstance(rect, (list, tuple)) and len(rect) >= 4 and finite_number(rect[2]) and finite_number(rect[3]):
            sizes.append([safe_int(rect[2], 0, 1, 32768), safe_int(rect[3], 0, 1, 32768)])
        if method:
            methods.add(method)
    identity = {
        "process_paths": sorted(paths),
        "window_classes": sorted(classes),
        "window_rule_version": WINDOW_RULE_VERSION,
    }
    adaptation = {
        "content_rect_norms": [list(value) for value in sorted(norms)],
        "content_aspect_min": min(aspects) if aspects else 0.0,
        "content_aspect_max": max(aspects) if aspects else 0.0,
        "dpi_min": min(dpis) if dpis else 0,
        "dpi_max": max(dpis) if dpis else 0,
        "capture_methods": sorted(methods),
        "content_sizes": sizes[:128],
        "capture_backend_version": CAPTURE_BACKEND_VERSION,
        "allow_proportional_resolution": True,
        "allow_dpi_recalibration": True,
        "allow_backend_revalidation": True,
    }
    return {
        **identity,
        **adaptation,
        "safety_identity": identity,
        "visual_adaptation": adaptation,
        "binding_schema_version": 2,
    }


class ThreadLocalSQLite:
    def __init__(self, path, read_only=False):
        self.path = Path(path)
        self.read_only = bool(read_only)
        self.lock = threading.RLock()
        self.local = threading.local()
        self.connections = {}
        self.closing = False

    def _new(self):
        if self.closing:
            raise RuntimeError("SQLite连接池正在关闭")
        if self.read_only:
            absolute = self.path.expanduser().resolve(strict=False).as_posix()
            encoded = urllib.parse.quote(absolute, safe="/:")
            connection = sqlite3.connect("file:" + encoded + "?mode=ro", uri=True, timeout=1.0, check_same_thread=False)
        else:
            connection = sqlite3.connect(str(self.path), timeout=3.0, check_same_thread=False)
        connection.row_factory = sqlite3.Row
        connection.execute("PRAGMA foreign_keys=ON")
        connection.execute("PRAGMA busy_timeout=3000")
        if not self.read_only:
            connection.execute("PRAGMA secure_delete=ON")
            connection.execute("PRAGMA synchronous=NORMAL")
        return connection

    def current(self):
        connection = getattr(self.local, "connection", None)
        if connection is None:
            connection = self._new()
            self.local.connection = connection
            with self.lock:
                self.connections[id(connection)] = {
                    "connection": connection,
                    "thread": threading.current_thread().name,
                    "created": time.monotonic(),
                }
        return connection

    @contextmanager
    def thread_connection(self):
        connection = self.current()
        try:
            yield connection
        except RECOVERABLE_ERRORS:
            try:
                connection.rollback()
            except sqlite3.Error as error:
                record_cleanup_error("SQLITE_THREAD_ROLLBACK_FAILED", error)
            raise
        finally:
            self.close_current_thread()

    def execute(self, *args, **kwargs):
        return self.current().execute(*args, **kwargs)

    def executemany(self, *args, **kwargs):
        return self.current().executemany(*args, **kwargs)

    def commit(self):
        started = time.monotonic()
        try:
            return self.current().commit()
        finally:
            RUNTIME_METRICS.observe("sqlite_commit_ms", (time.monotonic() - started) * 1000.0)

    def rollback(self):
        return self.current().rollback()

    def __enter__(self):
        self.current().__enter__()
        return self

    def __exit__(self, exc_type, exc_value, exc_traceback):
        return self.current().__exit__(exc_type, exc_value, exc_traceback)

    def close_current_thread(self):
        connection = getattr(self.local, "connection", None)
        if connection is None:
            return False
        self.local.connection = None
        with self.lock:
            self.connections.pop(id(connection), None)
        try:
            connection.close()
            return True
        except sqlite3.Error as error:
            record_cleanup_error("SQLITE_CONNECTION_CLOSE_FAILED", error)
            return False

    def connection_count(self):
        with self.lock:
            return len(self.connections)

    def close(self, timeout=3.0):
        self.closing = True
        deadline = time.monotonic() + max(0.0, float(timeout))
        self.close_current_thread()
        while True:
            with self.lock:
                remaining = list(self.connections.values())
            if not remaining or time.monotonic() >= deadline:
                break
            interruptible_wait(None, 0.01)
        failures = []
        for item in remaining:
            connection = item.get("connection")
            try:
                connection.rollback()
            except sqlite3.Error:
                pass
            try:
                connection.close()
            except sqlite3.Error as error:
                failures.append({"thread": item.get("thread"), "error": str(error)})
                record_cleanup_error("SQLITE_CONNECTION_CLOSE_FAILED", error, {"thread": item.get("thread")})
            finally:
                with self.lock:
                    self.connections.pop(id(connection), None)
        if failures:
            record_cleanup_error(
                "SQLITE_FOREIGN_THREAD_CONNECTIONS_REMAIN",
                RuntimeError(json.dumps(failures, ensure_ascii=False, separators=(",", ":"))),
            )
        return not failures and self.connection_count() == 0


