def guid(value):
    item = uuid.UUID(str(value))
    data = item.bytes_le
    return GUID(
        int.from_bytes(data[0:4], "little"),
        int.from_bytes(data[4:6], "little"),
        int.from_bytes(data[6:8], "little"),
        (ctypes.c_ubyte * 8).from_buffer_copy(data[8:16]),
    )


