@dataclass(frozen=True)
class WindowIdentity:
    hwnd: int
    pid: int
    process_path: str
    window_class: str
    title: str
    process_start: float = 0.0

    @classmethod
    def from_mapping(cls, value):
        item = dict(value) if isinstance(value, dict) else {}
        result = cls(
            safe_int(item.get("hwnd"), 0),
            safe_int(item.get("pid"), 0),
            str(item.get("process_path", "")),
            str(item.get("window_class") or item.get("class") or ""),
            str(item.get("title", "")),
            safe_float(item.get("process_start", item.get("process_created", 0.0)), 0.0),
        )
        if result.hwnd <= 0 or result.pid <= 0 or not result.process_path or not result.window_class:
            raise ValueError("窗口身份字段不完整")
        return result

    def to_dict(self):
        return {
            "hwnd": self.hwnd,
            "pid": self.pid,
            "process_path": self.process_path,
            "window_class": self.window_class,
            "title": self.title,
            "process_start": self.process_start,
        }


@dataclass(frozen=True, slots=True)
class PerceptionIsolationKey:
    game_id: str
    session_id: str
    process_creation_time: int
    hwnd: int
    window_generation: int

    def encode(self):
        return "|".join(
            (
                self.game_id or "<no-game>",
                self.session_id or "<no-session>",
                str(int(self.process_creation_time)),
                str(int(self.hwnd)),
                str(int(self.window_generation)),
            )
        )

    @classmethod
    def from_values(cls, game_id="", session_id="", target=None, window_generation=0):
        item = dict(target) if isinstance(target, dict) else {}
        return cls(
            str(game_id or item.get("game_id") or ""),
            str(session_id or item.get("session_id") or ""),
            safe_int(item.get("process_created", item.get("process_creation_time", 0)), 0),
            safe_int(item.get("hwnd"), 0),
            safe_int(item.get("window_generation", window_generation), window_generation),
        )


@dataclass(frozen=True)
class FramePacket:
    feature: bytes
    capture_method: str
    created: float
    usable_for_training: bool

    @classmethod
    def from_mapping(cls, value):
        item = dict(value) if isinstance(value, dict) else {}
        feature = feature_bytes(item.get("f"))
        method = str(item.get("method") or item.get("capture_method") or "")
        if not feature_valid(feature) or not method:
            raise ValueError("帧数据包无效")
        return cls(
            feature, method, safe_float(item.get("created"), time.time()), bool(item.get("usable_for_training", False))
        )


@dataclass(frozen=True)
class CalibrationResult:
    capture_method: str
    fps: float
    input_delay: float
    dynamic_passed: bool

    @classmethod
    def from_mapping(cls, value):
        item = dict(value) if isinstance(value, dict) else {}
        result = cls(
            str(item.get("capture_method") or item.get("method") or ""),
            safe_float(item.get("fps"), 0.0, 0.0, 240.0),
            safe_float(item.get("input_delay"), 0.24, 0.0, 5.0),
            bool(item.get("dynamic_passed", False)),
        )
        if not result.capture_method or result.fps <= 0:
            raise ValueError("校准结果无效")
        return result


def validate_packet(kind, value):
    name = str(kind)
    if name == "window_identity":
        return WindowIdentity.from_mapping(value).to_dict()
    if name == "frame":
        return FramePacket.from_mapping(value)
    if name == "calibration":
        return CalibrationResult.from_mapping(value)
    if name == "action":
        action = normalize_action(value)
        if action is None:
            raise ValueError("动作数据包无效")
        return action
    if name in {"review_request", "review_response", "runtime_packet", "ai_packet"}:
        if not isinstance(value, dict):
            raise ValueError("进程数据包必须是字典")
        return dict(value)
    raise ValueError("未知数据包类型：" + name)


@dataclass(frozen=True, slots=True)
class ModeResult:
    status: str
    summary: str
    details: dict = field(default_factory=dict)

    def __post_init__(self):
        value = self.status.value if isinstance(self.status, ModeResultStatus) else str(self.status)
        if value not in {item.value for item in ModeResultStatus}:
            raise ValueError("模式结果状态无效")
        object.__setattr__(self, "status", value)
        object.__setattr__(self, "summary", str(self.summary))
        object.__setattr__(self, "details", dict(self.details) if isinstance(self.details, dict) else {})


class ControlStateMachine:
    def __init__(self):
        self.lock = threading.RLock()
        self.state = MODE_IDLE
        self.name = None
        self.shared_stop_event = threading.Event()
        self.stop_event = None
        self.requested_status = "stopped"
        self.reason = ""
        self.data_ready = False
        self.runtime_ready = False
        self.directory_phase = "unselected"

    def set_directory_phase(self, phase):
        value = str(phase)
        if value not in {"unselected", "preparing", "prepared", "ready", "failed"}:
            raise ValueError("文件夹状态无效")
        with self.lock:
            self.directory_phase = value
            self.data_ready = value == "ready"
            if not self.data_ready:
                self.runtime_ready = False

    def set_runtime_ready(self, value):
        with self.lock:
            self.runtime_ready = bool(value and self.data_ready)

    def begin(self, name):
        with self.lock:
            if self.state != MODE_IDLE:
                raise RuntimeError("当前已有操作正在运行，请先停止")
            normalized = normalize_mode_id(name)
            if normalized != "文件" and not self.data_ready:
                raise RuntimeError("请先选择并确认文件夹")
            if normalized != "文件" and not self.runtime_ready:
                raise RuntimeError("请先完成文件完整性检查")
            self.state = MODE_STARTING
            self.name = normalized
            self.shared_stop_event.clear()
            self.stop_event = self.shared_stop_event
            self.requested_status = "completed"
            self.reason = ""
            return self.stop_event

    def mark_running(self):
        with self.lock:
            if self.state == MODE_STARTING:
                self.state = MODE_RUNNING
            return self.state

    def request_stop(self, status="stopped", reason=""):
        priority = {"completed": 0, "stopped": 1, "failed": 2}
        with self.lock:
            if self.state == MODE_IDLE:
                return False
            value = str(status) if str(status) in priority else "stopped"
            if priority[value] >= priority.get(self.requested_status, 0):
                self.requested_status = value
                if reason:
                    self.reason = str(reason)
            elif reason and not self.reason:
                self.reason = str(reason)
            self.state = MODE_STOPPING
            if self.stop_event is not None:
                self.stop_event.set()
            return True

    def mark_stopping(self, status=None, reason=""):
        return self.request_stop(status or self.requested_status, reason)

    def finish(self):
        with self.lock:
            self.state = MODE_IDLE
            self.name = None
            self.stop_event = None
            self.requested_status = "stopped"
            self.reason = ""

    def snapshot(self):
        with self.lock:
            return self.state, self.name, self.stop_event, self.requested_status, self.reason


class StrictInputIsolation:
    def __init__(self, stop_event):
        self.stop_event = stop_event
        self.lock = threading.Lock()
        self.kind = ""
        self.stamp = 0.0

    def signal(self, kind, stamp=None):
        with self.lock:
            if not self.kind:
                self.kind = str(kind)
                self.stamp = float(time.monotonic() if stamp is None else stamp)
            if self.stop_event is not None:
                self.stop_event.set()

    def tripped(self):
        with self.lock:
            return bool(self.kind)

    def can_automate(self):
        return not self.tripped() and self.stop_event is not None and not self.stop_event.is_set()


class PreviewCoordinateMapper:
    canvas_width = ASK_CANVAS_W
    canvas_height = ASK_CANVAS_H
    preview_width = ASK_PREVIEW_W
    preview_height = ASK_PREVIEW_H
    offset_x = ASK_PREVIEW_X
    offset_y = ASK_PREVIEW_Y

    @classmethod
    def to_normalized(cls, x, y):
        px = float(x)
        py = float(y)
        if (
            px < cls.offset_x
            or py < cls.offset_y
            or px > cls.offset_x + cls.preview_width - 1
            or py > cls.offset_y + cls.preview_height - 1
        ):
            return None
        return [
            (px - cls.offset_x) / max(1, cls.preview_width - 1),
            (py - cls.offset_y) / max(1, cls.preview_height - 1),
        ]

    @classmethod
    def to_canvas(cls, point):
        return [
            cls.offset_x + max(0.0, min(1.0, float(point[0]))) * (cls.preview_width - 1),
            cls.offset_y + max(0.0, min(1.0, float(point[1]))) * (cls.preview_height - 1),
        ]


class ManagedShutdownResource:
    def __init__(self, resource_name, request_stop, is_alive, close, force_close=None, phase=0):
        self.resource_name = str(resource_name)
        self._request_stop = request_stop
        self._is_alive = is_alive
        self._close = close
        self._force_close = force_close or (lambda: False)
        self.phase = max(0, int(phase))

    def request_stop(self):
        return self._request_stop()

    def is_alive(self):
        return bool(self._is_alive())

    def close(self, timeout):
        return bool(self._close(max(0.0, float(timeout))))

    def force_close(self):
        return bool(self._force_close())


class ShutdownCoordinator:
    def __init__(self, label, timeout):
        self.label = str(label)
        self.deadline = time.monotonic() + max(0.1, float(timeout))
        self.resources = []
        self.errors = []
        self.forced = []
        self.requested = False

    def add(self, resource):
        if not isinstance(resource, ManagedShutdownResource):
            raise TypeError("关闭资源必须实现统一接口")
        self.resources.append(resource)
        return resource

    def request_stop(self):
        self.requested = True
        for resource in self.resources:
            try:
                resource.request_stop()
            except RECOVERABLE_ERRORS as error:
                self.errors.append(
                    {"resource": resource.resource_name, "operation": "request_stop", "error": str(error)}
                )
                record_cleanup_error(
                    "SHUTDOWN_REQUEST_STOP_FAILED", error, {"resource": resource.resource_name, "label": self.label}
                )

    def poll(self):
        self.request_stop()
        alive = []
        for resource in self.resources:
            try:
                if resource.is_alive():
                    alive.append(resource)
            except RECOVERABLE_ERRORS as error:
                alive.append(resource)
                self.errors.append({"resource": resource.resource_name, "operation": "is_alive", "error": str(error)})
                record_cleanup_error(
                    "SHUTDOWN_ALIVE_CHECK_FAILED", error, {"resource": resource.resource_name, "label": self.label}
                )
        if not alive:
            return {
                "done": True,
                "pending": [],
                "deadline_reached": False,
                "unforceable": [],
                "forced": list(self.forced),
                "errors": list(self.errors),
            }
        phase = min(resource.phase for resource in alive)
        current = [resource for resource in alive if resource.phase == phase]
        for resource in current:
            try:
                resource.close(0.0)
            except RECOVERABLE_ERRORS as error:
                self.errors.append({"resource": resource.resource_name, "operation": "close", "error": str(error)})
                record_cleanup_error(
                    "SHUTDOWN_CLOSE_FAILED", error, {"resource": resource.resource_name, "label": self.label}
                )
        deadline_reached = time.monotonic() >= self.deadline
        unforceable = []
        if deadline_reached:
            for resource in current:
                try:
                    if resource.is_alive():
                        forced = resource.force_close()
                        if forced:
                            self.forced.append(resource.resource_name)
                        elif resource.is_alive():
                            unforceable.append(resource.resource_name)
                except RECOVERABLE_ERRORS as error:
                    unforceable.append(resource.resource_name)
                    self.errors.append(
                        {"resource": resource.resource_name, "operation": "force_close", "error": str(error)}
                    )
                    record_cleanup_error(
                        "SHUTDOWN_FORCE_CLOSE_FAILED", error, {"resource": resource.resource_name, "label": self.label}
                    )
        pending = []
        for resource in self.resources:
            try:
                if resource.is_alive():
                    pending.append(resource.resource_name)
            except RECOVERABLE_ERRORS:
                pending.append(resource.resource_name)
        return {
            "done": not pending,
            "pending": sorted(set(pending)),
            "deadline_reached": deadline_reached,
            "unforceable": sorted(set(unforceable)),
            "forced": list(dict.fromkeys(self.forced)),
            "errors": list(self.errors),
        }


class ResourceShutdownBarrier:
    def __init__(self, label, timeout=4.0):
        self.coordinator = ShutdownCoordinator(label, timeout)
        self.last = {"done": True, "pending": []}

    def add(self, name, stopper, alive, forcer=None, phase=0):
        resource = ManagedShutdownResource(
            name,
            lambda: stopper(0.0),
            alive,
            stopper,
            forcer or (lambda: False),
            phase,
        )
        self.coordinator.add(resource)
        return resource

    def request_stop(self):
        self.coordinator.request_stop()

    def poll(self):
        self.last = self.coordinator.poll()
        return bool(self.last.get("done"))

    def pending_names(self):
        if not self.last.get("done", True):
            return list(self.last.get("pending", []))
        pending = []
        for resource in self.coordinator.resources:
            try:
                if resource.is_alive():
                    pending.append(resource.resource_name)
            except RECOVERABLE_ERRORS as error:
                record_cleanup_error("RESOURCE_STATE_CHECK_FAILED", error, {"resource": resource.resource_name})
                pending.append(resource.resource_name)
        return sorted(set(pending))


def finite_number(value):
    try:
        return math.isfinite(float(value))
    except (TypeError, ValueError, OverflowError):
        return False


def safe_int(value, default=0, minimum=None, maximum=None):
    try:
        number = int(value)
    except (TypeError, ValueError, OverflowError):
        number = int(default)
    if minimum is not None:
        number = max(int(minimum), number)
    if maximum is not None:
        number = min(int(maximum), number)
    return number


def safe_float(value, default=0.0, minimum=None, maximum=None):
    try:
        number = float(value)
        if not math.isfinite(number):
            raise ValueError("非有限数")
    except (TypeError, ValueError, OverflowError):
        number = float(default)
    if minimum is not None:
        number = max(float(minimum), number)
    if maximum is not None:
        number = min(float(maximum), number)
    return number


def window_work_area(widget):
    try:
        if os.name == "nt":
            rect = RECT()
            if ctypes.WinDLL("user32", use_last_error=True).SystemParametersInfoW(0x0030, 0, ctypes.byref(rect), 0):
                return (
                    int(rect.left),
                    int(rect.top),
                    max(320, int(rect.right - rect.left)),
                    max(240, int(rect.bottom - rect.top)),
                )
    except RECOVERABLE_ERRORS as error:
        record_cleanup_error("BEST_EFFORT_EXCEPTION", error)
    try:
        return 0, 0, max(320, int(widget.winfo_screenwidth())), max(240, int(widget.winfo_screenheight()))
    except RECOVERABLE_ERRORS:
        return 0, 0, 900, 700


def fit_window(widget, desired_width, desired_height, minimum_width=480, minimum_height=320):
    left, top, work_width, work_height = window_work_area(widget)
    width = max(320, min(int(desired_width), max(320, int(work_width * 0.94))))
    height = max(240, min(int(desired_height), max(240, int(work_height * 0.92))))
    min_width = min(width, max(320, int(minimum_width)))
    min_height = min(height, max(240, int(minimum_height)))
    x = left + max(0, (work_width - width) // 2)
    y = top + max(0, (work_height - height) // 2)
    widget.geometry(str(width) + "x" + str(height) + "+" + str(x) + "+" + str(y))
    widget.minsize(min_width, min_height)
    return width, height


def scrollable_frame(window, padding=0, horizontal=False):
    shell = ttk.Frame(window)
    shell.pack(fill="both", expand=True)
    canvas = tk.Canvas(shell, highlightthickness=0, borderwidth=0)
    vertical = ttk.Scrollbar(shell, orient="vertical", command=canvas.yview)
    horizontal_bar = ttk.Scrollbar(shell, orient="horizontal", command=canvas.xview) if horizontal else None
    canvas.configure(yscrollcommand=vertical.set)
    if horizontal_bar is not None:
        canvas.configure(xscrollcommand=horizontal_bar.set)
    canvas.grid(row=0, column=0, sticky="nsew")
    vertical.grid(row=0, column=1, sticky="ns")
    if horizontal_bar is not None:
        horizontal_bar.grid(row=1, column=0, sticky="ew")
    shell.rowconfigure(0, weight=1)
    shell.columnconfigure(0, weight=1)
    inner = ttk.Frame(canvas, padding=padding)
    item = canvas.create_window((0, 0), window=inner, anchor="nw")

    def update_region(event=None):
        canvas.configure(scrollregion=canvas.bbox("all"))

    def update_width(event):
        if horizontal_bar is None:
            canvas.itemconfigure(item, width=max(1, event.width))

    inner.bind("<Configure>", update_region)
    canvas.bind("<Configure>", update_width)

    def wheel(event):
        if event.delta:
            canvas.yview_scroll(-1 if event.delta > 0 else 1, "units")

    canvas.bind("<MouseWheel>", wheel)
    inner._ugai_canvas = canvas
    return inner


def hamming_distance_hex(first, second):
    return (
        (int(str(first), 16) ^ int(str(second), 16)).bit_count()
        if hasattr(int, "bit_count")
        else bin(int(str(first), 16) ^ int(str(second), 16)).count("1")
    )


def near_perceptual_hash_pairs(values, max_distance=4, stop_check=None):
    hashes = sorted(set(str(value) for value in values))
    if len(hashes) < 2:
        return []
    segment_count = max(1, int(max_distance) + 1)
    widths = [64 // segment_count] * segment_count
    for index in range(64 % segment_count):
        widths[index] += 1
    masks = []
    shift = 64
    for width in widths:
        shift -= width
        masks.append((shift, (1 << width) - 1))
    buckets = defaultdict(list)
    pairs = set()
    for index, value in enumerate(hashes):
        number = int(value, 16)
        candidates = set()
        for segment, (shift, mask) in enumerate(masks):
            key = (segment, (number >> shift) & mask)
            candidates.update(buckets[key])
        for other in candidates:
            if hamming_distance_hex(value, other) <= max_distance:
                pairs.add((other, value) if other < value else (value, other))
        for segment, (shift, mask) in enumerate(masks):
            buckets[(segment, (number >> shift) & mask)].append(value)
        if stop_check is not None and index % 256 == 0 and stop_check():
            raise InputStopped("睡眠已停止")
    return sorted(pairs)


def batch_feature_distances(query, items, chunk_size=128):
    values = items
    if hasattr(values, "shape") and hasattr(values, "dtype"):
        total = safe_int(values.shape[0], 0, 0) if len(values.shape) >= 1 else 0
    else:
        values = list(values)
        total = len(values)
    if total <= 0:
        return []
    np = _optional_numpy()
    if np is None:
        return [feature_distance(query, item) for item in values]
    chunk = max(64, min(256, safe_int(chunk_size, 128, 64, 256)))
    first = np.frombuffer(feature_bytes(query), dtype=np.uint8).reshape(FEATURE_CHANNELS, PIXELS).astype(np.int16)
    weights = _feature_weight_array(np)
    matrix = np.empty((chunk, FEATURE_CHANNELS, PIXELS), dtype=np.uint8)
    differences = np.empty((chunk, FEATURE_CHANNELS, PIXELS), dtype=np.int16)
    squares = np.empty((chunk, FEATURE_CHANNELS, PIXELS), dtype=np.int32)
    output = []
    for start in range(0, total, chunk):
        stop = min(total, start + chunk)
        count = stop - start
        if hasattr(values, "shape") and hasattr(values, "dtype"):
            source = np.asarray(values[start:stop], dtype=np.uint8)
            source = source.reshape(count, FEATURE_CHANNELS, PIXELS)
            matrix[:count] = source
        else:
            raw = b"".join(feature_bytes(item) for item in values[start:stop])
            matrix[:count] = np.frombuffer(raw, dtype=np.uint8).reshape(count, FEATURE_CHANNELS, PIXELS)
        np.subtract(matrix[:count], first[None, :, :], out=differences[:count], casting="unsafe")
        np.multiply(differences[:count], differences[:count], out=squares[:count], dtype=np.int32, casting="unsafe")
        means = np.mean(squares[:count], axis=2, dtype=np.float64)
        output.extend(np.dot(means, weights).astype(float).tolist())
    return output


class PrototypeConflictTracker:
    def __init__(self, stop_check=None, max_candidates=80, max_buckets=8):
        self.stop_check = stop_check or (lambda: False)
        self.max_candidates = max(8, int(max_candidates))
        self.max_buckets = max(2, int(max_buckets))
        self.prototypes = {}
        self.buckets = defaultdict(list)
        self.bucket_representatives = {}

    def _scene(self, proto):
        feature = feature_bytes(proto.get("f"))
        plane = feature[:PIXELS]
        edges = feature[3 * PIXELS : 4 * PIXELS]
        mean = sum(plane) / max(1, len(plane))
        edge_mean = sum(edges) / max(1, len(edges))
        temporal = proto.get("temporal", {}) if isinstance(proto.get("temporal"), dict) else {}
        deltas = temporal.get("recent_frame_deltas", [])
        motion = sum(safe_float(value, 0.0) for value in deltas) / max(1, len(deltas))
        return (
            "L"
            + str(min(5, int(mean // 43)))
            + "|E"
            + str(min(5, int(edge_mean // 43)))
            + "|M"
            + str(min(5, int(motion // 120)))
        )

    def _keys(self, proto):
        family = action_family_key(proto.get("a"))
        scene = self._scene(proto)
        methods = proto.get("capture_methods", []) or ["unknown"]
        return [(family, scene, str(method)) for method in sorted(set(str(value) for value in methods))]

    def _candidate_ids(self, proto):
        own_keys = self._keys(proto)
        exact = []
        for family, scene, backend in own_keys:
            for key, ids in self.buckets.items():
                if key[1] == scene and key[2] == backend:
                    exact.extend(ids)
        selected = []
        seen = set()
        for value in exact:
            if value not in seen:
                seen.add(value)
                selected.append(value)
        if len(selected) < self.max_candidates:
            ranked = []
            for key, representative in self.bucket_representatives.items():
                if any(key[2] == own[2] for own in own_keys):
                    ranked.append((coarse_distance(proto.get("coarse"), representative), key))
            for _, key in sorted(ranked, key=lambda item: (item[0], item[1]))[: self.max_buckets]:
                for value in self.buckets.get(key, []):
                    if value not in seen:
                        seen.add(value)
                        selected.append(value)
                        if len(selected) >= self.max_candidates:
                            break
                if len(selected) >= self.max_candidates:
                    break
        return selected[: self.max_candidates]

    def _update_pair(self, first, second, visual_value):
        if str(first.get("cluster_id")) == str(second.get("cluster_id")):
            return
        temporal_value = temporal_distance(first.get("temporal", {}), second.get("temporal", {}))
        for current, other in ((first, second), (second, first)):
            old = safe_float(current.get("_nearest_conflict_distance"), float("inf"))
            if float(visual_value) < old:
                current["_nearest_conflict_distance"] = float(visual_value)
                current["_nearest_conflict_temporal"] = float(temporal_value)
                current["_nearest_conflict_id"] = str(other.get("id"))

    def add_batch(self, items):
        values = [item for item in items if isinstance(item, dict) and item.get("id")]
        for index, proto in enumerate(values):
            if index % 16 == 0 and self.stop_check():
                raise InputStopped("睡眠已停止")
            candidate_ids = self._candidate_ids(proto)
            candidates = [
                self.prototypes[value]
                for value in candidate_ids
                if value in self.prototypes
                and str(self.prototypes[value].get("cluster_id")) != str(proto.get("cluster_id"))
            ]
            if candidates:
                distances = batch_feature_distances(proto["f"], [item["f"] for item in candidates])
                for other, distance in zip(candidates, distances):
                    self._update_pair(proto, other, distance)
            identity = str(proto["id"])
            self.prototypes[identity] = proto
            for key in self._keys(proto):
                self.buckets[key].append(identity)
                self.bucket_representatives.setdefault(key, proto.get("coarse"))

    def retain(self, items):
        kept = {str(item.get("id")) for item in items}
        removed = set(self.prototypes) - kept
        if not removed:
            return
        for identity in removed:
            self.prototypes.pop(identity, None)
        self.buckets = defaultdict(list)
        self.bucket_representatives = {}
        for identity, proto in self.prototypes.items():
            for key in self._keys(proto):
                self.buckets[key].append(identity)
                self.bucket_representatives.setdefault(key, proto.get("coarse"))
        affected = []
        for proto in self.prototypes.values():
            if str(proto.get("_nearest_conflict_id", "")) in removed:
                proto.pop("_nearest_conflict_distance", None)
                proto.pop("_nearest_conflict_temporal", None)
                proto.pop("_nearest_conflict_id", None)
                affected.append(proto)
        for proto in affected:
            candidates = [
                self.prototypes[value]
                for value in self._candidate_ids(proto)
                if value in self.prototypes
                and value != str(proto.get("id"))
                and str(self.prototypes[value].get("cluster_id")) != str(proto.get("cluster_id"))
            ]
            if candidates:
                distances = batch_feature_distances(proto["f"], [item["f"] for item in candidates])
                for other, distance in zip(candidates, distances):
                    self._update_pair(proto, other, distance)

    def finalize(self, items):
        self.retain(items)
        for proto in items:
            nearest = safe_float(proto.pop("_nearest_conflict_distance", float("inf")), float("inf"))
            temporal_nearest = safe_float(proto.pop("_nearest_conflict_temporal", 1.0), 1.0)
            proto.pop("_nearest_conflict_id", None)
            proto["nearest_conflicting_distance"] = None if math.isinf(nearest) else round(nearest, 6)
            intra = float(proto.get("intra_threshold", proto["threshold"]))
            visual_close = not math.isinf(nearest) and nearest <= max(1e-6, intra * 0.20)
            temporal_close = temporal_nearest <= max(float(proto.get("temporal_threshold", 0.25)), 0.25)
            proto["ambiguous"] = bool(visual_close and temporal_close)
            proto["threshold"] = round(
                max(0.001, intra if math.isinf(nearest) else min(intra, max(0.001, nearest * 0.62))), 6
            )
            proto["minimum_second_candidate_gap"] = round(
                max(10.0, float(proto["threshold"]) * 0.15, 0.0 if math.isinf(nearest) else nearest * 0.10), 6
            )
            proto["channel_stats"] = {
                "mean": sum(proto["f"]) / len(proto["f"]),
                "minimum": min(proto["f"]),
                "maximum": max(proto["f"]),
            }
        return items


def bounded_decompress(data, maximum):
    raw = bytes(data)
    limit = max(1, safe_int(maximum, 1, 1, 268435456))
    decoder = zlib.decompressobj()
    result = decoder.decompress(raw, limit + 1)
    if len(result) > limit or decoder.unconsumed_tail or not decoder.eof:
        raise ValueError("压缩数据超过安全上限或已损坏")
    tail = decoder.flush()
    if tail:
        result += tail
    if len(result) > limit:
        raise ValueError("压缩数据超过安全上限")
    return result


def canonical_bytes(data):
    return json.dumps(data, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")


def deterministic_sleep_seed(game_id, samples):
    checksums = []
    for item in samples or []:
        checksum = str(item.get("checksum", "")).strip() if isinstance(item, dict) else ""
        if not checksum:
            checksum = immutable_digest(
                {
                    "rgb": item.get("rgb") if isinstance(item, dict) else None,
                    "action": item.get("a") if isinstance(item, dict) else None,
                    "session_id": item.get("session_id") if isinstance(item, dict) else None,
                }
            )
        checksums.append(checksum)
    material = {
        "game_id": str(game_id),
        "algorithm_version": ACTION_ALGORITHM_VERSION,
        "model_schema": MODEL_SCHEMA_VERSION,
        "sample_checksums": sorted(checksums),
    }
    digest = hashlib.sha256(canonical_bytes(material)).hexdigest()
    return int(digest[:16], 16) & 0x7FFFFFFFFFFFFFFF, {
        "material_hash": digest,
        "sample_count": len(checksums),
        "algorithm_version": ACTION_ALGORITHM_VERSION,
        "model_schema": MODEL_SCHEMA_VERSION,
    }


def model_quality_snapshot(rows):
    parsed = []
    for row in rows or []:
        validation = row.get("validation", {}) if isinstance(row, dict) else {}
        if isinstance(validation, str):
            try:
                validation = json.loads(validation)
            except RECOVERABLE_ERRORS:
                validation = {}
        parsed.append(
            {
                "overall_accuracy": safe_float(validation.get("overall_accuracy"), 0.0, 0.0, 1.0),
                "coverage": safe_float(validation.get("coverage"), 0.0, 0.0, 1.0),
                "dangerous_false": safe_int(validation.get("dangerous_false"), 0, 0),
                "prototype_count": safe_int(row.get("prototype_count"), 0, 0),
                "checksum": str(row.get("checksum", "")),
            }
        )
    return {
        "holdout_accuracy": max([item["overall_accuracy"] for item in parsed] or [0.0]),
        "rejection_coverage": max([item["coverage"] for item in parsed] or [0.0]),
        "dangerous_false_triggers": sum(item["dangerous_false"] for item in parsed),
        "prototype_count": sum(item["prototype_count"] for item in parsed),
        "model_count": len(parsed),
        "content_hash": hashlib.sha256(
            canonical_bytes([[item["checksum"], item["prototype_count"]] for item in parsed])
        ).hexdigest(),
    }


def immutable_digest(value):
    def normalize(item):
        if isinstance(item, (bytes, bytearray, memoryview)):
            raw = bytes(item)
            return {"bytes": len(raw), "sha256": hashlib.sha256(raw).hexdigest()}
        if isinstance(item, dict):
            return {str(key): normalize(item[key]) for key in sorted(item, key=lambda key: str(key))}
        if isinstance(item, (list, tuple)):
            return [normalize(entry) for entry in item]
        if isinstance(item, (set, frozenset)):
            return sorted(
                (normalize(entry) for entry in item),
                key=lambda entry: json.dumps(entry, ensure_ascii=False, sort_keys=True, separators=(",", ":")),
            )
        if isinstance(item, Path):
            return str(item)
        if isinstance(item, (str, int, float, bool)) or item is None:
            return item
        return str(item)

    return hashlib.sha256(canonical_bytes(normalize(value))).hexdigest()


def add_checksum(data):
    result = dict(data)
    result.pop("checksum", None)
    result["checksum"] = hashlib.sha256(canonical_bytes(result)).hexdigest()
    return result


def verify_checksum(data):
    if not isinstance(data, dict) or not isinstance(data.get("checksum"), str):
        return False
    expected = data.get("checksum")
    item = dict(data)
    item.pop("checksum", None)
    return hashlib.sha256(canonical_bytes(item)).hexdigest() == expected


class LightweightLogger:
    def __init__(self, path):
        self.path = Path(path)
        self.lock = threading.RLock()

    def write(self, code, error=None, thread_name=None, mode=None, game_id=None, window_identity=None, details=None):
        exception_type = type(error).__name__ if isinstance(error, BaseException) else ""
        message = str(error) if error is not None else ""
        stack = ""
        if isinstance(error, BaseException):
            stack = "".join(traceback.format_exception(type(error), error, error.__traceback__))[-6000:]
        record = {
            "time": time.time(),
            "code": str(code),
            "thread": str(thread_name or threading.current_thread().name),
            "mode": str(mode or ""),
            "game_id": str(game_id or ""),
            "window_identity": window_identity if isinstance(window_identity, dict) else {},
            "exception_type": exception_type,
            "message": message[:2000],
            "stack": stack,
            "details": details if isinstance(details, dict) else {},
        }
        try:
            self.path.parent.mkdir(parents=True, exist_ok=True)
            line = json.dumps(record, ensure_ascii=False, separators=(",", ":")) + "\n"
            with self.lock, self.path.open("a", encoding="utf-8") as handle:
                handle.write(line)
            return True
        except RECOVERABLE_ERRORS:
            return False


def binomial_error_upper(errors, total, confidence=0.95):
    n = max(0, int(total))
    k = max(0, min(n, int(errors)))
    if n < 1:
        return 1.0
    if k == 0:
        return 1.0 - (1.0 - float(confidence)) ** (1.0 / n)
    z = 1.6448536269514722 if confidence <= 0.95 else 1.959963984540054
    phat = k / n
    denominator = 1.0 + z * z / n
    center = (phat + z * z / (2.0 * n)) / denominator
    radius = z * math.sqrt(phat * (1.0 - phat) / n + z * z / (4.0 * n * n)) / denominator
    return min(1.0, center + radius)


def checksum_set(samples):
    return {str(item.get("checksum", "")) for item in samples if str(item.get("checksum", ""))}


def assert_disjoint_checksums(train, holdout):
    overlap = checksum_set(train) & checksum_set(holdout)
    if overlap:
        raise RuntimeError("训练集与留出集checksum发生重叠：" + str(len(overlap)))
    return True


def quantile(values, q):
    if not values:
        return 0.0
    ordered = sorted(float(x) for x in values)
    if len(ordered) == 1:
        return ordered[0]
    pos = (len(ordered) - 1) * q
    low = int(math.floor(pos))
    high = int(math.ceil(pos))
    if low == high:
        return ordered[low]
    part = pos - low
    return ordered[low] * (1.0 - part) + ordered[high] * part


def path_length(path):
    total = 0.0
    for a, b in zip(path, path[1:]):
        total += math.hypot(float(b[0]) - float(a[0]), float(b[1]) - float(a[1]))
    return total


def direction_changes(path):
    if len(path) < 3:
        return 0
    changes = 0
    previous = None
    for a, b in zip(path, path[1:]):
        dx = float(b[0]) - float(a[0])
        dy = float(b[1]) - float(a[1])
        if abs(dx) + abs(dy) < 0.002:
            continue
        angle = math.atan2(dy, dx)
        if previous is not None:
            delta = abs((angle - previous + math.pi) % (2 * math.pi) - math.pi)
            if delta > math.radians(35):
                changes += 1
        previous = angle
    return changes


def resample_path(path, count=16):
    clean = []
    for point in path or []:
        if isinstance(point, (list, tuple)) and len(point) >= 2 and finite_number(point[0]) and finite_number(point[1]):
            clean.append([max(0.0, min(1.0, float(point[0]))), max(0.0, min(1.0, float(point[1])))])
    if not clean:
        return []
    if len(clean) == 1:
        return [[round(clean[0][0], 5), round(clean[0][1], 5)] for _ in range(count)]
    distances = [0.0]
    for a, b in zip(clean, clean[1:]):
        distances.append(distances[-1] + math.hypot(b[0] - a[0], b[1] - a[1]))
    total = distances[-1]
    if total < 1e-9:
        return [[round(clean[0][0], 5), round(clean[0][1], 5)] for _ in range(count)]
    result = []
    segment = 0
    for index in range(count):
        target = total * index / (count - 1)
        while segment + 1 < len(distances) and distances[segment + 1] < target:
            segment += 1
        if segment + 1 >= len(clean):
            point = clean[-1]
        else:
            span = max(1e-9, distances[segment + 1] - distances[segment])
            ratio = (target - distances[segment]) / span
            point = [
                clean[segment][0] + (clean[segment + 1][0] - clean[segment][0]) * ratio,
                clean[segment][1] + (clean[segment + 1][1] - clean[segment][1]) * ratio,
            ]
        result.append([round(point[0], 5), round(point[1], 5)])
    return result


def normalized_identifier(value, default="default", maximum=96):
    text = str(value or "").strip()[: int(maximum)]
    allowed = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-"
    clean = "".join(character if character in allowed else "_" for character in text).strip("._-")
    return clean or str(default)


def _bounded_json_mapping(value, maximum=16384):
    if not isinstance(value, dict):
        return {}
    try:
        raw = json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        if len(raw.encode("utf-8")) > int(maximum):
            return {}
        loaded = json.loads(raw)
        return loaded if isinstance(loaded, dict) else {}
    except (TypeError, ValueError, OverflowError, json.JSONDecodeError):
        return {}


@dataclass(frozen=True)
class SemanticAction:
    action_type: str
    target_class: str = ""
    target_instance: str = ""
    target_index: int = -1
    target_text: str = ""
    offset: tuple = (0.0, 0.0)
    parameters: dict = field(default_factory=dict)
    coordinate_fallback: dict = field(default_factory=dict)
    attributes: dict = field(default_factory=dict)
    source_target: dict = field(default_factory=dict)
    destination_target: dict = field(default_factory=dict)
    source_offset: tuple = (0.0, 0.0)
    target_offset: tuple = (0.0, 0.0)
    risk_class: str = "safe"

    def to_dict(self):
        base = {"class": self.target_class or "none"}
        if self.target_instance:
            base["instance"] = self.target_instance
        if self.target_index >= 0:
            base["index"] = self.target_index
        if self.target_text:
            base["text"] = self.target_text
        if self.attributes:
            base["attributes"] = dict(self.attributes)
        result = {
            "schema_version": SEMANTIC_ACTION_SCHEMA_VERSION,
            "action_type": self.action_type,
            "parameters": dict(self.parameters),
            "risk_class": self.risk_class if self.risk_class in SEMANTIC_RISK_CLASSES else "safe",
        }
        if self.action_type == "drag":
            result["source"] = dict(self.source_target or base)
            result["target"] = dict(self.destination_target or base)
            result["source_offset"] = [round(float(self.source_offset[0]), 6), round(float(self.source_offset[1]), 6)]
            result["target_offset"] = [round(float(self.target_offset[0]), 6), round(float(self.target_offset[1]), 6)]
        else:
            result["target"] = base
            result["offset"] = [round(float(self.offset[0]), 6), round(float(self.offset[1]), 6)]
        if self.coordinate_fallback:
            result["coordinate_fallback"] = dict(self.coordinate_fallback)
        return result

    @classmethod
    def from_mapping(cls, value):
        normalized = normalize_semantic_action(value)
        if normalized is None:
            raise ValueError("语义动作无效")
        target = normalized.get("target", {})
        source = normalized.get("source", {})
        base = source if normalized["action_type"] == "drag" else target
        return cls(
            normalized["action_type"],
            str(base.get("class", "")),
            str(base.get("instance", "")),
            safe_int(base.get("index", -1), -1, -1, 1000000),
            str(base.get("text", "")),
            tuple(normalized.get("offset", [0.0, 0.0])),
            dict(normalized.get("parameters", {})),
            dict(normalized.get("coordinate_fallback", {})),
            dict(base.get("attributes", {})),
            dict(source),
            dict(target),
            tuple(normalized.get("source_offset", [0.0, 0.0])),
            tuple(normalized.get("target_offset", [0.0, 0.0])),
            str(normalized.get("risk_class", "safe")),
        )


@dataclass(frozen=True)
class GroundedAction:
    semantic_action: dict
    grounded_action: dict
    grounding: dict = field(default_factory=dict)

    def to_dict(self):
        return {
            "schema_version": SEMANTIC_ACTION_SCHEMA_VERSION,
            "semantic_action": dict(self.semantic_action),
            "grounded_action": dict(self.grounded_action),
            "grounding": dict(self.grounding),
        }


@dataclass(frozen=True)
class TaskDefinition:
    game_id: str
    task_id: str
    name: str
    goal: str
    allowed_families: tuple = ()
    reward_config: dict = field(default_factory=dict)
    success_detector: dict = field(default_factory=dict)
    failure_detector: dict = field(default_factory=dict)
    progress_detector: dict = field(default_factory=dict)
    reset_detector: dict = field(default_factory=dict)
    goal_predicates: tuple = ()
    enabled: bool = True
    schema_version: int = TASK_SCHEMA_VERSION

    @classmethod
    def from_mapping(cls, value, game_id="", task_id="default"):
        item = dict(value) if isinstance(value, dict) else {}
        gid = str(item.get("game_id") or game_id)
        tid = normalized_identifier(item.get("task_id") or task_id, "default", 96)
        reward_source = item.get("reward_config") if isinstance(item.get("reward_config"), dict) else item
        reward = {
            "step_penalty": safe_float(reward_source.get("step_penalty", -0.01), -0.01, -1.0, 0.0),
            "success_reward": safe_float(reward_source.get("success_reward", 1.0), 1.0, -10.0, 10.0),
            "failure_reward": safe_float(reward_source.get("failure_reward", -1.0), -1.0, -10.0, 10.0),
            "progress_scale": safe_float(reward_source.get("progress_scale", 0.5), 0.5, 0.0, 10.0),
            "subgoal_reward": safe_float(reward_source.get("subgoal_reward", 0.25), 0.25, 0.0, 5.0),
            "numeric_change_scale": safe_float(reward_source.get("numeric_change_scale", 0.15), 0.15, 0.0, 5.0),
            "exploration_reward": safe_float(reward_source.get("exploration_reward", 0.03), 0.03, 0.0, 1.0),
            "no_change_penalty": safe_float(reward_source.get("no_change_penalty", 0.0), 0.0, -1.0, 0.0),
            "invalid_action_penalty": safe_float(reward_source.get("invalid_action_penalty", -0.08), -0.08, -2.0, 0.0),
            "repeat_penalty": safe_float(reward_source.get("repeat_penalty", 0.0), 0.0, -1.0, 0.0),
            "risk_action_penalty": safe_float(reward_source.get("risk_action_penalty", -0.15), -0.15, -5.0, 0.0),
            "human_override_penalty": safe_float(reward_source.get("human_override_penalty", -0.05), -0.05, -2.0, 0.0),
            "minimum_reward_confidence": safe_float(
                reward_source.get("minimum_reward_confidence", 0.55), 0.55, 0.0, 1.0
            ),
        }
        families = tuple(sorted({str(entry) for entry in item.get("allowed_families", []) if str(entry)}))
        success_detector = _bounded_json_mapping(item.get("success_detector"))
        failure_detector = _bounded_json_mapping(item.get("failure_detector"))
        progress_detector = _bounded_json_mapping(item.get("progress_detector"))
        reset_detector = _bounded_json_mapping(item.get("reset_detector"))
        if not success_detector and item.get("success_states"):
            success_detector = {
                "type": "visual_hash",
                "states": sorted({str(entry) for entry in item.get("success_states", []) if str(entry)}),
                "hash_distance": safe_int(item.get("success_hash_distance", 6), 6, 0, 32),
            }
        if not failure_detector and item.get("failure_states"):
            failure_detector = {
                "type": "visual_hash",
                "states": sorted({str(entry) for entry in item.get("failure_states", []) if str(entry)}),
                "hash_distance": safe_int(item.get("failure_hash_distance", 6), 6, 0, 32),
            }
        raw_predicates = item.get("goal_predicates", [])
        if isinstance(raw_predicates, (str, dict)):
            raw_predicates = [raw_predicates]
        predicates = tuple(
            _bounded_json_mapping(entry) if isinstance(entry, dict) else str(entry)[:500]
            for entry in raw_predicates
            if isinstance(entry, (dict, str))
        )
        return cls(
            gid,
            tid,
            str(item.get("name") or tid)[:200],
            str(item.get("goal") or "完成任务并在不确定时停止")[:2000],
            families,
            reward,
            success_detector,
            failure_detector,
            progress_detector,
            reset_detector,
            predicates,
            bool(item.get("enabled", True)),
            TASK_SCHEMA_VERSION,
        )

    def to_dict(self):
        return {
            "schema_version": self.schema_version,
            "game_id": self.game_id,
            "task_id": self.task_id,
            "name": self.name,
            "goal": self.goal,
            "allowed_families": list(self.allowed_families),
            "reward_config": dict(self.reward_config),
            "success_detector": dict(self.success_detector),
            "failure_detector": dict(self.failure_detector),
            "progress_detector": dict(self.progress_detector),
            "reset_detector": dict(self.reset_detector),
            "goal_predicates": [
                dict(entry) if isinstance(entry, dict) else str(entry) for entry in self.goal_predicates
            ],
            "enabled": self.enabled,
        }


class RewardProvider:
    def evaluate(self, transition, task):
        raise NotImplementedError


class SuccessDetector:
    def detect(self, transition, task):
        raise NotImplementedError


class FailureDetector:
    def detect(self, transition, task):
        raise NotImplementedError


class ProgressDetector:
    def score(self, transition, task):
        raise NotImplementedError


class ResetDetector:
    def detect(self, transition, task):
        raise NotImplementedError


class StandardSuccessDetector(SuccessDetector):
    def detect(self, transition, task):
        return bool(transition.get("success") or str(transition.get("terminal", "")) == "success")


class StandardFailureDetector(FailureDetector):
    def detect(self, transition, task):
        return bool(transition.get("failure") or str(transition.get("terminal", "")) == "failure")


class StandardProgressDetector(ProgressDetector):
    def score(self, transition, task):
        return max(-1.0, min(1.0, safe_float(transition.get("progress_score", transition.get("progress", 0.0)), 0.0)))


class StandardResetDetector(ResetDetector):
    def detect(self, transition, task):
        return bool(transition.get("reset"))


class CompositeRewardProvider(RewardProvider):
    def _evaluate_components(self, transition, task):
        config = dict(task.reward_config)
        progress = StandardProgressDetector().score(transition, task)
        success = StandardSuccessDetector().detect(transition, task)
        failure = StandardFailureDetector().detect(transition, task)
        terminal_confidence = safe_float(
            transition.get("terminal_confidence", 1.0 if success or failure else 0.0), 0.0, 0.0, 1.0
        )
        progress_confidence = safe_float(
            transition.get("progress_confidence", transition.get("ocr_confidence", 0.0)), 0.0, 0.0, 1.0
        )
        state_confidence = safe_float(
            transition.get("state_confidence", 0.5 if transition.get("changed") is not None else 0.0), 0.0, 0.0, 1.0
        )
        subgoal_completed = bool(transition.get("subgoal_completed", False))
        numeric_progress = max(-1.0, min(1.0, safe_float(transition.get("numeric_progress", 0.0), 0.0)))
        components = {
            "step": safe_float(config.get("step_penalty", -0.01), -0.01),
            "terminal": 0.0,
            "subgoal": 0.0,
            "progress": 0.0,
            "numeric": 0.0,
            "exploration": 0.0,
            "no_change": 0.0,
            "invalid": 0.0,
            "repeat": 0.0,
            "risk": 0.0,
            "human_override": 0.0,
        }
        if success:
            components["terminal"] += safe_float(config.get("success_reward", 1.0), 1.0)
        if failure:
            components["terminal"] += safe_float(config.get("failure_reward", -1.0), -1.0)
        if subgoal_completed:
            components["subgoal"] += safe_float(config.get("subgoal_reward", 0.25), 0.25)
        components["progress"] += progress * safe_float(config.get("progress_scale", 0.5), 0.5)
        components["numeric"] += numeric_progress * safe_float(config.get("numeric_change_scale", 0.15), 0.15)
        if transition.get("new_state"):
            components["exploration"] += safe_float(config.get("exploration_reward", 0.03), 0.03)
        if transition.get("changed") is False and transition.get("should_wait") is not True:
            components["no_change"] += safe_float(config.get("no_change_penalty", 0.0), 0.0)
        if transition.get("invalid_action"):
            components["invalid"] += safe_float(config.get("invalid_action_penalty", -0.08), -0.08)
        if transition.get("repeated") or transition.get("loop_detected"):
            components["repeat"] += safe_float(config.get("repeat_penalty", 0.0), 0.0)
        if str(transition.get("risk_class", "safe")) in {"caution", "irreversible"}:
            multiplier = 2.0 if str(transition.get("risk_class")) == "irreversible" else 1.0
            components["risk"] += safe_float(config.get("risk_action_penalty", -0.15), -0.15) * multiplier
        if transition.get("human_override"):
            components["human_override"] += safe_float(config.get("human_override_penalty", -0.05), -0.05)
        confidence = max(
            terminal_confidence,
            (
                0.65 * progress_confidence + 0.35 * state_confidence
                if abs(progress) > 0 or abs(numeric_progress) > 0
                else state_confidence
            ),
        )
        if success or failure:
            confidence = max(confidence, terminal_confidence)
        minimum = safe_float(config.get("minimum_reward_confidence", 0.55), 0.55, 0.0, 1.0)
        update_eligible = bool(success or failure or confidence >= minimum)
        reward = sum(components.values())
        return {
            "reward": round(reward, 6),
            "components": {key: round(value, 6) for key, value in components.items()},
            "success": success,
            "failure": failure,
            "progress": round(progress, 6),
            "reset": StandardResetDetector().detect(transition, task),
            "confidence": round(confidence, 6),
            "update_eligible": update_eligible,
            "minimum_confidence": round(minimum, 6),
        }

    def evaluate(self, transition, task):
        result = self._evaluate_components(transition, task)
        confidence = safe_float(result.get("confidence", 0.0), 0.0, 0.0, 1.0)
        if result.get("success") or result.get("failure"):
            minimum = max(0.70, safe_float(result.get("minimum_confidence", 0.55), 0.55, 0.0, 1.0))
            result["update_eligible"] = bool(confidence >= minimum)
            result["terminal_update_gate"] = minimum
            result["trajectory_only"] = not result["update_eligible"]
        result["evidence"] = list(transition.get("terminal_evidence", [])) if isinstance(transition, dict) else []
        return result


class TaskRuntime:
    def __init__(self, definition, reward_provider=None):
        self.definition = (
            definition if isinstance(definition, TaskDefinition) else TaskDefinition.from_mapping(definition)
        )
        self.reward_provider = reward_provider or CompositeRewardProvider()

    def evaluate(self, transition):
        return self.reward_provider.evaluate(dict(transition) if isinstance(transition, dict) else {}, self.definition)


@dataclass(frozen=True)
class ObjectSlot:
    object_class: str
    instance: str = ""
    text: str = ""
    bbox: tuple = (0.0, 0.0, 0.0, 0.0)
    confidence: float = 0.0
    state: str = "unknown"
    interactable: bool = True
    value: object = None
    attributes: dict = field(default_factory=dict)
    schema_version: int = OBJECT_SLOT_SCHEMA_VERSION
    appearance_embedding: tuple = ()
    velocity: tuple = (0.0, 0.0)
    uncertainty: float = 1.0
    modality_mask: dict = field(default_factory=dict)
    affordances: dict = field(default_factory=dict)
    open_vocabulary_description: str = ""

    @classmethod
    def from_mapping(cls, value, index=0):
        item = dict(value) if isinstance(value, dict) else {}
        bbox = item.get("bbox", [0.0, 0.0, 0.0, 0.0])
        if not isinstance(bbox, (list, tuple)) or len(bbox) < 4:
            bbox = [0.0, 0.0, 0.0, 0.0]
        normalized = tuple(round(safe_float(bbox[position], 0.0, 0.0, 1.0), 6) for position in range(4))
        object_class = str(item.get("class") or item.get("object_class") or item.get("category") or "unknown")[:200]
        attributes = _bounded_json_mapping(item.get("attributes"))
        embedding = item.get("appearance_embedding", attributes.get("appearance_embedding", []))
        if not isinstance(embedding, (list, tuple)):
            embedding = []
        appearance = tuple(round(safe_float(entry, 0.0, -8.0, 8.0), 6) for entry in list(embedding)[:32])
        velocity = item.get("velocity", attributes.get("velocity", [0.0, 0.0]))
        if not isinstance(velocity, (list, tuple)) or len(velocity) < 2:
            velocity = [0.0, 0.0]
        motion = (round(safe_float(velocity[0], 0.0, -1.0, 1.0), 6), round(safe_float(velocity[1], 0.0, -1.0, 1.0), 6))
        confidence = safe_float(item.get("confidence", 0.0), 0.0, 0.0, 1.0)
        uncertainty = safe_float(
            item.get("uncertainty", attributes.get("uncertainty", 1.0 - confidence)), 1.0 - confidence, 0.0, 1.0
        )
        mask = item.get("modality_mask", attributes.get("modality_mask", {}))
        mask = {str(key): bool(entry) for key, entry in mask.items()} if isinstance(mask, dict) else {}
        affordances = infer_object_affordances(item)
        description = str(item.get("open_vocabulary_description") or object_open_vocabulary_description(item))[:500]
        return cls(
            object_class=object_class,
            instance=str(item.get("instance", item.get("id", index)))[:200],
            text=str(item.get("text", item.get("label", "")))[:500],
            bbox=normalized,
            confidence=confidence,
            state=str(item.get("state", "unknown"))[:100],
            interactable=bool(item.get("interactable", True)),
            value=item.get("value"),
            attributes=attributes,
            schema_version=OBJECT_SLOT_SCHEMA_VERSION,
            appearance_embedding=appearance,
            velocity=motion,
            uncertainty=uncertainty,
            modality_mask=mask,
            affordances=affordances,
            open_vocabulary_description=description,
        )

    def compact(self):
        quantized_bbox = [round(round(value / 0.025) * 0.025, 3) for value in self.bbox]
        allowed = {
            "patch_hash",
            "role",
            "selected",
            "disabled",
            "checked",
            "group",
            "kind",
            "track_id",
            "generic_class",
            "evidence_sources",
        }
        attributes = {key: self.attributes[key] for key in sorted(self.attributes) if key in allowed}
        if "patch_hash" in attributes:
            attributes["patch_hash"] = str(attributes["patch_hash"])[:16]
        return {
            "class": self.object_class,
            "instance": self.instance,
            "text": self.text.strip().casefold(),
            "bbox": quantized_bbox,
            "state": self.state,
            "interactable": self.interactable,
            "value": self.value,
            "appearance": [round(value, 3) for value in self.appearance_embedding[:12]],
            "velocity": [round(value, 4) for value in self.velocity],
            "uncertainty": round(self.uncertainty, 4),
            "affordances": dict(self.affordances),
            "description": self.open_vocabulary_description,
            "attributes": attributes,
        }

    def to_dict(self):
        return {
            "schema_version": self.schema_version,
            "class": self.object_class,
            "instance": self.instance,
            "text": self.text,
            "bbox": list(self.bbox),
            "confidence": round(self.confidence, 6),
            "state": self.state,
            "interactable": self.interactable,
            "value": self.value,
            "attributes": dict(self.attributes),
            "appearance_embedding": list(self.appearance_embedding),
            "velocity": list(self.velocity),
            "uncertainty": round(self.uncertainty, 6),
            "modality_mask": dict(self.modality_mask),
            "affordances": dict(self.affordances),
            "open_vocabulary_description": self.open_vocabulary_description,
        }


@dataclass(frozen=True)
class ObservationState:
    state_id: str
    environment_id: str
    visual_digest: str
