@runtime_checkable
class SafetyShieldProtocol(Protocol):
    def authorize(self, proposed_action, context): ...
class ObservationEncoder:
    def encode(self, frame, history=None, task=None):
        raise NotImplementedError


class ObjectDetector:
    def detect(self, observation):
        raise NotImplementedError


class SemanticObjectDetector(ObjectDetector):
    def detect(self, observation):
        item = dict(observation) if isinstance(observation, dict) else {}
        targets = item.get("semantic_targets")
        if not isinstance(targets, (list, tuple)):
            context = item.get("context", {}) if isinstance(item.get("context"), dict) else {}
            targets = context.get("semantic_targets", [])
        result = []
        for index, value in enumerate(targets or []):
            try:
                result.append(ObjectSlot.from_mapping(value, index))
            except (TypeError, ValueError, OverflowError):
                continue
        return tuple(
            sorted(result, key=lambda slot: (slot.object_class, slot.instance, slot.text.casefold(), slot.bbox))
        )


class MultiScaleObservationEncoder(ObservationEncoder):
    def __init__(self, object_detector=None):
        self.object_detector = object_detector or SemanticObjectDetector()

    @staticmethod
    def _pooled_signature(feature, width, height):
        try:
            source = feature_bytes(feature)
        except RECOVERABLE_ERRORS:
            return []
        if len(source) != FEATURE_LEN:
            return []
        values = []
        for channel in range(FEATURE_CHANNELS):
            plane = source[channel * PIXELS : (channel + 1) * PIXELS]
            for oy in range(height):
                top = oy * FEATURE_H // height
                bottom = max(top + 1, (oy + 1) * FEATURE_H // height)
                for ox in range(width):
                    left = ox * FEATURE_W // width
                    right = max(left + 1, (ox + 1) * FEATURE_W // width)
                    total = 0
                    count = 0
                    for py in range(top, min(FEATURE_H, bottom)):
                        start = py * FEATURE_W + left
                        end = py * FEATURE_W + min(FEATURE_W, right)
                        block = plane[start:end]
                        total += sum(block)
                        count += len(block)
                    values.append(min(31, max(0, round((total / max(1, count)) / 255.0 * 31.0))))
        return values

    @staticmethod
    def _normalized_ocr(frame, history):
        values = []
        sources = []
        if isinstance(frame, dict):
            sources.extend(frame.get("ocr_values", []) if isinstance(frame.get("ocr_values"), list) else [])
            sources.extend(frame.get("ocr_events", []) if isinstance(frame.get("ocr_events"), list) else [])
        if isinstance(history, dict):
            sources.extend(history.get("ocr_values", []) if isinstance(history.get("ocr_values"), list) else [])
            sources.extend(history.get("ocr_events", []) if isinstance(history.get("ocr_events"), list) else [])
        for item in sources[-32:]:
            if not isinstance(item, dict):
                continue
            values.append(
                {
                    "region_id": str(item.get("region_id", ""))[:100],
                    "text": str(item.get("text", item.get("raw_text", "")))[:128],
                    "value": item.get("value", item.get("numeric_value")),
                    "status": str(item.get("status", ""))[:64],
                    "terminal": str(item.get("terminal", ""))[:32],
                    "progress": round(safe_float(item.get("progress", 0.0), 0.0, -1.0, 1.0), 4),
                    "confidence": round(
                        safe_float(item.get("confidence", item.get("source_confidence", 0.0)), 0.0, 0.0, 1.0), 4
                    ),
                }
            )
        return tuple(values)

    @staticmethod
    def _task_payload(task, history):
        source = dict(task) if isinstance(task, dict) else {}
        if isinstance(task, TaskDefinition):
            source = task.to_dict()
        history_item = dict(history) if isinstance(history, dict) else {}
        return {
            "task_id": normalized_identifier(source.get("task_id") or history_item.get("task_id"), "default", 96),
            "goal": str(source.get("goal") or history_item.get("task_goal") or "")[:1000],
            "subgoal": str(history_item.get("subgoal_id", source.get("subgoal_id", "")))[:200],
        }

    def encode(self, frame, history=None, task=None):
        item = dict(frame) if isinstance(frame, dict) else {"f": frame}
        context = (
            dict(history)
            if isinstance(history, dict)
            else (dict(item.get("context")) if isinstance(item.get("context"), dict) else {})
        )
        feature = item.get("f", item.get("feature"))
        visual_payload = {
            "4x3": self._pooled_signature(feature, 4, 3),
            "8x5": self._pooled_signature(feature, 8, 5),
            "16x9": self._pooled_signature(feature, 16, 9),
        }
        coarse = item.get("coarse")
        if isinstance(coarse, (bytes, bytearray)):
            visual_payload["coarse_digest"] = hashlib.blake2b(bytes(coarse), digest_size=12).hexdigest()
        neural = item.get("neural_f", item.get("neural_feature"))
        if isinstance(neural, (bytes, bytearray)):
            visual_payload["neural_digest"] = hashlib.blake2b(bytes(neural), digest_size=12).hexdigest()
        visual_digest = hashlib.sha256(canonical_bytes(visual_payload)).hexdigest()
        objects = self.object_detector.detect({**item, "context": context})
        ocr_values = self._normalized_ocr(item, context)
        try:
            temporal = temporal_from_context(context)
        except RECOVERABLE_ERRORS:
            temporal = {
                "recent_frame_deltas": list(context.get("recent_frame_deltas", []))[-32:],
                "recent_actions": list(context.get("recent_actions", []))[-32:],
                "recent_action_results": list(context.get("recent_action_results", []))[-32:],
                "task_phase": str(context.get("task_phase", "unknown")),
                "object_signature": str(context.get("object_signature", "")),
            }
        recent_actions = tuple(str(value)[:200] for value in temporal.get("recent_actions", [])[-32:])
        recent_results = temporal.get("recent_action_results", [])[-32:]
        recent_rewards = tuple(
            round(safe_float(value.get("reward", 0.0), 0.0, -10.0, 10.0), 5)
            for value in recent_results
            if isinstance(value, dict)
        )
        task_payload = self._task_payload(task, context)
        internal_state = {
            "task_phase": str(temporal.get("task_phase", context.get("task_phase", "unknown")))[:100],
            "failure_count": safe_int(context.get("failure_count", 0), 0, 0, 100000),
            "terminal": str(context.get("terminal", ""))[:32],
            "object_count": len(objects),
            "should_wait": bool(context.get("should_wait", False)),
        }
        dynamic_payload = {
            "frame_deltas": [
                round(safe_float(value, 0.0) / 20.0) * 20 for value in temporal.get("recent_frame_deltas", [])[-8:]
            ],
            "task_phase": internal_state["task_phase"],
            "object_signature": str(temporal.get("object_signature", context.get("object_signature", "")))[:128],
        }
        environment_payload = {
            "visual": visual_digest,
            "objects": [slot.compact() for slot in objects],
            "ocr": list(ocr_values),
            "dynamic": dynamic_payload,
        }
        environment_id = hashlib.sha256(canonical_bytes(environment_payload)).hexdigest()[:32]
        state_payload = {
            "environment_id": environment_id,
            "recent_actions": list(recent_actions[-8:]),
            "recent_rewards": list(recent_rewards[-8:]),
            "task": task_payload,
            "internal_state": internal_state,
        }
        state_id = hashlib.sha256(canonical_bytes(state_payload)).hexdigest()[:32]
        confidences = [slot.confidence for slot in objects]
        confidences.extend(safe_float(value.get("confidence", 0.0), 0.0, 0.0, 1.0) for value in ocr_values)
        confidence = max(
            0.25,
            min(
                1.0,
                0.45 + (sum(confidences) / max(1, len(confidences))) * 0.35 + (0.20 if visual_payload["8x5"] else 0.0),
            ),
        )
        try:
            index_hash = visual_perceptual_hash(feature)
        except RECOVERABLE_ERRORS:
            index_hash = ""
        return ObservationState(
            state_id,
            environment_id,
            visual_digest,
            index_hash,
            objects,
            ocr_values,
            temporal,
            recent_actions,
            recent_rewards,
            task_payload,
            internal_state,
            confidence,
            OBSERVATION_SCHEMA_VERSION,
        )


@dataclass(frozen=True)
class Subgoal:
    subgoal_id: str
    description: str
    success_condition: dict = field(default_factory=dict)
