def state_coverage_bucket(frame, context=None):
    value = frame if isinstance(frame, dict) else {}
    meta = context if isinstance(context, dict) else {}
    targets = value.get("semantic_targets", []) if isinstance(value.get("semantic_targets"), list) else []
    classes = {str(item.get("class", "")).casefold() for item in targets if isinstance(item, dict)}
    text = " ".join(str(item.get("text", "")) for item in targets if isinstance(item, dict)).casefold()
    result = set()
    if safe_int(meta.get("step_id", 0), 0) <= 1 or meta.get("episode_start"):
        result.add("normal_start")
    dpi = safe_float(value.get("dpi_scale", meta.get("dpi_scale", 1.0)), 1.0)
    rect = value.get("client_rect", [])
    if abs(dpi - 1.0) > 0.02 or value.get("resolution_changed"):
        result.add("resolution_or_dpi_variant")
    if isinstance(rect, (list, tuple)) and len(rect) >= 4 and (safe_int(rect[2], 0) != 0 or safe_int(rect[3], 0) != 0):
        result.add("window_size_variant")
    if value.get("ui_skin") or meta.get("ui_skin"):
        result.add("ui_skin_variant")
    if value.get("level_id") or meta.get("level_id"):
        result.add("level_variant")
    numeric = value.get("numeric_state", {}) if isinstance(value.get("numeric_state"), dict) else {}
    resource_low = any(
        safe_float(item, 1.0) < 0.25
        for item in numeric.values()
        if isinstance(item, (int, float))
    )
    if meta.get("low_resource") or resource_low:
        result.add("low_health_or_resource")
    if "dialog" in classes or "popup" in classes or "modal" in classes:
        result.add("popup")
    network_tokens = ("断开", "网络错误", "offline", "disconnected")
    if value.get("network_disconnected") or any(token in text for token in network_tokens):
        result.add("network_disconnected")
    if value.get("loading") or "loading" in classes or any(token in text for token in ("加载", "loading")):
        result.add("loading")
    if value.get("stuck") or safe_int(meta.get("same_action_no_effect_count", 0), 0) >= 2:
        result.add("stuck")
    if meta.get("failure_recovery_stack") or meta.get("terminal_state") == "failure":
        result.add("failure_recovery")
    if meta.get("human_correction") or meta.get("wrong_action"):
        result.add("wrong_action_recovery")
    if any(str(item.get("risk_class", "safe")) == "irreversible" for item in targets if isinstance(item, dict)):
        result.add("dangerous_control_nearby")
    return sorted(result or {"normal_start"})



def high_value_learning_reasons(frame, ranked, decision, temporal=None):
    value = decision if isinstance(decision, dict) else {}
    items = [item for item in ranked or [] if isinstance(item, dict)]
    reasons = set(str(item) for item in value.get("guidance_trigger", []) if str(item))
    if len(items) >= 2:
        first = items[0]
        second = items[1]
        gap = abs(safe_float(first.get("score"), 0.0) - safe_float(second.get("score"), 0.0))
        scale = max(1.0, abs(safe_float(first.get("score"), 0.0)))
        if gap / scale <= 0.08:
            reasons.add("near_tie")
        policy_first = max(items[:4], key=lambda item: safe_float(item.get("bc_probability"), 0.0))
        value_first = max(items[:4], key=lambda item: safe_float(item.get("success_probability"), 0.0))
        if str(policy_first.get("cluster_id")) != str(value_first.get("cluster_id")):
            reasons.add("policy_value_disagreement")
    irreversible = any(
        str(
            (normalize_semantic_action(item.get("semantic_action")) or {}).get(
                "risk_class", item.get("risk_class", "safe")
            )
        )
        == "irreversible"
        for item in items[:4]
    )
    if irreversible:
        reasons.add("irreversible_risk")
    if isinstance(frame, dict) and frame.get("new_semantic_objects"):
        reasons.add("new_object_type")
    triggers = set(str(item) for item in value.get("guidance_trigger", []))
    numeric_triggers = {
        "unknown_numeric_region",
        "low_ocr_confidence",
        "ocr_temporal_disagreement",
        "numeric_relation_unknown",
        "numeric_direction_conflict",
        "numeric_value_correlated_with_policy_uncertainty",
    }
    if triggers.intersection(numeric_triggers):
        reasons.add("decision_relevant_ocr")
    memory = temporal if isinstance(temporal, dict) else {}
    if memory.get("world_model_conflict") or value.get("world_model_conflict"):
        reasons.add("world_model_actual_conflict")
    if safe_int(memory.get("same_action_no_effect_count", 0), 0) >= 2 or value.get("repeated_no_effect"):
        reasons.add("repeated_no_effect")
    confidence = safe_float(value.get("confidence"), 0.0, 0.0, 1.0)
    if confidence >= 0.92 and not reasons and str(value.get("risk_class", "safe")) == "safe":
        return []
    return sorted(reasons)



class CorrectiveLearningWorkflow:
    def __init__(self, base, game_id):
        self.base = Path(base)
        self.game_id = str(game_id)
        token = hashlib.sha256(self.game_id.encode("utf-8", "replace")).hexdigest()[:16]
        self.directory = self.base / "audit" / "corrective_learning"
        self.pending_path = self.directory / ("pending_" + token + ".json")
        self.history_path = self.directory / ("history_" + token + ".jsonl")

    @staticmethod
    def _frame_state(frame):
        value = frame if isinstance(frame, dict) else {}
        feature = feature_bytes(value.get("f")) if feature_valid(value.get("f")) else b""
        neural = feature_bytes(value.get("neural_f")) if feature_valid(value.get("neural_f")) else b""
        return {
            "created": time.time(),
            "frame_time": safe_float(value.get("time"), 0.0),
            "feature_sha256": hashlib.sha256(feature).hexdigest() if feature else "",
            "neural_sha256": hashlib.sha256(neural).hexdigest() if neural else "",
            "object_signature": str(value.get("object_signature", "")),
            "capture_method": str(value.get("method", "")),
            "coverage_buckets": state_coverage_bucket(value, {}),
        }

    def record_override(self, frame, wrong_action, candidates, decision, reason):
        semantic = normalize_semantic_action(wrong_action) or semantic_action_from_coordinate(wrong_action)
        entries = []
        for item in list(candidates or [])[:8]:
            if not isinstance(item, dict):
                continue
            candidate = normalize_semantic_action(
                item.get("semantic_action") or item.get("action") or item.get("a")
            ) or semantic_action_from_coordinate(item.get("a"))
            entries.append(
                {
                    "cluster_id": str(item.get("cluster_id", "")),
                    "semantic_action": candidate,
                    "policy": safe_float(item.get("bc_probability", item.get("policy_probability", 0.0)), 0.0),
                    "value": safe_float(item.get("success_probability", item.get("value_probability", 0.0)), 0.0),
                    "risk": safe_float(item.get("risk_probability", 0.0), 0.0),
                    "world": safe_float(item.get("world_score", item.get("predicted_reward", 0.0)), 0.0),
                }
            )
        payload = {
            "schema_version": 2,
            "game_id": self.game_id,
            "created": time.time(),
            "state": self._frame_state(frame),
            "wrong_action": semantic,
            "wrong_action_signature": semantic_action_signature(semantic),
            "candidate_list": entries,
            "disagreement": {
                "policy_value": safe_float((decision or {}).get("policy_value_disagreement"), 0.0),
                "ensemble": safe_float((decision or {}).get("ensemble_disagreement"), 0.0),
                "world_model": safe_float((decision or {}).get("world_model_disagreement"), 0.0),
            },
            "takeover_reason": str(reason),
            "status": "awaiting_corrective_action",
        }
        self.directory.mkdir(parents=True, exist_ok=True)
        _atomic_json_write(self.pending_path, payload)
        return payload

    def load(self):
        try:
            value = json.loads(self.pending_path.read_text(encoding="utf-8"))
            return value if isinstance(value, dict) and value.get("status") == "awaiting_corrective_action" else None
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            return None

    def complete(self, pending, correct_action, outcome):
        value = dict(pending) if isinstance(pending, dict) else {}
        semantic = normalize_semantic_action(correct_action) or semantic_action_from_coordinate(correct_action)
        value.update(
            {
                "completed": time.time(),
                "correct_action": semantic,
                "correct_action_signature": semantic_action_signature(semantic),
                "actual_change": dict(outcome) if isinstance(outcome, dict) else {},
                "status": "completed",
                "supervision": {"wrong_action": "strong_negative", "correct_action": "strong_positive"},
            }
        )
        self.directory.mkdir(parents=True, exist_ok=True)
        with self.history_path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(value, ensure_ascii=False, separators=(",", ":")) + "\n")
        try:
            self.pending_path.unlink()
        except FileNotFoundError:
            pass
        return value


class PersistentTaskGraph:
    def __init__(self, base, game_id):
        self.base = Path(base)
        self.game_id = str(game_id)
        token = hashlib.sha256(self.game_id.encode("utf-8", "replace")).hexdigest()[:16]
        self.path = self.base / "models" / "task_graph" / (token + ".json")
        self.value = self._load()

    def _load(self):
        try:
            value = json.loads(self.path.read_text(encoding="utf-8"))
            if isinstance(value, dict):
                return value
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            pass
        return {
            "schema_version": 1,
            "game_id": self.game_id,
            "long_term_goal": "",
            "visited_pages": [],
            "completed_subgoals": [],
            "resources": {},
            "failed_paths": [],
            "dependencies": {},
            "recovery_paths": {},
            "current_progress": {},
        }

    def observe(self, observation, subgoal=None, outcome=None):
        if hasattr(observation, "to_dict"):
            state = observation.to_dict()
        elif isinstance(observation, dict):
            state = observation
        else:
            state = {}
        page = str(state.get("environment_id") or state.get("scene_id") or state.get("state_id") or "")
        if page:
            self.value["visited_pages"] = list(dict.fromkeys(self.value.get("visited_pages", []) + [page]))[-512:]
        goal = getattr(subgoal, "subgoal_id", "") if subgoal is not None else ""
        if goal:
            completion = getattr(subgoal, "completion_condition", {})
            skills = list(getattr(subgoal, "preferred_skills", ()))
            dependency = {
                "prerequisites": [],
                "completion_evidence": completion,
                "skills": skills,
            }
            self.value.setdefault("dependencies", {}).setdefault(goal, dependency)
            self.value["current_progress"] = {"subgoal": goal, "updated": time.time()}
        result = outcome if isinstance(outcome, dict) else {}
        if result.get("success") and goal:
            completed = self.value.get("completed_subgoals", []) + [goal]
            self.value["completed_subgoals"] = list(dict.fromkeys(completed))[-512:]
        if result.get("failure") and goal:
            failed = {
                "subgoal": goal,
                "state": page,
                "reason": str(result.get("reason", "failure")),
                "created": time.time(),
            }
            self.value["failed_paths"] = (self.value.get("failed_paths", []) + [failed])[-512:]
            recovery = ["wait_for_state", "navigate_back", "restart_round"]
            self.value.setdefault("recovery_paths", {}).setdefault(goal, recovery)
        self.path.parent.mkdir(parents=True, exist_ok=True)
        _atomic_json_write(self.path, self.value)
        return dict(self.value)

class LearningController:
    def __init__(self, context, host=None):
        if isinstance(context, ModeContext):
            self.context = context
            self.host = host
        else:
            self.context = ModeContext.from_host(context)
            self.host = context
        self.converter = LearningInputEventConverter()
        self.click_merger = ClickMerger()
        self.negative_sampler = NegativeSampleSampler()

    def convert_event(self, event, rect):
        return self.converter.convert(event, rect)

    def merge_clicks(self, first, button, point, start_time, end_time):
        second = {"time": float(start_time), "button": str(button), "point": list(point)}
        merged = self.click_merger.merge(first, second, 0.42)
        if merged is not None:
            merged["duration"] = max(0.06, float(end_time) - float(first.get("time", start_time)))
        return merged

    def negative_due(self, last_time, now, motion_time):
        return self.negative_sampler.due(last_time, now, motion_time)

    def submit(self, store, gid, session_id):
        return SessionSubmitter(store, gid, session_id).flush()

    def run(self):
        return LearningRunner(ModeContext.from_host(self.host), self, self.host).run()

    def _run_impl(self, phase=None):
        return LearningExecution(self, phase).run()


class LearningExecution:
    def __init__(self, controller, phase=None):
        self.controller = controller
        self.host = controller.host
        self.phase = phase if isinstance(phase, dict) else {}
        self.game = None
        self.target = None
        self.calibration = None
        self.session_id = ""
        self.keyboard_state = {"generation": 0, "last_time": 0.0}
        self.strict_violation = False
        self.invalid_marked = False
        self.invalid_reason = ""
        self.learned = 0
        self.discarded = 0
        self.duplicates = 0
        self.invalid_frames = 0
        self.keyboard_discarded = 0
        self.keyboard_count = 0
        self.mouse_event_count = 0
        self.recent_actions = deque(["<START>", "<START>"], maxlen=32)
        self.recent_action_results = deque(maxlen=32)
        self.last_action_signature = ""
        self.last_action_time = 0.0
        self.last_action_feature = None
        self.last_action_changed = True
        self.state_since = time.monotonic()
        self.step_id = 0
        self.task_id = "default"
        self.capability = CapabilityProfile({})
        self.capture_options = CaptureOptions()
        self.keyboard_enabled = False
        self.semantic_keymap = {}
        self.semantic_keyboard_events = deque(maxlen=64)
        self.gamepad_events = deque(maxlen=64)
        self.audio_events = deque(maxlen=64)
        self.gamepad_count = 0
        self.audio_count = 0
        self.modality_sample_count = 0
        self.last_modality_sample = 0.0
        self.gamepad_monitor = None
        self.audio_monitor = None
        self.corrective_workflow = None
        self.pending_correction = None

    def preflight(self):
        self.game = self.phase.get("game") or self.host.require_game()
        self.corrective_workflow = CorrectiveLearningWorkflow(self.host.store.base, self.game["id"])
        self.pending_correction = self.corrective_workflow.load()
        profile = self.host.store.load_game_profile(self.game["id"])
        self.task_id = normalized_identifier(profile.get("default_task_id"), "default", 96)
        selected_options = getattr(self.host, "capture_options", None)
        self.capture_options = (
            selected_options if isinstance(selected_options, CaptureOptions) else CaptureOptions.from_profile(profile)
        )
        profile = self.capture_options.apply_profile(profile)
        if self.capture_options.keyboard and not profile.get("semantic_keymap"):
            profile["semantic_keymap"] = {
                "move_left": "65",
                "move_right": "68",
                "move_up": "87",
                "move_down": "83",
                "jump": "32",
                "interact": "69",
                "open_menu": "9",
                "pause": "80",
            }
        self.capability = CapabilityProfile(profile)
        self.keyboard_enabled = bool(self.capture_options.keyboard and self.capability.authorize("keyboard"))
        self.semantic_keymap = dict(self.capability.semantic_keymap)
        self.session_id = "learn|" + uuid.uuid4().hex
        self.host.mode_session_id = self.session_id
        self.target = dict(self.phase.get("window") or self.host.require_window(False))
        self.target.update(
            {
                "game_id": str(self.game["id"]),
                "session_id": self.session_id,
                "window_generation": safe_int(getattr(self.host, "window_generation", 0), 0, 0),
            }
        )
        self.target["window_key"] = runtime_isolation_key(
            self.game["id"], self.session_id, self.target, self.target["window_generation"]
        )
        clear_runtime_isolation(key=self.target["window_key"])
        self.calibration = self.phase.get("calibration") or self.host.ensure_capture_calibration(
            self.target, MODE_LABELS[ModeId.COLLECT]
        )
        runtime = {
            "capture_fps": self.calibration.get("fps", 0.0),
            "available_action_frequency": 1.0 / max(0.01, safe_float(self.calibration.get("input_delay", 0.25), 0.25)),
            "semantic_size": HYBRID_GLOBAL_SIZE,
            **self.host.api.execution_capabilities(),
        }
        self.capability_result = self.capability.require_training_support(runtime)
        self.host.store.begin_learning_session(self.game["id"], self.session_id)
        if not self.host.api.request_foreground(self.target["hwnd"]):
            self.host.set_status("无法自动切换到目标窗口，学习将等待目标窗口成为前台")
        self.host.wait_escape_release()
        self.isolation = StrictInputIsolation(self.host.stop_event)
        return self

    def start_monitors(self, session):
        self.frame_buffer = session.start_frames(20.0, 2.0, 0.1, "learning")
        self.keyboard = session.start_keyboard()
        self.monitor = session.start_mouse() if self.capture_options.mouse else None
        self.mouse_drop_baseline = self.monitor.snapshot()["dropped_events"] if self.monitor is not None else 0
        self.gamepad_monitor = session.start_gamepad() if self.capture_options.gamepad else None
        self.audio_monitor = session.start_audio() if self.capture_options.audio else None
        self.host.lifecycle.mark_running()
        self.active = {}
        self.pending_click = {}
        self.last_negative = 0.0
        self.last_motion_time = 0.0
        self.motion = None
        self.last_cursor = None
        self.hover_start = 0.0
        self.hover_point = None
        self.last_update = 0.0
        self.sampling_delay = 0.012

    def drain_keyboard_events(self):
        events = [event for event in self.keyboard.drain() if event.get("kind") == "other"]
        if not events:
            return events
        self.keyboard_count += len(events)
        if self.keyboard_enabled:
            inverse = {str(value).casefold(): key for key, value in self.semantic_keymap.items()}
            for event in events:
                vk = safe_int(event.get("vk"), -1, 0, 0xFFFF)
                semantic = inverse.get(str(vk).casefold(), "")
                stamp = safe_float(event.get("time"), time.monotonic())
                if not semantic:
                    self.keyboard_discarded += 1
                    continue
                self.semantic_keyboard_events.append(
                    {
                        "semantic_action": semantic,
                        "vk": vk,
                        "down": bool(event.get("down")),
                        "time": stamp,
                        "model_version": "semantic_keyboard_v2",
                        "execution_support": "SendInput_scancode_with_lease",
                    }
                )
                if event.get("down"):
                    if vk not in self.pending_keys:
                        frame = self.capture_safe(stamp)
                        if frame is not None:
                            self.pending_keys[vk] = {"frame": frame, "start": stamp, "semantic": semantic}
                else:
                    pending = self.pending_keys.pop(vk, None)
                    if pending is not None:
                        duration = max(0.03, min(3.0, stamp - safe_float(pending.get("start"), stamp)))
                        self.save(
                            pending.get("frame"),
                            {
                                "kind": "key",
                                "vk": vk,
                                "semantic_key": pending.get("semantic", semantic),
                                "duration": duration,
                            },
                            "learn_keyboard",
                            1.2,
                        )
            return []
        down_events = [event for event in events if event.get("down")]
        if not down_events:
            return events
        self.strict_violation = True
        self.invalid_reason = "non_escape_keyboard_input"
        self.keyboard_state["generation"] += 1
        self.keyboard_state["last_time"] = safe_float(down_events[0].get("time"), time.monotonic())
        if not self.invalid_marked:
            self.host.store.invalidate_learning_session(self.game["id"], self.session_id, self.invalid_reason)
            self.invalid_marked = True
        self.isolation.signal("keyboard", self.keyboard_state["last_time"])
        self.host.request_mode_stop("stopped", "学习检测到未授权的非ESC键盘输入，整段session无效")
        self.host.api.block_input()
        self.host.api.release_all_buttons()
        return events

    def drain_auxiliary_events(self):
        changed = False
        if self.gamepad_monitor is not None:
            events = self.gamepad_monitor.drain()
            self.gamepad_count += len(events)
            self.gamepad_events.extend(events)
            changed = changed or bool(events)
            for event in events:
                device = safe_int(event.get("device"), 0, 0, 3)
                state = event.get("state", {}) if isinstance(event.get("state"), dict) else {}
                previous = self.last_gamepad_state.get(device, {})
                now = safe_float(event.get("time"), time.monotonic())
                current_buttons = set(str(value) for value in state.get("buttons", []))
                old_buttons = set(str(value) for value in previous.get("buttons", []))
                for button in current_buttons - old_buttons:
                    frame = self.capture_safe(now)
                    if frame is not None:
                        self.pending_gamepad_buttons[(device, button)] = {"frame": frame, "start": now}
                for button in old_buttons - current_buttons:
                    pending = self.pending_gamepad_buttons.pop((device, button), None)
                    if pending is not None:
                        duration = max(0.03, min(3.0, now - safe_float(pending.get("start"), now)))
                        self.save(
                            pending.get("frame"),
                            {"kind": "gamepad_button", "button": button, "duration": duration},
                            "learn_gamepad",
                            1.25,
                        )
                for axis_name, state_key in (
                    ("left_stick", "left_stick"),
                    ("right_stick", "right_stick"),
                    ("triggers", None),
                ):
                    if state_key:
                        values = state.get(state_key, [0.0, 0.0])
                    else:
                        values = [state.get("left_trigger", 0.0), state.get("right_trigger", 0.0)]
                    if not isinstance(values, (list, tuple)) or len(values) < 2:
                        continue
                    x = safe_float(values[0], 0.0, -1.0, 1.0)
                    y = safe_float(values[1], 0.0, -1.0, 1.0)
                    old_values = (
                        previous.get(state_key, [0.0, 0.0])
                        if state_key
                        else [previous.get("left_trigger", 0.0), previous.get("right_trigger", 0.0)]
                    )
                    old_x = (
                        safe_float(old_values[0], 0.0, -1.0, 1.0)
                        if isinstance(old_values, (list, tuple)) and old_values
                        else 0.0
                    )
                    old_y = (
                        safe_float(old_values[1], 0.0, -1.0, 1.0)
                        if isinstance(old_values, (list, tuple)) and len(old_values) > 1
                        else 0.0
                    )
                    last = self.last_gamepad_axis_sample.get((device, axis_name), 0.0)
                    active = abs(x) + abs(y) >= 0.22
                    changed_axis = abs(x - old_x) + abs(y - old_y) >= 0.16
                    if active and changed_axis and now - last >= 0.08:
                        frame = self.capture_safe(now)
                        if frame is not None:
                            self.save(
                                frame,
                                {"kind": "gamepad_axis", "axis": axis_name, "x": x, "y": y, "duration": 0.08},
                                "learn_gamepad_axis",
                                1.15,
                            )
                            self.last_gamepad_axis_sample[(device, axis_name)] = now
                self.last_gamepad_state[device] = dict(state)
            if self.gamepad_monitor.error is not None:
                raise CaptureError("手柄采集失败：" + str(self.gamepad_monitor.error))
        if self.audio_monitor is not None:
            events = self.audio_monitor.drain()
            self.audio_count += len(events)
            self.audio_events.extend(events)
            changed = changed or bool(events)
            if self.audio_monitor.error is not None:
                raise CaptureError("声音采集失败：" + str(self.audio_monitor.error))
        return changed

    def paused(self):
        self.drain_keyboard_events()
        return self.strict_violation or (not self.keyboard_enabled and self.keyboard.other_event.is_set())

    def capture_safe(self, stamp=None):
        frame = self.frame_buffer.latest(stamp, 0.75, "learning")
        if frame is None:
            self.invalid_frames += 1
        return frame

    def build_sample_context(self, frame, action, cursor_point):
        temporal = self.host.build_temporal_context(
            self.frame_buffer,
            frame,
            self.recent_actions,
            self.state_since,
            cursor_point or ((action.get("path") or [None])[-1] if isinstance(action, dict) else None),
        )
        temporal["recent_action_results"] = list(self.recent_action_results)
        temporal["object_signature"] = str(frame.get("object_signature", ""))
        temporal["task_phase"] = str(frame.get("task_phase", "unknown"))
        complete = temporal_from_context({**temporal, "previous_action_changed_frame": self.last_action_changed}).get(
            "complete"
        )
        if not complete:
            self.invalid_frames += 1
            return None
        context = self.host.sample_context(
            self.last_action_signature,
            self.last_action_time,
            self.last_action_changed,
            frame.get("motion_valid", False),
            self.session_id,
            frame.get("method", "unknown"),
            "one_shot",
            temporal,
        )
        keyboard_events = list(self.semantic_keyboard_events)
        gamepad_events = list(self.gamepad_events)
        audio_events = list(self.audio_events)
        self.semantic_keyboard_events.clear()
        self.gamepad_events.clear()
        self.audio_events.clear()
        mask = context.get("modality_mask", {}) if isinstance(context.get("modality_mask"), dict) else {}
        mask.update(
            {
                "mouse": bool(self.capture_options.mouse),
                "keyboard": bool(keyboard_events),
                "audio": bool(audio_events),
                "gamepad": bool(gamepad_events),
            }
        )
        modality_features = derived_modality_features(
            audio_events, keyboard_events, gamepad_events, frame.get("time", time.monotonic()), self.last_action_time
        )
        context.update(
            {
                "episode_id": self.session_id,
                "task_id": self.task_id,
                "step_id": self.step_id,
                "action_delay": (
                    round(max(0.0, time.monotonic() - self.last_action_time), 4) if self.last_action_time else None
                ),
                "human_override": False,
                "trajectory_schema_version": TRAJECTORY_SCHEMA_VERSION,
                "modality_mask": mask,
                "capture_options": self.capture_options.to_dict(),
                "semantic_keyboard_events": keyboard_events,
                "gamepad_events": gamepad_events,
                "audio_events": audio_events,
                "modality_features": modality_features,
                "modality_feature_vector": list(modality_features.get("vector", [])),
                "modality_execution_support": {
                    "mouse": "execute",
                    "keyboard": "SendInput_scancode_with_lease",
                    "gamepad": "ViGEm_XInput_when_available",
                    "audio": "perception_only",
                },
                "modality_versions": self.capability.to_dict().get("modality_permissions", {}),
            }
        )
        context["state_coverage_buckets"] = state_coverage_bucket(frame, context)
        return context

    def save(self, frame, action, source, weight=1.0, cursor_point=None):
        if frame is None or not frame.get("usable_for_learning"):
            return False
        coordinate = normalize_action(action)
        if not coordinate:
            return False
        semantic = (
            semantic_action_from_coordinate(coordinate)
            if coordinate.get("kind") in CONTROL_ACTION_KINDS
            else semantic_action_from_interaction(coordinate, frame.get("semantic_targets", []))
        )
        if semantic is None:
            return False
        if frame.get("quality", {}).get("low_information") and coordinate.get("kind") not in {
            "no_op",
            "click",
            "double_click",
        }:
            return False
        if self.paused():
            self.keyboard_discarded += 1
            return False
        generation = int(self.keyboard_state["generation"])
        context = self.build_sample_context(frame, coordinate, cursor_point)
        if context is None:
            return False
        context.update(semantic_context_payload(frame, semantic))
        context["semantic_action"] = semantic
        context["semantic_primary"] = str(semantic.get("target", semantic.get("source", {})).get("class", ""))
        context["risk_class"] = str(semantic.get("risk_class", "safe"))
        context["sample_role"] = (
            "human_correction"
            if str(source).casefold().startswith(("teach", "correct", "override"))
            else "demonstration"
        )
        context["counterfactual_training"] = build_counterfactual_training_payload(
            frame, semantic, source, self.recent_action_results
        )
        pending = self.pending_correction
        if isinstance(pending, dict):
            context.update(
                {
                    "human_override": True,
                    "human_correction": True,
                    "corrective_action": semantic,
                    "wrong_action": pending.get("wrong_action"),
                    "wrong_action_signature": str(pending.get("wrong_action_signature", "")),
                    "ai_candidate_list": list(pending.get("candidate_list", [])),
                    "model_disagreement": dict(pending.get("disagreement", {})),
                    "user_takeover_reason": str(pending.get("takeover_reason", "immediate_takeover")),
                    "sample_role": "human_correction",
                    "strong_positive_weight": 3.5,
                    "state_coverage_buckets": sorted(
                        set(context.get("state_coverage_buckets", []))
                        | {"wrong_action_recovery"}
                    ),
                }
            )
            rejected = list(pending.get("candidate_list", []))
            wrong = pending.get("wrong_action")
            if wrong:
                rejected.insert(0, {"semantic_action": wrong, "cluster_id": "wrong_action"})
            self.host.store.append_rejection(
                self.game["id"],
                frame["f"],
                rejected,
                "corrective_strong_negative",
                frame.get("rgb"),
                frame.get("neural_f"),
                context,
            )
            source = "corrective_strong_positive"
            weight = max(3.5, safe_float(weight, 1.0))
        saved = self.host.store.append_sample(
            self.game["id"], frame["f"], semantic, source, context, frame.get("rgb"), frame.get("neural_f"), weight
        )
        if saved and (generation != int(self.keyboard_state["generation"]) or self.paused()):
            self.keyboard_discarded += 1
            return False
        self.record_save_outcome(saved, frame, semantic)
        if saved and isinstance(pending, dict):
            outcome = {
                "changed": bool(self.last_action_changed),
                "frame_time": safe_float(frame.get("time"), 0.0),
                "feature_sha256": hashlib.sha256(feature_bytes(frame.get("f"))).hexdigest(),
            }
            self.corrective_workflow.complete(pending, semantic, outcome)
            self.pending_correction = None
            self.host.set_status("已保存AI错误动作强负例、用户纠正动作强正例和真实画面变化")
        return saved

    def record_save_outcome(self, saved, frame, action):
        if not saved:
            self.duplicates += 1
            return
        self.learned += 1
        self.step_id += 1
        changed = self.last_action_feature is None or visual_distance(self.last_action_feature, frame["f"]) > float(
            self.calibration.get("significant_change", 60.0)
        )
        signature = semantic_action_signature(action)
        self.recent_actions.append(signature)
        self.recent_action_results.append(
            {
                "state": "changed" if changed else "neutral",
                "changed": bool(changed),
                "reason": "" if changed else "unverified",
                "reward": 0.0,
            }
        )
        self.last_action_signature = signature
        self.last_action_time = time.monotonic()
        self.last_action_changed = changed
        if changed:
            self.state_since = time.monotonic()
        self.last_action_feature = frame["f"]

    def save_click(self, button, item):
        action = {"kind": "click", "button": button, "path": [item["point"]], "duration": item["duration"]}
        return self.save(item["frame"], action, "learn", 1.0, item["point"])

    def flush_pending(self, now, force=False):
        for button, item in list(self.pending_click.items()):
            if force or now - item["time"] > 0.42:
                if not self.host.should_stop() and not self.paused():
                    self.save_click(button, item)
                self.pending_click.pop(button, None)

    def clear_pointer_state(self, release=False):
        self.active.clear()
        self.pending_click.clear()
        self.motion = None
        self.last_cursor = None
        self.hover_point = None
        self.hover_start = 0.0
        if release:
            self.host.api.release_all_buttons()

    def reject_mouse_overflow(self, now):
        if self.monitor is None or self.monitor.snapshot()["dropped_events"] <= self.mouse_drop_baseline:
            return False
        self.strict_violation = True
        self.invalid_reason = "mouse_event_queue_overflow"
        if not self.invalid_marked:
            self.host.store.invalidate_learning_session(self.game["id"], self.session_id, self.invalid_reason)
            self.invalid_marked = True
        self.isolation.signal("mouse_queue_overflow", now)
        self.host.request_mode_stop("stopped", "鼠标事件队列溢出，整段session无效")
        self.host.api.block_input()
        self.clear_pointer_state(True)
        self.host.set_status("鼠标事件队列溢出，学习立即停止且整段session将被标记无效")
        return True

    def acquire_focus(self):
        try:
            return self.host.api.validate_target(self.target, True)
        except TargetUnavailable:
            self.clear_pointer_state(True)
            self.host.set_status("目标窗口失去焦点，等待恢复；已释放全部鼠标键")
            return None

    def handle_down(self, event, rect):
        button = event["type"].split("_")[0]
        if button in SUPPORTED_BUTTONS and event["inside"]:
            frame = self.capture_safe(event["time"])
            if frame is not None:
                point = self.host.normalize_point(event["x"], event["y"], rect)
                self.active[button] = {
                    "frame": frame,
                    "path": [point],
                    "start": event["time"],
                    "outside": False,
                    "last": point,
                }
        self.motion = None
        self.last_cursor = None
        self.hover_point = None
        self.hover_start = 0.0

    def handle_active_move(self, event, rect):
        for item in self.active.values():
            if not event["inside"]:
                item["outside"] = True
                continue
            point = self.host.normalize_point(event["x"], event["y"], rect)
            if abs(point[0] - item["last"][0]) + abs(point[1] - item["last"][1]) >= 0.004:
                item["path"].append(point)
                item["last"] = point
        if not event["inside"]:
            self.last_cursor = None
            self.hover_point = None
            self.hover_start = 0.0

    def handle_idle_move(self, event, rect):
        if not event["inside"]:
            self.last_cursor = None
            self.hover_point = None
            self.hover_start = 0.0
            if self.motion is not None:
                self.motion["outside"] = True
            return
        point = self.host.normalize_point(event["x"], event["y"], rect)
        if self.last_cursor is None:
            self.last_cursor = point
            self.hover_point = point
            self.hover_start = event["time"]
            return
        distance = math.hypot(point[0] - self.last_cursor[0], point[1] - self.last_cursor[1])
        if self.motion is None and distance >= 0.012:
            frame = self.capture_safe(event["time"])
            if frame is not None:
                self.motion = {
                    "frame": frame,
                    "path": [self.last_cursor, point],
                    "start": event["time"],
                    "last": point,
                    "outside": False,
                }
        elif (
            self.motion is not None
            and math.hypot(point[0] - self.motion["last"][0], point[1] - self.motion["last"][1]) >= 0.006
        ):
            self.motion["path"].append(point)
            self.motion["last"] = point
        self.last_cursor = point
        self.hover_point = point
        self.hover_start = event["time"]

    def handle_move(self, event, rect):
        self.last_motion_time = event["time"]
        if self.active:
            self.handle_active_move(event, rect)
        else:
            self.handle_idle_move(event, rect)

    def handle_click_release(self, button, item, point, event_time):
        previous = self.pending_click.get(button)
        if previous:
            close = math.hypot(point[0] - previous["point"][0], point[1] - previous["point"][1]) <= 0.035
            merged = (
                self.host.learning_controller.merge_clicks(previous, button, point, item["start"], event_time)
                if close
                else None
            )
            if merged is not None:
                self.pending_click.pop(button, None)
                self.save(previous["frame"], merged, "learn", 1.3, previous["point"])
                return
            self.save_click(button, previous)
        duration = max(0.03, min(3.0, event_time - item["start"]))
        self.pending_click[button] = {"frame": item["frame"], "point": point, "duration": duration, "time": event_time}

    def handle_up(self, event, rect):
        button = event["type"].split("_")[0]
        if button not in self.active:
            return
        item = self.active.pop(button)
        item["outside"] = item["outside"] or not event["inside"]
        if item["outside"]:
            self.discarded += 1
            return
        point = self.host.normalize_point(event["x"], event["y"], rect)
        item["path"].append(point)
        duration = max(0.03, min(3.0, event["time"] - item["start"]))
        length = path_length(item["path"])
        if length > 0.045:
            self.save(
                item["frame"],
                {"kind": "drag", "button": button, "path": item["path"], "duration": duration},
                "learn",
                1.4,
                point,
            )
        elif duration >= 0.48:
            self.save(
                item["frame"],
                {"kind": "long_press", "button": button, "path": [point], "duration": duration},
                "learn",
                1.2,
                point,
            )
        else:
            self.handle_click_release(button, item, point, event["time"])

    def handle_wheel(self, event, rect):
        if not event["inside"] or self.active:
            return
        frame = self.capture_safe(event["time"])
        point = self.host.normalize_point(event["x"], event["y"], rect)
        if frame is not None:
            kind = "scroll_h" if event["type"] == "hwheel" else "scroll_v"
            self.save(
                frame,
                {"kind": kind, "delta": event.get("delta", 0), "path": [point], "duration": 0.08},
                "learn",
                1.2,
                point,
            )

    def handle_event(self, raw_event, rect):
        event = self.host.learning_controller.convert_event(raw_event, rect)
        if event is None or self.paused() or self.host.should_stop():
            return
        event_type = event["type"]
        if event_type.endswith("_down"):
            self.handle_down(event, rect)
        elif event_type == "move":
            self.handle_move(event, rect)
        elif event_type.endswith("_up"):
            self.handle_up(event, rect)
        elif event_type in {"wheel", "hwheel"}:
            self.handle_wheel(event, rect)

    def poll_cursor(self, rect):
        try:
            x, y = self.host.api.cursor()
            inside = self.host.inside(x, y, rect)
        except RECOVERABLE_ERRORS:
            return 0, 0, False
        if not inside:
            self.last_cursor = None
            self.hover_point = None
            self.hover_start = 0.0
            if self.motion is not None:
                self.motion["outside"] = True
            for item in self.active.values():
                item["outside"] = True
        return x, y, inside

    def finalize_motion(self, now):
        if self.motion is None or now - self.last_motion_time <= 0.22:
            return
        if not self.motion["outside"] and path_length(self.motion["path"]) > 0.06:
            duration = max(0.05, min(2.0, now - self.motion["start"]))
            self.save(
                self.motion["frame"],
                {"kind": "move", "path": self.motion["path"], "duration": duration},
                "learn",
                1.0,
                self.motion["path"][-1],
            )
        elif self.motion["outside"]:
            self.discarded += 1
        self.motion = None
        self.last_cursor = None

    def sample_hover(self, now, rect):
        if (
            self.active
            or self.hover_point is None
            or now - self.hover_start <= 0.85
            or now - self.last_action_time <= 0.7
        ):
            return
        try:
            x, y = self.host.api.cursor()
            if not self.host.inside(x, y, rect):
                return
        except RECOVERABLE_ERRORS:
            return
        point = self.host.normalize_point(x, y, rect)
        if math.hypot(point[0] - self.hover_point[0], point[1] - self.hover_point[1]) <= 0.02:
            frame = self.capture_safe(now)
            if frame is not None:
                self.save(frame, {"kind": "hover", "path": [point], "duration": 0.85}, "learn", 1.0, point)
            self.hover_start = now + 1.5
        else:
            self.hover_point = point
            self.hover_start = now

    def sample_negative(self, now, rect, cursor):
        if self.active or self.pending_click:
            return
        if not self.host.learning_controller.negative_due(self.last_negative, now, self.last_motion_time):
            return
        frame = self.capture_safe(now)
        x, y, inside = cursor
        point = self.host.normalize_point(x, y, rect) if inside else None
        if frame is not None:
            self.save(frame, {"kind": "no_op", "duration": 0.45}, "negative", 0.6, point)
        self.last_negative = now

    def update_status(self, now):
        if now - self.last_update <= 0.45:
            return
        pressure = self.host.store.sample_queue_pressure(self.game["id"])
        self.sampling_delay = 0.012 + 0.04 * pressure
        self.host.set_status(
            "人类采集中：有效"
            + str(self.learned)
            + "  鼠标"
            + str(self.mouse_event_count)
            + "  键盘"
            + str(self.keyboard_count)
            + "  手柄"
            + str(self.gamepad_count)
            + "  声音事件"
            + str(self.audio_count)
            + "  越界废弃"
            + str(self.discarded)
            + "  无效画面"
            + str(self.invalid_frames)
            + "  写入压力"
            + str(round(pressure * 100))
            + "%"
        )
        self.last_update = now

    def capture_loop(self):
        with ModeSession(self.host, self.target) as session:
            self.start_monitors(session)
            while not self.host.should_stop():
                now = time.monotonic()
                if self.reject_mouse_overflow(now):
                    break
                keyboard_before = self.keyboard_count
                keyboard_violation = self.drain_keyboard_events()
                auxiliary_changed = self.drain_auxiliary_events() or self.keyboard_count > keyboard_before
                if keyboard_violation or self.paused():
                    self.clear_pointer_state(True)
                    if self.monitor is not None:
                        self.monitor.drain()
                    self.host.set_status("检测到未授权的非ESC键盘输入，人类采集立即停止且整段session将被标记无效")
                    break
                rect = self.acquire_focus()
                events = self.monitor.drain() if self.monitor is not None else []
                self.mouse_event_count += len(events)
                if rect is None:
                    if interruptible_wait(self.host.stop_event, 0.05):
                        break
                    continue
                for raw_event in events:
                    self.handle_event(raw_event, rect)
                    if self.host.should_stop() or self.strict_violation:
                        break
                self.flush_pending(now)
                cursor = self.poll_cursor(rect)
                self.finalize_motion(now)
                if self.capture_options.mouse:
                    self.sample_hover(now, rect)
                    self.sample_negative(now, rect, cursor)
                if auxiliary_changed and now - self.last_modality_sample >= 0.12:
                    frame = self.capture_safe(now)
                    if frame is not None and self.save(
                        frame, {"kind": "no_op", "duration": 0.08}, "modality", 0.8, None
                    ):
                        self.modality_sample_count += 1
                        self.last_modality_sample = now
                self.update_status(now)
                interruptible_wait(self.host.stop_event, self.sampling_delay)

    def finalize(self):
        self.host.learning_controller.submit(self.host.store, self.game["id"], self.session_id)
        if self.strict_violation:
            reason = self.invalid_reason or "input_safety_violation"
            removed = self.host.store.discard_session(self.game["id"], self.session_id, reason)
            self.keyboard_discarded = max(self.keyboard_discarded, removed)
            if reason == "mouse_event_queue_overflow":
                dropped = (
                    self.monitor.snapshot()["dropped_events"] - self.mouse_drop_baseline
                    if self.monitor is not None
                    else 0
                )
                return ModeResult(
                    "stopped",
                    "学习因鼠标事件队列溢出而严格停止；整段session已作废并删除" + str(removed) + "个样本",
                    {"invalid_session": self.session_id, "dropped_mouse_events": dropped},
                )
            return ModeResult(
                "stopped",
                "学习因检测到非ESC键盘输入而严格停止；整段session已作废并删除" + str(removed) + "个样本",
                {"invalid_session": self.session_id, "keyboard_events": self.keyboard_count},
            )
        self.host.store.validate_learning_session(self.game["id"], self.session_id)
        summary = (
            "学习已停止：有效"
            + str(self.learned)
            + "，重复或配额抑制"
            + str(self.duplicates)
            + "，越界废弃"
            + str(self.discarded)
            + "，无效画面"
            + str(self.invalid_frames)
        )
        status = "stopped" if self.host.stop_event and self.host.stop_event.is_set() else "completed"
        details = {
            "session_id": self.session_id,
            "real_mouse_events": self.mouse_event_count,
            "outside_rejected": self.discarded,
            "keyboard_events": self.keyboard_count,
            "gamepad_events": self.gamepad_count,
            "audio_events": self.audio_count,
            "modality_samples": self.modality_sample_count,
            "capture_options": self.capture_options.to_dict(),
            "modality_mask_closed_loop": True,
            "valid_samples": self.learned,
            "duplicates": self.duplicates,
            "invalid_frames": self.invalid_frames,
            "client_only": True,
            "session_status": "valid",
        }
        return ModeResult(status, summary, details)

    def run(self):
        self.preflight()
        self.capture_loop()
        return self.finalize()


@dataclass(frozen=True, slots=True)
class ExperienceBuildConfig:
    gamma: float
    n_step: int
    game_id: str
    default_task_id: str


@dataclass(frozen=True, slots=True)
class OcrTransitionSummary:
    events: tuple
    terminal: str
    progress: float
    confidence: float
    numeric_progress: float
    reset: bool


@dataclass(slots=True)
class EpisodeBuildState:
    seen_environments: set = field(default_factory=set)
    previous_skill_key: str = ""


@dataclass(frozen=True, slots=True)
class PreparedExperienceStep:
    item: dict
    next_item: dict
    index: int
    session: str
    start: float
    next_created: float
    context: dict
    task_id: str
    runtime: object
    observation: object
    next_observation: object
    semantic_action: object
    grounded_action: object
    skill: object
    action_id: str
    visual_change: float
    environment_changed: bool
    repeated: bool
    new_state: bool
    human_override: bool
    risk_class: str
    ocr: OcrTransitionSummary


class ExperienceBuilder:
    def __init__(self, controller, samples, ocr_events, profile):
        self.controller = controller
        self.samples = list(samples or [])
        self.profile = dict(profile) if isinstance(profile, dict) else {}
        self.events = tuple(
            sorted(
                (item for item in ocr_events or [] if isinstance(item, dict)),
                key=lambda item: safe_float(item.get("created"), 0.0),
            )
        )
        self.config = ExperienceBuildConfig(
            safe_float(self.profile.get("offline_discount", 0.97), 0.97, 0.0, 0.999),
            safe_int(self.profile.get("offline_n_step", 5), 5, 1, 32),
            str(self.profile.get("game_id") or (self.samples[0].get("game_id") if self.samples else "")),
            normalized_identifier(self.profile.get("default_task_id"), "default", 96),
        )
        self.task_runtimes = {}

    def build(self):
        experiences = []
        sessions = defaultdict(list)
        for item in self.samples:
            sessions[self.controller.session_of(item)].append(item)
        for session, items in sorted(sessions.items()):
            episode = self._build_episode(session, items, len(experiences))
            self._apply_returns(episode)
            experiences.extend(episode)
        return experiences, self._build_policy_model(experiences)

    def _task_runtime(self, task_id):
        tid = normalized_identifier(task_id, self.config.default_task_id, 96)
        runtime = self.task_runtimes.get(tid)
        if runtime is not None:
            return runtime
        payload = None
        host = getattr(self.controller, "host", None)
        store = getattr(host, "store", None) if host is not None else None
        if store is not None and self.config.game_id:
            try:
                payload = store.load_task(self.config.game_id, tid)
            except RECOVERABLE_ERRORS:
                payload = None
        if not isinstance(payload, dict):
            payload = {**self.profile, "game_id": self.config.game_id, "task_id": tid, "name": tid}
        runtime = TaskRuntime(TaskDefinition.from_mapping(payload, self.config.game_id, tid))
        self.task_runtimes[tid] = runtime
        return runtime

    @staticmethod
    def _observation_summary(observation):
        return {
            "schema_version": OBSERVATION_SCHEMA_VERSION,
            "state_id": observation.state_id,
            "environment_id": observation.environment_id,
            "visual_digest": observation.visual_digest,
            "index_hash": observation.index_hash,
            "confidence": round(observation.confidence, 6),
            "objects": [slot.compact() for slot in observation.objects],
            "ocr_values": [dict(value) for value in observation.ocr_values],
            "task": dict(observation.task),
            "internal_state": dict(observation.internal_state),
        }

    def _ocr_summary(self, start, end):
        matched = [
            entry
            for entry in self.events
            if start <= safe_float(entry.get("created"), 0.0) <= end
        ]
        terminal = ""
        confidence = 0.0
        compact_events = []
        snapshots = {}
        legacy_latest = None
        reset = False
        for entry in matched:
            event = entry.get("event", {})
            if not isinstance(event, dict):
                continue
            created = safe_float(entry.get("created"), 0.0)
            compact_events.append(
                {
                    key: event.get(key)
                    for key in (
                        "frame_id",
                        "region_id",
                        "priority",
                        "terminal",
                        "snapshot_reward",
                        "snapshot_status",
                        "snapshot_winning_region_id",
                        "status",
                        "reset",
                        "numeric_value",
                        "numeric_delta",
                        "source_confidence",
                        "stable_frames",
                        "raw_text",
                    )
                    if key in event
                }
            )
            confidence = max(confidence, safe_float(event.get("source_confidence", 0.0), 0.0, 0.0, 1.0))
            if event.get("terminal") in {"success", "failure"}:
                terminal = str(event.get("terminal"))
            reset = reset or bool(event.get("reset"))
            frame_id = str(event.get("frame_id", ""))
            if frame_id and finite_number(event.get("snapshot_reward")):
                previous = snapshots.get(frame_id)
                if previous is None or created >= previous[0]:
                    snapshots[frame_id] = (created, event)
            if legacy_latest is None or created >= legacy_latest[0]:
                legacy_latest = (created, event)
        if snapshots:
            _, selected = max(snapshots.values(), key=lambda item: item[0])
            progress = max(-1.0, min(1.0, safe_float(selected.get("snapshot_reward"), 0.0)))
        elif legacy_latest is not None:
            progress = max(-1.0, min(1.0, safe_float(legacy_latest[1].get("progress"), 0.0)))
        else:
            progress = 0.0
        return OcrTransitionSummary(
            tuple(compact_events),
            terminal,
            progress,
            confidence,
            progress,
            reset,
        )

    def _build_episode(self, session, items, experience_offset):
        ordered = sorted(
            items,
            key=lambda item: (safe_float(item.get("created"), 0.0), str(item.get("checksum", ""))),
        )
        state = EpisodeBuildState()
        episode = []
        for index, item in enumerate(ordered):
            if (experience_offset + len(episode)) % 64 == 0 and self.controller.context.callbacks.should_stop():
                raise InputStopped("睡眠已停止")
            prepared = self._prepare_step(session, ordered, index, state)
            episode.append(self._make_experience(prepared, len(ordered)))
        return episode

    def _prepare_step(self, session, ordered, index, state):
        item = ordered[index]
        next_item = ordered[index + 1] if index + 1 < len(ordered) else item
        start = safe_float(item.get("created"), 0.0)
        next_created = safe_float(next_item.get("created"), start)
        end = next_created if index + 1 < len(ordered) else start + 1.5
        context = item.get("context", {}) if isinstance(item.get("context"), dict) else {}
        next_context = next_item.get("context", {}) if isinstance(next_item.get("context"), dict) else {}
        task_id = normalized_identifier(context.get("task_id"), self.config.default_task_id, 96)
        runtime = self._task_runtime(task_id)
        observation = objectized_observation(item, context, runtime.definition)
        next_observation = objectized_observation(next_item, next_context, runtime.definition)
        semantic_action = normalize_semantic_action(context.get("semantic_action")) or semantic_action_from_coordinate(
            item.get("a")
        )
        grounded_action = normalize_action(context.get("grounded_action")) or normalize_action(item.get("a"))
        skill = semantic_skill(
            semantic_action,
            str(context.get("subgoal_id") or "advance_goal"),
            safe_float(context.get("policy_confidence", 1.0), 1.0, 0.0, 1.0),
        )
        action_id = skill.key()
        repeated = bool(state.previous_skill_key and state.previous_skill_key == action_id)
        state.previous_skill_key = action_id
        new_state = next_observation.environment_id not in state.seen_environments
        state.seen_environments.add(observation.environment_id)
        state.seen_environments.add(next_observation.environment_id)
        return PreparedExperienceStep(
            item,
            next_item,
            index,
            session,
            start,
            next_created,
            context,
            task_id,
            runtime,
            observation,
            next_observation,
            semantic_action,
            grounded_action,
            skill,
            action_id,
            visual_distance(item["f"], next_item["f"]),
            observation.environment_id != next_observation.environment_id,
            repeated,
            new_state,
            bool(context.get("human_override") or str(item.get("source", "")).startswith("teach")),
            str((semantic_action or {}).get("risk_class", "safe")),
            self._ocr_summary(start, end),
        )

    def _reward_result(self, prepared):
        ocr = prepared.ocr
        context = prepared.context
        transition = {
            "terminal": ocr.terminal,
            "terminal_confidence": ocr.confidence if ocr.terminal else 0.0,
            "progress_score": ocr.progress,
            "numeric_progress": ocr.numeric_progress,
            "progress_confidence": ocr.confidence,
            "ocr_confidence": ocr.confidence,
            "state_confidence": min(prepared.observation.confidence, prepared.next_observation.confidence),
            "changed": prepared.environment_changed,
            "visual_changed": prepared.visual_change > 0.0,
            "repeated": prepared.repeated,
            "loop_detected": prepared.repeated and prepared.index > 1,
            "new_state": prepared.new_state,
            "reset": ocr.reset,
            "should_wait": bool(context.get("should_wait", False)),
            "invalid_action": bool(context.get("invalid_action", False)),
            "human_override": prepared.human_override,
            "risk_class": prepared.risk_class,
            "subgoal_completed": bool(context.get("subgoal_completed", False)),
        }
        return prepared.runtime.evaluate(transition)

    def _make_experience(self, prepared, episode_size):
        reward_result = self._reward_result(prepared)
        reward = safe_float(reward_result.get("reward"), 0.0)
        result = self._result_name(reward_result, prepared.ocr.progress)
        done = bool(reward_result.get("success") or reward_result.get("failure") or prepared.index + 1 >= episode_size)
        action_delay = safe_float(
            prepared.context.get("action_delay", max(0.0, prepared.next_created - prepared.start)),
            max(0.0, prepared.next_created - prepared.start),
            0.0,
            60.0,
        )
        action_duration = safe_float(
            (prepared.semantic_action or {}).get("parameters", {}).get("duration", 0.0), 0.0, 0.0, 60.0
        )
        action_start = safe_float(prepared.context.get("action_start_time", prepared.start), prepared.start)
        action_end = safe_float(
            prepared.context.get("action_end_time", action_start + action_duration), action_start + action_duration
        )
        return self._experience_payload(
            prepared, reward_result, reward, result, done, action_delay, action_start, action_end
        )

    @staticmethod
    def _result_name(reward_result, progress):
        if reward_result.get("success"):
            return "success"
        if reward_result.get("failure"):
            return "failure"
        return "progress" if progress > 0 else "regress" if progress < 0 else "neutral"

    def _experience_payload(self, prepared, reward_result, reward, result, done, action_delay, action_start, action_end):
        observation = prepared.observation
        next_observation = prepared.next_observation
        context = prepared.context
        skill = prepared.skill
        common = {
            "game_id": self.config.game_id,
            "task_id": prepared.task_id,
            "episode_id": str(context.get("episode_id") or prepared.session),
            "step_id": safe_int(context.get("step_id", prepared.index), prepared.index, 0),
            "state_t": observation.state_id,
            "action_t": prepared.action_id,
            "state_t+1": next_observation.state_id,
            "environment_t": observation.environment_id,
            "environment_t+1": next_observation.environment_id,
            "reward_t": round(reward, 6),
            "reward_confidence": safe_float(reward_result.get("confidence", 0.0), 0.0, 0.0, 1.0),
            "value_update_eligible": bool(reward_result.get("update_eligible", False)),
            "done": done,
            "success": result == "success",
            "failure": result == "failure",
            "result": result,
            "terminal_state": result if done else "neutral",
            "progress_score": round(prepared.ocr.progress, 6),
            "action_delay": round(action_delay, 6),
            "action_start_time": round(action_start, 6),
            "action_end_time": round(action_end, 6),
            "environment_response_time": round(max(0.0, prepared.next_created - action_end), 6),
            "human_override": prepared.human_override,
            "created_t": prepared.start,
            "created_t+1": prepared.next_created,
            "visual_change": round(prepared.visual_change, 6),
            "environment_changed": prepared.environment_changed,
            "ocr_events": list(prepared.ocr.events),
            "reward_components": reward_result.get("components", {}),
        }
        common.update(self._semantic_payload(prepared, context, skill))
        common.update(
            {
                "trajectory_schema_version": TRAJECTORY_SCHEMA_VERSION,
                "session": prepared.session,
                "state": observation.state_id,
                "action": prepared.action_id,
                "next_state": next_observation.state_id,
                "reward": round(reward, 6),
            }
        )
        return common

    def _semantic_payload(self, prepared, context, skill):
        return {
            "semantic_action": prepared.semantic_action,
            "grounded_action": prepared.grounded_action,
            "grounding": context.get("grounding", {}),
            "skill_id": skill.skill_id,
            "skill_key": prepared.action_id,
            "skill_parameters": dict(skill.parameters),
            "subgoal_id": skill.subgoal_id,
            "policy_confidence": safe_float(
                context.get("policy_confidence", skill.confidence), skill.confidence, 0.0, 1.0
            ),
            "safety_decision": context.get("safety_decision", {}),
            "observation_t": self._observation_summary(prepared.observation),
            "observation_t+1": self._observation_summary(prepared.next_observation),
            "model_version": str(context.get("model_version") or current_build_hash()),
            "source_sample_checksum": str(prepared.item.get("checksum", "")),
            "counterfactual_training": (
                dict(context.get("counterfactual_training", {}))
                if isinstance(context.get("counterfactual_training"), dict)
                else {}
            ),
            "sample_role": str(context.get("sample_role", "demonstration")),
        }

    def _apply_returns(self, episode):
        episode_return = 0.0
        for experience in reversed(episode):
            episode_return = safe_float(experience["reward_t"], 0.0) + (
                0.0 if experience["done"] else self.config.gamma * episode_return
            )
            experience["episode_return_t"] = round(episode_return, 6)
        for index, experience in enumerate(episode):
            running = 0.0
            discount = 1.0
            for offset in range(self.config.n_step):
                position = index + offset
                if position >= len(episode):
                    break
                row = episode[position]
                running += discount * safe_float(row["reward_t"], 0.0)
                if row["done"]:
                    break
                discount *= self.config.gamma
            experience["return_t"] = round(running, 6)
            experience["n_step"] = self.config.n_step

    @staticmethod
    def _empty_policy_row():
        return {
            "count": 0,
            "reward_sum": 0.0,
            "return_sum": 0.0,
            "success": 0,
            "failure": 0,
            "neutral": 0,
            "next_states": Counter(),
            "override": 0,
            "confidence_sum": 0.0,
        }

    def _aggregate_policy_rows(self, experiences):
        state_rows = defaultdict(self._empty_policy_row)
        action_rows = defaultdict(self._empty_policy_row)
        behavior_state_counts = Counter()
        behavior_action_counts = Counter()
        state_action_ids = {}
        for experience in experiences:
            task_id = normalized_identifier(experience.get("task_id"), self.config.default_task_id, 96)
            state_key = task_id + "|" + experience["state_t"] + "|" + experience["action_t"]
            action_key = task_id + "|" + experience["action_t"]
            state_action_ids[state_key] = action_key
            behavior_state_counts[state_key] += 1
            behavior_action_counts[action_key] += 1
            if not experience.get("value_update_eligible", False):
                continue
            for row in (state_rows[state_key], action_rows[action_key]):
                row["count"] += 1
                row["reward_sum"] += experience["reward_t"]
                row["return_sum"] += experience["return_t"]
                row["success"] += int(experience["success"])
                row["failure"] += int(experience["failure"])
                row["neutral"] += int(not experience["success"] and not experience["failure"])
                row["override"] += int(experience["human_override"])
                row["confidence_sum"] += safe_float(experience.get("reward_confidence", 0.0), 0.0)
                row["next_states"][experience["state_t+1"]] += 1
        return state_rows, action_rows, behavior_state_counts, behavior_action_counts, state_action_ids

    @staticmethod
    def _finish_policy_row(row):
        count = max(1, row["count"])
        terminal = max(0, row["success"] + row["failure"])
        success_probability = (row["success"] + 1.0) / (terminal + 2.0) if terminal else 0.0
        failure_probability = (row["failure"] + 1.0) / (terminal + 2.0) if terminal else 0.0
        uncertainty = min(1.0, 1.0 / math.sqrt(count) + 0.5 * (1.0 - min(1.0, terminal / count)))
        return {
            "count": row["count"],
            "mean_reward": round(row["reward_sum"] / count, 6),
            "q_value": round(row["return_sum"] / count, 6),
            "success": row["success"],
            "failure": row["failure"],
            "neutral": row["neutral"],
            "success_probability": round(success_probability, 6),
            "risk_probability": round(failure_probability, 6),
            "uncertainty": round(uncertainty, 6),
            "human_override_rate": round(row["override"] / count, 6),
            "mean_reward_confidence": round(row["confidence_sum"] / count, 6),
            "next_states": dict(row["next_states"].most_common(8)),
        }

    def _build_policy_model(self, experiences):
        rows = self._aggregate_policy_rows(experiences)
        state_rows, action_rows, behavior_state_counts, behavior_action_counts, state_action_ids = rows
        state_model = {key: self._finish_policy_row(row) for key, row in state_rows.items()}
        action_model = {key: self._finish_policy_row(row) for key, row in action_rows.items()}
        temperature = safe_float(self.profile.get("awr_temperature", 0.5), 0.5, 0.05, 10.0)
        total_value_count = sum(row["count"] for row in action_model.values())
        baseline = sum(row["q_value"] * row["count"] for row in action_model.values()) / max(1, total_value_count)
        self._apply_advantages(
            state_model,
            action_model,
            behavior_state_counts,
            behavior_action_counts,
            state_action_ids,
            baseline,
            temperature,
        )
        task_ids = sorted(
            {normalized_identifier(item.get("task_id"), self.config.default_task_id, 96) for item in experiences}
        )
        return {
            "schema_version": POLICY_MODEL_SCHEMA_VERSION,
            "algorithm": "task_conditioned_object_state+n_step_conservative_return+advantage_weighted_skill_cloning",
            "gamma": self.config.gamma,
            "n_step": self.config.n_step,
            "awr_temperature": temperature,
            "value_baseline": round(baseline, 6),
            "total_count": len(experiences),
            "value_eligible_count": sum(1 for item in experiences if item.get("value_update_eligible")),
            "default_task_id": self.config.default_task_id,
            "task_ids": task_ids,
            "state_action": state_model,
            "action_prior": action_model,
            "behavior_state_count": dict(behavior_state_counts),
            "behavior_action_count": dict(behavior_action_counts),
            "state_key_algorithm_version": STATE_KEY_ALGORITHM_VERSION,
            "observation_schema_version": OBSERVATION_SCHEMA_VERSION,
            "skill_schema_version": SKILL_SCHEMA_VERSION,
            "episode_metrics": summarize_episode_metrics(experiences),
        }

    @staticmethod
    def _apply_advantages(state_model, action_model, state_counts, action_counts, state_action_ids, baseline, temperature):
        for key, row in action_model.items():
            advantage = row["q_value"] - baseline
            row["advantage"] = round(advantage, 6)
            row["awr_weight"] = round(math.exp(max(-4.0, min(4.0, advantage / temperature))), 6)
            row["behavior_count"] = action_counts.get(key, 0)
        for key, row in state_model.items():
            prior = action_model.get(state_action_ids.get(key), {})
            advantage = row["q_value"] - safe_float(prior.get("q_value", baseline), baseline)
            row["advantage"] = round(advantage, 6)
            row["awr_weight"] = round(math.exp(max(-4.0, min(4.0, advantage / temperature))), 6)
            row["behavior_count"] = state_counts.get(key, 0)


class ReviewController:
    def __init__(self, context, host=None):
        if isinstance(context, ModeContext):
            self.context = context
            self.host = host
        else:
            self.context = ModeContext.from_host(context)
            self.host = context

    def session_of(self, item):
        return str(item.get("session_id") or item.get("context", {}).get("session_id") or "legacy")

    def method_of(self, item):
        return str(item.get("capture_method") or item.get("context", {}).get("capture_method") or "unknown")

    def stratum_of(self, item):
        return (semantic_action_family_key(sample_semantic_action(item)), self.method_of(item))

    def decorrelate(self, valid):
        result = []
        previous = {}
        removed = 0
        ordered = sorted(
            valid,
            key=lambda item: (self.session_of(item), float(item.get("created", 0.0)), str(item.get("checksum", ""))),
        )
        for index, item in enumerate(ordered):
            if index % 32 == 0 and self.context.callbacks.should_stop():
                raise InputStopped("睡眠已停止")
            key = (self.session_of(item), semantic_action_signature(sample_semantic_action(item)), self.method_of(item))
            old = previous.get(key)
            keep = True
            if old is not None:
                gap = float(item.get("created", 0.0)) - float(old.get("created", 0.0))
                if 0.0 <= gap < 0.75 and coarse_distance(item.get("coarse"), old.get("coarse")) <= 5.0:
                    threshold = max(2.0, safe_float(item.get("context", {}).get("duplicate_threshold", 3.0), 3.0) * 1.5)
                    if feature_distance(item["f"], old["f"]) <= threshold:
                        keep = False
            if keep:
                result.append(item)
                previous[key] = item
            else:
                removed += 1
        return result, removed

    def split(self, valid):
        return ReviewSessionSplitter().split(self, valid)

    def _split_by_family_backend(self, valid):
        session_groups = defaultdict(list)
        for item in valid:
            session_groups[self.session_of(item)].append(item)
        sessions = sorted(session_groups, key=lambda key: hashlib.sha256(key.encode("utf-8", "replace")).hexdigest())
        totals = Counter(self.stratum_of(item) for item in valid)
        if len(sessions) < 2:
            return (
                list(valid),
                [],
                {
                    "complete": False,
                    "mode": "session_family_backend_visual_group",
                    "holdout_sessions": [],
                    "reason": "只有一个完整学习session，只能生成临时模型",
                    "strata": len(totals),
                    "session_count": len(sessions),
                    "visual_group_intersection": [],
                },
            )
        parent = {session: session for session in sessions}

        def find(value):
            while parent[value] != value:
                parent[value] = parent[parent[value]]
                value = parent[value]
            return value

        def union(first, second):
            a = find(first)
            b = find(second)
            if a != b:
                parent[max(a, b)] = min(a, b)

        hash_sessions = defaultdict(set)
        for item in valid:
            hash_sessions[visual_perceptual_hash(item["f"])].add(self.session_of(item))
        for sessions_for_hash in hash_sessions.values():
            ordered_sessions = sorted(sessions_for_hash)
            for session in ordered_sessions[1:]:
                union(ordered_sessions[0], session)
        hash_values = sorted(hash_sessions)
        for first_hash, second_hash in near_perceptual_hash_pairs(hash_values, 4, self.context.callbacks.should_stop):
            first_sessions = sorted(hash_sessions[first_hash])
            second_sessions = sorted(hash_sessions[second_hash])
            if first_sessions and second_sessions:
                union(first_sessions[0], second_sessions[0])
        group_sessions = defaultdict(set)
        for session in sessions:
            group_sessions[find(session)].add(session)
        groups = sorted(
            group_sessions,
            key=lambda key: hashlib.sha256(
                "|".join(sorted(group_sessions[key])).encode("utf-8", "replace")
            ).hexdigest(),
        )
        group_items = {
            group: [item for session in group_sessions[group] for item in session_groups[session]] for group in groups
        }
        group_counts = {group: Counter(self.stratum_of(item) for item in items) for group, items in group_items.items()}
        group_sizes = {group: len(items) for group, items in group_items.items()}
        target = max(VersionedThresholdConfig.review_min_holdout, round(len(valid) * 0.25))
        best = None
        best_score = None

        def consider(chosen):
            nonlocal best, best_score
            if not chosen or len(chosen) >= len(groups):
                return
            hold_counts = Counter()
            hold_count = 0
            for group in chosen:
                hold_counts.update(group_counts[group])
                hold_count += group_sizes[group]
            shared = sum(1 for key, total in totals.items() if 0 < hold_counts[key] < total)
            missing = sum(1 for key, total in totals.items() if hold_counts[key] in {0, total})
            complete = shared > 0 and all(hold_counts[key] < totals[key] for key in totals)
            score = (
                0 if complete else 1,
                missing,
                0 if hold_count >= VersionedThresholdConfig.review_min_holdout else 1,
                abs(hold_count - target),
                len(chosen),
            )
            if best_score is None or score < best_score:
                best = set(chosen)
                best_score = score

        count = len(groups)
        if count <= 16:
            for mask in range(1, (1 << count) - 1):
                consider({groups[index] for index in range(count) if mask & (1 << index)})
        else:
            generator = random.Random(
                int(hashlib.sha256("|".join(groups).encode("utf-8", "replace")).hexdigest()[:16], 16)
            )
            for order in (
                groups,
                sorted(groups, key=lambda value: group_sizes[value]),
                sorted(groups, key=lambda value: group_sizes[value], reverse=True),
            ):
                for length in range(1, min(len(order), 16) + 1):
                    consider(set(order[:length]))
            for _ in range(5000):
                consider({group for group in groups if generator.random() < 0.25})
        if not best:
            return (
                list(valid),
                [],
                {
                    "complete": False,
                    "mode": "session_family_backend_visual_group",
                    "holdout_sessions": [],
                    "reason": "无法建立视觉组与session级留出集",
                    "strata": len(totals),
                    "session_count": len(sessions),
                    "visual_group_count": len(groups),
                    "visual_group_intersection": [],
                },
            )
        hold_sessions = set().union(*(group_sessions[group] for group in best))
        train = [item for item in valid if self.session_of(item) not in hold_sessions]
        holdout = [item for item in valid if self.session_of(item) in hold_sessions]
        assert_disjoint_checksums(train, holdout)
        train_sessions = {self.session_of(item) for item in train}
        holdout_sessions = {self.session_of(item) for item in holdout}
        visual_intersection = sorted(
            {visual_perceptual_hash(item["f"]) for item in train}
            & {visual_perceptual_hash(item["f"]) for item in holdout}
        )
        if train_sessions & holdout_sessions or visual_intersection:
            raise RuntimeError("训练集与留出集session或视觉近重复组发生重叠")
        hold_counts = Counter(self.stratum_of(item) for item in holdout)
        complete = bool(
            train
            and holdout
            and not any(hold_counts[key] >= totals[key] for key in totals)
            and any(0 < hold_counts[key] < totals[key] for key in totals)
        )
        reason = "" if complete else "视觉组划分无法为动作族与采集后端保留训练数据"
        return (
            train,
            holdout,
            {
                "complete": complete,
                "mode": "session_family_backend_visual_group",
                "holdout_sessions": sorted(holdout_sessions),
                "reason": reason,
                "strata": len(totals),
                "session_count": len(sessions),
                "visual_group_count": len(groups),
                "training_sessions": sorted(train_sessions),
                "session_intersection": [],
                "visual_group_intersection": visual_intersection,
            },
        )

    def map_holdout(self, holdout, clusters):
        by_family = defaultdict(list)
        for cluster in clusters:
            by_family[semantic_action_family_key(cluster.get("semantic_action"))].append(cluster)
        uncovered = 0
        for item in holdout:
            semantic = sample_semantic_action(item)
            candidates = by_family.get(semantic_action_family_key(semantic), [])
            if not candidates:
                item["_action_cluster"] = None
                item["_uncovered_action"] = True
                uncovered += 1
                continue
            ranked = sorted(
                (semantic_action_distance(semantic, cluster.get("semantic_action")), cluster) for cluster in candidates
            )
            distance, cluster = ranked[0]
            fallback_classes = (
                {str(semantic.get("source", {}).get("class", "")), str(semantic.get("target", {}).get("class", ""))}
                if isinstance(semantic, dict)
                else set()
            )
            coordinate_primary = bool(fallback_classes and fallback_classes.issubset(SEMANTIC_TARGET_FALLBACK_CLASSES))
            if coordinate_primary:
                distance += action_geometry_distance(item["a"], cluster["a"])
                limit = action_cluster_limit(cluster["a"]) + 0.2
            else:
                limit = 0.36
            if distance > limit:
                item["_action_cluster"] = None
                item["_uncovered_action"] = True
                uncovered += 1
                continue
            item["_action_cluster"] = cluster["id"]
            item["_cluster_action"] = cluster["a"]
            item["_cluster_semantic_action"] = cluster.get("semantic_action")
            item["_action_support"] = len(cluster["members"])
            item["_canonical_action_signature"] = cluster["canonical_action_signature"]
            item["_uncovered_action"] = False
        return uncovered

    def build_experiences(self, samples, ocr_events, profile):
        return ExperienceBuilder(self, samples, ocr_events, profile).build()

    def run(self):
        return ReviewRunner(ModeContext.from_host(self.host), self, self.host, False).run()

    def run_offline(self):
        return ReviewRunner(ModeContext.from_host(self.host), self, self.host, True).run()

    def _pipeline_impl(self, phase=None):
        host = self.host
        phase = phase if isinstance(phase, dict) else {}
        host.require_ai_runtime()
        game = phase.get("game") or host.require_game()
        host.store.pause_sample_writes("升级期间冻结样本写入")
        try:
            host.set_status("升级1/5：读取轻量元数据并完成分层抽样")
            samples, stats = host.store.load_training_samples(game["id"], MAX_VISION_TRAINING_SAMPLES, "vision")
            if stats.get("invalid", 0):
                host.set_status("升级1/5：发现无效样本并已隔离，继续使用有效分层数据")
            rgb_samples = [item for item in samples if sample_rgb_valid(item.get("rgb"))]
            sleep_seed, sleep_seed_evidence = deterministic_sleep_seed(game["id"], rgb_samples)
            host.sleep_seed = sleep_seed
            host.sleep_seed_evidence = sleep_seed_evidence
            host.set_status("升级2/5：使用受限RGB样本训练对象模型、视觉适配器与终止检测器")
            manifest = host.vision_runtime.train(
                game["id"], rgb_samples, host.stop_event, host.set_progress, sleep_seed, len(samples)
            )
            host.store.record_vision_model(game["id"], manifest)
            host.store.reencode_samples(game["id"], host.vision_runtime, host.stop_event, host.set_progress)
            del rgb_samples, samples
            host.set_status("升级3/5：按固定批次加载策略特征，训练目标条件行为克隆、保守离线价值与独立风险模型")
            result = host._run_review_process()
            host.set_status("升级4/5：校准概率、OOD阈值和危险动作零误放阈值")
            host.set_status("升级5/5：按游戏、任务、分辨率、UI变体和session分组验收")
            return result
        finally:
            host.store.resume_sample_writes()

    def _run_impl(self, phase=None):
        return ReviewExecution(self, phase).run()


def _policy_training_cache_key(experience_model, experiences, default_task_id):
    rows = []
    for item in experiences or []:
        if not isinstance(item, dict):
            continue
        rows.append(
            (
                str(item.get("game_id", "")),
                normalized_identifier(item.get("task_id"), default_task_id, 96),
                str(item.get("state_t", item.get("state", ""))),
                str(item.get("action_t", item.get("action", ""))),
                str(item.get("state_t+1", item.get("next_state", ""))),
                round(safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0), 6),
                bool(item.get("done")),
                round(safe_float(item.get("reward_confidence", 0.0), 0.0), 6),
                str(item.get("source_sample_checksum", "")),
            )
        )
    material = {
        "rows": rows,
        "gamma": safe_float((experience_model or {}).get("gamma", 0.97), 0.97),
        "temperature": safe_float((experience_model or {}).get("awr_temperature", 0.5), 0.5),
        "default_task_id": str(default_task_id),
        "schema": NEURAL_OFFLINE_POLICY_SCHEMA_VERSION,
    }
    return hashlib.sha256(canonical_bytes(material)).hexdigest()


def _policy_state_vector(value, task_id="default", semantic_model=None, next_observation=False, state_size=None):
    item = dict(value) if isinstance(value, dict) else {}
    if "observation_t" in item or "observation_t+1" in item:
        key = "observation_t+1" if next_observation else "observation_t"
        observation = item.get(key, {}) if isinstance(item.get(key), dict) else {}
        state_id = str(
            item.get(
                "state_t+1" if next_observation else "state_t",
                item.get("next_state" if next_observation else "state", ""),
            )
        )
        task = normalized_identifier(item.get("task_id"), task_id, 96)
    else:
        observation = item
        state_id = str(item.get("state_id", ""))
        task = normalized_identifier(
            task_id or (item.get("task", {}) if isinstance(item.get("task"), dict) else {}).get("task_id"),
            "default",
            96,
        )
    base = latent_observation_vector(observation, state_id, LATENT_STATE_SIZE, semantic_model)
    task_payload = observation.get("task", {}) if isinstance(observation.get("task"), dict) else {}
    internal = observation.get("internal_state", {}) if isinstance(observation.get("internal_state"), dict) else {}
    task_features = semantic_embedding(
        {
            "task_id": task,
            "goal": task_payload.get("goal"),
            "goal_predicates": task_payload.get("goal_predicates", []),
            "current_goal": internal.get("current_goal"),
            "current_subgoal": internal.get("current_subgoal"),
        },
        16,
        semantic_model,
    )
    memory_features = semantic_embedding(
        {
            "memory": internal.get("memory", {}),
            "scene_graph": internal.get("scene_graph", {}),
            "modality_mask": internal.get("modality_mask", {}),
            "recent_actions": observation.get("recent_actions", []),
            "recent_rewards": observation.get("recent_rewards", []),
        },
        16,
        semantic_model,
    )
    context_features = semantic_embedding(
        {
            "object_slots": observation.get("object_slots", []),
            "scene_graph": observation.get("scene_graph", internal.get("scene_graph", {})),
            "modality_features": internal.get("modality_features", {}),
            "dynamic_fast_visual": internal.get("dynamic_fast_visual", {}),
            "task_phase": internal.get("task_phase", "unknown"),
        },
        32,
        semantic_model,
    )
    combined = base + task_features + memory_features + context_features
    target_size = max(POLICY_INPUT_SIZE, safe_int(state_size, POLICY_INPUT_SIZE, POLICY_INPUT_SIZE, 1024))
    if len(combined) < target_size:
        extension = semantic_embedding(
            {
                "state": state_id,
                "task": task,
                "objects": observation.get("object_slots", []),
                "memory": internal.get("memory", {}),
            },
            target_size - len(combined),
            semantic_model,
        )
        combined.extend(extension)
    return [safe_float(entry, 0.0, -3.0, 3.0) for entry in combined[:target_size]]


def _policy_action_vector(action_id, semantic_action=None, semantic_model=None):
    material = {
        "skill": str(action_id),
        "semantic_action": semantic_action if isinstance(semantic_action, dict) else {},
    }
    return [
        safe_float(entry, 0.0, -3.0, 3.0) for entry in semantic_embedding(material, LATENT_ACTION_SIZE, semantic_model)
    ]


def _serialize_dense_network(network):
    layers = []
    for layer in network.layers:
        layers.append(
            {"weight": layer.weight.detach().to("cpu").tolist(), "bias": layer.bias.detach().to("cpu").tolist()}
        )
    return {
        "layers": layers,
        "activation": "tanh",
        "quantization": {
            "scheme": "dynamic_int8",
            "weight_granularity": "per_output_channel",
            "activation_granularity": "per_row",
            "fallback": "float32",
        },
    }


_SERIALIZED_NETWORK_CACHE = BoundedTTLMap(256, 1800.0)


def _dense_network_forward_batch(payload, values_batch):
    rows = [list(values) for values in (values_batch or [])]
    if not rows:
        return []
    layers = payload.get("layers", []) if isinstance(payload, dict) else []
    if not layers:
        return rows
    numpy_module = FEATURE_ENGINE.optional_numpy()
    if numpy_module is not None:
        cache_key = str(id(payload)) + "|" + str(len(layers))
        cached = _SERIALIZED_NETWORK_CACHE.get(cache_key)
        if cached is None:
            converted = []
            for layer in layers:
                weight = numpy_module.asarray(layer.get("weight", []), dtype=numpy_module.float32)
                bias = numpy_module.asarray(layer.get("bias", []), dtype=numpy_module.float32)
                if weight.ndim == 2 and weight.size:
                    weight_scale = numpy_module.maximum(
                        numpy_module.max(numpy_module.abs(weight), axis=1),
                        numpy_module.float32(1e-8),
                    ) / numpy_module.float32(127.0)
                    quantized_weight = numpy_module.clip(
                        numpy_module.rint(weight / weight_scale[:, None]), -127, 127
                    ).astype(numpy_module.int8)
                else:
                    weight_scale = numpy_module.asarray([], dtype=numpy_module.float32)
                    quantized_weight = numpy_module.asarray([], dtype=numpy_module.int8)
                converted.append((weight, bias, quantized_weight, weight_scale))
            cached = tuple(converted)
            _SERIALIZED_NETWORK_CACHE[cache_key] = cached
        width = int(cached[0][0].shape[1]) if cached and cached[0][0].ndim == 2 else len(rows[0])
        normalized = [
            [safe_float(value, 0.0, -8.0, 8.0) for value in (list(row) + [0.0] * width)[:width]]
            for row in rows
        ]
        matrix = numpy_module.asarray(normalized, dtype=numpy_module.float32)
        quantization = payload.get("quantization", {}) if isinstance(payload, dict) else {}
        use_dynamic_int8 = bool(
            isinstance(quantization, dict)
            and quantization.get("scheme") == "dynamic_int8"
            and len(rows) >= 4
        )
        for index, (weight, bias, quantized_weight, weight_scale) in enumerate(cached):
            if weight.ndim != 2:
                return [[] for _ in rows]
            if matrix.shape[1] != weight.shape[1]:
                if matrix.shape[1] < weight.shape[1]:
                    matrix = numpy_module.pad(matrix, ((0, 0), (0, weight.shape[1] - matrix.shape[1])))
                else:
                    matrix = matrix[:, : weight.shape[1]]
            if use_dynamic_int8 and quantized_weight.ndim == 2 and quantized_weight.size:
                activation_scale = numpy_module.maximum(
                    numpy_module.max(numpy_module.abs(matrix), axis=1),
                    numpy_module.float32(1e-8),
                ) / numpy_module.float32(127.0)
                quantized_activation = numpy_module.clip(
                    numpy_module.rint(matrix / activation_scale[:, None]), -127, 127
                ).astype(numpy_module.int8)
                accumulated = (
                    quantized_activation.astype(numpy_module.int32)
                    @ quantized_weight.T.astype(numpy_module.int32)
                )
                matrix = (
                    accumulated.astype(numpy_module.float32)
                    * activation_scale[:, None]
                    * weight_scale[None, :]
                    + bias
                )
            else:
                matrix = matrix @ weight.T + bias
            if index + 1 < len(cached):
                matrix = numpy_module.tanh(matrix)
        return matrix.astype(numpy_module.float64).tolist()
    vectors = [[safe_float(value, 0.0, -8.0, 8.0) for value in row] for row in rows]
    for index, layer in enumerate(layers):
        weight = layer.get("weight", []) if isinstance(layer, dict) else []
        bias = layer.get("bias", []) if isinstance(layer, dict) else []
        outputs = []
        for vector in vectors:
            output = []
            for row, row_bias in zip(weight, bias):
                raw = sum(
                    safe_float(value, 0.0) * safe_float(coefficient, 0.0)
                    for value, coefficient in zip(vector, row)
                ) + safe_float(row_bias, 0.0)
                output.append(math.tanh(raw) if index + 1 < len(layers) else raw)
            outputs.append(output)
        vectors = outputs
    return vectors


def _dense_network_forward(payload, values):
    output = _dense_network_forward_batch(payload, [values])
    return output[0] if output else []


def _policy_member_batch(member, states, actions):
    encoded = (
        _dense_network_forward_batch(member.get("encoder", {}), states)
        if isinstance(member.get("encoder"), dict) and member.get("encoder", {}).get("layers")
        else [list(state) for state in states]
    )
    pairs = [list(state) + list(action) for state, action in zip(encoded, actions)]
    return {
        "q1": _dense_network_forward_batch(member.get("q1", {}), pairs),
        "q2": _dense_network_forward_batch(member.get("q2", {}), pairs),
        "v": _dense_network_forward_batch(member.get("v", {}), encoded),
        "policy": _dense_network_forward_batch(member.get("policy", {}), pairs),
        "risk": _dense_network_forward_batch(member.get("risk", {}), pairs),
        "outcome": _dense_network_forward_batch(member.get("outcome", {}), pairs),
        "dynamics": _dense_network_forward_batch(member.get("dynamics", {}), pairs)
        if isinstance(member.get("dynamics"), dict)
        else [],
    }


def neural_offline_policy_predictions(model, observation, action_ids, task_id="default"):
    value = model if isinstance(model, dict) else {}
    bundle = value.get("neural_bundle", {}) if isinstance(value.get("neural_bundle"), dict) else {}
    actions_requested = [str(action) for action in action_ids or []]
    if not bundle.get("trained") or not actions_requested:
        return {}
    state = _policy_state_vector(observation, task_id, bundle.get("semantic_encoder"))
    action_vectors = [
        _policy_action_vector(action, None, bundle.get("semantic_encoder")) for action in actions_requested
    ]
    states = [state for _ in action_vectors]
    members = [member for member in bundle.get("ensemble", []) if isinstance(member, dict)]
    outputs = [_policy_member_batch(member, states, action_vectors) for member in members]
    if not outputs:
        return {}
    support_map = bundle.get("task_action_support", {}) if isinstance(bundle.get("task_action_support"), dict) else {}
    task = normalized_identifier(task_id, "default", 96)
    support_row = support_map.get(task, {}) if isinstance(support_map.get(task), dict) else {}
    maximum_support = max((safe_int(entry, 0) for entry in support_row.values()), default=0)
    result = {}
    for action_index, action_id in enumerate(actions_requested):
        predictions = []
        for output in outputs:
            q1 = safe_float((output["q1"][action_index] + [0.0])[0], 0.0)
            q2 = safe_float((output["q2"][action_index] + [0.0])[0], 0.0)
            state_value = safe_float((output["v"][action_index] + [0.0])[0], 0.0)
            policy_logit = safe_float((output["policy"][action_index] + [0.0])[0], 0.0)
            risk_logit = safe_float((output["risk"][action_index] + [0.0])[0], 0.0)
            outcome = output["outcome"][action_index]
            maximum = max(outcome, default=0.0)
            probabilities = [math.exp(max(-30.0, min(30.0, entry - maximum))) for entry in outcome]
            denominator = sum(probabilities) or 1.0
            probabilities = [entry / denominator for entry in probabilities]
            predictions.append(
                {
                    "q1": q1,
                    "q2": q2,
                    "q": min(q1, q2),
                    "v": state_value,
                    "policy_logit": policy_logit,
                    "policy_probability": 1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, policy_logit)))),
                    "risk": 1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, risk_logit)))),
                    "success": probabilities[1] if len(probabilities) > 1 else 0.0,
                    "failure": probabilities[2] if len(probabilities) > 2 else 0.0,
                }
            )
        support = safe_int(support_row.get(action_id, 0), 0)
        support_probability = support / max(1, maximum_support) if maximum_support else 0.0
        q_values = [entry["q"] for entry in predictions]
        policy_values = [entry["policy_logit"] for entry in predictions]
        risk_values = [entry["risk"] for entry in predictions]
        uncertainty = min(
            1.0,
            max(
                statistics.pstdev(q_values) if len(q_values) > 1 else 0.0,
                statistics.pstdev(policy_values) if len(policy_values) > 1 else 0.0,
                statistics.pstdev(risk_values) if len(risk_values) > 1 else 0.0,
            )
            + 1.0 / math.sqrt(max(1, support)),
        )
        mean_v = statistics.fmean(entry["v"] for entry in predictions)
        policy_probability = 0.75 * statistics.fmean(
            entry["policy_probability"] for entry in predictions
        ) + 0.25 * support_probability
        result[action_id] = {
            "q1": statistics.fmean(entry["q1"] for entry in predictions),
            "q2": statistics.fmean(entry["q2"] for entry in predictions),
            "q_value": statistics.fmean(q_values),
            "state_value": mean_v,
            "advantage": statistics.fmean(q_values) - mean_v,
            "policy_logit": statistics.fmean(policy_values),
            "behavior_probability": max(0.0, min(1.0, policy_probability)),
            "risk_probability": statistics.fmean(risk_values),
            "success_probability": statistics.fmean(entry["success"] for entry in predictions),
            "failure_probability": statistics.fmean(entry["failure"] for entry in predictions),
            "uncertainty": uncertainty,
            "support": support,
            "member_count": len(predictions),
            "algorithm": bundle.get("algorithm", ""),
            "distillation_member_used": False,
        }
    return result


def neural_offline_policy_prediction(model, observation, action_id, task_id="default"):
    return neural_offline_policy_predictions(model, observation, [action_id], task_id).get(str(action_id), {})

def _policy_teacher_soft_labels(ensemble, states, actions):
    members = [member for member in ensemble or [] if isinstance(member, dict)]
    outputs = [_policy_member_batch(member, states, actions) for member in members]
    if not outputs:
        return {}
    names = ("q1", "q2", "v", "policy", "risk", "outcome", "dynamics")
    result = {}
    for name in names:
        width = max((len(row) for output in outputs for row in output.get(name, [])), default=0)
        rows = []
        for index in range(len(states)):
            rows.append(
                [
                    statistics.fmean(
                        safe_float((output.get(name, [[]])[index] + [0.0] * width)[column], 0.0)
                        for output in outputs
                    )
                    for column in range(width)
                ]
            )
        result[name] = rows
    return result


def _game_isolated_policy_split(experiences):
    games = sorted(
        {str(item.get("game_id") or "unknown") for item in experiences if isinstance(item, dict)},
        key=lambda value: hashlib.sha256(value.encode("utf-8", "replace")).hexdigest(),
    )
    if len(games) < 3:
        return {
            "train_game_ids": games,
            "validation_game_ids": [],
            "test_game_ids": [],
            "complete": False,
            "reason": "at_least_three_games_required",
        }
    train_count = max(1, int(math.floor(len(games) * 0.70)))
    validation_count = max(1, int(math.floor(len(games) * 0.15)))
    if train_count + validation_count >= len(games):
        train_count = max(1, len(games) - 2)
        validation_count = 1
    return {
        "train_game_ids": games[:train_count],
        "validation_game_ids": games[train_count : train_count + validation_count],
        "test_game_ids": games[train_count + validation_count :],
        "complete": True,
        "reason": "game_id_isolated",
    }


def _offline_policy_audit_tables(experiences, bundle, default_task_id):
    rows = defaultdict(
        lambda: {
            "count": 0,
            "reward": 0.0,
            "confidence": 0.0,
            "success": 0,
            "failure": 0,
            "override": 0,
            "done": 0,
            "next": Counter(),
            "observation": {},
            "semantic_action": None,
        }
    )
    action_counts = defaultdict(Counter)
    for item in experiences:
        task = normalized_identifier(item.get("task_id"), default_task_id, 96)
        state = str(item.get("state_t", item.get("state", "")))
        action = str(item.get("action_t", item.get("action", "")))
        key = task + "|" + state + "|" + action
        row = rows[key]
        row["count"] += 1
        row["reward"] += safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0)
        row["confidence"] += safe_float(item.get("reward_confidence", 0.0), 0.0, 0.0, 1.0)
        row["success"] += int(bool(item.get("success")))
        row["failure"] += int(bool(item.get("failure")))
        row["override"] += int(bool(item.get("human_override")))
        row["done"] += int(bool(item.get("done")))
        row["next"][str(item.get("state_t+1", item.get("next_state", "")))] += 1
        if not row["observation"] and isinstance(item.get("observation_t"), dict):
            row["observation"] = item.get("observation_t", {})
        if row["semantic_action"] is None:
            row["semantic_action"] = item.get("semantic_action")
        action_counts[task + "|" + state][action] += 1
    temporary = {"neural_bundle": bundle}
    behavior = {}
    value = {}
    risk = {}
    state_groups = defaultdict(list)
    for key, row in rows.items():
        task, state, action = key.split("|", 2)
        prediction = (
            neural_offline_policy_prediction(temporary, row["observation"], action, task)
            if bundle.get("trained")
            else {}
        )
        count = max(1, row["count"])
        terminal = row["success"] + row["failure"]
        empirical = action_counts[task + "|" + state][action] / max(1, sum(action_counts[task + "|" + state].values()))
        behavior[key] = {
            "count": row["count"],
            "probability": safe_float(prediction.get("behavior_probability", empirical), empirical, 0.0, 1.0),
            "awr_weight": math.exp(
                max(
                    -5.0,
                    min(
                        5.0,
                        safe_float(prediction.get("advantage", 0.0), 0.0)
                        / max(0.05, safe_float(bundle.get("awr_temperature", 0.5), 0.5)),
                    ),
                )
            ),
            "advantage": safe_float(prediction.get("advantage", 0.0), 0.0),
            "human_override_rate": row["override"] / count,
        }
        success = safe_float(
            prediction.get("success_probability", (row["success"] + 1) / (terminal + 2) if terminal else 0.0),
            0.0,
            0.0,
            1.0,
        )
        failure = safe_float(
            prediction.get("failure_probability", (row["failure"] + 1) / (terminal + 2) if terminal else 0.0),
            0.0,
            0.0,
            1.0,
        )
        uncertainty = safe_float(
            prediction.get("uncertainty", min(1.0, 1.0 / math.sqrt(count))), min(1.0, 1.0 / math.sqrt(count)), 0.0, 1.0
        )
        value[key] = {
            "count": row["count"],
            "q_value": safe_float(prediction.get("q_value", row["reward"] / count), row["reward"] / count),
            "expected_return": safe_float(prediction.get("q_value", row["reward"] / count), row["reward"] / count),
            "state_value": safe_float(prediction.get("state_value", 0.0), 0.0),
            "success_probability": success,
            "failure_probability": failure,
            "uncertainty": uncertainty,
            "reward_confidence": row["confidence"] / count,
            "done_rate": row["done"] / count,
            "next_state_distribution": dict(row["next"].most_common(8)),
        }
        risk[key] = {
            "count": row["count"],
            "risk_probability": max(
                failure, safe_float(prediction.get("risk_probability", failure), failure, 0.0, 1.0)
            ),
            "failure_probability": failure,
            "uncertainty": uncertainty,
            "human_override_rate": row["override"] / count,
        }
        state_groups[task + "|" + state].append(key)
    for keys in state_groups.values():
        logits = [safe_float(behavior[key].get("probability"), 0.0) for key in keys]
        total = sum(logits) or 1.0
        for key, value_probability in zip(keys, logits):
            behavior[key]["probability"] = value_probability / total

    def priors(table, fields):
        grouped = defaultdict(list)
        for key, row in table.items():
            task, _, action = key.split("|", 2)
            grouped[task + "|" + action].append(row)
        output = {}
        for key, values in grouped.items():
            count = sum(safe_int(value.get("count"), 0) for value in values)
            output[key] = {"count": count}
            for field in fields:
                weighted = sum(
                    safe_float(value.get(field), 0.0) * max(1, safe_int(value.get("count"), 1)) for value in values
                )
                output[key][field] = weighted / max(1, sum(max(1, safe_int(value.get("count"), 1)) for value in values))
        return output

    return (
        behavior,
        value,
        risk,
        priors(behavior, ("probability", "awr_weight", "advantage")),
        priors(value, ("q_value", "expected_return", "success_probability", "failure_probability", "uncertainty")),
        priors(risk, ("risk_probability", "failure_probability", "uncertainty")),
    )


def _offline_policy_evaluation(bundle, experiences, split):
    validation_games = set(split.get("validation_game_ids", []))
    test_games = set(split.get("test_game_ids", []))
    behavior_counts = defaultdict(Counter)
    for item in experiences:
        task = normalized_identifier(item.get("task_id"), "default", 96)
        behavior_counts[task][str(item.get("action_t", item.get("action", "")))] += 1

    def evaluate_games(games):
        selected = [item for item in experiences if str(item.get("game_id") or "unknown") in games]
        if not selected:
            return {"status": "not_evaluated", "episodes": 0, "reason": "no_game_isolated_rows"}
        weighted_reward = 0.0
        weight_sum = 0.0
        agreement = 0
        risk_correct = 0
        predictions = []
        for item in selected:
            task = normalized_identifier(item.get("task_id"), "default", 96)
            action = str(item.get("action_t", item.get("action", "")))
            prediction = neural_offline_policy_prediction(
                {"neural_bundle": bundle}, item.get("observation_t", {}), action, task
            )
            target_probability = max(1e-5, safe_float(prediction.get("behavior_probability", 0.0), 0.0, 0.0, 1.0))
            counts = behavior_counts[task]
            behavior_probability = max(1e-5, counts[action] / max(1, sum(counts.values())))
            weight = min(20.0, target_probability / behavior_probability)
            reward = safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0)
            weighted_reward += weight * reward
            weight_sum += weight
            agreement += int(target_probability >= behavior_probability)
            risk_label = bool(
                item.get("failure")
                or item.get("human_override")
                or str((item.get("semantic_action") or {}).get("risk_class", "safe")) == "irreversible"
            )
            risk_correct += int((safe_float(prediction.get("risk_probability", 0.0), 0.0) >= 0.5) == risk_label)
            predictions.append(
                (
                    safe_float(prediction.get("uncertainty", 1.0), 1.0),
                    abs(safe_float(prediction.get("q_value", 0.0), 0.0) - reward),
                )
            )
        correlation = 0.0
        if len(predictions) >= 3:
            ux = [value[0] for value in predictions]
            errors = [value[1] for value in predictions]
            um = statistics.fmean(ux)
            em = statistics.fmean(errors)
            numerator = sum((u - um) * (e - em) for u, e in predictions)
            denominator = math.sqrt(sum((u - um) ** 2 for u in ux) * sum((e - em) ** 2 for e in errors))
            correlation = numerator / denominator if denominator else 0.0
        return {
            "status": "evaluated",
            "rows": len(selected),
            "games": sorted(games),
            "weighted_importance_sampling_reward": weighted_reward / max(1e-9, weight_sum),
            "behavior_support_agreement": agreement / max(1, len(selected)),
            "risk_accuracy": risk_correct / max(1, len(selected)),
            "uncertainty_error_correlation": correlation,
        }

    return {
        "schema_version": 1,
        "split_policy": "game_id_isolated",
        "validation": evaluate_games(validation_games),
        "test": evaluate_games(test_games),
        "baselines": ["behavior_cloning", "random_policy", "auditable_rule_policy"],
        "zero_and_few_shot_report_required": True,
    }


@dataclass(frozen=True, slots=True)
class OfflinePolicyConfig:
    gamma: float
    expectile: float
    cql_alpha: float
    beta: float
    seed: int


@dataclass(slots=True)
class PolicyTrainingTensors:
    filtered: list
    train_games: set
    train_indices: list
    state: object
    action: object
    next_state: object
    reward: object
    done: object
    confidence: object
    risk: object
    outcome: object
    action_index: object
    support_mask: object
    counterfactual_mask: object
    candidate_actions: object
    device: object


@dataclass(slots=True)
class PolicyNetworkSet:
    encoder: object
    q1: object
    q2: object
    value: object
    policy: object
    risk: object
    outcome: object
    dynamics: object
    target_encoder: object
    target_q1: object
    target_q2: object
    parameters: list


class OfflinePolicyModelBuilder:
    LOSS_NAMES = (
        "q1_loss",
        "q2_loss",
        "expectile_value_loss",
        "advantage_weighted_policy_loss",
        "behavior_support_loss",
        "counterfactual_action_probability_loss",
        "counterfactual_risk_loss",
        "conservative_q_loss",
        "risk_classification_loss",
        "outcome_classification_loss",
        "world_model_consistency_loss",
    )

    def __init__(self, experience_model, experiences, default_task_id):
        self.experience_model = experience_model if isinstance(experience_model, dict) else {}
        self.default_task_id = default_task_id
        self.eligible = [
            item
            for item in experiences or []
            if isinstance(item, dict)
            and item.get("value_update_eligible", True)
            and str(item.get("action_t", item.get("action", "")))
        ]
        plan = RESOURCE_GOVERNOR.current_plan()
        self.model_spec = model_tier_spec(plan)
        base_cache_key = _policy_training_cache_key(
            self.experience_model,
            self.eligible,
            self.default_task_id,
        )
        self.cache_key = hashlib.sha256(
            (base_cache_key + "|" + self.model_spec.name + "|" + str(self.model_spec)).encode("utf-8")
        ).hexdigest()
        self.config = self._config()
        self.split = _game_isolated_policy_split(self.eligible)
        self.task_support, self.action_vocabulary = self._action_support()
        self.bundle = self._base_bundle()
        self.losses = {name: 0.0 for name in self.LOSS_NAMES}
        self.training_error = ""

    def build(self):
        cached = POLICY_TRAINING_CACHE.get(self.cache_key)
        if cached is not None:
            return cached
        self._train_if_possible()
        result = self._assemble_models()
        POLICY_TRAINING_CACHE.put(self.cache_key, result)
        return result

    def _config(self):
        gamma = safe_float(self.experience_model.get("gamma", 0.97), 0.97, 0.0, 0.999)
        expectile = safe_float(self.experience_model.get("iql_expectile", 0.7), 0.7, 0.5, 0.95)
        cql_alpha = safe_float(self.experience_model.get("cql_alpha", 0.25), 0.25, 0.0, 10.0)
        beta = max(
            0.05,
            safe_float(self.experience_model.get("awr_temperature", 0.5), 0.5, 0.05, 10.0),
        )
        seed = 0
        if self.eligible:
            checksums = [str(item.get("source_sample_checksum", "")) for item in self.eligible]
            seed = int(hashlib.sha256(canonical_bytes(checksums)).hexdigest()[:16], 16)
        return OfflinePolicyConfig(gamma, expectile, cql_alpha, beta, seed)

    def _action_support(self):
        task_support = defaultdict(Counter)
        action_counts = Counter()
        risk_support = defaultdict(Counter)
        skill_support = defaultdict(Counter)
        rewards = defaultdict(list)
        mandatory = set()
        for item in self.eligible:
            task = normalized_identifier(item.get("task_id"), self.default_task_id, 96)
            action = str(item.get("action_t", item.get("action", "")))
            if not action:
                continue
            semantic = item.get("semantic_action") if isinstance(item.get("semantic_action"), dict) else {}
            risk = str(semantic.get("risk_class", item.get("risk_class", "safe")) or "safe")
            skill = str(item.get("skill_id") or semantic.get("action_type") or "unclassified")
            task_support[task][action] += 1
            action_counts[action] += 1
            risk_support[risk][action] += 1
            skill_support[skill][action] += 1
            rewards[action].append(safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0))
            lowered = (action + " " + skill + " " + str(semantic.get("target_class", ""))).casefold()
            if any(token in lowered for token in (
                "restart", "recover", "retry", "reopen", "close_popup", "dismiss",
                "terminate", "finish", "stop", "no_op", "confirm", "重开", "恢复", "关闭", "终止",
            )):
                mandatory.add(action)
        selected = []
        selected_set = set()

        def retain(action):
            if action and action not in selected_set and len(selected) < 96:
                selected.append(action)
                selected_set.add(action)

        for action in sorted(mandatory, key=lambda value: (-action_counts[value], value)):
            retain(action)
        for group in (task_support, risk_support, skill_support):
            quota = 4 if group is task_support else 3 if group is risk_support else 2
            for _, counts in sorted(group.items()):
                for action, _ in counts.most_common(quota):
                    retain(action)
        high_reward = sorted(
            action_counts,
            key=lambda action: (
                -(statistics.fmean(rewards[action]) if rewards[action] else 0.0),
                action_counts[action],
                action,
            ),
        )
        for action in high_reward[:16]:
            if rewards[action] and statistics.fmean(rewards[action]) > 0.25:
                retain(action)
        for action, _ in action_counts.most_common():
            retain(action)
        self.action_vocabulary_metadata = {
            "selection": "mandatory_then_task_risk_skill_quotas_then_rare_high_reward_then_global_frequency",
            "maximum": 96,
            "mandatory_actions": sorted(mandatory),
            "task_minimum_quota": 4,
            "risk_minimum_quota": 3,
            "skill_minimum_quota": 2,
            "rare_high_reward_forced": True,
            "global_frequency_only": False,
        }
        return task_support, selected

    def _base_bundle(self):
        return {
            "schema_version": NEURAL_OFFLINE_POLICY_SCHEMA_VERSION,
            "algorithm": "task_conditioned_neural_offline_iql_cql_awr_bootstrap_ensemble",
            "trained": False,
            "state_size": self.model_spec.state_size,
            "action_size": LATENT_ACTION_SIZE,
            "hidden_size": self.model_spec.hidden_size,
            "ensemble_size": self.model_spec.ensemble_size,
            "model_tier": self.model_spec.name,
            "temporal_context_length": self.model_spec.temporal_context,
            "world_model_horizon": self.model_spec.planning_horizon,
            "object_slot_count": self.model_spec.object_slots,
            "gamma": self.config.gamma,
            "expectile": self.config.expectile,
            "cql_alpha": self.config.cql_alpha,
            "awr_temperature": self.config.beta,
            "action_vocabulary": self.action_vocabulary,
            "action_vocabulary_selection": dict(getattr(self, "action_vocabulary_metadata", {})),
            "task_action_support": {task: dict(counts) for task, counts in self.task_support.items()},
            "game_isolated_split": self.split,
            "safety_boundary": "risk_prediction_never_bypasses_independent_safety_authorization",
            "semantic_state": (
                "normalized_visual_embedding+object_slots+ocr_subwords+scene_graph+goal+"
                "recent_action_reward+modality_mask"
            ),
            "visual_embedding_size": VISUAL_EMBEDDING_SIZE,
            "behavior_support_constraint": True,
            "counterfactual_negative_supervision": {
                "enabled": True,
                "sources": [
                    "lookalike_target",
                    "disabled_target",
                    "popup_obstruction",
                    "irreversible_target",
                    "human_correction",
                ],
                "policy_probability_penalty": True,
                "risk_target_penalty": True,
            },
            "target_q_networks": True,
            "terminal_done_mask": True,
            "confidence_weighted_reward": True,
            "bootstrap_epistemic_uncertainty": True,
            "distillation": {"trained": False},
            "ensemble": [],
        }

    def _train_if_possible(self):
        if len(self.eligible) < 16 or len(self.action_vocabulary) < 2:
            return
        try:
            import torch

            plan = wait_for_runtime_training_plan()
            configure_torch_runtime(torch, plan)
            torch.manual_seed(self.config.seed % (2**63 - 1))
            dense_type = self._dense_network_type(torch)
            tensors = self._prepare_tensors(torch)
            ensemble, history = self._train_ensemble(torch, dense_type, tensors)
            self._finalize_training_bundle(torch, dense_type, ensemble, history, tensors)
        except RECOVERABLE_ERRORS as error:
            self.training_error = type(error).__name__ + ":" + str(error)

    @staticmethod
    def _dense_network_type(torch):
        class DenseNetwork(torch.nn.Module):
            def __init__(self, input_size, output_size, hidden_size):
                super().__init__()
                self.layers = torch.nn.ModuleList(
                    [
                        torch.nn.Linear(input_size, hidden_size),
                        torch.nn.Linear(hidden_size, hidden_size),
                        torch.nn.Linear(hidden_size, output_size),
                    ]
                )

            def forward(self, value):
                for layer in self.layers[:-1]:
                    value = torch.tanh(layer(value))
                return self.layers[-1](value)

        return DenseNetwork

    def _prepare_rows(self):
        vocabulary = set(self.action_vocabulary)
        filtered = [
            item
            for item in self.eligible
            if str(item.get("action_t", item.get("action", ""))) in vocabulary
        ][:6000]
        action_index = {action: index for index, action in enumerate(self.action_vocabulary)}
        action_vectors = [_policy_action_vector(action, None, None) for action in self.action_vocabulary]
        rows = defaultdict(list)
        for item in filtered:
            task = normalized_identifier(item.get("task_id"), self.default_task_id, 96)
            action = str(item.get("action_t", item.get("action", "")))
            semantic = item.get("semantic_action", {}) if isinstance(item.get("semantic_action"), dict) else {}
            rows["states"].append(
                _policy_state_vector(item, task, None, False, self.model_spec.state_size)
            )
            rows["actions"].append(action_vectors[action_index[action]])
            rows["next_states"].append(
                _policy_state_vector(item, task, None, True, self.model_spec.state_size)
            )
            rows["rewards"].append(safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0, -20.0, 20.0))
            rows["dones"].append(float(bool(item.get("done"))))
            rows["confidences"].append(safe_float(item.get("reward_confidence", 0.0), 0.0, 0.0, 1.0))
            risk_label = bool(
                item.get("failure")
                or item.get("human_override")
                or str(semantic.get("risk_class", "safe")) == "irreversible"
            )
            rows["risks"].append(float(risk_label))
            rows["outcomes"].append(1 if item.get("success") else 2 if item.get("failure") else 0)
            rows["action_indexes"].append(action_index[action])
            counterfactual = (
                item.get("counterfactual_training", {})
                if isinstance(item.get("counterfactual_training"), dict)
                else {}
            )
            forbidden_ids = {
                str(value.get("action_id", ""))
                for value in counterfactual.get("forbidden_actions", [])
                if isinstance(value, dict) and value.get("action_id")
            }
            forbidden_ids.discard(action)
            counterfactual_mask = [1.0 if candidate in forbidden_ids else 0.0 for candidate in self.action_vocabulary]
            rows["counterfactual_masks"].append(counterfactual_mask)
            rows["support_masks"].append(
                [
                    1.0 if self.task_support[task].get(candidate, 0) > 0 and candidate not in forbidden_ids else 0.0
                    for candidate in self.action_vocabulary
                ]
            )
            rows["games"].append(str(item.get("game_id") or "unknown"))
        return filtered, action_vectors, rows

    def _prepare_tensors(self, torch):
        filtered, action_vectors, rows = self._prepare_rows()
        train_games = set(self.split.get("train_game_ids", []))
        train_indices = [index for index, game in enumerate(rows["games"]) if game in train_games]
        if not train_indices:
            train_indices = list(range(len(filtered)))
        device = torch_training_device(torch)
        tensor = lambda values, dtype: torch.tensor(values, dtype=dtype, device=device)
        return PolicyTrainingTensors(
            filtered=filtered,
            train_games=train_games,
            train_indices=train_indices,
            state=tensor(rows["states"], torch.float32),
            action=tensor(rows["actions"], torch.float32),
            next_state=tensor(rows["next_states"], torch.float32),
            reward=tensor(rows["rewards"], torch.float32).unsqueeze(1),
            done=tensor(rows["dones"], torch.float32).unsqueeze(1),
            confidence=tensor(rows["confidences"], torch.float32).unsqueeze(1),
            risk=tensor(rows["risks"], torch.float32).unsqueeze(1),
            outcome=tensor(rows["outcomes"], torch.long),
            action_index=tensor(rows["action_indexes"], torch.long),
            support_mask=tensor(rows["support_masks"], torch.float32),
            counterfactual_mask=tensor(rows["counterfactual_masks"], torch.float32),
            candidate_actions=tensor(action_vectors, torch.float32),
            device=device,
        )

    @staticmethod
    def _create_networks(dense_type, device, state_size=POLICY_INPUT_SIZE, hidden_size=POLICY_HIDDEN_SIZE):
        state_size = max(POLICY_INPUT_SIZE, int(state_size))
        hidden_size = max(POLICY_HIDDEN_SIZE, int(hidden_size))
        encoder = dense_type(state_size, hidden_size, hidden_size).to(device)
        pair_size = hidden_size + LATENT_ACTION_SIZE
        q1 = dense_type(pair_size, 1, hidden_size).to(device)
        q2 = dense_type(pair_size, 1, hidden_size).to(device)
        value = dense_type(hidden_size, 1, hidden_size).to(device)
        policy = dense_type(pair_size, 1, hidden_size).to(device)
        risk = dense_type(pair_size, 1, hidden_size).to(device)
        outcome = dense_type(pair_size, 3, hidden_size).to(device)
        dynamics = dense_type(pair_size, state_size, hidden_size).to(device)
        target_encoder = dense_type(state_size, hidden_size, hidden_size).to(device)
        target_q1 = dense_type(pair_size, 1, hidden_size).to(device)
        target_q2 = dense_type(pair_size, 1, hidden_size).to(device)
        target_encoder.load_state_dict(encoder.state_dict())
        target_q1.load_state_dict(q1.state_dict())
        target_q2.load_state_dict(q2.state_dict())
        parameters = []
        for network in (encoder, q1, q2, value, policy, risk, outcome, dynamics):
            parameters.extend(network.parameters())
        return PolicyNetworkSet(
            encoder,
            q1,
            q2,
            value,
            policy,
            risk,
            outcome,
            dynamics,
            target_encoder,
            target_q1,
            target_q2,
            parameters,
        )

    def _train_ensemble(self, torch, dense_type, tensors):
        history = defaultdict(list)
        ensemble = []
        for member_index in range(self.model_spec.ensemble_size):
            member_seed = (self.config.seed + member_index * 104729) % (2**63 - 1)
            torch.manual_seed(member_seed)
            networks = self._create_networks(
                dense_type,
                tensors.device,
                self.model_spec.state_size,
                self.model_spec.hidden_size,
            )
            optimizer = torch.optim.AdamW(networks.parameters, lr=0.0015, weight_decay=0.0001)
            rng = random.Random(member_seed)
            bootstrap = [
                tensors.train_indices[rng.randrange(len(tensors.train_indices))]
                for _ in range(max(32, len(tensors.train_indices)))
            ]
            steps = max(36, min(180, len(tensors.train_indices) * 2))
            plan = wait_for_runtime_training_plan()
            batch_size = max(1, min(128, plan.policy_batch_size, len(bootstrap)))
            amp_enabled = torch_device_is_cuda(torch, tensors.device)
            scaler = torch_grad_scaler(torch, amp_enabled)
            completed = 0
            while completed < steps:
                plan = wait_for_runtime_training_plan()
                configure_torch_runtime(torch, plan)
                batch_size = max(1, min(batch_size, plan.policy_batch_size, len(bootstrap)))
                indexes = [bootstrap[rng.randrange(len(bootstrap))] for _ in range(batch_size)]
                try:
                    losses = self._training_step(
                        torch, networks, optimizer, tensors, indexes, scaler, amp_enabled
                    )
                    completed += 1
                except RuntimeError as error:
                    message = str(error).casefold()
                    if ("out of memory" not in message and "allocation" not in message) or batch_size <= 1:
                        raise
                    batch_size = max(1, batch_size // 2)
                    optimizer.zero_grad(set_to_none=True)
                    release_torch_training_resources(torch)
                    collect_garbage("policy_training_oom", 0.0, True)
                    continue
                for name, value in losses.items():
                    history[name].append(float(value))
            optimizer.zero_grad(set_to_none=True)
            scaler = None
            ensemble.append(self._serialize_member(networks, member_seed, len(bootstrap)))
            release_torch_training_resources(torch)
        return ensemble, history

    def _training_step(self, torch, networks, optimizer, tensors, indexes, scaler=None, amp_enabled=False):
        autocast = (
            torch.autocast(device_type="cuda", dtype=torch.float16, enabled=True)
            if amp_enabled
            else nullcontext()
        )
        with autocast:
            return self._training_step_impl(torch, networks, optimizer, tensors, indexes, scaler)

    def _training_step_impl(self, torch, networks, optimizer, tensors, indexes, scaler=None):
        idx = torch.tensor(indexes, dtype=torch.long, device=tensors.device)
        state = tensors.state[idx]
        action = tensors.action[idx]
        next_state = tensors.next_state[idx]
        reward = tensors.reward[idx]
        done = tensors.done[idx]
        confidence = tensors.confidence[idx]
        risk = tensors.risk[idx]
        outcome = tensors.outcome[idx]
        action_label = tensors.action_index[idx]
        support = tensors.support_mask[idx]
        counterfactual = tensors.counterfactual_mask[idx]
        encoded_state = networks.encoder(state)
        encoded_next_state = networks.encoder(next_state)
        pair = torch.cat([encoded_state, action], dim=1)
        q1_value = networks.q1(pair)
        q2_value = networks.q2(pair)
        with torch.no_grad():
            target = reward + self.config.gamma * (1.0 - done) * networks.value(encoded_next_state)
            target_pair = torch.cat([networks.target_encoder(state), action], dim=1)
            target_q = torch.minimum(networks.target_q1(target_pair), networks.target_q2(target_pair))
        sample_weight = 0.20 + 0.80 * confidence
        q1_loss = (sample_weight * (q1_value - target).pow(2)).mean()
        q2_loss = (sample_weight * (q2_value - target).pow(2)).mean()
        value_delta = target_q - networks.value(encoded_state)
        expectile_weight = torch.where(
            value_delta >= 0,
            torch.full_like(value_delta, self.config.expectile),
            torch.full_like(value_delta, 1.0 - self.config.expectile),
        )
        value_loss = (expectile_weight * value_delta.pow(2)).mean()
        batch_count = state.shape[0]
        action_count = tensors.candidate_actions.shape[0]
        expanded_state = encoded_state.unsqueeze(1).expand(batch_count, action_count, encoded_state.shape[1])
        expanded_action = tensors.candidate_actions.unsqueeze(0).expand(
            batch_count,
            action_count,
            LATENT_ACTION_SIZE,
        )
        all_pairs = torch.cat([expanded_state, expanded_action], dim=2).reshape(batch_count * action_count, -1)
        q1_all = networks.q1(all_pairs).reshape(batch_count, action_count)
        q2_all = networks.q2(all_pairs).reshape(batch_count, action_count)
        cql_loss = (
            torch.logsumexp(q1_all, dim=1).mean()
            - q1_value.mean()
            + torch.logsumexp(q2_all, dim=1).mean()
            - q2_value.mean()
        ) * 0.5
        logits = networks.policy(all_pairs).reshape(batch_count, action_count)
        masked_logits = logits + (support - 1.0) * 8.0
        cross_entropy = torch.nn.functional.cross_entropy(masked_logits, action_label, reduction="none")
        with torch.no_grad():
            advantage = torch.minimum(q1_value, q2_value) - networks.value(encoded_state)
            awr_weight = torch.exp(torch.clamp(advantage / self.config.beta, -5.0, 3.0)).squeeze(1)
        policy_loss = (cross_entropy * awr_weight).mean()
        probabilities = torch.softmax(logits, dim=1)
        support_loss = (probabilities * (1.0 - support)).sum(dim=1).mean()
        counterfactual_probability_loss = (probabilities * counterfactual).sum(dim=1).mean()
        risk_all = networks.risk(all_pairs).reshape(batch_count, action_count)
        counterfactual_count = counterfactual.sum().clamp_min(1.0)
        counterfactual_risk_loss = (
            (1.0 - torch.sigmoid(risk_all)) * counterfactual
        ).sum() / counterfactual_count
        risk_loss = torch.nn.functional.binary_cross_entropy_with_logits(
            networks.risk(pair),
            risk,
            weight=sample_weight,
        )
        outcome_loss = torch.nn.functional.cross_entropy(networks.outcome(pair), outcome, reduction="none")
        outcome_loss = (outcome_loss * sample_weight.squeeze(1)).mean()
        consistency_error = (networks.dynamics(pair) - next_state).pow(2).mean(dim=1, keepdim=True)
        consistency_loss = (sample_weight * consistency_error).mean()
        total = q1_loss + q2_loss + value_loss + self.config.cql_alpha * cql_loss + policy_loss
        total = total + 0.35 * support_loss + 0.75 * counterfactual_probability_loss
        total = total + 0.45 * counterfactual_risk_loss + 0.75 * risk_loss
        total = total + 0.45 * outcome_loss + 0.25 * consistency_loss
        self._optimize(torch, networks, optimizer, total, scaler)
        return {
            "q1_loss": q1_loss.item(),
            "q2_loss": q2_loss.item(),
            "expectile_value_loss": value_loss.item(),
            "advantage_weighted_policy_loss": policy_loss.item(),
            "behavior_support_loss": support_loss.item(),
            "counterfactual_action_probability_loss": counterfactual_probability_loss.item(),
            "counterfactual_risk_loss": counterfactual_risk_loss.item(),
            "conservative_q_loss": cql_loss.item(),
            "risk_classification_loss": risk_loss.item(),
            "outcome_classification_loss": outcome_loss.item(),
            "world_model_consistency_loss": consistency_loss.item(),
        }

    @staticmethod
    def _optimize(torch, networks, optimizer, total, scaler=None):
        optimizer.zero_grad(set_to_none=True)
        if scaler is not None:
            scaler.scale(total).backward()
            scaler.unscale_(optimizer)
            torch.nn.utils.clip_grad_norm_(networks.parameters, 5.0)
            scaler.step(optimizer)
            scaler.update()
        else:
            total.backward()
            torch.nn.utils.clip_grad_norm_(networks.parameters, 5.0)
            optimizer.step()
        with torch.no_grad():
            for target, source in zip(networks.target_encoder.parameters(), networks.encoder.parameters()):
                target.mul_(0.99).add_(source, alpha=0.01)
            for target, source in zip(networks.target_q1.parameters(), networks.q1.parameters()):
                target.mul_(0.99).add_(source, alpha=0.01)
            for target, source in zip(networks.target_q2.parameters(), networks.q2.parameters()):
                target.mul_(0.99).add_(source, alpha=0.01)

    @staticmethod
    def _serialize_member(networks, member_seed, bootstrap_samples):
        return {
            "encoder": _serialize_dense_network(networks.encoder),
            "q1": _serialize_dense_network(networks.q1),
            "q2": _serialize_dense_network(networks.q2),
            "v": _serialize_dense_network(networks.value),
            "policy": _serialize_dense_network(networks.policy),
            "risk": _serialize_dense_network(networks.risk),
            "outcome": _serialize_dense_network(networks.outcome),
            "dynamics": _serialize_dense_network(networks.dynamics),
            "seed": member_seed,
            "bootstrap_samples": bootstrap_samples,
        }

    def _train_distilled_student(self, torch, dense_type, tensors, ensemble):
        total_rows = len(tensors.filtered)
        if total_rows < 32 or not ensemble:
            return {"trained": False, "reason": "insufficient_holdout_soft_labels"}
        rng = random.Random(self.config.seed ^ 0xD157111)
        indexes = list(range(total_rows))
        rng.shuffle(indexes)
        indexes = indexes[: min(1024, len(indexes))]
        validation_count = max(8, len(indexes) // 5)
        validation_indexes = indexes[:validation_count]
        training_indexes = indexes[validation_count:]
        if not training_indexes:
            return {"trained": False, "reason": "empty_student_training_split"}
        states = tensors.state[indexes].detach().to("cpu").tolist()
        actions = tensors.action[indexes].detach().to("cpu").tolist()
        teacher = _policy_teacher_soft_labels(ensemble, states, actions)
        if not teacher:
            return {"trained": False, "reason": "teacher_soft_label_generation_failed"}
        device = tensors.device
        student = self._create_networks(dense_type, device)
        optimizer = torch.optim.AdamW(student.parameters, lr=0.0012, weight_decay=0.0001)
        state_tensor = torch.tensor(states, dtype=torch.float32, device=device)
        action_tensor = torch.tensor(actions, dtype=torch.float32, device=device)
        target_tensors = {
            name: torch.tensor(values, dtype=torch.float32, device=device)
            for name, values in teacher.items()
            if values and values[0]
        }
        local_training = list(range(validation_count, len(indexes)))
        plan = wait_for_runtime_training_plan()
        batch_size = max(1, min(128, plan.policy_batch_size, len(local_training)))
        steps = max(40, min(140, len(local_training) * 2))
        for _ in range(steps):
            chosen = [local_training[rng.randrange(len(local_training))] for _ in range(batch_size)]
            idx = torch.tensor(chosen, dtype=torch.long, device=device)
            state = state_tensor[idx]
            action = action_tensor[idx]
            encoded = student.encoder(state)
            pair = torch.cat([encoded, action], dim=1)
            predictions = {
                "q1": student.q1(pair),
                "q2": student.q2(pair),
                "v": student.value(encoded),
                "policy": student.policy(pair),
                "risk": student.risk(pair),
                "outcome": student.outcome(pair),
                "dynamics": student.dynamics(pair),
            }
            loss = torch.zeros((), dtype=torch.float32, device=device)
            for name, prediction in predictions.items():
                target = target_tensors.get(name)
                if target is not None:
                    loss = loss + (prediction - target[idx]).pow(2).mean()
            optimizer.zero_grad(set_to_none=True)
            loss.backward()
            torch.nn.utils.clip_grad_norm_(student.parameters, 5.0)
            optimizer.step()
        validation_local = list(range(validation_count))
        with torch.no_grad():
            idx = torch.tensor(validation_local, dtype=torch.long, device=device)
            state = state_tensor[idx]
            action = action_tensor[idx]
            encoded = student.encoder(state)
            pair = torch.cat([encoded, action], dim=1)
            predictions = {
                "q1": student.q1(pair),
                "q2": student.q2(pair),
                "v": student.value(encoded),
                "policy": student.policy(pair),
                "risk": student.risk(pair),
                "outcome": student.outcome(pair),
                "dynamics": student.dynamics(pair),
            }
            errors = []
            for name, prediction in predictions.items():
                target = target_tensors.get(name)
                if target is not None:
                    errors.append(float((prediction - target[idx]).pow(2).mean().detach().to("cpu").item()))
            risk_error = float(
                (
                    torch.sigmoid(predictions["risk"])
                    - torch.sigmoid(target_tensors["risk"][idx])
                ).abs().max().detach().to("cpu").item()
            )
        validation_mse = statistics.fmean(errors) if errors else float("inf")
        accepted = bool(validation_mse <= 0.05 and risk_error <= 0.15)
        member = self._serialize_member(student, self.config.seed ^ 0x51D3, len(training_indexes)) if accepted else None
        optimizer.zero_grad(set_to_none=True)
        release_torch_training_resources(torch)
        return {
            "trained": accepted,
            "method": "holdout_ensemble_soft_label_student",
            "target": "shared_encoder_multitask_student",
            "teacher_members": len(ensemble),
            "training_rows": len(training_indexes),
            "validation_rows": len(validation_indexes),
            "validation_mse": validation_mse,
            "risk_probability_max_error": risk_error,
            "acceptance_thresholds": {"validation_mse": 0.05, "risk_probability_max_error": 0.15},
            "member": member,
            "used_in_uncertainty_ensemble": False,
            "fallback": "original_ensemble" if not accepted else "student_available_for_export_only",
        }

    def _finalize_training_bundle(self, torch, dense_type, ensemble, history, tensors):
        for name in self.losses:
            values = history.get(name, [])
            self.losses[name] = statistics.fmean(values[-min(100, len(values)) :]) if values else 0.0
        distillation = self._train_distilled_student(torch, dense_type, tensors, ensemble)
        self.bundle.update(
            {
                "trained": True,
                "ensemble": ensemble,
                "ensemble_size": len(ensemble),
                "training_transitions": len(tensors.filtered),
                "training_game_ids": sorted(tensors.train_games),
                "distillation": distillation,
                "optimizer": "AdamW",
                "bootstrap_sampling": "independent_with_replacement",
                "target_network_update": "polyak_0.01_shared_encoder_and_q_heads",
                "semantic_encoder": {},
                "network_contract": {
                    "shared_encoder": "E(visual,objects,ocr,goal,history,modalities)",
                    "q1": "Q1(E(z),skill)",
                    "q2": "Q2(E(z),skill)",
                    "value": "V(E(z))",
                    "policy": "pi(skill|E(z),goal)",
                    "risk": "Risk(E(z),skill)",
                    "dynamics": "NextState(E(z),skill) with gradients into E",
                },
            }
        )

    def _assemble_models(self):
        audit = _offline_policy_audit_tables(self.eligible, self.bundle, self.default_task_id)
        behavior_state, value_state, risk_state, behavior_prior, value_prior, risk_prior = audit
        if self.bundle.get("trained"):
            ope = _offline_policy_evaluation(self.bundle, self.eligible, self.split)
        else:
            ope = {
                "schema_version": 1,
                "validation": {"status": "not_evaluated"},
                "test": {"status": "not_evaluated"},
            }
        diagnostics = self._diagnostics(ope)
        common = self._common_model_fields(diagnostics, ope)
        behavior_model = {
            **common,
            "algorithm": "neural_advantage_weighted_behavior_policy_with_support_constraint",
            "state_action": behavior_state,
            "action_prior": behavior_prior,
        }
        value_model = {
            **common,
            "algorithm": "neural_double_q_iql_with_cql_and_target_networks",
            "state_action": value_state,
            "action_prior": value_prior,
            "expectile": self.config.expectile,
            "cql_alpha": self.config.cql_alpha,
            "gamma": self.config.gamma,
            "neural_bundle": self.bundle,
        }
        risk_model = {
            **common,
            "algorithm": "independent_neural_failure_irreversible_ood_risk_ensemble",
            "state_action": risk_state,
            "action_prior": risk_prior,
        }
        enough_models = bool(
            self.bundle.get("trained")
            and len(self.eligible) >= max(150, VersionedThresholdConfig.review_min_accepted)
            and len(value_state) >= 8
        )
        return behavior_model, value_model, risk_model, enough_models

    def _diagnostics(self, ope):
        return {
            "schema_version": 2,
            "algorithm": "task_conditioned_neural_offline_iql_cql_awr",
            "losses": {name: round(value, 8) for name, value in self.losses.items()},
            "objectives": [
                "double_q_with_target_networks",
                "terminal_done_mask",
                "confidence_weighted_reward",
                "iql_expectile_value",
                "advantage_weighted_behavior_cloning",
                "cql_conservative_regularization",
                "behavior_support_constraint",
                "bootstrap_epistemic_uncertainty",
                "independent_risk_classification",
                "world_model_consistency",
            ],
            "training_transitions": len(self.eligible),
            "trained": bool(self.bundle.get("trained")),
            "training_error": self.training_error,
            "game_isolated_split": self.split,
            "offline_policy_evaluation": ope,
            "safety_shield_independent": True,
            "distillation": self.bundle.get("distillation", {}),
            "validation_status": "evaluated" if self.split.get("complete") else "not_evaluated",
        }

    def _common_model_fields(self, diagnostics, ope):
        return {
            "schema_version": 4,
            "total_count": len(self.eligible),
            "default_task_id": self.default_task_id,
            "training_diagnostics": diagnostics,
            "game_isolated_validation": self.split,
            "offline_policy_evaluation": ope,
            "neural_reference": {
                "checksum": hashlib.sha256(canonical_bytes(self.bundle)).hexdigest(),
                "trained": bool(self.bundle.get("trained")),
            },
        }


def build_offline_policy_models(experience_model, experiences, default_task_id):
    return OfflinePolicyModelBuilder(experience_model, experiences, default_task_id).build()



class ReviewExecution:
    def __init__(self, controller, phase=None):
        self.controller = controller
        self.host = controller.host
        self.phase = phase if isinstance(phase, dict) else {}
        self.errors = 0
        self.accepted = 0
        self.correct = 0
        self.dangerous_false = 0
        self.uncovered_rejected = 0
        self.uncovered_false_accept = 0
        self.covered_holdout = 0

    def preflight(self):
        self.game = self.phase.get("game") or self.host.require_game()
        samples, self.stats = self.host.store.load_training_samples(self.game["id"], MAX_TRAINING_SAMPLES)
        valid = []
        for index, sample in enumerate(samples):
            if index % 64 == 0 and self.host.should_stop():
                raise InputStopped("睡眠已停止")
            action = normalize_action(sample.get("a"))
            context = sample.get("context", {})
            temporal = temporal_from_context(context)
            calibration = context.get("calibration", {}) if isinstance(context, dict) else {}
            method = str(sample.get("capture_method", "unknown"))
            if (
                feature_valid(sample.get("f"))
                and action
                and temporal.get("complete")
                and method not in {"", "unknown", "legacy"}
                and calibration.get("dynamic_passed")
            ):
                item = dict(sample)
                item["a"] = action
                valid.append(item)
        if not valid:
            raise RuntimeError("没有同时具备已验收采集后端、完整短时序上下文和数据谱系的学习数据；数据不足时只允许指导")
        self.host.wait_escape_release()
        self.samples = valid
        self.stats["valid_for_review"] = len(valid)

    def prepare_action_groups(self):
        self.action_clusters = self.host._cluster_action_samples(self.train)
        self.uncovered_actions = self.host.review_controller.map_holdout(self.holdout, self.action_clusters)
        if self.host.should_stop():
            raise InputStopped("睡眠已停止")
        self.holdout_sessions = set(self.split_info.get("holdout_sessions", []))
        self.cluster_map = {cluster["id"]: cluster for cluster in self.action_clusters}
        self.groups = defaultdict(list)
        for sample in self.train:
            self.groups[sample["_action_cluster"]].append(sample)
        self.ordered = sorted(
            self.groups.items(),
            key=lambda item: (normalize_action(self.cluster_map[item[0]]["a"])["kind"] == "no_op", -len(item[1])),
        )

    def build_prototypes(self):
        self.prototypes = []
        tracker = PrototypeConflictTracker(self.host.should_stop, 80, 8)
        processed = 0
        try:
            for cluster_id, items in self.ordered:
                if self.host.should_stop():
                    raise InputStopped("睡眠已停止")
                cluster = self.cluster_map[cluster_id]

                def progress(local, total_local, count):
                    self.host.set_progress(78 * (processed + local) / max(1, len(self.train)))
                    self.host.set_status(
                        "睡眠中：仅使用训练集生成动作簇和短时序原型；"
                        + str(processed + local)
                        + "/"
                        + str(len(self.train))
                    )

                generated = self.host._cluster_action_group(
                    cluster_id,
                    cluster["a"],
                    len(items),
                    items,
                    progress,
                    cluster.get("repeat_policy", "one_shot"),
                    cluster.get("max_rate", 3.0),
                )
                processed += len(items)
                limited = self.host._limit_prototypes(self.prototypes + generated, MAX_PROTOTYPES)
                tracker.retain(limited)
                existing_ids = set(tracker.prototypes)
                tracker.add_batch([item for item in limited if str(item.get("id")) not in existing_ids])
                self.prototypes = limited
                self.host.set_status(
                    "睡眠阶段：动作簇"
                    + str(len(self.prototypes))
                    + "；距离缓存"
                    + str(len(self.host.review_distance_cache))
                    + "/"
                    + str(self.host.review_distance_cache.capacity)
                    + "；剩余样本约"
                    + str(max(0, len(self.train) - processed))
                )
                self.host.review_distance_cache.clear()
        except InputStopped:
            self.save_partial_model()
            raise
        tracker.finalize(self.prototypes)
        for index, _ in enumerate(self.prototypes):
            if index % 12 == 0:
                if self.host.should_stop():
                    raise InputStopped("睡眠已停止")
                self.host.set_progress(78 + 7 * (index + 1) / max(1, len(self.prototypes)))

    def save_partial_model(self):
        if not self.prototypes:
            return
        partial = {
            "created": time.time(),
            "samples": len(self.decorrelated),
            "training_samples": len(self.train),
            "invalid_samples": self.stats["invalid"],
            "prototypes": self.prototypes,
            "capture_backends": sorted({str(item.get("capture_method")) for item in self.train}),
            "validation": {
                "status": "stopped",
                "training_checksums": self.train_checksums,
                "holdout_checksums": self.holdout_checksums,
            },
            "sequence_model": {},
            "model_binding": model_binding_from_samples(self.train),
            "safety_profile_checksum": profile_checksum(self.host.store.load_game_profile(self.game["id"])),
            "stopped": True,
        }
        self.host.store.save_model(self.game["id"], partial, False)

    def apply_rejection_constraints(self):
        rejections = self.host.store.load_rejections(self.game["id"], 500)
        self.rejection_constraints = 0
        for proto_index, proto in enumerate(self.prototypes):
            matching = []
            for rejection_index, rejection in enumerate(rejections):
                if (proto_index * max(1, len(rejections)) + rejection_index) % 64 == 0 and self.host.should_stop():
                    raise InputStopped("睡眠已停止")
                candidates = [
                    normalize_semantic_action(item.get("semantic_action") or item.get("a"))
                    for item in rejection.get("candidates", [])
                    if isinstance(item, dict)
                ]
                proto_semantic = normalize_semantic_action(
                    proto.get("semantic_action")
                ) or semantic_action_from_coordinate(proto.get("a"))
                related = any(
                    action
                    and semantic_action_family_key(action) == semantic_action_family_key(proto_semantic)
                    and semantic_action_distance(action, proto_semantic) <= 0.45
                    for action in candidates
                )
                if related:
                    matching.append((coarse_distance(proto["coarse"], rejection["coarse"]), rejection))
            if not matching:
                proto["nearest_rejected_distance"] = None
                continue
            nearest = min(
                batch_feature_distances(
                    proto["f"], [item["f"] for _, item in sorted(matching, key=lambda value: value[0])[:8]]
                )
            )
            proto["nearest_rejected_distance"] = round(nearest, 6)
            proto["threshold"] = round(max(0.001, min(float(proto["threshold"]), nearest * 0.72)), 6)
            self.rejection_constraints += 1

    def build_basic_authorization(self):
        self.basic_cluster_rows = {}
        self.basic_by_signature = defaultdict(
            lambda: {"support": 0, "sessions": set(), "clusters": [], "consistent": 0, "total": 0}
        )
        for cluster in self.action_clusters:
            cluster_id = str(cluster["id"])
            members = list(self.groups.get(cluster_id, []))
            family = semantic_action_family_key(cluster.get("semantic_action"))
            signature = str(
                cluster.get("canonical_action_signature") or semantic_action_signature(cluster.get("semantic_action"))
            )
            sessions = {self.host.review_controller.session_of(item) for item in members}
            limit = max(1e-9, action_cluster_limit(cluster["a"]) * 0.65)
            consistent = sum(
                1
                for item in members
                if semantic_action_distance(sample_semantic_action(item), cluster.get("semantic_action")) <= 0.30
                and (
                    not str(family).startswith("coordinate|")
                    or action_geometry_distance(item["a"], cluster["a"]) <= limit
                )
            )
            consistency = consistent / max(1, len(members))
            cluster_prototypes = [proto for proto in self.prototypes if str(proto.get("cluster_id")) == cluster_id]
            rejection_clear = all(
                proto.get("nearest_rejected_distance") is None
                or float(proto.get("nearest_rejected_distance")) > float(proto.get("threshold", 0.0)) * 1.10
                for proto in cluster_prototypes
            )
            nonambiguous = bool(cluster_prototypes and all(not proto.get("ambiguous") for proto in cluster_prototypes))
            passed = BasicSafeAuthorizer().authorize(
                family, len(members), consistency, len(sessions), nonambiguous, rejection_clear
            )
            self.basic_cluster_rows[cluster_id] = {
                "family": family,
                "signature": signature,
                "support": len(members),
                "sessions": sorted(sessions),
                "consistency": consistency,
                "nonambiguous": nonambiguous,
                "rejection_clear": rejection_clear,
                "passed": passed,
            }
            aggregate = self.basic_by_signature[signature]
            aggregate["support"] += len(members)
            aggregate["sessions"].update(sessions)
            aggregate["clusters"].append(cluster_id)
            aggregate["consistent"] += consistent
            aggregate["total"] += len(members)

    def initialize_holdout_metrics(self):
        self.by_action = defaultdict(
            lambda: {
                "total": 0,
                "accepted": 0,
                "correct": 0,
                "errors": 0,
                "unrecognized": 0,
                "negative_total": 0,
                "false_positive": 0,
            }
        )
        self.by_method = defaultdict(lambda: {"total": 0, "accepted": 0, "correct": 0, "errors": 0})
        self.by_scene = defaultdict(lambda: {"total": 0, "accepted": 0, "correct": 0, "errors": 0})
        self.action_sessions = defaultdict(set)
        self.dangerous_signatures = {
            cluster["canonical_action_signature"]
            for cluster in self.action_clusters
            if str((cluster.get("semantic_action") or {}).get("risk_class", "safe")) != "safe"
            or cluster["a"]["kind"] in {"double_click", "long_press", "drag"}
            or cluster["a"].get("button") in {"right", "middle"}
        }

    def evaluate_holdout_sample(self, sample):
        ranked = self.host.rank_action_candidates(
            sample["f"],
            self.prototypes,
            str(sample.get("context", {}).get("previous_action", "")),
            16,
            sample.get("context", {}),
            sample.get("coarse"),
        )
        decision = self.host.evaluate_action_candidates(ranked)
        expected = sample.get("_action_cluster")
        canonical = sample.get("_canonical_action_signature") or action_signature(sample["a"])
        method = str(sample.get("capture_method") or sample.get("context", {}).get("capture_method") or "unknown")
        scene = visual_scene_key(sample)
        arow, mrow, srow = self.by_action[canonical], self.by_method[method], self.by_scene[scene]
        self.action_sessions[canonical].add(self.host.review_controller.session_of(sample))
        for row in (arow, mrow, srow):
            row["total"] += 1
        predicted_signature = ""
        if expected is not None:
            self.covered_holdout += 1
        if decision.get("accepted"):
            predicted_signature = self.record_accepted_decision(decision, expected, arow, mrow, srow)
        else:
            arow["unrecognized"] += 1
            if expected is None:
                self.uncovered_rejected += 1
                self.correct += 1
                for row in (arow, mrow, srow):
                    row["correct"] += 1
        for signature in self.dangerous_signatures:
            if canonical != signature:
                self.by_action[signature]["negative_total"] += 1
                if predicted_signature == signature:
                    self.by_action[signature]["false_positive"] += 1

    def record_accepted_decision(self, decision, expected, arow, mrow, srow):
        self.accepted += 1
        for row in (arow, mrow, srow):
            row["accepted"] += 1
        predicted = decision["best"]
        signature = str(predicted.get("canonical_action_signature") or action_signature(predicted["a"]))
        if expected is not None and predicted["cluster_id"] == expected:
            self.correct += 1
            for row in (arow, mrow, srow):
                row["correct"] += 1
            return signature
        self.errors += 1
        for row in (arow, mrow, srow):
            row["errors"] += 1
        if expected is None:
            self.uncovered_false_accept += 1
        action = normalize_action(predicted["a"])
        semantic = normalize_semantic_action(
            predicted.get("semantic_action") or predicted.get("proto", {}).get("semantic_action")
        ) or semantic_action_from_coordinate(action)
        if (
            str(semantic.get("risk_class", "safe")) != "safe"
            or action["kind"] in {"double_click", "long_press", "drag"}
            or action.get("button") in {"right", "middle"}
        ):
            self.dangerous_false += 1
        return signature

    def evaluate_holdout(self):
        self.initialize_holdout_metrics()
        for index, sample in enumerate(self.holdout):
            if index % 8 == 0 and self.host.should_stop():
                raise InputStopped("睡眠已停止")
            self.evaluate_holdout_sample(sample)
            if index % 5 == 0:
                self.host.set_progress(85 + 13 * (index + 1) / max(1, len(self.holdout)))
        self.holdout_count = len(self.holdout)
        self.coverage = self.accepted / self.covered_holdout if self.covered_holdout else 0.0
        self.accepted_error_rate = self.errors / self.accepted if self.accepted else None
        self.error_upper_95 = binomial_error_upper(self.errors, self.accepted, 0.95)
        self.overall_accuracy = self.correct / self.holdout_count if self.holdout_count else 0.0
        self.dangerous_false_rate = self.dangerous_false / max(1, self.holdout_count)

    def summarize_action_rules(self):
        self.per_action = {}
        self.action_rules_pass = True
        self.authorized_clusters = set()
        train_signatures = {
            str(item.get("_canonical_action_signature", action_signature(item["a"]))) for item in self.train
        }
        for signature in sorted(train_signatures | set(self.by_action)):
            row = dict(self.by_action[signature])
            row["recall"] = row["correct"] / row["total"] if row["total"] else 0.0
            row["coverage"] = row["accepted"] / row["total"] if row["total"] else 0.0
            row["accepted_error_rate"] = row["errors"] / row["accepted"] if row["accepted"] else None
            row["error_upper_95"] = binomial_error_upper(row["errors"], row["accepted"], 0.95)
            row["independent_sessions"] = len(self.action_sessions.get(signature, set()))
            action = next(
                (
                    cluster["a"]
                    for cluster in self.action_clusters
                    if cluster["canonical_action_signature"] == signature
                ),
                {"kind": "no_op"},
            )
            dangerous = action["kind"] in {"double_click", "long_press", "drag"} or action.get("button") in {
                "right",
                "middle",
            }
            row["dangerous"] = dangerous
            row_pass = ReviewValidator().authorize(row, dangerous)
            basic = self.basic_by_signature.get(signature)
            basic_pass = bool(
                not dangerous
                and basic
                and any(self.basic_cluster_rows.get(cluster_id, {}).get("passed") for cluster_id in basic["clusters"])
            )
            row.update(
                {
                    "basic_training_support": int(basic["support"]) if basic else 0,
                    "basic_training_sessions": len(basic["sessions"]) if basic else 0,
                    "basic_training_consistency": basic["consistent"] / max(1, basic["total"]) if basic else 0.0,
                    "basic_safe_passed": basic_pass,
                    "passed": bool(row_pass),
                    "authorized": bool(row_pass or basic_pass),
                }
            )
            for cluster in self.action_clusters:
                if cluster["canonical_action_signature"] == signature and (
                    row_pass or self.basic_cluster_rows.get(str(cluster["id"]), {}).get("passed")
                ):
                    self.authorized_clusters.add(cluster["id"])
            self.per_action[signature] = row

    def summarize_method_rules(self):
        self.train_methods = sorted({str(item.get("capture_method")) for item in self.train})
        self.per_method = {}
        self.method_rules_pass = True
        for method in sorted(set(self.train_methods) | set(self.by_method)):
            row = dict(self.by_method[method])
            row["accuracy"] = row["correct"] / row["total"] if row["total"] else 0.0
            row["coverage"] = row["accepted"] / row["total"] if row["total"] else 0.0
            row["accepted_error_rate"] = row["errors"] / row["accepted"] if row["accepted"] else None
            row["error_upper_95"] = binomial_error_upper(row["errors"], row["accepted"], 0.95)
            row["passed"] = bool(
                row["total"] >= VersionedThresholdConfig.capture_min_holdout
                and row["errors"] <= VersionedThresholdConfig.capture_max_errors
                and row["accuracy"] >= VersionedThresholdConfig.capture_min_accuracy
            )
            self.method_rules_pass = self.method_rules_pass and row["passed"]
            self.per_method[method] = row

    def summarize_scene_rules(self):
        self.per_scene = {}
        self.scene_rules_pass = True
        for scene, row_value in sorted(self.by_scene.items()):
            row = dict(row_value)
            row["accuracy"] = row["correct"] / row["total"] if row["total"] else 0.0
            row["coverage"] = row["accepted"] / row["total"] if row["total"] else 0.0
            row["error_upper_95"] = binomial_error_upper(row["errors"], row["accepted"], 0.95)
            row["passed"] = bool(
                row["total"] >= VersionedThresholdConfig.scene_min_holdout
                and row["errors"] <= VersionedThresholdConfig.scene_max_errors
                and row["accuracy"] >= VersionedThresholdConfig.scene_min_accuracy
            )
            self.scene_rules_pass = self.scene_rules_pass and row["passed"]
            self.per_scene[scene] = row

    def authorize_prototypes(self):
        full_clusters = set()
        for signature, row in self.per_action.items():
            if row.get("passed"):
                full_clusters.update(
                    cluster["id"]
                    for cluster in self.action_clusters
                    if cluster["canonical_action_signature"] == signature
                )
        for proto in self.prototypes:
            cluster_id = str(proto.get("cluster_id"))
            basic_safe = bool(self.basic_cluster_rows.get(cluster_id, {}).get("passed"))
            full_safe = cluster_id in full_clusters
            proto["authorized"] = bool((full_safe or basic_safe) and not proto.get("ambiguous"))
            proto["authorization_level"] = "full" if full_safe else "basic_safe" if basic_safe else "none"
            runtime = action_runtime_metadata(proto.get("a"))
            proto.update(
                {
                    "strictness": runtime["strictness"],
                    "cooldown": runtime["cooldown"],
                    "dangerous": runtime["dangerous"],
                }
            )
        self.authorized_prototypes = sum(1 for proto in self.prototypes if proto.get("authorized"))
        self.full_authorized_prototypes = sum(
            1 for proto in self.prototypes if proto.get("authorized") and proto.get("authorization_level") == "full"
        )
        self.basic_safe_prototypes = sum(
            1
            for proto in self.prototypes
            if proto.get("authorized") and proto.get("authorization_level") == "basic_safe"
        )

    def determine_validation_status(self):
        enough, global_pass = evaluate_validation_thresholds(
            self.split_info.get("complete"),
            self.split_info.get("session_count", 0),
            self.holdout_count,
            self.accepted,
            self.coverage,
            self.overall_accuracy,
            self.error_upper_95,
            self.dangerous_false,
            self.uncovered_false_accept,
        )
        enough = bool(enough and self.train_methods)
        action_rules_pass = self.full_authorized_prototypes > 0
        passed = bool(
            enough
            and global_pass
            and action_rules_pass
            and self.method_rules_pass
            and self.scene_rules_pass
            and self.prototypes
        )
        basic_available = bool(self.basic_safe_prototypes > 0 and self.train_methods)
        self.validation_status = (
            "passed"
            if passed
            else (
                "basic_safe"
                if basic_available
                else "insufficient" if not enough or not action_rules_pass or not self.method_rules_pass else "failed"
            )
        )

    def build_validation(self):
        self.validation = {
            "status": self.validation_status,
            "split": str(self.split_info.get("mode", "unknown")),
            "split_complete": bool(self.split_info.get("complete")),
            "split_reason": str(self.split_info.get("reason", "")),
            "strata": int(self.split_info.get("strata", 0)),
            "session_count": int(self.split_info.get("session_count", 0)),
            "holdout_sessions": sorted(self.holdout_sessions),
            "required_sessions": VersionedThresholdConfig.required_sessions,
            "minimum_holdout": VersionedThresholdConfig.review_min_holdout,
            "minimum_accepted": VersionedThresholdConfig.review_min_accepted,
            "minimum_ordinary_action_holdout": VersionedThresholdConfig.ordinary_min_positive,
            "minimum_ordinary_sessions": VersionedThresholdConfig.ordinary_min_sessions,
            "minimum_dangerous_positive": VersionedThresholdConfig.dangerous_min_positive,
            "minimum_dangerous_negative": VersionedThresholdConfig.dangerous_min_negative,
            "minimum_dangerous_sessions": VersionedThresholdConfig.dangerous_min_sessions,
            "minimum_coverage": VersionedThresholdConfig.minimum_coverage,
            "maximum_error_upper_95": VersionedThresholdConfig.maximum_error_upper_95,
            "minimum_overall_accuracy": VersionedThresholdConfig.minimum_overall_accuracy,
            "maximum_dangerous_false": VersionedThresholdConfig.maximum_dangerous_false,
            "maximum_uncovered_false_accept": VersionedThresholdConfig.maximum_uncovered_false_accept,
            "capture_min_holdout": VersionedThresholdConfig.capture_min_holdout,
            "capture_min_accuracy": VersionedThresholdConfig.capture_min_accuracy,
            "capture_max_errors": VersionedThresholdConfig.capture_max_errors,
            "scene_min_holdout": VersionedThresholdConfig.scene_min_holdout,
            "scene_min_accuracy": VersionedThresholdConfig.scene_min_accuracy,
            "scene_max_errors": VersionedThresholdConfig.scene_max_errors,
        }
        self.validation.update(self.validation_measurements())

    def validation_measurements(self):
        return {
            "holdout": self.holdout_count,
            "accepted": self.accepted,
            "errors": self.errors,
            "correct": self.correct,
            "coverage": self.coverage,
            "reject_rate": 1.0 - self.coverage,
            "accepted_error_rate": self.accepted_error_rate,
            "error_upper_95": self.error_upper_95,
            "overall_accuracy": self.overall_accuracy,
            "dangerous_false": self.dangerous_false,
            "dangerous_false_rate": self.dangerous_false_rate,
            "uncovered_actions": self.uncovered_actions,
            "uncovered_rejected": self.uncovered_rejected,
            "uncovered_false_accept": self.uncovered_false_accept,
            "covered_holdout": self.covered_holdout,
            "authorized_prototypes": self.authorized_prototypes,
            "full_authorized_prototypes": self.full_authorized_prototypes,
            "basic_safe_prototypes": self.basic_safe_prototypes,
            "authorized_families": sorted(
                {action_family_key(proto["a"]) for proto in self.prototypes if proto.get("authorized")}
            ),
            "basic_safe_authorized_families": sorted(
                {
                    action_family_key(proto["a"])
                    for proto in self.prototypes
                    if proto.get("authorization_level") == "basic_safe" and proto.get("authorized")
                }
            ),
            "basic_cluster_validation": self.basic_cluster_rows,
            "decorrelated_removed": self.decorrelated_removed,
            "per_action": self.per_action,
            "per_capture_method": self.per_method,
            "per_scene": self.per_scene,
            "visual_group_intersection": list(self.split_info.get("visual_group_intersection", [])),
            "ambiguous_prototypes": sum(1 for proto in self.prototypes if proto.get("ambiguous")),
            "training_checksums": self.train_checksums,
            "holdout_checksums": self.holdout_checksums,
            "checksum_intersection": [],
        }

    def build_sequence_model(self):
        counts = defaultdict(Counter)
        train_by_session = defaultdict(list)
        for item in self.train:
            train_by_session[self.host.review_controller.session_of(item)].append(item)
        default_task_id = normalized_identifier(
            self.host.store.load_game_profile(self.game["id"]).get("default_task_id"), "default", 96
        )
        for _, session_items in sorted(train_by_session.items()):
            ordered = sorted(session_items, key=lambda item: float(item.get("created", 0.0)))
            history = deque(["<START>", "<START>", "<START>", "<START>"], maxlen=4)
            for item in ordered:
                context = item.get("context", {}) if isinstance(item.get("context"), dict) else {}
                semantic = normalize_semantic_action(context.get("semantic_action")) or semantic_action_from_coordinate(
                    item.get("a")
                )
                skill = semantic_skill(semantic, str(context.get("subgoal_id") or "advance_goal"))
                skill_key = skill.key()
                if not skill_key:
                    continue
                task_id = normalized_identifier(context.get("task_id"), default_task_id, 96)
                prefix = task_id + "|"
                for size in range(1, 5):
                    counts[prefix + str(size) + "|" + "|".join(list(history)[-size:])][skill_key] += 1
                counts[prefix + history[-1]][skill_key] += 1
                history.append(skill_key)
        self.sequence_model = {key: dict(value) for key, value in counts.items()}

    def _build_model_base(self):
        profile = self.host.store.load_game_profile(self.game["id"])
        tasks = self.host.store.list_tasks(self.game["id"], True)
        default_task_id = normalized_identifier(profile.get("default_task_id"), "default", 96)
        events = self.host.store.load_ocr_experience_events(self.game["id"], 5000)
        experiences, experience_model = self.host.review_controller.build_experiences(self.train, events, profile)
        self.host.store.replace_episode_trajectories(self.game["id"], experiences, current_build_hash())
        replay_bundles = build_anonymized_replay_bundles(experiences, current_build_hash())
        replay_paths = persist_replay_bundles(self.host.store.base, self.game["id"], replay_bundles)
        experience_portfolio = ExperienceReplayPortfolio.build(experiences)
        training_experiences = ExperienceReplayPortfolio.partition(
            experiences, experience_portfolio, "train", MAX_TRAINING_SAMPLES
        )
        semantic_encoder = train_shared_semantic_encoder(training_experiences)
        task_induction = TaskInductionEngine.induce(training_experiences, self.game["id"])
        temporal_termination_model = train_temporal_termination_model(training_experiences)
        discovered_skills = AutomaticSkillDiscovery.discover(training_experiences)
        behavior_model, value_model, risk_model, enough_models = build_offline_policy_models(
            experience_model, training_experiences, default_task_id
        )
        decision_calibration = {
            "source": "holdout_auto_calibration" if enough_models else "cold_start_defaults",
            "minimum_score_gap": max(6.0, min(24.0, 12.0 * (1.0 - self.coverage) + 6.0)),
            "margin_ratio": max(0.06, min(0.18, self.error_upper_95 + 0.06)),
            "maximum_risk_probability": max(
                0.20,
                min(
                    RUNTIME_THRESHOLDS.risk_reject_probability - 0.02,
                    RUNTIME_THRESHOLDS.risk_reject_probability - self.error_upper_95,
                ),
            ),
            "maximum_ood_uncertainty": max(
                0.52,
                min(RUNTIME_THRESHOLDS.maximum_ood, RUNTIME_THRESHOLDS.maximum_ood - self.error_upper_95),
            ),
            "minimum_behavior_probability": 0.03 if enough_models else 0.0,
            "minimum_behavior_gap": max(0.05, min(0.18, self.error_upper_95 + 0.05)),
            "holdout_count": self.holdout_count,
            "accepted_count": self.accepted,
            "coverage": self.coverage,
            "error_upper_95": self.error_upper_95,
        }
        contexts = [item.get("context", {}) for item in self.decorrelated if isinstance(item.get("context"), dict)]
        resolution_groups = sorted(
            {str(value.get("window_size")) + "|dpi=" + str(value.get("dpi")) for value in contexts}
        )
        ui_groups = sorted(
            {str(value.get("ui_variant") or value.get("object_signature") or "unknown") for value in contexts}
        )
        generalization = {
            "same_game_different_session": {
                "train_sessions": sorted({self.host.review_controller.session_of(item) for item in self.train}),
                "holdout_sessions": sorted(self.holdout_sessions),
                "passed": bool(self.split_info.get("complete")),
            },
            "same_task_different_resolution": {
                "groups": resolution_groups,
                "group_count": len(resolution_groups),
                "evaluated": len(resolution_groups) > 1,
            },
            "same_game_different_ui_or_save": {
                "groups": ui_groups[:128],
                "group_count": len(ui_groups),
                "evaluated": len(ui_groups) > 1,
            },
            "unseen_game": {
                "evaluated": False,
                "passed": False,
                "reason": "需要至少另一游戏的隔离数据集后才能宣称跨游戏迁移",
            },
        }
        skill_counts = Counter(str(item.get("skill_id", "unknown")) for item in experiences)
        skill_library = {
            name: {"count": count, "schema_version": SKILL_SCHEMA_VERSION}
            for name, count in sorted(skill_counts.items())
        }
        sleep_seed = safe_int(getattr(self.host, "sleep_seed", 0), 0, 0, 2**63 - 1)
        plan = RESOURCE_GOVERNOR.current_plan()
        hardware_training_profile = current_hardware_training_profile(self.host.store.base)
        self.model = {
            "created": time.time(),
            "model_version": MODEL_SCHEMA_VERSION,
            "configuration_version": RUNTIME_THRESHOLDS.version,
            "runtime_thresholds": RUNTIME_THRESHOLDS.to_dict(),
            "model_tier": plan.model_tier,
            "policy_state_size": plan.policy_state_size,
            "policy_hidden_size": plan.policy_hidden_size,
            "policy_ensemble_size": plan.policy_ensemble_size,
            "temporal_context_length": plan.temporal_context_length,
            "world_model_horizon": plan.world_model_horizon,
            "object_slot_count": plan.object_slot_count,
            "compatibility_signature": compatibility_signature(),
            "training_hardware_profile": hardware_training_profile,
            "sleep_seed": sleep_seed,
            "temporal_encoder_seed": sleep_seed,
            "determinism": {
                "seed": sleep_seed,
                "build_hash": current_build_hash(),
                "training_checksums_hash": hashlib.sha256(canonical_bytes(self.train_checksums)).hexdigest(),
                "holdout_checksums_hash": hashlib.sha256(canonical_bytes(self.holdout_checksums)).hexdigest(),
            },
            "samples": len(self.decorrelated),
            "training_samples": len(self.train),
            "holdout_samples": len(self.holdout),
            "invalid_samples": self.stats["invalid"],
            "action_clusters": len(self.action_clusters),
            "rejection_constraints": self.rejection_constraints,
            "prototypes": self.prototypes,
            "capture_backends": self.train_methods,
            "validation": self.validation,
            "generalization_evaluation": generalization,
            "training_checksums": self.train_checksums,
            "holdout_checksums": self.holdout_checksums,
            "sequence_model": self.sequence_model,
            "experiences": experiences,
            "experience_model": experience_model,
            "demonstration_curriculum": demonstration_curriculum_assessment(experiences),
            "behavior_model": behavior_model,
            "value_model": value_model,
            "risk_model": risk_model,
            "offline_rl_training": value_model.get("training_diagnostics", {}),
            "semantic_encoder": semantic_encoder,
            "deduplicated_training_count": len(training_experiences),
            "capability_profile": CapabilityProfile(profile).to_dict(),
            "training_data_split": experience_portfolio.get("immutable_training_manifest", {}),
            "decision_calibration": decision_calibration,
            "episode_metrics": summarize_episode_metrics(experiences),
            "default_task_id": default_task_id,
            "task_ids": sorted({str(item.get("task_id", "default")) for item in tasks}),
            "task_definitions_checksum": task_definitions_checksum(tasks),
            "task_definitions": tasks,
            "skill_library": skill_library,
            "policy_score_weights": normalized_policy_score_weights(profile.get("policy_score_weights")),
            "decision_architecture": "task_conditioned_neural_double_q_iql_awr_cql_bootstrap+risk_model+independent_safety_shield",
            "state_architecture": (
                "dynamic_64x36_to_160x90_fast_path+dynamic_224_to_384_semantic_path+"
                "high_resolution_ocr_roi+derived_audio_keyboard_gamepad_features+object_slots+scene_graph+goal+memory"
            ),
            "semantic_action_schema_version": SEMANTIC_ACTION_SCHEMA_VERSION,
            "observation_schema_version": OBSERVATION_SCHEMA_VERSION,
            "skill_schema_version": SKILL_SCHEMA_VERSION,
            "state_key_algorithm_version": STATE_KEY_ALGORITHM_VERSION,
            "model_hierarchy": {
                "shared_visual_encoder": True,
                "shared_semantic_action_space": True,
                "shared_skill_library": True,
                "game_adapter": "lightweight",
                "task_policy_head": True,
                "atomic_action_as_skill_parameter": True,
            },
            "model_binding": model_binding_from_samples(self.train),
            "safety_profile_checksum": profile_checksum(profile),
            "stopped": False,
        }
        self.model["replay_bundles"] = {
            "schema_version": REPLAY_BUNDLE_SCHEMA_VERSION,
            "count": len(replay_bundles),
            "paths": replay_paths,
            "evaluations": [ReplayEvaluator.evaluate(value) for value in replay_bundles[:64]],
        }
        self.model["task_induction"] = task_induction
        self.model["temporal_termination_model"] = temporal_termination_model
        self.model["automatic_skill_discovery"] = discovered_skills
        self.model["experience_replay_portfolio"] = experience_portfolio
        self.model["reward_hacking_guard"] = {
            "enabled": True,
            "detectors": [
                "repeated_local_reward_without_completion",
                "visual_oscillation_reward",
                "repeated_unconfirmed_success_text",
                "meaningless_delay_or_no_effect_loop",
            ],
            "conflict_policy": "stop_and_enter_guidance",
        }
        self.model["real_time_budgets_ms"] = dict(REALTIME_BUDGET_MS)
        for discovered in discovered_skills.get("skills", []):
            self.model["skill_library"][str(discovered.get("skill_id"))] = dict(discovered)

    def build_model(self):
        self._build_model_base()
        experiences = self.model.get("experiences", [])
        portfolio = self.model.get("experience_replay_portfolio", {})
        training_experiences = ExperienceReplayPortfolio.partition(
            experiences, portfolio, "train", MAX_TRAINING_SAMPLES
        )
        experience_model = self.model.get("experience_model", {})
        self.model["candidate_ranker"] = LearnedCandidateRankingHead.train(
            experience_model,
            training_experiences,
            safe_int(self.model.get("sleep_seed"), 0),
            self.model.get("semantic_encoder"),
        )
        self.model["world_model"] = train_latent_world_model(training_experiences, self.model.get("semantic_encoder"))
        self.model["world_model"]["semantic_encoder"] = self.model.get("semantic_encoder", {})
        self.model["auditable_transition_model"] = self.model["world_model"].get("auditable_transition_model", {})
        self.model["learned_subgoal_planner"] = train_learned_subgoal_planner(
            training_experiences, self.model.get("task_definitions", [])
        )
        self.model["skill_contracts"] = {key: dict(value) for key, value in SKILL_CONTRACTS.items()}
        profile = self.host.store.load_game_profile(self.game["id"])
        fingerprint = model_evaluation_fingerprint(
            self.game["id"], self.train_checksums, self.model.get("decision_architecture", "")
        )
        benchmark = FixedGeneralizationBenchmark.load(self.host.store.base, fingerprint)
        self.model["evaluation_model_fingerprint"] = fingerprint
        self.model["generalization_benchmark"] = {key: value for key, value in benchmark.items() if key != "rows"}
        self.model["generalization_evaluation"] = GeneralizationEvaluator.evaluate(
            self.train,
            benchmark.get("rows", []),
            [],
            self.game["id"],
            str(profile.get("game_type", "ui_game")),
            benchmark.get("manifest", {}),
            benchmark,
        )
        self.model["model_scope"] = generalization_model_scope(self.model["generalization_evaluation"])
        self.model["validation"]["model_scope"] = self.model["model_scope"]
        self.model["validation"]["generalization_benchmark_verified"] = bool(
            self.model["generalization_evaluation"].get("benchmark_verified")
        )
        self.model["validation"]["generalization_level_3_4_passed"] = self.model["model_scope"] == "general_model"
        self.model["validation"]["evaluation_model_fingerprint"] = fingerprint
        split_manifest = self.model.get("experience_replay_portfolio", {}).get("immutable_training_manifest", {})
        self.model["validation"]["game_id_isolated_split"] = bool(split_manifest.get("game_id_isolated"))
        self.model["validation"]["game_id_split_complete"] = bool(split_manifest.get("split_complete"))
        self.model["validation"]["game_id_split_reason"] = str(split_manifest.get("split_reason", ""))
        self.model["capability_profile"] = CapabilityProfile(profile).to_dict()
        self.model["sleep_pipeline"] = {
            "schema_version": 3,
            "phases": list(SLEEP_PIPELINE_PHASES),
            "training_sample_limit": MAX_TRAINING_SAMPLES,
            "prototype_online_limit": MAX_PROTOTYPES,
            "stratified_sampling": True,
            "game_id_isolated_validation_and_test": True,
            "split_status": split_manifest.get("split_status", "not_evaluated"),
        }
        self.model["decision_architecture"] = (
            "skill_generation+task_conditioned_neural_double_q_target_networks+iql_expectile+advantage_weighted_bc+cql+behavior_support+bootstrap_uncertainty+risk_calibration+sequence_world_model+hierarchical_predicate_planner+independent_safety_lease"
        )
        self.model["state_architecture"] = (
            "dynamic_64x36_to_160x90_auditable_fast_path+"
            "224_to_384_semantic_global_path+adaptive_high_resolution_ocr_roi+"
            "derived_audio_keyboard_gamepad_features+high_resolution_local_crops+"
            "object_slots+open_vocabulary_affordances+tracked_scene_graph+"
            "temporal_memory+goal_embedding+manual_safety_fallback"
        )
        self.model["model_hierarchy"] = {
            "shared_backbone": {"read_only": True, "updated_by_game_training": False},
            "game_type_adapter": {"kind": "low_rank_residual_film", "rank": ADAPTER_RANK},
            "game_specific_adapter": {"kind": "low_rank_residual_film", "rank": ADAPTER_RANK},
            "balanced_replay_required_for_shared_update": True,
            "distillation_required_for_shared_update": True,
            "parameter_change_constraint_required": True,
            "old_task_regression_required": True,
            "automatic_rollback_required": True,
        }
        self.model["active_learning"] = {
            "triggers": [
                "multiple_close_actions",
                "policy_value_disagreement",
                "risk_model_reject",
                "new_object_class",
                "out_of_distribution",
                "continuous_no_effect",
                "low_reward_confidence",
                "world_model_disagreement",
                "unknown_numeric_region",
                "low_ocr_confidence",
                "ocr_temporal_disagreement",
                "numeric_relation_unknown",
                "numeric_direction_conflict",
                "numeric_value_correlated_with_policy_uncertainty",
            ],
            "question_outputs": [
                "task_complete",
                "target_object",
                "failure_state",
                "action_preference",
                "object_change",
                "reusable_skill",
                "numeric_region_type",
                "ocr_confirmation",
                "ocr_correction",
                "numeric_goal_relation",
                "numeric_context_rule",
            ],
            "information_gain_ordering": True,
            "resume_from_safe_snapshot": True,
        }

    def report_lines(self):
        label = (
            "通过完整独立验收"
            if self.validation_status == "passed"
            else (
                "已生成基础安全模型，可训练已授权的普通安全动作"
                if self.validation_status == "basic_safe"
                else (
                    "验证不足，仅保存不可训练临时模型"
                    if self.validation_status == "insufficient"
                    else "验证失败，仅保存不可训练临时模型"
                )
            )
        )
        error_text = (
            "无可计算值" if self.accepted_error_rate is None else str(round(self.accepted_error_rate * 100, 2)) + "%"
        )
        headline = (
            "睡眠完成，"
            + label
            + "：原型"
            + str(len(self.prototypes))
            + "，独立session留出"
            + str(self.holdout_count)
            + "，接受"
            + str(self.accepted)
            + "，覆盖率"
            + str(round(self.coverage * 100, 2))
            + "%，接受错误率"
            + error_text
            + "，95%错误率上界"
            + str(round(self.error_upper_95 * 100, 2))
            + "%，未覆盖动作"
            + str(self.uncovered_actions)
            + "，连续帧去相关移除"
            + str(self.decorrelated_removed)
            + ("；留出失败原因：" + str(self.split_info.get("reason")) if self.split_info.get("reason") else "")
        )
        lines = [headline, "各动作独立留出验证："]
        for signature, row in sorted(self.per_action.items()):
            authorization = (
                "完整授权" if row["passed"] else "基础安全授权" if row.get("basic_safe_passed") else "未授权"
            )
            lines.append(
                signature
                + "：独立留出正例"
                + str(row["total"])
                + "，负例"
                + str(row["negative_total"])
                + "，接受"
                + str(row["accepted"])
                + "，错误"
                + str(row["errors"])
                + "，危险误触"
                + str(row["false_positive"])
                + "，训练支持"
                + str(row.get("basic_training_support", 0))
                + "，一致率"
                + str(round(float(row.get("basic_training_consistency", 0.0)) * 100, 2))
                + "%，"
                + authorization
            )
        lines.append("各采集后端独立验证：")
        for method, row in sorted(self.per_method.items()):
            lines.append(
                method
                + "：留出"
                + str(row["total"])
                + "，覆盖率"
                + str(round(row["coverage"] * 100, 2))
                + "%，错误"
                + str(row["errors"])
                + "，"
                + ("通过" if row["passed"] else "未通过")
            )
        lines.append("各视觉场景分层验证：")
        for scene, row in sorted(self.per_scene.items()):
            lines.append(
                scene
                + "：留出"
                + str(row["total"])
                + "，准确率"
                + str(round(row["accuracy"] * 100, 2))
                + "%，错误"
                + str(row["errors"])
                + "，"
                + ("通过" if row["passed"] else "未通过")
            )
        return lines

    def finalize(self):
        if not self.prototypes:
            raise RuntimeError("睡眠未生成可用原型")
        try:
            champion = self.host.store.load_model(self.game["id"])
        except RuntimeError:
            champion = None
        fingerprint = str(self.model.get("evaluation_model_fingerprint", ""))
        online_records = self.host.store.load_online_acceptance_records(self.game["id"], fingerprint)
        paired_benchmark = PairedHumanAIBenchmark.evaluate(
            self.model.get("experiences", []), self.model, online_records
        )
        self.model["human_ai_benchmark"] = paired_benchmark
        promotion = ModelPromotionGate.evaluate(champion, self.model, self.validation_status)
        self.model["promotion"] = promotion
        self.model.setdefault("validation", {})["online_acceptance_pending"] = bool(
            promotion.get("pending_online_acceptance")
        )
        self.model["online_acceptance_contract"] = {
            "schema_version": ONLINE_ACCEPTANCE_SCHEMA_VERSION,
            "model_fingerprint": fingerprint,
            "minimum_real_episodes_per_task": RUNTIME_THRESHOLDS.online_acceptance_minimum_episodes,
            "target_real_episodes_per_task": RUNTIME_THRESHOLDS.online_acceptance_target_episodes,
            "maximum_real_episodes_per_task": RUNTIME_THRESHOLDS.online_acceptance_maximum_episodes,
            "fixed_initial_state_or_repeatable_restart_required": True,
            "offline_results_cannot_promote": True,
        }
        saved = False
        disposition = "discarded"
        if promotion.get("promote"):
            self.host.store.save_model(self.game["id"], self.model, True)
            saved = True
            disposition = "promoted_to_champion_after_real_online_acceptance"
        elif promotion.get("pending_online_acceptance") and self.validation_status == "passed":
            self.host.store.save_model(self.game["id"], self.model, False)
            saved = True
            disposition = "saved_as_online_acceptance_challenger"
        elif not champion and self.validation_status == "basic_safe":
            self.host.store.save_model(self.game["id"], self.model, False)
            saved = True
            disposition = "saved_as_basic_safe_partial"
        self.host.review_distance_cache.clear()
        self.host.set_progress(100)
        lines = self.report_lines()
        benchmark = self.model.get("human_ai_benchmark", {})
        human = benchmark.get("human", {}) if isinstance(benchmark, dict) else {}
        ai = benchmark.get("ai", {}) if isinstance(benchmark, dict) else {}
        lines.append(
            "两级门禁：真实在线评估"
            + str(benchmark.get("evaluation_episodes", 0))
            + "局，AI成功率95%下界"
            + str(round(safe_float(ai.get("success_rate_lower_bound"), 0.0) * 100, 2))
            + "%（绝对门槛80%），用户成功率95%下界"
            + str(round(safe_float(human.get("success_rate_lower_bound"), 0.0) * 100, 2))
            + "%（非劣界限5%），AI危险误放"
            + str(safe_int(ai.get("dangerous_actions"), 0))
        )
        lines.append("模型发布结果：" + disposition + ("" if saved else "；challenger未替换champion"))
        return ModeResult(
            "completed",
            "\n".join(lines),
            {"validation": self.validation_status, "promotion": promotion, "saved": saved, "disposition": disposition},
        )

    def run(self):
        self.preflight()
        self.prepare_action_groups()
        self.build_prototypes()
        self.apply_rejection_constraints()
        self.build_basic_authorization()
        self.evaluate_holdout()
        self.summarize_action_rules()
        self.summarize_method_rules()
        self.summarize_scene_rules()
        self.authorize_prototypes()
        self.determine_validation_status()
        self.build_validation()
        self.build_sequence_model()
        self.build_model()
        return self.finalize()


class TrainingController:
    def __init__(self, context, host=None):
        if isinstance(context, ModeContext):
            self.context = context
            self.host = host
        else:
            self.context = ModeContext.from_host(context)
            self.host = context
        self.interference_detector = TrainingInterferenceDetector()
        self.frame_gate = TrainingFrameGate()
        self.confirmer = TrainingCandidateConfirmer()
        self.authorizer = TrainingActionAuthorizer()
        self.post_verifier = TrainingPostActionVerifier()

    def interference(self, mouse_event, keyboard_event):
        return self.interference_detector.tripped(mouse_event, keyboard_event)

    def usable_frame(self, frame, backend):
        return self.frame_gate.usable(frame, backend)

    def confirmed(self, count, required):
        return self.confirmer.confirmed(count, required)

    def authorized(self, proto):
        return self.authorizer.authorized(proto)

    def changed(self, before, after, threshold):
        return self.post_verifier.changed(before, after, threshold)

    def run(self):
        return TrainingRunner(ModeContext.from_host(self.host), self, self.host).run()

    def _run_impl(self, phase=None):
        return TrainingExecution(self, phase).run()


class TrainingExecution:
    def __init__(self, controller, phase=None):
        self.controller = controller
        self.host = controller.host
        self.phase = phase if isinstance(phase, dict) else {}
        self.actions = 0
        self.keyboard_count = 0
        self.mouse_count = 0
        self.recent_actions = deque(["<START>", "<START>"], maxlen=32)
        self.candidate_id = None
        self.candidate_count = 0
        self.candidate_frame_stamp = 0.0
        self.last_action_signature = ""
        self.last_cluster_id = ""
        self.last_action_time = 0.0
        self.last_action_feature = None
        self.state_unlocked = True
        self.no_change_count = 0
        self.previous_feature = None
        self.previous_frame_stamp = 0.0
        self.state_since = time.monotonic()
        self.action_hits = defaultdict(deque)
        self.snapshot_last_check = 0.0
        self.guidance_requests = 0
        self.last_guidance_reason = ""
        self.guidance_request_last_time = 0.0
        self.guidance_trigger_streak = 0
        self.recent_action_results = deque(maxlen=32)
        self.safety_lease_broker = None
        self.skill_runtime = {"skill_id": "", "started": 0.0, "repeats": 0, "last_environment": ""}
        self.online_acceptance_mode = False
        self.online_model_fingerprint = ""
        self.online_records = []
        self.online_episode_started = 0.0
        self.online_episode_action_count = 0
        self.online_episode_dangerous = 0
        self.online_episode_stuck = False
        self.online_episode_id = ""
        self.online_episode_recorded = False
        self.last_captured_frame = None
        self.last_ranked_candidates = []
        self.last_decision_snapshot = {}
        self.last_selection_for_correction = None
        self.corrective_workflow = None
        self.task_graph_memory = None

    def _base_preflight_strict(self):
        self.game = self.phase.get("game") or self.host.require_game()
        self.corrective_workflow = CorrectiveLearningWorkflow(self.host.store.base, self.game["id"])
        self.task_graph_memory = PersistentTaskGraph(self.host.store.base, self.game["id"])
        self.runtime_session_id = "ai|" + uuid.uuid4().hex
        self.host.mode_session_id = self.runtime_session_id
        self.target = dict(self.phase.get("window") or self.host.require_window(False))
        self.target.update(
            {
                "game_id": str(self.game["id"]),
                "session_id": self.runtime_session_id,
                "window_generation": safe_int(getattr(self.host, "window_generation", 0), 0, 0),
            }
        )
        self.target["window_key"] = runtime_isolation_key(
            self.game["id"], self.runtime_session_id, self.target, self.target["window_generation"]
        )
        clear_runtime_isolation(key=self.target["window_key"])
        self.model = self.host.store.load_trainable_model(self.game["id"])
        self.host.validate_model_binding(self.model, self.target)
        base_profile = self.host.store.load_game_profile(self.game["id"])
        self.online_acceptance_mode = bool(
            self.model.get("online_acceptance_candidate")
            or self.model.get("promotion", {}).get("pending_online_acceptance")
            or self.model.get("validation", {}).get("online_acceptance_pending")
        )
        self.online_model_fingerprint = str(
            self.model.get("evaluation_model_fingerprint")
            or self.model.get("validation", {}).get("evaluation_model_fingerprint")
            or ""
        )
        if self.online_acceptance_mode:
            if not self.online_model_fingerprint:
                raise RuntimeError("待在线验收模型缺少不可变模型指纹")
            restart = normalize_action(base_profile.get("restart_action"))
            fixed_initial = bool(base_profile.get("fixed_initial_state"))
            repeatable = str(base_profile.get("repeatable_restart_protocol", ""))
            if not restart and not fixed_initial and not repeatable:
                raise RuntimeError("真实在线验收必须配置固定初始状态或可重复的重新开始流程")
            self.online_records = load_online_acceptance_records(
                self.host.store.base, self.game["id"], self.online_model_fingerprint
            )
        active_task_id = normalized_identifier(base_profile.get("default_task_id"), "default", 96)
        task = self.host.store.load_task(self.game["id"], active_task_id)
        self.profile = task_profile_overlay(base_profile, task or {**base_profile, "task_id": active_task_id})
        self.profile["temporal_termination_model"] = (
            dict(self.model.get("temporal_termination_model", {}))
            if isinstance(self.model.get("temporal_termination_model"), dict)
            else {}
        )
        self.profile["reward_hacking_guard"] = (
            dict(self.model.get("reward_hacking_guard", {}))
            if isinstance(self.model.get("reward_hacking_guard"), dict)
            else {}
        )
        self.profile["perception_key"] = self.target["window_key"]
        self.task_definition = TaskDefinition.from_mapping(
            task or {**self.profile, "game_id": self.game["id"], "task_id": active_task_id},
            self.game["id"],
            active_task_id,
        )
        self.task_planner = HierarchicalTaskPlanner(
            self.model.get("learned_subgoal_planner", {}),
            self.model.get("world_model", {}),
            RUNTIME_THRESHOLDS.world_model_horizon,
        )
        self.skill_policy = DEFAULT_SKILL_POLICY
        self.safety_shield = DEFAULT_SAFETY_SHIELD
        self.current_subgoal = Subgoal("advance_goal", self.task_definition.goal, {}, (), 0, 0.0)
        experience_schema = (
            safe_int(self.model.get("experience_model", {}).get("schema_version", 0), 0)
            if isinstance(self.model.get("experience_model"), dict)
            else 0
        )
        if experience_schema >= 3 and active_task_id not in {str(value) for value in self.model.get("task_ids", [])}:
            raise RuntimeError("当前任务未包含在已睡眠模型中，请重新学习和睡眠")
        self.agent_policy = TaskAgentPolicy(self.profile)
        if not self.agent_policy.allowed:
            raise RuntimeError("当前游戏未配置任何自动动作白名单，请先打开“任务与安全”")
        self.host.active_model_runtime = self.model
        self.prototypes = [
            proto
            for proto in self.model["prototypes"]
            if self.host.training_controller.authorized(proto) and self.agent_policy.allowed_action(proto.get("a"))
        ]
        if not self.prototypes:
            raise RuntimeError("当前模型与任务白名单没有共同的已授权动作")
        self.allowed_backends = {
            method for proto in self.prototypes for method in proto.get("capture_methods", [])
        } or set(self.model.get("capture_backends", []))
        self.calibration = self.phase.get("calibration") or self.host.ensure_capture_calibration(
            self.target, MODE_LABELS[ModeId.AI]
        )
        self.capability = CapabilityProfile(base_profile)
        self.capability_result = self.capability.require_training_support(
            {
                "capture_fps": self.calibration.get("fps", 0.0),
                "available_action_frequency": 1.0
                / max(0.01, safe_float(self.calibration.get("input_delay", 0.25), 0.25)),
                "semantic_size": HYBRID_GLOBAL_SIZE,
                **self.host.api.execution_capabilities(),
            }
        )
        self.validated_backend = str(self.calibration.get("validated_backend", ""))
        if self.validated_backend not in self.allowed_backends:
            raise RuntimeError("当前采集后端未被当前可训练模型授权；请用该后端重新学习并睡眠")
        self.build_snapshot()
        self.host.api.request_foreground(self.target["hwnd"])
        self.host.wait_escape_release()
        self.isolation = StrictInputIsolation(self.host.stop_event)
        if self.online_acceptance_mode:
            task_id = self.task_definition.task_id
            completed = sum(1 for item in self.online_records if str(item.get("task_id", "")) == str(task_id))
            if completed >= RUNTIME_THRESHOLDS.online_acceptance_target_episodes:
                raise RuntimeError(
                    "当前候选模型已完成目标真实在线局数，请点击“升级”重新执行统计门禁并发布模型"
                )
            self.start_online_episode()
            self.host.set_status(
                "真实在线验收：任务"
                + str(task_id)
                + "已完成"
                + str(completed)
                + "/"
                + str(RUNTIME_THRESHOLDS.online_acceptance_target_episodes)
                + "局；用时和动作数均为实测"
            )

    def preflight(self):
        return _strict_training_preflight(self)

    def start_online_episode(self):
        self.online_episode_started = time.monotonic()
        self.online_episode_action_count = 0
        self.online_episode_dangerous = 0
        self.online_episode_stuck = False
        self.online_episode_id = "online|" + uuid.uuid4().hex
        self.online_episode_recorded = False

    def online_episode_count(self):
        task_id = str(self.task_definition.task_id)
        return sum(
            1
            for item in load_online_acceptance_records(
                self.host.store.base, self.game["id"], self.online_model_fingerprint
            )
            if str(item.get("task_id", "")) == task_id
        )

    def record_online_episode(self, success, terminal_reason, frame=None, human_intervention=False):
        if not self.online_acceptance_mode or self.online_episode_recorded:
            return None
        finished_monotonic = time.monotonic()
        started_wall = time.time() - max(0.0, finished_monotonic - self.online_episode_started)
        rect = tuple(self.host.api.client_rect(int(self.target["hwnd"])))
        width = max(1, safe_int(rect[2] if len(rect) >= 4 else 0, 1))
        height = max(1, safe_int(rect[3] if len(rect) >= 4 else 0, 1))
        captured = (
            frame
            if isinstance(frame, dict)
            else self.last_captured_frame
            if isinstance(self.last_captured_frame, dict)
            else {}
        )
        popup_variant = str(captured.get("popup_variant") or captured.get("task_phase") or "none")
        fps = safe_float(self.calibration.get("fps"), 0.0)
        frame_rate_group = "60fps+" if fps >= 55 else "45fps" if fps >= 40 else "30fps" if fps >= 25 else "low_fps"
        profile_restart = normalize_action(self.profile.get("restart_action"))
        record = {
            "episode_id": self.online_episode_id,
            "model_fingerprint": self.online_model_fingerprint,
            "task_id": str(self.task_definition.task_id),
            "started": started_wall,
            "finished": time.time(),
            "duration_seconds": max(0.001, finished_monotonic - self.online_episode_started),
            "action_count": max(0, self.online_episode_action_count),
            "success": bool(success),
            "failure": not bool(success),
            "terminal_reason": str(terminal_reason),
            "stuck": bool(self.online_episode_stuck or self.no_change_count >= 2),
            "human_intervention": bool(human_intervention),
            "dangerous_false_release_count": max(0, int(self.online_episode_dangerous)),
            "fixed_initial_state": bool(self.profile.get("fixed_initial_state")),
            "repeatable_restart_protocol": str(
                self.profile.get("repeatable_restart_protocol")
                or ("configured_restart_action" if profile_restart else "")
            ),
            "resolution": str(width) + "x" + str(height),
            "dpi": safe_int(self.host.api.dpi_for_window(int(self.target["hwnd"])), 96),
            "ui_skin": str(self.profile.get("ui_skin", "default")),
            "popup_variant": popup_variant,
            "frame_rate_group": frame_rate_group,
            "capture_backend": self.validated_backend,
            "real_duration_measured": True,
            "real_actions_executed": True,
            "manual_takeover": bool(human_intervention),
            "window_generation": safe_int(self.target.get("window_generation"), 0),
        }
        saved = append_online_acceptance_record(self.host.store.base, self.game["id"], record)
        self.online_episode_recorded = True
        self.online_records.append(saved)
        RUNTIME_METRICS.increment("real_online_acceptance_episode")
        return saved

    def restart_online_episode(self, frame, reason):
        if not self.online_acceptance_mode:
            return False
        count = self.online_episode_count()
        if count >= RUNTIME_THRESHOLDS.online_acceptance_target_episodes:
            self.host.request_mode_stop(
                "completed",
                "候选模型已完成目标真实在线验收局数；请点击“升级”执行最终统计门禁",
            )
            return False
        if self.host.should_stop():
            return False
        restart_action = normalize_action(self.profile.get("restart_action"))
        if not restart_action:
            protocol = str(self.profile.get("repeatable_restart_protocol", "")).strip()
            fixed = bool(self.profile.get("fixed_initial_state"))
            self.host.request_mode_stop(
                "completed",
                (
                    "本局真实在线结果已保存；请按已保存固定初始状态重新载入后再次运行AI"
                    if fixed
                    else "本局真实在线结果已保存；请执行可重复重开流程后再次运行AI：" + protocol
                ),
            )
            return False
        if not self.execute_profile_restart(frame):
            self.host.request_mode_stop(
                "stopped",
                "真实在线验收无法恢复到固定初始状态：" + str(reason),
            )
            return False
        interruptible_wait(self.host.stop_event, max(0.15, float(self.calibration.get("input_delay", 0.24))))
        self.agent_policy.failures = 0
        self.no_change_count = 0
        self.state_unlocked = True
        self.recent_actions.clear()
        self.recent_actions.extend(["<START>", "<START>"])
        self.start_online_episode()
        self.host.set_status(
            "真实在线验收：已实测" + str(count) + "/" + str(RUNTIME_THRESHOLDS.online_acceptance_target_episodes) + "局"
        )
        return True

    def model_table_token(self):
        with self.host.store.lock:
            rows = list(
                iter_rows(
                    self.host.store.db.execute(
                        "SELECT slot,saved,checksum FROM models WHERE game_id=? ORDER BY slot",
                        (self.game["id"],),
                    )
                )
            )
        values = [[str(row["slot"]), float(row["saved"]), str(row["checksum"])] for row in rows]
        return immutable_digest(values)

    def build_snapshot(self):
        identity = self.host.api.target_identity(self.target)
        rect = tuple(self.host.api.validate_target(self.target, False))
        dpi = self.host.api.dpi_for_window(int(self.target["hwnd"]))
        self.visual_runtime_layout = {
            "content_rect": list(rect),
            "dpi": dpi,
            "capture_backend": self.validated_backend,
            "aspect": rect[2] / max(1, rect[3]),
        }
        self.snapshot_payload = {
            "game_id": str(self.game["id"]),
            "model_table_token": self.model_table_token(),
            "model_digest": immutable_digest(self.model),
            "safety_profile_checksum": profile_checksum(self.profile),
            "window": self.identity_payload(identity),
            "allowed_actions": sorted(
                {semantic_action_signature(proto.get("semantic_action") or proto.get("a")) for proto in self.prototypes}
            ),
            "allowed_backends": sorted(self.allowed_backends),
        }
        self.training_snapshot_checksum = immutable_digest(self.snapshot_payload)

    def identity_payload(self, identity):
        return {
            "hwnd": safe_int(identity.get("hwnd"), 0),
            "pid": safe_int(identity.get("pid"), 0),
            "process_created": safe_int(identity.get("process_created"), 0),
            "window_thread_id": safe_int(identity.get("window_thread_id"), 0),
            "class": str(identity.get("class", "")),
            "process_path": os.path.normcase(str(identity.get("process_path", ""))),
            "integrity": safe_int(identity.get("integrity"), 0),
        }

    def _base_assert_training_snapshot_strict(self, force=False):
        now = time.monotonic()
        if not force and now - self.snapshot_last_check < 0.25:
            return True
        self.snapshot_last_check = now
        current_game = self.host.require_game()
        identity = self.host.api.target_identity(self.target)
        rect = tuple(self.host.api.validate_target(self.target, False))
        dpi = self.host.api.dpi_for_window(int(self.target["hwnd"]))
        backend = str(self.host.api.calibration_for(self.target).get("validated_backend", self.validated_backend))
        current_profile = self.host.store.load_game_profile(self.game["id"])
        payload = {
            "game_id": str(current_game.get("id", "")),
            "model_table_token": self.model_table_token(),
            "model_digest": self.snapshot_payload["model_digest"],
            "safety_profile_checksum": profile_checksum(current_profile),
            "window": self.identity_payload(identity),
            "allowed_actions": self.snapshot_payload["allowed_actions"],
            "allowed_backends": self.snapshot_payload["allowed_backends"],
        }
        if immutable_digest(payload) != self.training_snapshot_checksum:
            self.host.api.block_input()
            self.host.api.release_all_buttons()
            self.host.request_mode_stop("stopped", "训练安全身份、模型、任务或动作白名单发生变化")
            raise InputStopped("安全身份或不可变策略快照发生变化")
        if backend not in self.allowed_backends:
            self.host.api.block_input()
            self.host.request_mode_stop("stopped", "采集后端切换到未经验证的实现")
            raise InputStopped("采集后端未经模型验证")
        aspect = rect[2] / max(1, rect[3])
        previous = self.visual_runtime_layout
        if abs(aspect - safe_float(previous.get("aspect", aspect), aspect)) > max(
            0.04, VersionedThresholdConfig.content_aspect_tolerance
        ):
            self.host.api.block_input()
            self.host.request_mode_stop("stopped", "内容区域发生非等比例变化")
            raise InputStopped("视觉布局无法安全自动校准")
        changed = (
            list(rect) != list(previous.get("content_rect", []))
            or dpi != safe_int(previous.get("dpi", dpi), dpi)
            or backend != str(previous.get("capture_backend", backend))
        )
        if changed:
            self.visual_runtime_layout = {
                "content_rect": list(rect),
                "dpi": dpi,
                "capture_backend": backend,
                "aspect": aspect,
            }
            self.validated_backend = backend
            self.reset_candidate()
            self.state_since = time.monotonic()
            self.host.set_status("检测到纯视觉布局变化，已重新校准客户区、DPI或采集后端并等待连续确认")
        return True

    def assert_training_snapshot(self, force=False):
        return _strict_assert_snapshot(self, force)

    def _start_monitors_base(self, session):
        fps = max(8.0, float(self.calibration.get("fps", 15.0)))
        self.frame_buffer = session.start_frames(fps, 2.5, 0.1, "training")
        self.keyboard = session.start_keyboard()
        self.mouse = session.start_mouse()
        self.host.lifecycle.mark_running()
        self.keyboard_interrupt = self.keyboard.other_event
        self.mouse_interrupt = self.mouse.input_event

    def start_monitors(self, session):
        self._start_monitors_base(session)
        self.safety_lease_broker = SafetyLeaseBroker().start()
        session.add_resource(
            "SafetyLeaseProcess",
            self.safety_lease_broker,
            self.safety_lease_broker.stop,
            self.safety_lease_broker.alive,
            self.safety_lease_broker.stop,
        )

    def execute_profile_restart(self, frame):
        self.assert_training_snapshot(True)
        restart = normalize_action(self.profile.get("restart_action"))
        if not restart:
            return False
        if not self.agent_policy.allowed_action(restart):
            raise InputStopped("重新开始动作不在安全白名单")
        if (
            not self.host.training_controller.usable_frame(frame, self.validated_backend)
            or frame.get("method") not in self.allowed_backends
        ):
            raise InputStopped("重新开始前画面或采集后端不可用")
        if (
            self.mouse_interrupt.is_set()
            or self.keyboard_interrupt.is_set()
            or not self.keyboard.all_released()
            or not self.mouse.stable_for(0.45)
        ):
            raise InputStopped("重新开始前检测到人工输入")
        self.host.api.validate_target(self.target, True)
        self.host.api.validate_uipi(self.target)
        try:
            if restart.get("kind") != "no_op":
                self.host.api.allow_input(self.host.stop_event)
                self.host.set_input_status("允许执行一次已配置的重新开始动作")
            self.host.execute_action(
                self.target, restart, frame, self.mouse_interrupt, self.keyboard, self.keyboard_interrupt
            )
            self.actions += 1
            self.recent_actions.append(
                semantic_skill(semantic_action_from_coordinate(restart), "recover_after_failure").key()
            )
            return True
        finally:
            self.host.api.block_input()
            self.host.api.release_all_buttons()

    def detect_interference(self):
        key_events = [event for event in self.keyboard.drain() if event.get("kind") == "other" and event.get("down")]
        mouse_events = self.mouse.drain()
        tripped = self.host.training_controller.interference(self.mouse_interrupt, self.keyboard_interrupt)
        if not tripped and not key_events and not mouse_events:
            return False
        self.keyboard_count += len(key_events)
        self.mouse_count += len(mouse_events)
        if key_events or self.keyboard_interrupt.is_set():
            self.isolation.signal("keyboard", key_events[0].get("time") if key_events else time.monotonic())
            reason = "检测到非ESC键盘输入，训练立即停止"
            self.host.set_input_status("因键盘输入锁定")
        else:
            self.isolation.signal("mouse", mouse_events[0].get("time") if mouse_events else time.monotonic())
            reason = "检测到物理或其他程序注入的鼠标输入，训练立即停止"
            self.host.set_input_status("因人工鼠标输入锁定")
        if self.corrective_workflow is not None and self.last_selection_for_correction is not None:
            self.corrective_workflow.record_override(
                self.last_captured_frame,
                self.last_selection_for_correction.get("action", self.last_selection_for_correction),
                self.last_ranked_candidates,
                self.last_decision_snapshot,
                reason,
            )
        self.host.request_mode_stop("stopped", reason)
        self.host.api.block_input()
        self.host.api.release_all_buttons()
        self.host.set_status(
            reason + "；下一次点击“人”后首个正确动作将自动形成强正负纠错样本"
        )
        return True

    def acquire_frame(self):
        self.host.api.block_input()
        self.host.set_input_status("等待连续确认")
        try:
            self.host.api.validate_target(self.target, True)
        except TargetUnavailable as error:
            self.reset_candidate()
            self.host.set_confidence("训练置信度：0%")
            self.host.set_input_status("目标窗口不可用，已锁定")
            self.host.set_status("目标窗口失去焦点，等待恢复；" + str(error))
            interruptible_wait(self.host.stop_event, 0.08)
            return None
        captured = self.frame_buffer.latest(None, 0.8)
        if not self.host.training_controller.usable_frame(captured, self.validated_backend):
            self.host.set_input_status(
                "检测到黑屏，已锁定" if captured and captured.get("black_frame") else "画面不可用，已锁定"
            )
            self.host.set_status(
                "采集画面不可用于训练；等待已验收、非受保护黑屏且后端未冻结的最新帧；"
                + (self.frame_buffer.last_error or "尚无画面")
            )
            interruptible_wait(self.host.stop_event, 0.08)
            return None
        if self.validate_backend(captured):
            self.last_captured_frame = captured
            return captured
        return None

    def validate_backend(self, captured):
        frame = CapturedFrame.from_payload(captured)
        current = str(self.host.api.calibration_for(self.target).get("validated_backend", self.validated_backend))
        if current != self.validated_backend:
            if current in self.allowed_backends:
                self.validated_backend = current
                self.reset_candidate()
                self.host.set_input_status("采集后端切换，等待连续确认")
                self.host.set_status("原采集后端已熔断，已切换到剩余已验证后端：" + self.validated_backend)
            else:
                self.host.set_status("替代采集后端未在模型中验证，拒绝自动动作")
            interruptible_wait(self.host.stop_event, 0.1)
            return False
        if frame.method != self.validated_backend or frame.method not in self.allowed_backends:
            self.host.set_status("采集后端变化或未在模型中验证，拒绝自动动作；请重新学习和睡眠")
            interruptible_wait(self.host.stop_event, 0.1)
            return False
        return True

    def reset_candidate(self):
        self.candidate_id = None
        self.candidate_count = 0
        self.candidate_frame_stamp = 0.0

    def handle_terminal_state(self, captured):
        frame = CapturedFrame.from_payload(captured)
        feature = frame.feature
        state, _ = self.agent_policy.classify(feature)
        if state == "success":
            if self.online_acceptance_mode:
                self.record_online_episode(True, "visual_success_terminal", captured, False)
                try:
                    return "continue" if self.restart_online_episode(captured, "success_terminal") else "break"
                except InputStopped as error:
                    self.host.request_mode_stop("stopped", "成功后无法安全重开下一局：" + str(error))
                    return "break"
            self.host.request_mode_stop("completed", "检测到已定义的成功状态，训练完成")
            return "break"
        if state != "failure":
            return None
        if self.online_acceptance_mode:
            self.record_online_episode(False, "visual_failure_terminal", captured, False)
            try:
                return "continue" if self.restart_online_episode(captured, "failure_terminal") else "break"
            except InputStopped as error:
                self.host.request_mode_stop("stopped", "失败后无法安全重开下一局：" + str(error))
                return "break"
        outcome = self.agent_policy.register(feature, {"kind": "no_op", "duration": 0.1}, feature, False)
        if outcome["stop"]:
            self.host.request_mode_stop(
                "stopped", "失败状态连续出现达到安全上限" + str(self.agent_policy.max_failures) + "次，已自动停机"
            )
            return "break"
        try:
            if self.execute_profile_restart(captured):
                self.host.set_status("检测到失败或死亡状态，已执行白名单内的重新开始动作")
                interruptible_wait(self.host.stop_event, max(0.1, float(self.calibration.get("input_delay", 0.24))))
                return "continue"
        except InputStopped as error:
            self.host.request_mode_stop("stopped", "失败状态回滚无法安全执行：" + str(error))
            return "break"
        self.host.set_status("检测到失败或死亡状态，但未配置重新开始动作；保持锁定")
        interruptible_wait(self.host.stop_event, 0.12)
        return "continue"

    def update_temporal_state(self, captured):
        frame = CapturedFrame.from_payload(captured)
        feature = frame.feature
        if frame.timestamp != self.previous_frame_stamp:
            if self.previous_feature is not None and visual_distance(self.previous_feature, feature) > float(
                self.calibration.get("significant_change", 60.0)
            ):
                self.state_since = time.monotonic()
            self.previous_feature = feature
            self.previous_frame_stamp = frame.timestamp
        self.significant = self.last_action_feature is not None and visual_distance(
            self.last_action_feature, feature
        ) > float(self.calibration.get("significant_change", 60.0))
        if self.significant:
            self.state_unlocked = True
            self.no_change_count = 0
            self.state_since = time.monotonic()
        temporal = self.host.build_temporal_context(self.frame_buffer, captured, self.recent_actions, self.state_since)
        temporal.update(
            {
                "recent_action_results": list(self.recent_action_results),
                "failure_count": self.agent_policy.failures,
                "object_signature": str(captured.get("object_signature", "")),
                "task_phase": str(
                    captured.get("task_phase", self.agent_policy.last_classification.get("state", "neutral"))
                ),
                "task_id": self.task_definition.task_id,
                "task_goal": self.task_definition.goal,
            }
        )
        observation = objectized_observation(captured, temporal, self.task_definition)
        self.current_subgoal = self.task_planner.propose_subgoal(observation, self.task_definition)
        if self.task_graph_memory is not None:
            temporal["task_graph"] = self.task_graph_memory.observe(observation, self.current_subgoal, {})
        temporal["subgoal_id"] = self.current_subgoal.subgoal_id
        temporal["planner_plan"] = dict(getattr(self.task_planner, "last_plan", {}))
        temporal["observation_state_id"] = observation.state_id
        temporal["environment_id"] = observation.environment_id
        if not temporal_from_context({**temporal, "previous_action_changed_frame": self.significant}).get("complete"):
            self.host.set_status("等待至少3帧短时序上下文")
            interruptible_wait(self.host.stop_event, 0.05)
            return None
        temporal["previous_action_changed_frame"] = bool(self.significant)
        return temporal

    def _choose_action_base(self, captured, temporal):
        ranked = self.host.rank_action_candidates(
            captured["f"],
            self.prototypes,
            self.last_action_signature,
            VersionedThresholdConfig.candidate_full_limit,
            temporal,
            captured.get("coarse"),
            captured.get("neural_f"),
            captured.get("semantic_targets", []),
            self.agent_policy.task_id,
        )
        decision = self.host.evaluate_action_candidates(ranked)
        self.last_ranked_candidates = [dict(item) for item in ranked[:8] if isinstance(item, dict)]
        self.last_decision_snapshot = dict(decision)
        self.last_decision_snapshot["high_value_reasons"] = high_value_learning_reasons(
            captured, ranked, decision, temporal
        )
        if not decision.get("accepted"):
            self.reset_candidate()
            now = time.monotonic()
            reason = str(decision.get("reason", "识别不确定"))
            if reason != self.last_guidance_reason or now - self.guidance_request_last_time >= 2.0:
                self.guidance_requests += 1
                self.guidance_request_last_time = now
                self.guidance_trigger_streak = 1
            else:
                self.guidance_trigger_streak += 1
            self.last_guidance_reason = reason
            self.host.set_input_status("等待指导")
            self.host.set_confidence("训练置信度：" + str(round(float(decision.get("confidence", 0.0)) * 100, 1)) + "%")
            self.host.set_status("训练中：" + reason + "；不产生鼠标输入")
            information = (
                active_learning_information_score(decision, temporal)
                if "active_learning_information_score" in globals()
                else {"score": 0.0}
            )
            high_information = safe_float(information.get("score"), 0.0) >= 2.4
            if high_information or self.guidance_trigger_streak >= RUNTIME_THRESHOLDS.active_learning_trigger_streak:
                decision["information_score"] = information
                (
                    register_active_learning_request(self, captured, temporal, decision)
                    if "register_active_learning_request" in globals()
                    else None
                )
                self.host.request_mode_stop("stopped", "主动学习触发指导：" + reason)
            else:
                interruptible_wait(self.host.stop_event, 0.12)
            return None
        self.guidance_trigger_streak = 0
        best = decision["best"]
        cluster_id = best["cluster_id"]
        if self.candidate_id == cluster_id:
            if captured["time"] == self.candidate_frame_stamp:
                interruptible_wait(self.host.stop_event, 0.025)
                return None
            self.candidate_count += 1
        else:
            self.candidate_id = cluster_id
            self.candidate_count = 1
        self.candidate_frame_stamp = captured["time"]
        confirmations = max(
            RUNTIME_THRESHOLDS.confirmation_frames,
            int(self.calibration.get("confirm_frames", RUNTIME_THRESHOLDS.confirmation_frames)),
        )
        self.host.set_confidence(
            "训练置信度："
            + str(round(decision["confidence"] * 100, 1))
            + "%  连续确认"
            + str(self.candidate_count)
            + "/"
            + str(confirmations)
        )
        if not self.host.training_controller.confirmed(self.candidate_count, confirmations):
            interruptible_wait(self.host.stop_event, 0.05)
            return None
        return self.build_selection(captured, best, confirmations)

    def _base_choose_action_strict(self, captured, temporal):
        started = time.monotonic()
        try:
            result = self._choose_action_base(captured, temporal)
            if result is None and self.guidance_trigger_streak > 0:
                register_active_learning_request(
                    self,
                    captured,
                    temporal,
                    {"guidance_trigger": [self.last_guidance_reason], "reason": self.last_guidance_reason},
                )
            return result
        finally:
            RUNTIME_METRICS.observe("candidate_ranking_ms", (time.monotonic() - started) * 1000.0)

    def choose_action(self, captured, temporal):
        return _strict_choose_action(self, captured, temporal)

    def _build_selection_base(self, captured, best, confirmations):
        coordinate = normalize_action(best["a"])
        semantic = normalize_semantic_action(best.get("semantic_action")) or semantic_action_from_coordinate(coordinate)
        proto = best["proto"]
        if not self.host.training_controller.authorized(proto):
            self.host.set_status("动作原型未通过独立留出授权，拒绝动作")
            interruptible_wait(self.host.stop_event, 0.1)
            return None
        if not self.agent_policy.allowed_action(coordinate):
            self.host.set_status("动作不在当前任务安全白名单中，拒绝动作：" + self.host.action_text(semantic))
            interruptible_wait(self.host.stop_event, 0.1)
            return None
        risk_class = str(semantic.get("risk_class", "safe"))
        if risk_class == "irreversible":
            self.host.set_status("不可逆操作始终需要人工确认；自主训练拒绝执行并进入指导")
            self.guidance_trigger_streak = RUNTIME_THRESHOLDS.active_learning_trigger_streak
            return None
        if captured["method"] not in proto.get("capture_methods", frozenset()):
            self.host.set_status("当前原型未在该采集后端训练，拒绝动作")
            interruptible_wait(self.host.stop_event, 0.1)
            return None
        grounding = ground_semantic_action(semantic, captured.get("semantic_targets", []), True)
        if not grounding or not grounding.get("grounded_action") or grounding.get("grounding", {}).get("ambiguous"):
            self.host.set_status("执行前语义目标缺失或不唯一，拒绝坐标猜测并进入指导")
            self.guidance_trigger_streak = RUNTIME_THRESHOLDS.active_learning_trigger_streak
            return None
        grounded_coordinate = normalize_action(grounding.get("grounded_action"))
        points = grounded_coordinate.get("path", []) if isinstance(grounded_coordinate, dict) else []
        control_action = bool(grounded_coordinate and grounded_coordinate.get("kind") in CONTROL_ACTION_KINDS)
        in_client = bool(
            control_action
            or grounded_coordinate
            and points
            and all(
                isinstance(point, (list, tuple))
                and len(point) >= 2
                and 0.0 <= safe_float(point[0], -1.0) <= 1.0
                and 0.0 <= safe_float(point[1], -1.0) <= 1.0
                for point in points
            )
        )
        control_capability = bool(grounded_coordinate and self.host.api.can_execute_action(grounded_coordinate))
        calibration = (
            self.model.get("decision_calibration", {})
            if isinstance(self.model.get("decision_calibration"), dict)
            else {}
        )
        shield_context = {
            "window_identity_verified": True,
            "client_bounds_verified": in_client,
            "target_unique": not bool(grounding.get("grounding", {}).get("ambiguous")),
            "in_distribution": safe_float(best.get("ood_uncertainty", 1.0), 1.0)
            <= safe_float(
                calibration.get("maximum_ood_uncertainty", RUNTIME_THRESHOLDS.maximum_ood),
                RUNTIME_THRESHOLDS.maximum_ood,
            ),
            "action_authorized": True,
            "control_capability": control_capability,
            "input_clear": not self.mouse_interrupt.is_set()
            and not self.keyboard_interrupt.is_set()
            and self.keyboard.all_released()
            and self.mouse.stable_for(0.45),
            "consecutive_failures": self.agent_policy.failures,
            "failure_limit": self.agent_policy.max_failures,
            "coordinate_fallback_allowed": risk_class == "safe",
            "human_confirmed": False,
        }
        safety_decision = self.safety_shield.authorize(semantic, shield_context)
        if not safety_decision.allowed:
            self.host.set_status("独立安全屏障拒绝动作：" + safety_decision.reason + "；保持输入锁定并进入指导")
            self.guidance_trigger_streak = RUNTIME_THRESHOLDS.active_learning_trigger_streak
            return None
        repeat_policy = str(proto.get("repeat_policy", "one_shot"))
        max_rate = max(0.25, min(12.0, float(proto.get("max_rate", 3.0))))
        skill = semantic_skill(
            semantic, self.current_subgoal.subgoal_id, safe_float(best.get("bc_probability", 1.0), 1.0, 0.0, 1.0)
        )
        return {
            "action": semantic,
            "coordinate_action": coordinate,
            "canonical": semantic_action_signature(semantic),
            "proto": proto,
            "cluster_id": best["cluster_id"],
            "prototype_cluster_id": best.get("prototype_cluster_id", proto.get("cluster_id", "")),
            "skill_id": skill.skill_id,
            "skill_key": skill.key(),
            "skill_parameters": dict(skill.parameters),
            "subgoal_id": skill.subgoal_id,
            "repeat_policy": repeat_policy,
            "max_rate": max_rate,
            "confirmations": confirmations,
            "risk_class": risk_class,
            "policy_confidence": safe_float(best.get("bc_probability", 0.0), 0.0, 0.0, 1.0),
            "safety_decision": safety_decision.to_dict(),
        }

    def build_selection(self, captured, best, confirmations):
        selection = self._build_selection_base(captured, best, confirmations)
        if selection is None:
            return None
        contracts = self.model.get("skill_contracts", {}) if isinstance(self.model, dict) else {}
        contract = dict(
            contracts.get(
                selection.get("skill_id"),
                SKILL_CONTRACTS.get(selection.get("skill_id"), SKILL_CONTRACTS["stop_and_ask"]),
            )
        )
        selection["skill_contract"] = contract
        if selection.get("skill_id") == "scroll_until_target":
            selection["repeat_policy"] = "repeatable"
            selection["max_rate"] = min(1.5, safe_float(selection.get("max_rate"), 1.5))
        current = str(selection.get("skill_id", ""))
        now = time.monotonic()
        if current != self.skill_runtime.get("skill_id"):
            self.skill_runtime = {
                "skill_id": current,
                "started": now,
                "repeats": 0,
                "last_environment": str(best.get("environment_id", "")),
            }
        self.skill_runtime["repeats"] += 1
        if self.skill_runtime["repeats"] > safe_int(
            contract.get("max_repeats", 1), 1, 0, 100
        ) or now - self.skill_runtime["started"] > safe_float(contract.get("max_duration", 3.0), 3.0, 0.0, 60.0):
            self.host.set_status("闭环技能达到最大时间或重复次数，进入指导")
            self.guidance_trigger_streak = RUNTIME_THRESHOLDS.active_learning_trigger_streak
            return None
        return selection

    def authorize_action_lease(self, fresh, selection):
        if self.safety_lease_broker is None or not self.safety_lease_broker.alive():
            raise InputStopped("独立安全授权进程不可用")
        frame_token = hashlib.sha256(
            feature_bytes(fresh.get("f"))
            + str(fresh.get("object_signature", "")).encode("utf-8", "replace")
            + str(fresh.get("time", "")).encode()
        ).hexdigest()
        semantic = normalize_semantic_action(selection.get("action"))
        grounding = ground_semantic_action(semantic, fresh.get("semantic_targets", []), True)
        coordinate = normalize_action(grounding.get("grounded_action")) if isinstance(grounding, dict) else None
        points = coordinate.get("path", []) if isinstance(coordinate, dict) else []
        control_action = bool(coordinate and coordinate.get("kind") in CONTROL_ACTION_KINDS)
        sources = set()
        for target in fresh.get("semantic_targets", []) if isinstance(fresh, dict) else []:
            if isinstance(target, dict):
                sources.update(
                    str(value)
                    for value in (
                        target.get("attributes", {}).get("evidence_sources", [])
                        if isinstance(target.get("attributes"), dict)
                        else []
                    )
                )
        risk = str((semantic or {}).get("risk_class", "safe"))
        independent_evidence = len(sources) >= 2 or risk == "safe"
        evidence = {
            "window_identity": True,
            "same_frame": True,
            "target_unique": bool(grounding and not grounding.get("grounding", {}).get("ambiguous")),
            "client_bounds": bool(
                control_action
                or coordinate
                and points
                and all(
                    0.0 <= safe_float(point[0], -1.0) <= 1.0 and 0.0 <= safe_float(point[1], -1.0) <= 1.0
                    for point in points
                )
            ),
            "control_capability": bool(coordinate and self.host.api.can_execute_action(coordinate)),
            "input_clear": not self.mouse_interrupt.is_set()
            and not self.keyboard_interrupt.is_set()
            and self.keyboard.all_released()
            and self.mouse.stable_for(0.45),
            "authorization_current": True,
            "risk_class": risk,
            "human_confirmed": False,
            "independent_evidence": independent_evidence,
            "irreversible_release_forbidden": risk != "irreversible",
            "frame_token": frame_token,
        }
        lease = self.safety_lease_broker.authorize(evidence, 0.22)
        if not lease.get("allowed") or time.monotonic() >= safe_float(lease.get("expires"), 0.0):
            raise InputStopped("独立安全进程拒绝动作租约：" + str(lease.get("reason", "expired")))
        selection["action_lease"] = {
            "token": lease.get("token"),
            "expires": lease.get("expires"),
            "frame_token": frame_token,
            "checks": lease.get("checks", {}),
        }
        return selection["action_lease"]

    def action_ready(self, selection):
        cluster_id = selection["cluster_id"]
        policy = selection["repeat_policy"]
        if (
            policy in {"one_shot", "hold_until_change"}
            and self.last_cluster_id == cluster_id
            and not self.state_unlocked
        ):
            self.host.set_status("等待画面变化：该动作策略为" + policy)
            interruptible_wait(self.host.stop_event, 0.1)
            return False
        minimum_gap = max(
            self.host.action_cooldown(selection["action"]) if policy == "one_shot" else 0.0,
            1.0 / selection["max_rate"] if policy in {"rate_limited", "repeatable"} else 0.0,
        )
        if time.monotonic() - self.last_action_time < minimum_gap:
            interruptible_wait(self.stop_event, 0.03)
            return False
        hits = self.action_hits[cluster_id]
        now = time.monotonic()
        while hits and now - hits[0] > 1.0:
            hits.popleft()
        if len(hits) >= max(1, int(math.ceil(selection["max_rate"]))):
            self.host.set_status("动作专属频率限制中：" + self.host.action_text(selection["action"]))
            interruptible_wait(self.host.stop_event, 0.05)
            return False
        return True

    def verify_fresh_decision(self, fresh, selection):
        proto = selection["proto"]
        if (
            not self.host.training_controller.usable_frame(fresh, self.validated_backend)
            or fresh.get("method") not in self.allowed_backends
            or fresh.get("method") not in proto.get("capture_methods", frozenset())
        ):
            raise InputStopped("动作前最后一帧或采集后端不可用")
        if self.keyboard_interrupt.is_set() or not self.keyboard.all_released():
            raise InputStopped("检测到键盘输入")
        if self.mouse_interrupt.is_set() or not self.mouse.stable_for(0.45):
            raise InputStopped("检测到人工鼠标干扰")
        temporal = self.host.build_temporal_context(self.frame_buffer, fresh, self.recent_actions, self.state_since)
        temporal.update(
            {
                "previous_action_changed_frame": bool(self.significant),
                "recent_action_results": list(self.recent_action_results),
                "failure_count": self.agent_policy.failures,
                "object_signature": str(fresh.get("object_signature", "")),
                "task_id": self.task_definition.task_id,
                "task_goal": self.task_definition.goal,
                "subgoal_id": selection.get("subgoal_id", self.current_subgoal.subgoal_id),
            }
        )
        ranked = self.host.rank_action_candidates(
            fresh["f"],
            self.prototypes,
            self.last_action_signature,
            VersionedThresholdConfig.candidate_full_limit,
            temporal,
            fresh.get("coarse"),
            fresh.get("neural_f"),
            fresh.get("semantic_targets", []),
            self.agent_policy.task_id,
        )
        decision = self.host.evaluate_action_candidates(ranked)
        if not decision.get("accepted") or decision.get("best", {}).get("cluster_id") != selection["cluster_id"]:
            raise InputStopped("动作前模型判断已变化")
        grounding = ground_semantic_action(selection["action"], fresh.get("semantic_targets", []), True)
        if not grounding or not grounding.get("grounded_action") or grounding.get("grounding", {}).get("ambiguous"):
            raise InputStopped("动作前语义目标无法唯一定位")
        grounded_coordinate = normalize_action(grounding.get("grounded_action"))
        points = grounded_coordinate.get("path", []) if isinstance(grounded_coordinate, dict) else []
        control_action = bool(grounded_coordinate and grounded_coordinate.get("kind") in CONTROL_ACTION_KINDS)
        in_client = bool(
            control_action
            or grounded_coordinate
            and points
            and all(
                isinstance(point, (list, tuple))
                and len(point) >= 2
                and 0.0 <= safe_float(point[0], -1.0) <= 1.0
                and 0.0 <= safe_float(point[1], -1.0) <= 1.0
                for point in points
            )
        )
        fresh_best = decision.get("best", {})
        calibration = (
            self.model.get("decision_calibration", {})
            if isinstance(self.model.get("decision_calibration"), dict)
            else {}
        )
        fresh_safety = self.safety_shield.authorize(
            selection["action"],
            {
                "window_identity_verified": True,
                "client_bounds_verified": in_client,
                "target_unique": True,
                "in_distribution": safe_float(fresh_best.get("ood_uncertainty", 1.0), 1.0)
                <= safe_float(
                    calibration.get("maximum_ood_uncertainty", RUNTIME_THRESHOLDS.maximum_ood),
                    RUNTIME_THRESHOLDS.maximum_ood,
                ),
                "action_authorized": True,
                "control_capability": bool(
                    grounded_coordinate and self.host.api.can_execute_action(grounded_coordinate)
                ),
                "input_clear": not self.mouse_interrupt.is_set()
                and not self.keyboard_interrupt.is_set()
                and self.keyboard.all_released()
                and self.mouse.stable_for(0.45),
                "consecutive_failures": self.agent_policy.failures,
                "failure_limit": self.agent_policy.max_failures,
                "coordinate_fallback_allowed": selection.get("risk_class") == "safe",
                "human_confirmed": False,
            },
        )
        if not fresh_safety.allowed:
            raise InputStopped("动作前独立安全屏障拒绝：" + fresh_safety.reason)
        selection["safety_decision"] = fresh_safety.to_dict()
        if not self.host.training_controller.confirmed(self.candidate_count, selection["confirmations"]):
            raise InputStopped("动作前连续帧确认不足")
        self.assert_training_snapshot(True)

    def _base_execute_selected_action_strict(self, selection):
        fresh = self.frame_buffer.latest(None, 0.35)
        self.last_selection_for_correction = dict(selection) if isinstance(selection, dict) else selection
        try:
            self.host.api.validate_target(self.target, True)
            self.host.api.validate_uipi(self.target)
            self.verify_fresh_decision(fresh, selection)
            self.authorize_action_lease(fresh, selection)
            before = fresh
            if normalize_semantic_action(selection["action"]).get("action_type") != "no_op":
                self.host.set_input_status("允许执行单个动作")
                self.host.api.allow_input(self.host.stop_event)
            else:
                self.host.set_input_status("已锁定")
            self.host.set_status(
                "训练中："
                + self.host.action_text(selection["action"])
                + "；全部安全条件已通过；采集="
                + fresh["method"]
            )
            self.host.execute_action(
                self.target, selection["action"], fresh, self.mouse_interrupt, self.keyboard, self.keyboard_interrupt
            )
        except InputStopped:
            self.handle_execution_interference()
            raise
        except TargetUnavailable as error:
            self.reset_candidate()
            self.host.set_status(str(error))
            self.host.set_input_status("目标身份变化，已锁定")
            return None
        finally:
            self.host.api.block_input()
            if (
                not self.mouse_interrupt.is_set()
                and not self.keyboard_interrupt.is_set()
                and self.keyboard.all_released()
            ):
                self.host.set_input_status("已锁定")
        return self.collect_outcome(selection, before)

    def execute_selected_action(self, selection):
        return _strict_execute_selected(self, selection)

    def handle_execution_interference(self):
        if not self.mouse_interrupt.is_set() and not self.keyboard_interrupt.is_set() and self.keyboard.all_released():
            return
        kind = "mouse" if self.mouse_interrupt.is_set() else "keyboard"
        self.isolation.signal(kind, time.monotonic())
        reason = (
            "检测到物理或其他程序注入的鼠标输入，训练立即停止"
            if kind == "mouse"
            else "检测到非ESC键盘输入，训练立即停止"
        )
        if self.corrective_workflow is not None and self.last_selection_for_correction is not None:
            self.corrective_workflow.record_override(
                self.last_captured_frame,
                self.last_selection_for_correction.get("action", self.last_selection_for_correction),
                self.last_ranked_candidates,
                self.last_decision_snapshot,
                reason,
            )
        self.host.request_mode_stop("stopped", reason)
        self.host.api.block_input()
        self.host.api.release_all_buttons()
        self.host.set_status(
            reason + "；下一次点击“人”后首个正确动作将自动形成强正负纠错样本"
        )

    def _collect_outcome_base(self, selection, before):
        action_end = time.monotonic()
        self.actions += 1
        if self.online_acceptance_mode:
            self.online_episode_action_count += 1
            if str(selection.get("risk_class", "safe")) in {"irreversible", "dangerous"}:
                self.online_episode_dangerous += 1
        self.action_hits[selection["cluster_id"]].append(action_end)
        self.recent_actions.append(selection.get("skill_key", selection["cluster_id"]))
        self.last_action_signature = selection["canonical"]
        self.last_cluster_id = selection["cluster_id"]
        self.last_action_time = action_end
        self.last_action_feature = before.get("f") if isinstance(before, dict) else before
        self.state_unlocked = selection["repeat_policy"] in {"repeatable", "rate_limited"}
        self.candidate_count = 0
        delay = float(self.calibration.get("input_delay", 0.24))
        deadline = time.monotonic() + delay
        while time.monotonic() < deadline and not self.host.should_stop():
            interruptible_wait(self.host.stop_event, 0.02)
        after = self.wait_after_frame(action_end, delay)
        before_feature = before.get("f") if isinstance(before, dict) else before
        changed = self.host.training_controller.changed(
            before_feature, after, float(self.calibration.get("post_action_change", 45.0))
        )
        classification = (
            {"reason": "changed", "counts_as_failure": False, "should_wait": False, "confidence": 1.0}
            if changed
            else classify_no_change_state(before, after, self.target, self.calibration)
        )
        outcome = self.agent_policy.register(
            before_feature,
            selection["coordinate_action"],
            after["f"] if after is not None else None,
            changed or not classification.get("counts_as_failure", False),
        )
        if not changed and not classification.get("counts_as_failure", False) and outcome.get("state") == "neutral":
            self.agent_policy.failures = max(0, self.agent_policy.failures - 1)
            outcome["failures"] = self.agent_policy.failures
            outcome["stop"] = False
        record = {
            "state": outcome.get("state", "neutral"),
            "changed": bool(changed),
            "reason": classification.get("reason", ""),
            "reward": outcome.get("reward", 0.0),
            "should_wait": bool(classification.get("should_wait", False)),
        }
        self.recent_action_results.append(record)
        return {
            "selection": selection,
            "after": after,
            "changed": changed,
            "outcome": outcome,
            "no_change": classification,
        }

    def collect_outcome(self, selection, before):
        result = self._collect_outcome_base(selection, before)
        after = result.get("after") if isinstance(result, dict) else None
        if isinstance(after, dict):
            before_objects = {
                str(value.get("track_id") or value.get("instance")): (value.get("bbox"), value.get("state"))
                for value in before.get("semantic_targets", [])
                if isinstance(value, dict) and str(value.get("source")) != "compatibility_alias"
            }
            after_objects = {
                str(value.get("track_id") or value.get("instance")): (value.get("bbox"), value.get("state"))
                for value in after.get("semantic_targets", [])
                if isinstance(value, dict) and str(value.get("source")) != "compatibility_alias"
            }
            changed = before_objects != after_objects
            result["skill_closed_loop"] = {
                "skill_id": selection.get("skill_id"),
                "contract": selection.get("skill_contract", {}),
                "object_state_changed": changed,
                "repeats": self.skill_runtime.get("repeats", 0),
                "elapsed": round(time.monotonic() - self.skill_runtime.get("started", time.monotonic()), 6),
            }
            if changed:
                self.skill_runtime = {"skill_id": "", "started": 0.0, "repeats": 0, "last_environment": ""}
        return result

    def wait_after_frame(self, action_end, delay):
        wait_end = time.monotonic() + max(0.35, delay * 2.0)
        while time.monotonic() < wait_end and not self.host.should_stop():
            candidate = self.frame_buffer.latest_after(action_end)
            if self.host.training_controller.usable_frame(candidate, self.validated_backend):
                return candidate
            interruptible_wait(self.host.stop_event, 0.025)
        return None

    def evaluate_outcome(self, result):
        selection = result["selection"]
        classification = result.get("no_change", {})
        if result["changed"]:
            self.no_change_count = 0
            self.state_unlocked = True
            self.state_since = time.monotonic()
        elif classification.get("should_wait"):
            self.no_change_count = 0
            self.state_unlocked = False
            self.host.set_status(
                "动作结果尚未出现：" + str(classification.get("reason", "waiting")) + "；保持输入锁定并等待"
            )
        elif classification.get("counts_as_failure"):
            self.no_change_count += 1
            if selection["repeat_policy"] in {"one_shot", "hold_until_change"} and self.no_change_count >= 2:
                self.state_unlocked = False
                self.host.set_status("动作确实无效，暂停并进入指导")
        outcome = result["outcome"]
        if outcome["state"] == "success":
            if self.online_acceptance_mode:
                frame = result.get("after") or self.frame_buffer.latest(None, 0.35)
                self.record_online_episode(True, "post_action_success", frame, False)
                try:
                    return not self.restart_online_episode(frame, "post_action_success")
                except InputStopped as error:
                    self.host.request_mode_stop("stopped", "成功后无法安全重开下一局：" + str(error))
                    return True
            self.host.request_mode_stop("completed", "检测到已定义的成功状态，训练完成")
            return True
        if outcome["stop"]:
            if self.online_acceptance_mode:
                frame = result.get("after") or self.frame_buffer.latest(None, 0.35)
                self.online_episode_stuck = True
                self.record_online_episode(False, "failure_limit_or_stuck", frame, False)
            self.host.request_mode_stop(
                "stopped",
                "连续失败或确认无效达到安全上限" + str(self.agent_policy.max_failures) + "次，已自动停机并请求指导",
            )
            return True
        if (
            outcome["state"] == "failure"
            and (self.online_acceptance_mode or self.profile.get("restart_action"))
            and not self.host.should_stop()
        ):
            frame = result["after"] or self.frame_buffer.latest(None, 0.35)
            try:
                if self.online_acceptance_mode:
                    self.record_online_episode(False, "post_action_failure", frame, False)
                    return not self.restart_online_episode(frame, "post_action_failure")
                if self.execute_profile_restart(frame):
                    self.host.set_status("检测到失败状态，已执行白名单内的重新开始动作")
            except InputStopped as error:
                self.host.request_mode_stop("stopped", "失败状态回滚无法安全执行：" + str(error))
                return True
        return False

    def capture_loop(self):
        with ModeSession(self.host, self.target) as session:
            self.start_monitors(session)
            while not self.host.should_stop():
                self.assert_training_snapshot(False)
                if self.detect_interference():
                    break
                captured = self.acquire_frame()
                if captured is None:
                    continue
                terminal = self.handle_terminal_state(captured)
                if terminal == "break":
                    break
                if terminal == "continue":
                    continue
                temporal = self.update_temporal_state(captured)
                if temporal is None:
                    continue
                selection = self.choose_action(captured, temporal)
                if selection is None or not self.action_ready(selection):
                    continue
                result = self.execute_selected_action(selection)
                if result is None:
                    continue
                if self.evaluate_outcome(result):
                    break
                interruptible_wait(self.host.stop_event, 0.05)

    def finalize(self):
        requested = self.host.lifecycle.snapshot()[3]
        if (
            self.online_acceptance_mode
            and not self.online_episode_recorded
            and self.online_episode_action_count > 0
        ):
            manual = bool(
                requested == "stopped"
                or self.keyboard_count
                or self.mouse_count
                or (self.host.stop_event is not None and self.host.stop_event.is_set())
            )
            self.record_online_episode(
                False,
                "manual_stop_or_incomplete_episode",
                self.last_captured_frame,
                manual,
            )
        if requested in {"completed", "stopped", "failed"}:
            status = requested
        else:
            status = "stopped" if self.host.stop_event and self.host.stop_event.is_set() else "completed"
        summary = (
            ("训练完成" if status == "completed" else "训练已停止")
            + "，AI执行"
            + str(self.actions)
            + "个鼠标动作；检测到非ESC键盘输入"
            + str(self.keyboard_count)
            + "次，人工或外部注入鼠标输入"
            + str(self.mouse_count)
            + "次"
        )
        details = {
            "strict_input_violation": self.isolation.kind,
            "task_history": list(self.agent_policy.history),
            "training_snapshot_checksum": self.training_snapshot_checksum,
            "snapshot_guarded": True,
            "coordinate_audit": {
                "sent": self.actions,
                "outside": 0,
                "client_rect": list(self.host.api.client_rect(int(self.target["hwnd"]))),
            },
            "keyboard_events": self.keyboard_count,
            "external_mouse_events": self.mouse_count,
            "guidance_requests": self.guidance_requests,
            "last_guidance_reason": self.last_guidance_reason,
            "terminal_classification": dict(self.agent_policy.last_classification),
            "online_acceptance": {
                "enabled": self.online_acceptance_mode,
                "model_fingerprint": self.online_model_fingerprint,
                "real_episode_count_for_task": self.online_episode_count() if self.online_acceptance_mode else 0,
                "minimum_required": RUNTIME_THRESHOLDS.online_acceptance_minimum_episodes,
                "target_required": RUNTIME_THRESHOLDS.online_acceptance_target_episodes,
                "durations_inferred": False,
            },
        }
        return ModeResult(status, summary, details)

    def run(self):
        self.preflight()
        self.capture_loop()
        return self.finalize()



