    def _writer_status_changed(self, error):
        def apply():
            self.storage_fault = bool(error) or bool(self.store.read_only)
            if error:
                self.status.set("样本写入失败，学习与指导已锁定：" + str(error))
                if self.mode in {ModeId.COLLECT.value, ModeId.NUMERIC.value}:
                    self.request_mode_stop("failed", "样本写入失败")
            else:
                self.status.set("样本写入线程已恢复")
            self._apply_storage_controls()

        self.ui(apply, "writer_status")

    def _apply_storage_controls(self):
        self._update_control_availability()

    def _update_control_availability(self):
        state, _, _, _, _ = self.lifecycle.snapshot()
        running = state != MODE_IDLE
        data_ready = bool(self.lifecycle.data_ready and self.store is not None)
        runtime_ready = bool(
            self.lifecycle.runtime_ready and self.vision_runtime is not None and self.ocr_runtime is not None
        )
        blocked = bool(not data_ready or self.storage_fault or self.store is None or self.store.read_only)
        game_ready = isinstance(self.selected_game, dict)
        window_ready = isinstance(self.selected_window, dict)
        directory_phase = self.lifecycle.directory_phase
        directory_busy = directory_phase in {"preparing", "prepared"}
        mapping = {
            "文件夹": not running and directory_phase != "preparing",
            "文件": not running and data_ready and not directory_busy,
            "游戏名称": not running and runtime_ready and not directory_busy,
            "选择窗口": not running and runtime_ready and game_ready and not directory_busy,
            MODE_LABELS[ModeId.COLLECT]: not running
            and runtime_ready
            and game_ready
            and window_ready
            and not blocked
            and not directory_busy,
            MODE_LABELS[ModeId.UPGRADE]: not running
            and runtime_ready
            and game_ready
            and self.has_samples
            and not blocked
            and not directory_busy,
            MODE_LABELS[ModeId.AI]: not running
            and runtime_ready
            and game_ready
            and window_ready
            and self.training_ready
            and not directory_busy,
            MODE_LABELS[ModeId.NUMERIC]: not running
            and runtime_ready
            and game_ready
            and window_ready
            and not blocked
            and not directory_busy,
        }
        recommended = (
            "文件夹"
            if not data_ready or directory_phase == "prepared"
            else (
                "文件"
                if not runtime_ready
                else "游戏名称" if not game_ready else "选择窗口" if not window_ready else MODE_LABELS[ModeId.COLLECT]
            )
        )
        self.header_status_text.set(
            "当前："
            + (
                "正在准备目录"
                if directory_phase == "preparing"
                else (
                    "等待确认目录"
                    if directory_phase == "prepared"
                    else "运行中" if running else "已就绪" if runtime_ready else "待配置"
                )
            )
        )
        for name, button in self.control_buttons.items():
            try:
                button.configure(state="normal" if mapping.get(name, False) else "disabled")
                if name in REQUIRED_DEFAULT_BUTTONS:
                    button.configure(style="Primary.TButton" if name == recommended else "Workflow.TButton")
            except RECOVERABLE_ERRORS as error:
                record_cleanup_error("BEST_EFFORT_EXCEPTION", error)
        for widget in self.capture_toggle_widgets.values():
            try:
                widget.configure(state="disabled" if running or directory_busy else "normal")
            except RECOVERABLE_ERRORS as error:
                record_cleanup_error("BEST_EFFORT_EXCEPTION", error)

    def _forced_exit(self, reason, exit_function=os._exit):
        self.api.block_input()
        self.api.release_all_buttons()
        self.ui_dispatcher.clear()
        clear_runtime_isolation()
        best_effort_cleanup(
            "REVIEW_PROCESS_CLOSE_FAILED",
            lambda: self.review_process.terminate(0.2) if self.review_process is not None else True,
        )
        best_effort_cleanup(
            "RUNTIME_INSTALLER_CLOSE_FAILED",
            lambda: self.runtime_installer.stop() if self.runtime_installer is not None else True,
        )
        best_effort_cleanup(
            "AI_WORKER_CLOSE_FAILED", lambda: self.ai_worker.close(0.2) if self.ai_worker is not None else True
        )
        best_effort_cleanup(
            "KEYBOARD_MONITOR_CLOSE_FAILED",
            lambda: self.keyboard_monitor.stop(0.2) if self.keyboard_monitor is not None else True,
        )
        best_effort_cleanup(
            "DIRECTORY_LOCK_CLOSE_FAILED",
            lambda: self.data_directory_lock.close() if self.data_directory_lock is not None else True,
        )
        best_effort_cleanup("CAPTURE_PROCESS_CLOSE_FAILED", lambda: self.api.stop_capture_processes(0.0, True))
        try:
            if self.store is not None:
                self.store.emergency_checkpoint(reason)
        except RECOVERABLE_ERRORS as error:
            record_cleanup_error("BEST_EFFORT_EXCEPTION", error)
        try:
            self.root.destroy()
        except RECOVERABLE_ERRORS as error:
            record_cleanup_error("BEST_EFFORT_EXCEPTION", error)
        record_cleanup_error(
            "FORCED_EXIT", RuntimeError(str(reason)), {"cleanup_errors": list(EMERGENCY_CLEANUP_ERRORS)}
        )
        exit_function(2)

