class PerceptionEvidenceHub:
    def __init__(self, maximum=128, ttl_seconds=5.0):
        self.maximum = max(8, int(maximum))
        self.ttl_seconds = max(0.1, float(ttl_seconds))
        self.lock = threading.RLock()
        self.values = OrderedDict()

    def _prune_locked(self, now=None):
        current = time.monotonic() if now is None else float(now)
        for token, value in list(self.values.items()):
            if current - safe_float(value.get("published_monotonic"), 0.0) > self.ttl_seconds:
                self.values.pop(token, None)
        while len(self.values) > self.maximum:
            self.values.popitem(last=False)

    def publish(self, key, payload):
        token = str(key or "").strip()
        if not token:
            raise ValueError("感知证据必须提供隔离键")
        value = dict(payload) if isinstance(payload, dict) else {}
        value["published_monotonic"] = time.monotonic()
        value["isolation_key"] = token
        with self.lock:
            self.values.pop(token, None)
            self.values[token] = value
            self._prune_locked()

    def latest(self, key, max_age=2.0):
        token = str(key or "").strip()
        if not token:
            raise ValueError("禁止跨窗口读取最新感知证据")
        now = time.monotonic()
        with self.lock:
            self._prune_locked(now)
            source = self.values.get(token)
            value = dict(source) if source is not None else None
        if value is None or now - safe_float(value.get("published_monotonic"), 0.0) > min(
            self.ttl_seconds, max(0.05, float(max_age))
        ):
            return None
        return value

    def clear(self, key=None, prefix=None):
        with self.lock:
            if key is not None:
                return self.values.pop(str(key), None) is not None
            if prefix is not None:
                tokens = [token for token in self.values if token.startswith(str(prefix))]
                for token in tokens:
                    self.values.pop(token, None)
                return bool(tokens)
            self.values.clear()
            return True

    def __len__(self):
        with self.lock:
            self._prune_locked()
            return len(self.values)


PERCEPTION_EVIDENCE_HUB = PerceptionEvidenceHub()


class CrossFrameObjectTracker:
    def __init__(self, history=18, maximum_scenes=64, ttl_seconds=30.0):
        self.history = max(4, int(history))
        self.maximum_scenes = max(8, int(maximum_scenes))
        self.ttl_seconds = max(1.0, float(ttl_seconds))
        self.lock = threading.RLock()
        self.scenes = OrderedDict()
        self.counter = 0

    @staticmethod
    def _center(item):
        x, y, w, h = item.get("bbox", [0.0, 0.0, 0.0, 0.0])
        return x + w * 0.5, y + h * 0.5

    @staticmethod
    def _identity_class(item):
        return str(item.get("generic_class") or item.get("class") or "unknown")

    def _score(self, current, tracked):
        if self._identity_class(current) != self._identity_class(tracked):
            return -1.0
        iou = _rect_iou(current.get("bbox", [0, 0, 0, 0]), tracked.get("bbox", [0, 0, 0, 0]))
        cx, cy = self._center(current)
        tx, ty = self._center(tracked)
        distance = math.hypot(cx - tx, cy - ty)
        text_current = str(current.get("text", "")).strip().casefold()
        text_old = str(tracked.get("text", "")).strip().casefold()
        text_bonus = (
            0.25 if text_current and text_old and (text_current in text_old or text_old in text_current) else 0.0
        )
        role_bonus = (
            0.18
            if str(current.get("role", current.get("instance", "")))
            == str(tracked.get("role", tracked.get("instance", "")))
            else 0.0
        )
        patch_current = str((current.get("attributes") or {}).get("patch_hash", ""))
        patch_old = str((tracked.get("attributes") or {}).get("patch_hash", ""))
        patch_bonus = 0.22 if patch_current and patch_old and patch_current == patch_old else 0.0
        return 1.65 * iou + max(0.0, 0.32 - distance) + text_bonus + role_bonus + patch_bonus

    def _prune_locked(self, now):
        for token, scene in list(self.scenes.items()):
            if now - safe_float(scene.get("last_time"), 0.0) > self.ttl_seconds:
                self.scenes.pop(token, None)
        while len(self.scenes) > self.maximum_scenes:
            self.scenes.popitem(last=False)

    def update(self, key, objects, stamp=None):
        scene_key = str(key or "").strip()
        if not scene_key:
            raise ValueError("对象跟踪必须提供隔离键")
        now = safe_float(stamp, time.monotonic())
        with self.lock:
            self._prune_locked(now)
            scene = self.scenes.pop(scene_key, None) or {"frame": 0, "tracks": {}, "last_time": now}
            self.scenes[scene_key] = scene
            scene["frame"] += 1
            scene["last_time"] = now
            frame_index = scene["frame"]
            tracks = scene["tracks"]
            candidates = []
            for object_index, item in enumerate(objects):
                for track_id, old in tracks.items():
                    if frame_index - safe_int(old.get("last_frame"), 0) > self.history:
                        continue
                    score = self._score(item, old)
                    if score >= 0.35:
                        candidates.append((score, object_index, track_id))
            candidates.sort(reverse=True)
            used_objects = set()
            used_tracks = set()
            assignment = {}
            for score, object_index, track_id in candidates:
                if object_index in used_objects or track_id in used_tracks:
                    continue
                used_objects.add(object_index)
                used_tracks.add(track_id)
                assignment[object_index] = track_id
            result = []
            for index, source in enumerate(objects):
                item = dict(source)
                track_id = assignment.get(index)
                if track_id is None:
                    self.counter += 1
                    track_id = "object_" + str(self.counter)
                old = tracks.get(track_id, {})
                old_center = self._center(old) if old else self._center(item)
                current_center = self._center(item)
                velocity = [round(current_center[0] - old_center[0], 6), round(current_center[1] - old_center[1], 6)]
                item["track_id"] = track_id
                item.setdefault("instance", track_id)
                attributes = dict(item.get("attributes")) if isinstance(item.get("attributes"), dict) else {}
                attributes.update({"track_id": track_id, "velocity": velocity, "age": safe_int(old.get("age"), 0) + 1})
                item["attributes"] = attributes
                item["index"] = index
                tracks[track_id] = {**item, "last_frame": frame_index, "last_time": now, "age": attributes["age"]}
                result.append(item)
            stale = [
                track_id
                for track_id, value in tracks.items()
                if frame_index - safe_int(value.get("last_frame"), 0) > self.history
            ]
            for track_id in stale:
                tracks.pop(track_id, None)
            self._prune_locked(now)
            return result

    def clear(self, key=None, prefix=None):
        with self.lock:
            if key is not None:
                return self.scenes.pop(str(key), None) is not None
            if prefix is not None:
                tokens = [token for token in self.scenes if token.startswith(str(prefix))]
                for token in tokens:
                    self.scenes.pop(token, None)
                return bool(tokens)
            self.scenes.clear()
            return True

    def __len__(self):
        with self.lock:
            self._prune_locked(time.monotonic())
            return len(self.scenes)


