def runtime_isolation_key(game_id="", session_id="", target=None, window_generation=0):
    return PerceptionIsolationKey.from_values(game_id, session_id, target, window_generation).encode()


def frame_isolation_key(frame):
    item = frame if isinstance(frame, dict) else {}
    existing = str(item.get("window_key") or "").strip()
    if existing:
        return existing
    identity_present = any(item.get(name) not in (None, "", 0) for name in ("game_id", "session_id", "hwnd", "process_created", "process_creation_time"))
    if identity_present:
        return runtime_isolation_key(item.get("game_id", ""), item.get("session_id", ""), item, item.get("window_generation", 0))
    feature = item.get("f") or item.get("feature")
    if feature_valid(feature):
        return "offline|" + hashlib.sha256(feature_bytes(feature)).hexdigest()[:32]
    raise ValueError("感知帧缺少窗口、会话和离线特征隔离信息")


def clear_runtime_isolation(key=None, prefix=None):
    PERCEPTION_EVIDENCE_HUB.clear(key=key, prefix=prefix)
    OBJECT_TRACKER.clear(key=key, prefix=prefix)
    memory = globals().get("STRUCTURED_MEMORY")
    if memory is not None:
        if key is not None:
            memory.clear(str(key))
        elif prefix is None:
            memory.clear()
        else:
            with memory.lock:
                tokens = [token for token in memory.memories if token.startswith(str(prefix))]
            for token in tokens:
                memory.clear(token)
    FEATURE_ENGINE.clear_frames()
    return True


class AutonomousObjectCenterDetector(ObjectDetector):
    role_map = {
        "confirm_button": ("button", "confirm"),
        "cancel_button": ("button", "cancel"),
        "close_button": ("button", "close"),
        "purchase_button": ("button", "purchase"),
        "delete_button": ("button", "delete"),
        "exit_button": ("button", "exit"),
        "overwrite_button": ("button", "overwrite"),
        "save_button": ("button", "save"),
        "start_button": ("button", "start"),
        "restart_button": ("button", "restart"),
        "text_button": ("button", "text"),
        "inventory_item": ("item", "inventory"),
        "equipment_slot": ("slot", "equipment"),
        "status_bar": ("meter", "status"),
        "interactive_region": ("target_area", "interactive"),
    }

    @staticmethod
    def _rgb_small(frame, width=160, height=90):
        source, source_width, source_height = _frame_rgb_source(frame)
        if source is None:
            return None
        return resize_rgb(source, source_width, source_height, width, height)

    @staticmethod
    def _gray(rgb):
        return bytes(
            (int(rgb[index]) * 77 + int(rgb[index + 1]) * 150 + int(rgb[index + 2]) * 29) // 256
            for index in range(0, len(rgb), 3)
        )

    @staticmethod
    def _feature_source(frame):
        if not isinstance(frame, dict):
            return None
        for key in ("neural_f", "f", "feature"):
            value = frame.get(key)
            if feature_valid(value):
                return feature_bytes(value)
        return None

    @classmethod
    def _appearance_embedding(cls, frame, bbox):
        feature = cls._feature_source(frame)
        values = []
        if feature is not None:
            left = max(0, min(FEATURE_W - 1, round(safe_float(bbox[0], 0.0) * FEATURE_W)))
            top = max(0, min(FEATURE_H - 1, round(safe_float(bbox[1], 0.0) * FEATURE_H)))
            right = max(
                left + 1, min(FEATURE_W, round((safe_float(bbox[0], 0.0) + safe_float(bbox[2], 0.0)) * FEATURE_W))
            )
            bottom = max(
                top + 1, min(FEATURE_H, round((safe_float(bbox[1], 0.0) + safe_float(bbox[3], 0.0)) * FEATURE_H))
            )
            for channel in range(FEATURE_CHANNELS):
                plane = feature[channel * PIXELS : (channel + 1) * PIXELS]
                region = []
                for y in range(top, bottom):
                    region.extend(plane[y * FEATURE_W + left : y * FEATURE_W + right])
                mean = sum(region) / max(1, len(region)) / 255.0
                variance = sum((entry / 255.0 - mean) ** 2 for entry in region) / max(1, len(region))
                values.extend((round(mean, 6), round(math.sqrt(variance), 6)))
        rgb = cls._rgb_small(frame, 64, 36)
        if rgb is not None:
            left = max(0, min(63, round(safe_float(bbox[0], 0.0) * 64)))
            top = max(0, min(35, round(safe_float(bbox[1], 0.0) * 36)))
            right = max(left + 1, min(64, round((safe_float(bbox[0], 0.0) + safe_float(bbox[2], 0.0)) * 64)))
            bottom = max(top + 1, min(36, round((safe_float(bbox[1], 0.0) + safe_float(bbox[3], 0.0)) * 36)))
            for channel in range(3):
                region = [rgb[(y * 64 + x) * 3 + channel] for y in range(top, bottom) for x in range(left, right)]
                values.append(round(sum(region) / max(1, len(region)) / 255.0, 6))
        return values[:16]

    @staticmethod
    def _connected_components(mask, width, height, minimum=4, maximum_area_ratio=0.72):
        visited = bytearray(width * height)
        result = []
        for seed in range(width * height):
            if not mask[seed] or visited[seed]:
                continue
            stack = [seed]
            visited[seed] = 1
            points = []
            while stack and len(points) < width * height:
                current = stack.pop()
                points.append(current)
                x = current % width
                y = current // width
                for neighbor in (current - 1, current + 1, current - width, current + width):
                    if neighbor < 0 or neighbor >= width * height or visited[neighbor] or not mask[neighbor]:
                        continue
                    nx = neighbor % width
                    ny = neighbor // width
                    if abs(nx - x) + abs(ny - y) != 1:
                        continue
                    visited[neighbor] = 1
                    stack.append(neighbor)
            if len(points) < minimum:
                continue
            xs = [point % width for point in points]
            ys = [point // width for point in points]
            left = max(0, min(xs) - 1)
            top = max(0, min(ys) - 1)
            right = min(width, max(xs) + 2)
            bottom = min(height, max(ys) + 2)
            area = (right - left) * (bottom - top)
            if area < 8 or area > width * height * maximum_area_ratio:
                continue
            result.append((points, left, top, right, bottom))
        return result

    def _region_proposals(self, frame, maximum):
        width, height = 80, 45
        rgb = self._rgb_small(frame, width, height)
        if rgb is None:
            return []
        gray = self._gray(rgb)
        gradients = []
        for y in range(1, height - 1):
            for x in range(1, width - 1):
                index = y * width + x
                gradients.append(
                    abs(gray[index + 1] - gray[index - 1]) + abs(gray[index + width] - gray[index - width])
                )
        median = statistics.median(gradients) if gradients else 0.0
        threshold = max(34.0, median + 28.0)
        mask = bytearray(width * height)
        for y in range(1, height - 1):
            for x in range(1, width - 1):
                index = y * width + x
                gradient = abs(gray[index + 1] - gray[index - 1]) + abs(gray[index + width] - gray[index - width])
                local = (gray[index - 1] + gray[index + 1] + gray[index - width] + gray[index + width]) / 4.0
                if gradient >= threshold or abs(gray[index] - local) >= 30:
                    mask[index] = 1
        components = []
        for points, left, top, right, bottom in self._connected_components(mask, width, height, 5):
            area = (right - left) * (bottom - top)
            density = len(points) / max(1, area)
            if density < 0.045:
                continue
            components.append(
                (
                    len(points) * density,
                    [left / width, top / height, (right - left) / width, (bottom - top) / height],
                    density,
                )
            )
        components.sort(reverse=True)
        proposals = []
        for _, bbox, density in components[: max(4, int(maximum))]:
            object_class, role = self._classify_region(bbox, density, "")
            patch = _crop_semantic_patch(frame, bbox, 32, 18)
            confidence = max(0.32, min(0.82, 0.34 + density * 0.55))
            embedding = self._appearance_embedding(frame, bbox)
            uncertainty = max(0.05, min(0.95, 1.0 - confidence + 0.10))
            proposals.append(
                {
                    "class": object_class,
                    "generic_class": object_class,
                    "role": role,
                    "instance": "",
                    "text": "",
                    "bbox": [round(value, 6) for value in bbox],
                    "state": "enabled",
                    "confidence": confidence,
                    "uncertainty": uncertainty,
                    "appearance_embedding": embedding,
                    "interactable": object_class
                    in {"button", "item", "card", "tile", "slot", "target_area", "scroll_area"},
                    "source": "manual_fallback_region_detector",
                    "attributes": {
                        "patch_hash": patch["sha256"] if patch else "",
                        "density": round(density, 5),
                        "appearance_embedding": embedding,
                        "uncertainty": uncertainty,
                        "evidence_sources": ["rgb_edges", "color_contrast"],
                        "modality_mask": {"rgb": True, "neural": False, "ocr": False, "motion": False},
                    },
                }
            )
        return proposals

    def _neural_region_proposals(self, frame, maximum):
        feature = self._feature_source(frame)
        if feature is None:
            return []
        width, height = FEATURE_W, FEATURE_H
        edge = feature[3 * PIXELS : 4 * PIXELS]
        motion = feature[4 * PIXELS : 5 * PIXELS]
        activation = []
        for index in range(PIXELS):
            activation.append(0.68 * edge[index] + 0.32 * motion[index])
        median = statistics.median(activation) if activation else 0.0
        deviation = statistics.median(abs(value - median) for value in activation) if activation else 0.0
        threshold = max(48.0, median + 2.2 * deviation)
        mask = bytearray(PIXELS)
        for y in range(1, height - 1):
            for x in range(1, width - 1):
                index = y * width + x
                local = (
                    activation[index - 1]
                    + activation[index + 1]
                    + activation[index - width]
                    + activation[index + width]
                ) / 4.0
                if activation[index] >= threshold and activation[index] >= local * 1.05:
                    mask[index] = 1
        components = []
        for points, left, top, right, bottom in self._connected_components(mask, width, height, 3, 0.55):
            area = (right - left) * (bottom - top)
            density = len(points) / max(1, area)
            strength = statistics.fmean(activation[point] for point in points) / 255.0
            if density < 0.03 or strength < 0.18:
                continue
            bbox = [left / width, top / height, (right - left) / width, (bottom - top) / height]
            components.append((strength * density, bbox, density, strength))
        components.sort(reverse=True)
        proposals = []
        for _, bbox, density, strength in components[: max(4, int(maximum))]:
            object_class, role = self._classify_region(bbox, density, "")
            embedding = self._appearance_embedding(frame, bbox)
            confidence = max(0.34, min(0.90, 0.38 + 0.34 * strength + 0.28 * density))
            uncertainty = max(0.04, min(0.90, 1.0 - confidence))
            proposals.append(
                {
                    "class": object_class,
                    "generic_class": object_class,
                    "role": role,
                    "instance": "",
                    "text": "",
                    "bbox": [round(value, 6) for value in bbox],
                    "state": "enabled",
                    "confidence": confidence,
                    "uncertainty": uncertainty,
                    "appearance_embedding": embedding,
                    "interactable": object_class
                    in {"button", "item", "card", "tile", "slot", "target_area", "scroll_area"},
                    "source": "shared_backbone_multiscale_proposal",
                    "attributes": {
                        "activation": round(strength, 5),
                        "density": round(density, 5),
                        "appearance_embedding": embedding,
                        "uncertainty": uncertainty,
                        "evidence_sources": ["shared_backbone", "motion_encoder"],
                        "modality_mask": {"rgb": False, "neural": True, "ocr": False, "motion": True},
                    },
                }
            )
        return proposals

    @staticmethod
    def _classify_region(bbox, density, text):
        x, y, w, h = bbox
        aspect = w / max(0.001, h)
        area = w * h
        value = str(text or "").strip()
        digits = sum(character.isdigit() for character in value)
        lowered = value.casefold()
        if value and digits >= max(1, len(value.replace(" ", "")) * 0.55):
            return "number", "value"
        if any(token in lowered for token in ("victory", "win", "胜利", "成功", "失败", "defeat", "game over")):
            return "dialog", "terminal"
        if aspect >= 4.0 and h <= 0.13:
            return "meter", "status"
        if x >= 0.88 and h >= 0.25 and w <= 0.12:
            return "scroll_area", "vertical"
        if area >= 0.20 and 0.12 <= x <= 0.36 and 0.08 <= y <= 0.38:
            return "dialog", "modal"
        if area >= 0.28 and y <= 0.18:
            return "menu", "overlay"
        if w <= 0.045 and h <= 0.07 and density > 0.28:
            return "cursor", "pointer"
        if 0.75 <= aspect <= 1.45 and 0.055 <= w <= 0.19 and 0.07 <= h <= 0.25:
            if y >= 0.56:
                return "card", "playable"
            if x < 0.5:
                return "character", "actor"
            return "enemy", "opponent"
        if 0.75 <= aspect <= 1.35 and w <= 0.16 and h <= 0.20:
            if y >= 0.62:
                return "slot", "drop"
            return "tile", "board"
        if h >= 0.18 and 0.35 <= aspect <= 1.35:
            return ("character", "actor") if x < 0.5 else ("enemy", "opponent")
        if aspect >= 1.65 and h <= 0.18:
            return "button", "generic"
        if area <= 0.035:
            return "item", "collectible"
        return "target_area", "interactive"

    @classmethod
    def _legacy_to_object(cls, item, frame=None):
        legacy_class = str(item.get("class", "interactive_region"))
        generic, role = cls.role_map.get(
            legacy_class, (legacy_class if legacy_class in GENERAL_OBJECT_CLASSES else "target_area", legacy_class)
        )
        value = dict(item)
        value["legacy_class"] = legacy_class
        value["class"] = generic
        value["generic_class"] = generic
        value["role"] = role
        value["instance"] = str(value.get("instance") or role or "")
        value["state"] = (
            "disabled"
            if bool((value.get("attributes") or {}).get("disabled"))
            else str(value.get("state") or "enabled")
        )
        value["interactable"] = bool(value.get("interactable", generic not in {"dialog", "menu", "number", "meter"}))
        attributes = dict(value.get("attributes")) if isinstance(value.get("attributes"), dict) else {}
        embedding = cls._appearance_embedding(frame or {}, value.get("bbox", [0, 0, 0, 0]))
        evidence = ["ocr"] if str(value.get("text", "")) else ["legacy_semantic_rule"]
        attributes.update(
            {
                "legacy_class": legacy_class,
                "role": role,
                "appearance_embedding": embedding,
                "uncertainty": max(0.02, 1.0 - safe_float(value.get("confidence"), 0.5)),
                "evidence_sources": evidence,
                "modality_mask": {"rgb": True, "neural": False, "ocr": bool(value.get("text")), "motion": False},
            }
        )
        value["attributes"] = attributes
        value["appearance_embedding"] = embedding
        value["uncertainty"] = attributes["uncertainty"]
        value["affordances"] = infer_object_affordances(value)
        value["open_vocabulary_description"] = object_open_vocabulary_description(value)
        attributes["affordances"] = dict(value["affordances"])
        value["risk_class"] = semantic_target_risk({**value, "class": legacy_class})
        return value

    @staticmethod
    def _merge_object(old, item):
        merged = dict(old)
        old_attributes = dict(old.get("attributes")) if isinstance(old.get("attributes"), dict) else {}
        new_attributes = dict(item.get("attributes")) if isinstance(item.get("attributes"), dict) else {}
        evidence = list(
            dict.fromkeys(
                list(old_attributes.get("evidence_sources", [])) + list(new_attributes.get("evidence_sources", []))
            )
        )
        old_attributes.update(new_attributes)
        old_attributes["evidence_sources"] = evidence
        merged["attributes"] = old_attributes
        merged["confidence"] = max(safe_float(old.get("confidence"), 0.0), safe_float(item.get("confidence"), 0.0))
        merged["uncertainty"] = min(safe_float(old.get("uncertainty"), 1.0), safe_float(item.get("uncertainty"), 1.0))
        merged["appearance_embedding"] = item.get("appearance_embedding") or old.get("appearance_embedding", [])
        if item.get("text") and not old.get("text"):
            merged["text"] = item.get("text")
        return merged

    def detect_frame(self, frame, maximum=32):
        try:
            legacy = LEGACY_OCR_SEMANTIC_DETECTOR.detect_frame(frame, max(8, min(24, int(maximum))))
        except (TypeError, ValueError, RuntimeError, CaptureUnavailable):
            legacy = []
        canonical = [self._legacy_to_object(item, frame) for item in legacy if isinstance(item, dict)]
        canonical.extend(self._neural_region_proposals(frame, max(8, int(maximum))))
        canonical.extend(self._region_proposals(frame, max(8, int(maximum))))
        unique = []
        for item in sorted(
            canonical,
            key=lambda value: (
                safe_float(value.get("confidence"), 0.0),
                len((value.get("attributes") or {}).get("evidence_sources", [])),
                bool(value.get("text")),
            ),
            reverse=True,
        ):
            match = next(
                (
                    index
                    for index, old in enumerate(unique)
                    if str(item.get("class")) == str(old.get("class"))
                    and str(item.get("role")) == str(old.get("role"))
                    and _rect_iou(item.get("bbox", []), old.get("bbox", [])) > 0.56
                ),
                None,
            )
            if match is not None:
                unique[match] = self._merge_object(unique[match], item)
            else:
                unique.append(item)
            if len(unique) >= max(8, int(maximum)):
                break
        key = frame_isolation_key(frame)
        tracked = OBJECT_TRACKER.update(
            key,
            unique,
            safe_float(frame.get("time"), time.monotonic()) if isinstance(frame, dict) else time.monotonic(),
        )
        result = []
        for index, item in enumerate(tracked):
            attributes = dict(item.get("attributes")) if isinstance(item.get("attributes"), dict) else {}
            velocity = attributes.get("velocity", [0.0, 0.0])
            item["velocity"] = velocity
            item["index"] = index
            item["affordances"] = infer_object_affordances(item)
            item["open_vocabulary_description"] = object_open_vocabulary_description(item)
            attributes["affordances"] = dict(item["affordances"])
            item["attributes"] = attributes
            item["risk_class"] = semantic_target_risk(item)
            result.append(item)
            legacy_class = str(item.get("legacy_class") or attributes.get("legacy_class") or "")
            if legacy_class and legacy_class != item.get("class"):
                alias = dict(item)
                alias["class"] = legacy_class
                alias["generic_class"] = str(item.get("class"))
                alias["source"] = "compatibility_alias"
                alias["confidence"] = max(
                    SEMANTIC_TARGET_MIN_CONFIDENCE, safe_float(item.get("confidence"), 0.5) - 0.02
                )
                alias["index"] = len(result)
                result.append(alias)
        return result[: max(8, int(maximum)) * 2]

    def detect(self, observation):
        item = dict(observation) if isinstance(observation, dict) else {}
        targets = item.get("semantic_targets")
        if not isinstance(targets, (list, tuple)) or not targets:
            targets = self.detect_frame(item, 32)
        slots = []
        for index, value in enumerate(targets):
            try:
                payload = dict(value)
                attributes = dict(payload.get("attributes")) if isinstance(payload.get("attributes"), dict) else {}
                attributes.update(
                    {
                        "track_id": payload.get("track_id", ""),
                        "role": payload.get("role", ""),
                        "generic_class": payload.get("generic_class", payload.get("class", "")),
                    }
                )
                payload["attributes"] = attributes
                payload["instance"] = str(payload.get("track_id") or payload.get("instance") or index)
                slots.append(ObjectSlot.from_mapping(payload, index))
            except (TypeError, ValueError, OverflowError):
                continue
        return tuple(
            sorted(slots, key=lambda slot: (slot.object_class, slot.instance, slot.text.casefold(), slot.bbox))
        )


AUTONOMOUS_OBJECT_DETECTOR = AutonomousObjectCenterDetector()


def build_scene_graph(objects):
    canonical = [
        dict(item)
        for item in objects or []
        if isinstance(item, dict) and str(item.get("source")) != "compatibility_alias"
    ]
    nodes = []
    edges = []
    for item in canonical:
        node_id = str(item.get("track_id") or item.get("instance") or "object_" + str(len(nodes)))
        affordances = infer_object_affordances(item)
        nodes.append(
            {
                "id": node_id,
                "class": str(item.get("class", "unknown")),
                "role": str(item.get("role", "")),
                "text": str(item.get("text", ""))[:128],
                "bbox": list(item.get("bbox", [0, 0, 0, 0])),
                "state": str(item.get("state", "unknown")),
                "affordances": affordances,
                "description": str(item.get("open_vocabulary_description") or object_open_vocabulary_description(item))[
                    :256
                ],
            }
        )
        for name, confidence in affordances.items():
            edges.append({"source": node_id, "relation": "affords", "target": name, "confidence": confidence})
        text = str(item.get("text", "")).strip()
        if text:
            edges.append(
                {
                    "source": node_id,
                    "relation": "text_is",
                    "target": text[:128],
                    "confidence": safe_float(item.get("confidence"), 0.0),
                }
            )
    for first_index, first in enumerate(canonical):
        first_id = str(first.get("track_id") or first.get("instance") or "object_" + str(first_index))
        fx, fy, fw, fh = first.get("bbox", [0, 0, 0, 0])
        fcx = fx + fw * 0.5
        fcy = fy + fh * 0.5
        for second_index, second in enumerate(canonical):
            if first_index == second_index:
                continue
            second_id = str(second.get("track_id") or second.get("instance") or "object_" + str(second_index))
            sx, sy, sw, sh = second.get("bbox", [0, 0, 0, 0])
            scx = sx + sw * 0.5
            scy = sy + sh * 0.5
            if sx <= fcx <= sx + sw and sy <= fcy <= sy + sh and sw * sh > fw * fh * 1.4:
                edges.append({"source": first_id, "relation": "located_in", "target": second_id, "confidence": 0.82})
            distance = math.hypot(fcx - scx, fcy - scy)
            if distance < 0.18 and first_index < second_index:
                edges.append(
                    {
                        "source": first_id,
                        "relation": "near",
                        "target": second_id,
                        "confidence": round(max(0.35, 1.0 - distance / 0.18), 4),
                    }
                )
        first_text = (str(first.get("text", "") + " " + str(first.get("role", "")))).casefold()
        if any(token in first_text for token in ("key", "钥匙")):
            for second in canonical:
                second_text = (str(second.get("text", "") + " " + str(second.get("role", "")))).casefold()
                if any(token in second_text for token in ("door", "门")):
                    edges.append(
                        {
                            "source": first_id,
                            "relation": "can_open",
                            "target": str(second.get("track_id") or second.get("instance")),
                            "confidence": 0.68,
                        }
                    )
    return {"schema_version": 1, "nodes": nodes[:64], "edges": edges[:160]}


def high_resolution_semantic_tokens(
    frame, width=HYBRID_GLOBAL_SIZE[0], height=HYBRID_GLOBAL_SIZE[1], patch=HYBRID_SEMANTIC_PATCH
):
    item = dict(frame) if isinstance(frame, dict) else {}
    external = item.get("semantic_backbone_tokens")
    if isinstance(external, list) and external:
        tokens = []
        for value in external[:512]:
            if isinstance(value, (list, tuple)):
                tokens.append([round(safe_float(entry, 0.0, -8.0, 8.0), 6) for entry in list(value)[:64]])
        if tokens:
            return {
                "backend": str(item.get("semantic_backbone_backend") or "external_learned_backbone"),
                "learned": True,
                "quantized": bool(item.get("semantic_backbone_quantized")),
                "device": str(item.get("semantic_backbone_device") or "unknown"),
                "input_size": [safe_int(width, HYBRID_GLOBAL_SIZE[0]), safe_int(height, HYBRID_GLOBAL_SIZE[1])],
                "patch_size": safe_int(patch, HYBRID_SEMANTIC_PATCH),
                "tokens": tokens,
                "token_count": len(tokens),
                "checksum": hashlib.sha256(canonical_bytes(tokens)).hexdigest(),
            }
    source, source_width, source_height = _frame_rgb_source(item)
    if source is None:
        return {
            "backend": "manual_feature_only",
            "learned": False,
            "quantized": False,
            "device": "cpu",
            "input_size": [width, height],
            "patch_size": patch,
            "tokens": [],
            "token_count": 0,
            "checksum": "",
        }
    rgb = resize_rgb(source, source_width, source_height, width, height)
    tokens = []
    for top in range(0, height, patch):
        bottom = min(height, top + patch)
        for left in range(0, width, patch):
            right = min(width, left + patch)
            count = max(1, (right - left) * (bottom - top))
            sums = [0.0, 0.0, 0.0]
            squares = [0.0, 0.0, 0.0]
            edge = 0.0
            for y in range(top, bottom):
                for x in range(left, right):
                    offset = (y * width + x) * 3
                    values = [rgb[offset] / 255.0, rgb[offset + 1] / 255.0, rgb[offset + 2] / 255.0]
                    for channel, value in enumerate(values):
                        sums[channel] += value
                        squares[channel] += value * value
                    if x + 1 < right:
                        adjacent = offset + 3
                        edge += sum(
                            abs(int(rgb[offset + channel]) - int(rgb[adjacent + channel])) for channel in range(3)
                        ) / (3.0 * 255.0)
                    if y + 1 < bottom:
                        adjacent = offset + width * 3
                        edge += sum(
                            abs(int(rgb[offset + channel]) - int(rgb[adjacent + channel])) for channel in range(3)
                        ) / (3.0 * 255.0)
            means = [value / count for value in sums]
            deviations = [
                math.sqrt(max(0.0, squares[channel] / count - means[channel] * means[channel])) for channel in range(3)
            ]
            cx = (left + right) / (2.0 * width)
            cy = (top + bottom) / (2.0 * height)
            token = [
                *means,
                *deviations,
                min(1.0, edge / max(1.0, count * 2.0)),
                cx,
                cy,
                (right - left) / width,
                (bottom - top) / height,
            ]
            tokens.append([round(value, 6) for value in token])
    checksum = hashlib.sha256(canonical_bytes(tokens)).hexdigest()
    return {
        "backend": "high_resolution_patch_fallback",
        "learned": False,
        "quantized": False,
        "device": "cpu",
        "input_size": [width, height],
        "patch_size": patch,
        "tokens": tokens,
        "token_count": len(tokens),
        "checksum": checksum,
        "upgrade_contract": {"cpu": "quantized_onnx_int8", "gpu": "full_cnn_or_vit", "manual_feature_fallback": True},
    }


def build_hybrid_visual_state(frame, history=None):
    item = dict(frame) if isinstance(frame, dict) else {}
    source, source_width, source_height = _frame_rgb_source(item)
    if source is None:
        return {
            "schema_version": 1,
            "global_size": list(HYBRID_GLOBAL_SIZE),
            "global_digest": "",
            "local_crops": [],
            "motion": [],
            "manual_fallback": {"available": feature_valid(item.get("f"))},
        }
    global_width, global_height = HYBRID_GLOBAL_SIZE
    global_rgb = resize_rgb(source, source_width, source_height, global_width, global_height)
    compressed = zlib.compress(global_rgb, 4)
    semantic_tokens = high_resolution_semantic_tokens(item, global_width, global_height, HYBRID_SEMANTIC_PATCH)
    targets = [
        value
        for value in item.get("semantic_targets", [])
        if isinstance(value, dict) and str(value.get("source")) != "compatibility_alias"
    ]
    local = []
    for target in sorted(
        targets,
        key=lambda value: (
            str(value.get("class")) in {"number", "button", "meter"},
            safe_float(value.get("confidence"), 0.0),
        ),
        reverse=True,
    )[:10]:
        crop_size = 128 if str(target.get("class")) in {"number", "button", "meter"} else 96
        patch = _crop_semantic_patch(item, target.get("bbox"), crop_size, crop_size)
        if patch is not None:
            local.append(
                {
                    "track_id": str(target.get("track_id", "")),
                    "class": str(target.get("class", "")),
                    "role": str(target.get("role", "")),
                    "size": [crop_size, crop_size],
                    "sha256": patch["sha256"],
                    "data_b85": patch["data_b85"],
                }
            )
    motion = []
    for old in list(history or [])[-(HYBRID_HISTORY_FRAMES - 1) :]:
        old_source, old_width, old_height = _frame_rgb_source(old if isinstance(old, dict) else {})
        if old_source is None:
            continue
        old_global = resize_rgb(old_source, old_width, old_height, global_width, global_height)
        difference = sum(abs(int(a) - int(b)) for a, b in zip(global_rgb, old_global)) / max(1, len(global_rgb))
        motion.append(round(difference, 5))
    manual = item.get("f")
    manual_status = {
        "available": feature_valid(manual),
        "black_frame": bool(item.get("black_frame")),
        "capture_frozen": bool(item.get("capture_frozen")),
        "protected_or_black": bool(item.get("protected_or_black")),
        "ood_independent_evidence": True,
    }
    return {
        "schema_version": 3,
        "global_size": [global_width, global_height],
        "optional_global_size": list(HYBRID_GLOBAL_OPTIONAL_SIZE),
        "global_digest": hashlib.sha256(global_rgb).hexdigest(),
        "global_rgb_b85": base64.b85encode(compressed).decode("ascii"),
        "semantic_tokens": semantic_tokens,
        "local_crops": local,
        "motion": motion[-HYBRID_HISTORY_FRAMES:],
        "history_frames": min(HYBRID_HISTORY_FRAMES, len(motion) + 1),
        "manual_fallback": manual_status,
        "dual_path": {
            "fast_path": [FEATURE_W, FEATURE_H, FEATURE_CHANNELS],
            "semantic_path": [global_width, global_height],
            "temporal_frames": HYBRID_HISTORY_FRAMES,
        },
    }


@dataclass(frozen=True, slots=True)
class FrameComputationKey:
    session_id: str
    window_identity: str
    frame_timestamp: object
    feature_version: int


def frame_computation_key(frame):
    item = frame if isinstance(frame, dict) else {}
    session_id = str(item.get("session_id") or item.get("mode_session_id") or "offline")
    try:
        window_identity = frame_isolation_key(item)
    except ValueError:
        window_identity = "offline|" + frame_digest(item)[:32]
    timestamp = item.get("frame_timestamp", item.get("time", item.get("timestamp")))
    if timestamp in (None, ""):
        timestamp = frame_digest(item)
    feature_version = safe_int(
        item.get("feature_version", item.get("feature_algorithm_version", FEATURE_ALGORITHM_VERSION)),
        FEATURE_ALGORITHM_VERSION,
        1,
    )
    return FrameComputationKey(session_id, window_identity, timestamp, feature_version)


class FrozenCacheDict(dict):
    @staticmethod
    def _immutable(*args, **kwargs):
        raise TypeError("帧计算缓存值不可变")

    __setitem__ = _immutable
    __delitem__ = _immutable
    clear = _immutable
    pop = _immutable
    popitem = _immutable
    setdefault = _immutable
    update = _immutable
    __ior__ = _immutable


class FrozenCacheList(list):
    @staticmethod
    def _immutable(*args, **kwargs):
        raise TypeError("帧计算缓存值不可变")

    __setitem__ = _immutable
    __delitem__ = _immutable
    append = _immutable
    clear = _immutable
    extend = _immutable
    insert = _immutable
    pop = _immutable
    remove = _immutable
    reverse = _immutable
    sort = _immutable
    __iadd__ = _immutable
    __imul__ = _immutable


def freeze_frame_cache_value(value):
    if isinstance(value, (FrozenCacheDict, FrozenCacheList)):
        return value
    if value is None or isinstance(value, (str, int, float, bool, bytes)):
        return value
    if isinstance(value, memoryview):
        return value.tobytes()
    if isinstance(value, Path):
        return str(value)
    if isinstance(value, dict):
        return FrozenCacheDict((str(key), freeze_frame_cache_value(item)) for key, item in value.items())
    if isinstance(value, (list, tuple, deque)):
        return FrozenCacheList(freeze_frame_cache_value(item) for item in value)
    if isinstance(value, (set, frozenset)):
        return frozenset(freeze_frame_cache_value(item) for item in value)
    return value


class FrameComputationCache:
    def __init__(self, maximum=256):
        self.maximum = max(32, int(maximum))
        self.lock = threading.RLock()
        self.values = OrderedDict()

    def get(self, key):
        with self.lock:
            token = str(key)
            value = self.values.pop(token, None)
            if value is None:
                return None
            self.values[token] = value
            return value

    def put(self, key, value):
        frozen = freeze_frame_cache_value(value)
        with self.lock:
            token = str(key)
            self.values.pop(token, None)
            self.values[token] = frozen
            while len(self.values) > self.maximum:
                self.values.popitem(last=False)

    def get_component(self, key, component):
        with self.lock:
            token = str(key)
            value = self.values.pop(token, None)
            if value is None:
                return None
            self.values[token] = value
            return value.get(str(component)) if isinstance(value, dict) else None

    def put_component(self, key, component, value):
        with self.lock:
            token = str(key)
            existing = self.values.pop(token, None)
            payload = dict(existing) if isinstance(existing, dict) else {}
            payload[str(component)] = freeze_frame_cache_value(value)
            self.values[token] = freeze_frame_cache_value(payload)
            while len(self.values) > self.maximum:
                self.values.popitem(last=False)

    def clear(self):
        with self.lock:
            self.values.clear()


FEATURE_ENGINE.frame_cache = FrameComputationCache()


def frame_digest(frame):
    item = frame if isinstance(frame, dict) else {}
    existing = str(item.get("frame_digest", "")).strip()
    if len(existing) == 64:
        return existing
    material = None
    for key in ("preview_rgb", "rgb", "neural_f", "f", "feature"):
        value = item.get(key)
        if isinstance(value, memoryview):
            value = value.tobytes()
        if isinstance(value, (bytes, bytearray)) and value:
            material = bytes(value)
            break
    if material is None:
        material = canonical_bytes(
            {key: item.get(key) for key in ("time", "rect", "method", "capture_method", "object_signature")}
        )
    digest = hashlib.sha256(material).hexdigest()
    item["frame_digest"] = digest
    return digest


SEMANTIC_DETECTORS = {
    "legacy_ocr": LEGACY_OCR_SEMANTIC_DETECTOR,
    "object_centric_v2": AUTONOMOUS_OBJECT_DETECTOR,
}
DEFAULT_SEMANTIC_DETECTOR_VERSION = "object_centric_v2"


def detect_semantic_targets(frame, maximum=32, version="object_centric_v2"):
    started = time.monotonic()
    item = frame if isinstance(frame, dict) else {}
    detector_version = str(version or DEFAULT_SEMANTIC_DETECTOR_VERSION)
    detector = SEMANTIC_DETECTORS.get(detector_version)
    if detector is None:
        raise ValueError("未知语义检测器版本：" + detector_version)
    cache_key = frame_computation_key(item)
    component = "semantic:" + detector_version + ":" + str(max(1, int(maximum)))
    cached = FEATURE_ENGINE.frame_cache.get_component(cache_key, component)
    if isinstance(cached, dict):
        targets = cached.get("targets", [])
        scene_graph = cached.get("scene_graph", {})
        RUNTIME_METRICS.increment("semantic_cache_hit")
    else:
        targets = detector.detect_frame(item, maximum)
        scene_graph = build_scene_graph(targets)
        payload = {"targets": targets, "scene_graph": scene_graph}
        FEATURE_ENGINE.frame_cache.put_component(cache_key, component, payload)
        RUNTIME_METRICS.increment("semantic_cache_miss")
    item["scene_graph"] = scene_graph
    item["semantic_detector_version"] = detector_version
    text_values = [
        str(value.get("text", "")).strip()
        for value in targets
        if isinstance(value, dict) and str(value.get("text", "")).strip()
    ]
    canonical = [value for value in targets if str(value.get("source")) != "compatibility_alias"]
    key = frame_isolation_key(item)
    PERCEPTION_EVIDENCE_HUB.publish(
        key,
        {
            "objects": canonical,
            "texts": text_values,
            "scene_graph": scene_graph,
            "motion": list((item.get("visual_pyramid") or {}).get("motion", [])),
            "frame_time": item.get("time"),
            "game_id": item.get("game_id", ""),
        },
    )
    RUNTIME_METRICS.observe("semantic_ocr_ms", (time.monotonic() - started) * 1000.0)
    return targets


class StructuredTemporalMemory:
    def __init__(self, maximum=STRUCTURED_MEMORY_LENGTH):
        plan = RESOURCE_GOVERNOR.current_plan()
        self.maximum = max(32, min(128, int(max(maximum, plan.temporal_context_length))))
        self.lock = threading.RLock()
        self.memories = {}
        self.failure_recovery_stacks = {}
        self.long_term_variables = {}
        self.completed_subgoals = {}

    def update(self, key, observation, context=None):
        memory_key = str(key or "default")
        item = observation.to_dict() if isinstance(observation, ObservationState) else dict(observation or {})
        source = dict(context) if isinstance(context, dict) else {}
        internal = item.get("internal_state", {}) if isinstance(item.get("internal_state"), dict) else {}
        failure_reason = str(source.get("no_change_reason") or source.get("failure_reason") or "")
        completed = list(source.get("completed_subgoals", []))
        with self.lock:
            recovery_stack = self.failure_recovery_stacks.setdefault(memory_key, deque(maxlen=32))
            long_term = self.long_term_variables.setdefault(
                memory_key,
                {"resources": {}, "tasks": {}, "characters": {}, "cross_scene": {}},
            )
            completed_memory = self.completed_subgoals.setdefault(memory_key, deque(maxlen=128))
            if failure_reason:
                recovery_stack.append(
                    {
                        "time": time.monotonic(),
                        "reason": failure_reason,
                        "state_id": str(item.get("state_id", "")),
                        "last_action": list(item.get("recent_actions", []))[-1:] or [None],
                    }
                )
            for subgoal in completed:
                if subgoal:
                    completed_memory.append(str(subgoal))
            for category in ("resources", "tasks", "characters", "cross_scene"):
                values = internal.get(category, {}) if isinstance(internal.get(category), dict) else {}
                for variable, variable_value in values.items():
                    long_term[category][str(variable)] = variable_value
        compact = {
            "state_id": str(item.get("state_id", "")),
            "environment_id": str(item.get("environment_id", "")),
            "objects": [
                {
                    key: value.get(key)
                    for key in ("class", "instance", "text", "bbox", "state", "value", "attributes")
                    if key in value
                }
                for value in item.get("objects", [])[:48]
            ],
            "task": dict(item.get("task", {})),
            "internal_state": dict(item.get("internal_state", {})),
            "recent_actions": list(item.get("recent_actions", []))[-8:],
            "recent_rewards": list(item.get("recent_rewards", []))[-8:],
            "time": time.monotonic(),
            "failure_reason": failure_reason,
            "scene_graph": source.get("scene_graph", {}),
        }
        with self.lock:
            memory = self.memories.setdefault(memory_key, deque(maxlen=self.maximum))
            if (
                not memory
                or memory[-1].get("state_id") != compact["state_id"]
                or compact["recent_actions"] != memory[-1].get("recent_actions")
            ):
                memory.append(compact)
            values = list(memory)
        visited = sorted({str(value.get("environment_id")) for value in values if value.get("environment_id")})[-64:]
        actions = []
        failures = []
        remembered = {}
        for value in values:
            actions.extend(str(action) for action in value.get("recent_actions", []))
            if value.get("failure_reason"):
                failures.append(value["failure_reason"])
            for obj in value.get("objects", []):
                track_id = str((obj.get("attributes") or {}).get("track_id") or obj.get("instance") or "")
                if track_id:
                    remembered[track_id] = {
                        "class": obj.get("class"),
                        "text": obj.get("text"),
                        "state": obj.get("state"),
                        "bbox": obj.get("bbox"),
                    }
        phases = Counter(str(value.get("internal_state", {}).get("task_phase", "unknown")) for value in values)
        with self.lock:
            recovery_stack = list(self.failure_recovery_stacks.get(memory_key, ()))
            long_term = {
                category: dict(data)
                for category, data in self.long_term_variables.get(memory_key, {}).items()
            }
            completed_memory = list(self.completed_subgoals.get(memory_key, ()))
        compressed = semantic_embedding(
            [
                {
                    "state_id": value.get("state_id"),
                    "objects": value.get("objects", [])[:12],
                    "reward": value.get("recent_rewards", [])[-1:] or [0.0],
                    "failure": value.get("failure_reason", ""),
                }
                for value in values[-min(len(values), 128):]
            ],
            64,
        )
        return {
            "backend": "structured_memory_gru_or_lightweight_transformer_context",
            "length": len(values),
            "capacity": self.maximum,
            "current_phase": phases.most_common(1)[0][0] if phases else "unknown",
            "visited_regions": visited,
            "attempted_actions": list(dict.fromkeys(actions))[-64:],
            "failure_reasons": failures[-16:],
            "failure_recovery_stack": recovery_stack[-16:],
            "remembered_objects": list(remembered.values())[-48:],
            "completed_subgoals": list(
                dict.fromkeys(completed_memory + list(source.get("completed_subgoals", [])))
            )[-128:],
            "long_term_variables": long_term,
            "compressed_key_state_memory": compressed,
            "temporal_architecture": (
                "lightweight_transformer"
                if RESOURCE_GOVERNOR.current_plan().model_tier == "Large"
                else "gru"
            ),
        }

    def clear(self, key=None):
        with self.lock:
            if key is None:
                self.memories.clear()
                self.failure_recovery_stacks.clear()
                self.long_term_variables.clear()
                self.completed_subgoals.clear()
            else:
                token = str(key)
                self.memories.pop(token, None)
                self.failure_recovery_stacks.pop(token, None)
                self.long_term_variables.pop(token, None)
                self.completed_subgoals.pop(token, None)


STRUCTURED_MEMORY = StructuredTemporalMemory()


def shared_multiscale_feature_maps(frame):
    item = dict(frame) if isinstance(frame, dict) else {"f": frame}
    feature = None
    for key in ("neural_f", "f", "feature"):
        if feature_valid(item.get(key)):
            feature = feature_bytes(item.get(key))
            break
    pyramid = (
        item.get("visual_pyramid")
        if isinstance(item.get("visual_pyramid"), dict)
        else build_hybrid_visual_state(item, [])
    )
    semantic = pyramid.get("semantic_tokens", {}) if isinstance(pyramid.get("semantic_tokens"), dict) else {}
    levels = {}
    if feature is not None:
        for width, height in ((16, 9), (8, 5), (4, 3)):
            values = []
            for channel in range(FEATURE_CHANNELS):
                plane = feature[channel * PIXELS : (channel + 1) * PIXELS]
                for oy in range(height):
                    top = oy * FEATURE_H // height
                    bottom = max(top + 1, (oy + 1) * FEATURE_H // height)
                    for ox in range(width):
                        left = ox * FEATURE_W // width
                        right = max(left + 1, (ox + 1) * FEATURE_W // width)
                        block = []
                        for py in range(top, min(FEATURE_H, bottom)):
                            block.extend(plane[py * FEATURE_W + left : py * FEATURE_W + min(FEATURE_W, right)])
                        values.append(round(sum(block) / max(1, len(block)) / 255.0, 5))
            levels[str(width) + "x" + str(height)] = values
    motion = (
        [round(value / 255.0, 5) for value in feature[4 * PIXELS : 5 * PIXELS : 64]][:64]
        if feature is not None
        else list(pyramid.get("motion", []))[-64:]
    )
    digest = hashlib.sha256(
        canonical_bytes({"levels": levels, "motion": motion, "semantic": semantic.get("checksum", "")})
    ).hexdigest()
    return {
        "levels": levels,
        "motion": motion,
        "semantic_tokens": semantic.get("tokens", [])[:512],
        "semantic_token_count": safe_int(semantic.get("token_count"), 0, 0, 512),
        "semantic_backend": str(semantic.get("backend", "manual_feature_only")),
        "semantic_input_size": list(semantic.get("input_size", HYBRID_GLOBAL_SIZE)),
        "semantic_learned": bool(semantic.get("learned")),
        "semantic_quantized": bool(semantic.get("quantized")),
        "semantic_device": str(semantic.get("device", "cpu")),
        "digest": digest,
        "read_only_backbone": bool(semantic.get("learned")),
        "fallback": "manual_features" if not semantic.get("learned") else "manual_features_on_failure",
    }


def normalized_visual_embedding(shared_maps=None, objects=None, size=VISUAL_EMBEDDING_SIZE):
    maps = shared_maps if isinstance(shared_maps, dict) else {}
    object_values = objects if isinstance(objects, (list, tuple)) else []
    output_size = max(16, min(256, safe_int(size, VISUAL_EMBEDDING_SIZE, 16, 256)))
    accumulator = [0.0] * output_size
    counts = [0] * output_size

    def add(value, ordinal, namespace):
        number = safe_float(value, 0.0, -8.0, 8.0)
        digest = hashlib.blake2b((str(namespace) + "|" + str(ordinal)).encode("utf-8"), digest_size=4).digest()
        first = int.from_bytes(digest[:2], "little") % output_size
        second = int.from_bytes(digest[2:], "little") % output_size
        sign = -1.0 if digest[0] & 1 else 1.0
        accumulator[first] += sign * number
        accumulator[second] += 0.5 * number
        counts[first] += 1
        counts[second] += 1

    ordinal = 0
    levels = maps.get("levels", {}) if isinstance(maps.get("levels"), dict) else {}
    for level_name in sorted(levels):
        values = levels.get(level_name, [])
        if not isinstance(values, (list, tuple)):
            continue
        step = max(1, len(values) // 1024)
        for value in values[::step]:
            add(value, ordinal, "level:" + level_name)
            ordinal += 1
    for value in maps.get("motion", []) if isinstance(maps.get("motion"), list) else []:
        add(value, ordinal, "motion")
        ordinal += 1
    tokens = maps.get("semantic_tokens", []) if isinstance(maps.get("semantic_tokens"), list) else []
    for token_index, token in enumerate(tokens[:256]):
        if not isinstance(token, (list, tuple)):
            continue
        for column, value in enumerate(token[:64]):
            add(value, column, "semantic:" + str(token_index))
    for object_index, item in enumerate(object_values[:32]):
        if not isinstance(item, dict):
            continue
        appearance = item.get("appearance", item.get("appearance_embedding", []))
        if isinstance(appearance, (list, tuple)):
            for column, value in enumerate(appearance[:32]):
                add(value, column, "object:" + str(object_index))
        bbox = item.get("bbox", [])
        if isinstance(bbox, (list, tuple)):
            for column, value in enumerate(bbox[:4]):
                add(value, column, "bbox:" + str(object_index))
    vector = [accumulator[index] / math.sqrt(max(1, counts[index])) for index in range(output_size)]
    mean = statistics.fmean(vector) if vector else 0.0
    centered = [value - mean for value in vector]
    norm = math.sqrt(sum(value * value for value in centered)) or 1.0
    return [round(value / norm, 7) for value in centered]


def observation_visual_embedding(observation, size=VISUAL_EMBEDDING_SIZE):
    item = observation if isinstance(observation, dict) else {}
    internal = item.get("internal_state", {}) if isinstance(item.get("internal_state"), dict) else {}
    stored = internal.get("visual_embedding", item.get("visual_embedding", []))
    if isinstance(stored, (list, tuple)) and stored:
        values = [safe_float(value, 0.0, -4.0, 4.0) for value in stored[:size]]
        norm = math.sqrt(sum(value * value for value in values)) or 1.0
        return [(value / norm) for value in (values + [0.0] * size)[:size]]
    maps = (
        internal.get("shared_multiscale_backbone", {})
        if isinstance(internal.get("shared_multiscale_backbone"), dict)
        else {}
    )
    objects = item.get("objects", []) if isinstance(item.get("objects"), list) else []
    return normalized_visual_embedding(maps, objects, size)


class ObjectCentricObservationEncoder(MultiScaleObservationEncoder):
    def __init__(self):
        super().__init__(AUTONOMOUS_OBJECT_DETECTOR)

    def encode(self, frame, history=None, task=None):
        item = dict(frame) if isinstance(frame, dict) else {"f": frame}
        context = dict(history) if isinstance(history, dict) else {}
        if not isinstance(item.get("semantic_targets"), list) or not item.get("semantic_targets"):
            item["semantic_targets"] = detect_semantic_targets(item, 32)
        pyramid = (
            item.get("visual_pyramid")
            if isinstance(item.get("visual_pyramid"), dict)
            else build_hybrid_visual_state(item, context.get("recent_frames", []))
        )
        item["visual_pyramid"] = pyramid
        shared_maps = shared_multiscale_feature_maps(item)
        item.setdefault("scene_graph", build_scene_graph(item.get("semantic_targets", [])))
        base = super().encode(item, {**context, "scene_graph": item.get("scene_graph", {})}, task)
        object_material = []
        for slot in base.objects:
            object_material.append(
                {
                    "class": slot.object_class,
                    "bbox": list(slot.bbox),
                    "appearance": list(slot.appearance_embedding),
                    "velocity": list(slot.velocity),
                    "uncertainty": slot.uncertainty,
                    "interactable": slot.interactable,
                }
            )
        visual_digest = hashlib.sha256(
            canonical_bytes(
                {
                    "base": base.visual_digest,
                    "global": pyramid.get("global_digest", ""),
                    "shared": shared_maps.get("digest", ""),
                    "objects": object_material,
                    "motion": pyramid.get("motion", []),
                }
            )
        ).hexdigest()
        task_id = str(base.task.get("task_id", "default"))
        memory_key = (
            str(context.get("memory_key") or context.get("session_id") or frame_isolation_key(item))
            + "|"
            + task_id
        )
        preliminary = ObservationState(
            base.state_id,
            base.environment_id,
            visual_digest,
            base.index_hash,
            base.objects,
            base.ocr_values,
            base.temporal,
            base.recent_actions,
            base.recent_rewards,
            base.task,
            base.internal_state,
            base.confidence,
            base.schema_version,
        )
        memory = STRUCTURED_MEMORY.update(
            memory_key, preliminary, {**context, "scene_graph": item.get("scene_graph", {})}
        )
        modality_mask = context.get("modality_mask", {}) if isinstance(context.get("modality_mask"), dict) else {}
        modality_mask = {
            "rgb": bool(modality_mask.get("rgb", True)),
            "neural": bool(modality_mask.get("neural", feature_valid(item.get("neural_f")))),
            "ocr": bool(modality_mask.get("ocr", bool(base.ocr_values))),
            "motion": bool(modality_mask.get("motion", bool(shared_maps.get("motion")))),
            "keyboard": bool(modality_mask.get("keyboard", False)),
            "audio": bool(modality_mask.get("audio", False)),
            "gamepad": bool(modality_mask.get("gamepad", False)),
        }
        internal = dict(base.internal_state)
        internal.update(
            {
                "scene_graph": item.get("scene_graph", {}),
                "memory": memory,
                "shared_multiscale_backbone": shared_maps,
                "hybrid_visual": {
                    "global_size": pyramid.get("global_size"),
                    "global_digest": pyramid.get("global_digest"),
                    "local_crop_count": len(pyramid.get("local_crops", [])),
                    "history_frames": pyramid.get("history_frames", 1),
                    "semantic_backend": shared_maps.get("semantic_backend"),
                    "semantic_token_count": shared_maps.get("semantic_token_count", 0),
                    "semantic_input_size": shared_maps.get("semantic_input_size"),
                    "semantic_learned": shared_maps.get("semantic_learned", False),
                    "semantic_quantized": shared_maps.get("semantic_quantized", False),
                    "fast_path_size": list(item.get("dynamic_fast_size", [FEATURE_W, FEATURE_H])) + [FEATURE_CHANNELS],
                },
                "manual_feature_fallback": pyramid.get("manual_fallback", {}),
                "modality_mask": modality_mask,
                "modality_features": (
                    dict(context.get("modality_features", {}))
                    if isinstance(context.get("modality_features"), dict)
                    else {}
                ),
                "dynamic_fast_visual": {
                    "size": list(item.get("dynamic_fast_size", [FEATURE_W, FEATURE_H])),
                    "embedding": list(item.get("dynamic_fast_embedding", []))[:32],
                    "digest": str(item.get("dynamic_fast_digest", "")),
                    "resolution_tier": str(
                        getattr(
                            item.get("runtime_plan"),
                            "resolution_tier",
                            item.get("resource_state", "low"),
                        )
                    ),
                },
                "object_relation_count": (
                    len(item.get("scene_graph", {}).get("edges", []))
                    if isinstance(item.get("scene_graph"), dict)
                    else 0
                ),
            }
        )
        environment_id = hashlib.sha256(
            canonical_bytes(
                {
                    "base": base.environment_id,
                    "visual": visual_digest,
                    "objects": [slot.compact() for slot in base.objects],
                    "scene_graph": item.get("scene_graph", {}),
                }
            )
        ).hexdigest()[:32]
        state_material = {
            "environment_id": environment_id,
            "actions": list(base.recent_actions[-16:]),
            "rewards": list(base.recent_rewards[-16:]),
            "task": base.task,
            "memory_phase": memory.get("current_phase"),
            "completed_subgoals": memory.get("completed_subgoals", []),
        }
        state_id = hashlib.sha256(canonical_bytes(state_material)).hexdigest()[:32]
        semantic_model = context.get("semantic_encoder") if isinstance(context.get("semantic_encoder"), dict) else None
        internal["visual_embedding"] = normalized_visual_embedding(
            shared_maps,
            object_material,
            VISUAL_EMBEDDING_SIZE,
        )
        internal["continuous_state_embedding"] = semantic_embedding(
            {
                "objects": object_material,
                "task": base.task,
                "memory": memory,
                "visual_embedding": internal["visual_embedding"],
                "visual_tokens": shared_maps.get("semantic_tokens", [])[:128],
                "visual_backend": shared_maps.get("semantic_backend", ""),
            },
            LATENT_STATE_SIZE,
            semantic_model,
        )
        evidence_count = sum(len(slot.attributes.get("evidence_sources", [])) for slot in base.objects)
        confidence = max(
            0.0,
            min(
                1.0,
                base.confidence
                + 0.04 * (1 if shared_maps.get("digest") else 0)
                + 0.02 * min(2, evidence_count / max(1, len(base.objects))),
            ),
        )
        return ObservationState(
            state_id,
            environment_id,
            visual_digest,
            base.index_hash,
            base.objects,
            base.ocr_values,
            base.temporal,
            base.recent_actions,
            base.recent_rewards,
            base.task,
            internal,
            confidence,
            OBSERVATION_SCHEMA_VERSION,
        )


