@dataclass(frozen=True)
class GoalPredicate:
    subject: str
    relation: str
    target: object = None
    attribute: str = ""
    raw: str = ""

    def key(self):
        return self.subject + "|" + self.attribute + "|" + self.relation + "|" + str(self.target)

    def to_dict(self):
        return {
            "subject": self.subject,
            "attribute": self.attribute,
            "relation": self.relation,
            "target": self.target,
            "raw": self.raw,
        }


def parse_goal_predicates(task):
    definition = task if isinstance(task, TaskDefinition) else TaskDefinition.from_mapping(task or {})
    source = list(definition.goal_predicates)
    if not source:
        source = [line.strip() for line in re.split(r"[\n;；]+", definition.goal) if line.strip()]
    result = []
    for entry in source:
        if isinstance(entry, dict):
            subject = str(entry.get("subject") or entry.get("object") or entry.get("metric") or "goal")
            relation = str(entry.get("relation") or entry.get("operator") or "satisfied")
            result.append(
                GoalPredicate(
                    subject,
                    relation,
                    entry.get("target", entry.get("value")),
                    str(entry.get("attribute") or entry.get("state") or ""),
                    json.dumps(entry, ensure_ascii=False, sort_keys=True),
                )
            )
            continue
        text = str(entry).strip()
        match = re.search(
            r'object\(["\']([^"\']+)["\']\)\.([A-Za-z_][A-Za-z0-9_]*)\s*(==|!=|>=|<=|>|<)\s*["\']?([^"\']+?)["\']?$',
            text,
        )
        if match:
            result.append(GoalPredicate(match.group(1), match.group(3), match.group(4).strip(), match.group(2), text))
            continue
        match = re.search(r'inventory\.contains\(["\']([^"\']+)["\']\)', text, re.I)
        if match:
            result.append(GoalPredicate(match.group(1), "contains", True, "inventory", text))
            continue
        match = re.search(r"([A-Za-z_\u4e00-\u9fff][\w\u4e00-\u9fff]*)\s*(>=|<=|==|>|<)\s*(-?\d+(?:\.\d+)?)", text)
        if match:
            result.append(
                GoalPredicate(match.group(1), match.group(2), safe_float(match.group(3), 0.0), "numeric", text)
            )
            continue
        tokens = [token for token in re.split(r"[^A-Za-z0-9_\u4e00-\u9fff]+", text) if len(token) > 1]
        if tokens:
            result.append(GoalPredicate(tokens[0], "satisfied", True, "goal", text))
    if not result:
        result.append(GoalPredicate("task", "satisfied", True, "goal", definition.goal))
    return tuple(result[:32])


def predicate_evidence(state, predicate):
    observation = state if isinstance(state, ObservationState) else None
    objects = list(observation.objects) if observation is not None else []
    internal = observation.internal_state if observation is not None else {}
    memory = internal.get("memory", {}) if isinstance(internal.get("memory"), dict) else {}
    candidates = []
    subject = predicate.subject.casefold()
    for slot in objects:
        role = str(slot.attributes.get("role", "")).casefold()
        generic = str(slot.attributes.get("generic_class", slot.object_class)).casefold()
        text = slot.text.casefold()
        if subject in {slot.object_class.casefold(), role, generic, slot.instance.casefold()} or subject in text:
            candidates.append(slot)
    remembered = [
        entry
        for entry in memory.get("remembered_objects", [])
        if isinstance(entry, dict)
        and subject
        in (
            str(entry.get("class", "")) + " " + str(entry.get("text", "")) + " " + str(entry.get("role", ""))
        ).casefold()
    ]
    if predicate.attribute == "inventory" or predicate.relation == "contains":
        satisfied = bool(candidates or remembered)
        return {"satisfied": satisfied, "visible": bool(candidates), "candidates": candidates, "remembered": remembered}
    if predicate.attribute == "numeric":
        values = []
        for slot in candidates:
            if finite_number(slot.value):
                values.append(float(slot.value))
        for value in observation.ocr_values if observation is not None else []:
            if subject in str(value.get("region_id", "")).casefold() and finite_number(value.get("value")):
                values.append(float(value.get("value")))
        current = max(values) if values else None
        target = safe_float(predicate.target, 0.0)
        operations = {
            ">=": lambda value: value >= target,
            "<=": lambda value: value <= target,
            ">": lambda value: value > target,
            "<": lambda value: value < target,
            "==": lambda value: abs(value - target) < 1e-6,
        }
        satisfied = current is not None and operations.get(predicate.relation, lambda value: False)(current)
        return {
            "satisfied": satisfied,
            "visible": bool(candidates),
            "current": current,
            "target": target,
            "candidates": candidates,
        }
    if predicate.attribute and predicate.attribute not in {"goal", ""}:
        target = str(predicate.target).casefold()
        values = [
            str(getattr(slot, predicate.attribute, slot.attributes.get(predicate.attribute, ""))).casefold()
            for slot in candidates
        ]
        if predicate.relation == "!=":
            satisfied = bool(values) and all(value != target for value in values)
        else:
            satisfied = any(value == target or target in value for value in values)
        return {"satisfied": satisfied, "visible": bool(candidates), "values": values, "candidates": candidates}
    return {
        "satisfied": bool(candidates or remembered),
        "visible": bool(candidates),
        "candidates": candidates,
        "remembered": remembered,
    }


def train_learned_subgoal_planner(experiences, tasks):
    counts = defaultdict(Counter)
    outcomes = defaultdict(lambda: Counter(success=0, failure=0, total=0))
    for item in experiences or []:
        if not isinstance(item, dict):
            continue
        task_id = normalized_identifier(item.get("task_id"), "default", 96)
        skill = str(item.get("skill_id") or item.get("action_t") or "stop_and_ask")
        subgoal = str(item.get("subgoal_id") or "advance_goal")
        counts[task_id + "|" + subgoal][skill] += 1
        row = outcomes[task_id + "|" + subgoal + "|" + skill]
        row["total"] += 1
        row["success"] += int(bool(item.get("success")))
        row["failure"] += int(bool(item.get("failure")))
    task_predicates = {}
    for task in tasks or []:
        definition = TaskDefinition.from_mapping(task)
        task_predicates[definition.task_id] = [entry.to_dict() for entry in parse_goal_predicates(definition)]
    priors = {key: dict(value.most_common(16)) for key, value in counts.items()}
    quality = {
        key: {
            "total": value["total"],
            "success_rate": value["success"] / max(1, value["total"]),
            "failure_rate": value["failure"] / max(1, value["total"]),
        }
        for key, value in outcomes.items()
    }
    return {
        "schema_version": 2,
        "algorithm": "rule_generated_goal_planner_with_learned_skill_priors",
        "task_predicates": task_predicates,
        "skill_priors": priors,
        "skill_quality": quality,
        "training_transitions": len(experiences or []),
    }


class HierarchicalTaskPlanner(TaskPlanner):
    def __init__(self, learned_model=None, world_model=None, beam_width=4):
        self.learned_model = dict(learned_model) if isinstance(learned_model, dict) else {}
        self.world_model = dict(world_model) if isinstance(world_model, dict) else {}
        self.beam_width = max(2, min(8, safe_int(beam_width, 4, 2, 8)))
        self.last_plan = {}

    def configure(self, learned_model, world_model=None):
        self.learned_model = dict(learned_model) if isinstance(learned_model, dict) else {}
        self.world_model = dict(world_model) if isinstance(world_model, dict) else {}
        return self

    def _skills(self, task_id, subgoal_id, defaults):
        priors = self.learned_model.get("skill_priors", {}) if isinstance(self.learned_model, dict) else {}
        quality = self.learned_model.get("skill_quality", {}) if isinstance(self.learned_model, dict) else {}
        row = priors.get(task_id + "|" + subgoal_id, {}) if isinstance(priors, dict) else {}
        learned = []
        for key in row if isinstance(row, dict) else []:
            metric = quality.get(task_id + "|" + subgoal_id + "|" + str(key), {}) if isinstance(quality, dict) else {}
            learned.append(
                (
                    str(key),
                    safe_float(metric.get("success_rate"), 0.0) - safe_float(metric.get("failure_rate"), 0.0),
                    safe_int(row.get(key), 0),
                )
            )
        learned.sort(key=lambda value: (-value[1], -value[2], value[0]))
        return tuple(dict.fromkeys([value[0] for value in learned] + list(defaults)))[:8]

    def _rule_candidates(self, state, task):
        observation = state if isinstance(state, ObservationState) else None
        definition = task if isinstance(task, TaskDefinition) else TaskDefinition.from_mapping(task or {})
        internal = observation.internal_state if observation is not None else {}
        candidates = []
        if str(internal.get("terminal")) == "failure" or safe_int(internal.get("failure_count"), 0) > 0:
            skills = self._skills(
                definition.task_id, "recover_after_failure", ("wait_for_state", "restart_round", "navigate_back")
            )
            candidates.append(
                Subgoal("recover_after_failure", "恢复到可操作状态", {"terminal_not": "failure"}, skills, 100, 0.94)
            )
        dialogs = (
            [slot for slot in observation.objects if slot.object_class == "dialog"] if observation is not None else []
        )
        close_targets = (
            [slot for slot in observation.objects if str(slot.attributes.get("role", "")) in {"close", "cancel"}]
            if observation is not None
            else []
        )
        if dialogs and close_targets:
            skills = self._skills(
                definition.task_id, "close_blocking_popup", ("close_popup", "click_semantic_target", "wait_for_state")
            )
            candidates.append(
                Subgoal("close_blocking_popup", "关闭阻塞目标的弹窗", {"object_absent": "dialog"}, skills, 96, 0.91)
            )
        for predicate in parse_goal_predicates(definition):
            evidence = predicate_evidence(observation, predicate)
            if evidence.get("satisfied"):
                continue
            safe_name = normalized_identifier(predicate.subject, "goal", 64)
            if predicate.attribute == "inventory" or predicate.relation == "contains":
                if evidence.get("visible"):
                    subgoal_id = "acquire_" + safe_name
                    description = "获取目标对象 " + predicate.subject
                    defaults = ("click_semantic_target", "drag_object_to_target", "wait_for_state")
                else:
                    subgoal_id = "locate_" + safe_name
                    description = "定位目标对象 " + predicate.subject
                    defaults = ("scroll_until_target", "navigate_back", "wait_for_state")
            elif predicate.attribute == "numeric":
                subgoal_id = "improve_" + safe_name
                description = "推进数值谓词 " + predicate.raw
                defaults = ("click_semantic_target", "drag_object_to_target", "scroll_until_target", "wait_for_state")
            elif evidence.get("visible"):
                subgoal_id = "change_" + safe_name
                description = "使对象满足谓词 " + predicate.raw
                defaults = ("click_semantic_target", "drag_object_to_target", "inspect_target", "wait_for_state")
            else:
                subgoal_id = "locate_" + safe_name
                description = "定位谓词对象 " + predicate.subject
                defaults = ("scroll_until_target", "navigate_back", "wait_for_state")
            skills = self._skills(definition.task_id, subgoal_id, defaults)
            visibility_bonus = 0.08 if evidence.get("visible") else 0.0
            candidates.append(
                Subgoal(
                    subgoal_id, description, {"predicate": predicate.to_dict()}, skills, 86, 0.72 + visibility_bonus
                )
            )
        if not candidates:
            skills = self._skills(
                definition.task_id, "verify_goal", ("wait_for_state", "inspect_target", "stop_and_ask")
            )
            candidates.append(
                Subgoal("verify_goal", "验证所有目标谓词已经满足", {"all_predicates": True}, skills, 70, 0.76)
            )
        return candidates

    def _skill_prediction(self, task_id, state_id, skill):
        prediction = world_model_prediction(self.world_model, task_id, state_id, skill) if self.world_model else {}
        reward = safe_float(prediction.get("expected_reward"), 0.0)
        success = safe_float(prediction.get("success_probability"), 0.0, 0.0, 1.0)
        failure = safe_float(prediction.get("failure_probability"), 0.0, 0.0, 1.0)
        no_effect = safe_float(prediction.get("no_effect_probability"), 0.0, 0.0, 1.0)
        uncertainty = safe_float(
            prediction.get("rollout_uncertainty", prediction.get("uncertainty", 1.0)), 1.0, 0.0, 1.0
        )
        score = 0.55 * success + 0.18 * math.tanh(reward / 2.0) - 0.48 * failure - 0.28 * no_effect - 0.24 * uncertainty
        return score, prediction

    def plan(self, state, task):
        observation = state if isinstance(state, ObservationState) else None
        definition = task if isinstance(task, TaskDefinition) else TaskDefinition.from_mapping(task or {})
        state_id = observation.state_id if observation is not None else ""
        memory = (
            observation.internal_state.get("memory", {})
            if observation is not None and isinstance(observation.internal_state, dict)
            else {}
        )
        failed = (
            set(str(value) for value in memory.get("failure_reasons", []) if str(value))
            if isinstance(memory, dict)
            else set()
        )
        candidates = self._rule_candidates(observation, definition)
        beams = []
        for subgoal in candidates:
            base = subgoal.priority / 100.0 + subgoal.confidence
            if subgoal.subgoal_id in failed:
                base -= 0.25
            paths = [([], base, [])]
            for depth in range(min(3, max(1, len(subgoal.preferred_skills)))):
                expanded = []
                for path, score, predictions in paths:
                    for skill in subgoal.preferred_skills[: self.beam_width]:
                        if skill in path and skill not in {"wait_for_state", "scroll_until_target"}:
                            continue
                        value, prediction = self._skill_prediction(definition.task_id, state_id, skill)
                        repeat_penalty = 0.08 * path.count(skill)
                        expanded.append(
                            (path + [skill], score + value / (depth + 1) - repeat_penalty, predictions + [prediction])
                        )
                expanded.sort(key=lambda item: (-item[1], item[0]))
                paths = expanded[: self.beam_width] or paths
            best_path, best_score, predictions = max(paths, key=lambda item: item[1])
            beams.append(
                {"subgoal": subgoal, "skill_sequence": best_path, "score": best_score, "predictions": predictions}
            )
        beams.sort(key=lambda item: (-item["score"], -item["subgoal"].priority, item["subgoal"].subgoal_id))
        selected = beams[0]
        preferred = tuple(dict.fromkeys(selected["skill_sequence"] + list(selected["subgoal"].preferred_skills)))[:8]
        chosen = Subgoal(
            selected["subgoal"].subgoal_id,
            selected["subgoal"].description,
            selected["subgoal"].completion_condition,
            preferred,
            selected["subgoal"].priority,
            max(0.0, min(1.0, selected["subgoal"].confidence)),
        )
        self.last_plan = {
            "algorithm": "bounded_goal_conditioned_beam_search",
            "beam_width": self.beam_width,
            "replan_each_observation": True,
            "selected_subgoal": chosen.subgoal_id,
            "selected_skill_sequence": list(preferred[:3]),
            "score": round(selected["score"], 6),
            "alternatives": [
                {
                    "subgoal_id": item["subgoal"].subgoal_id,
                    "score": round(item["score"], 6),
                    "skills": item["skill_sequence"][:3],
                }
                for item in beams[: self.beam_width]
            ],
        }
        return chosen

    def propose_subgoal(self, state, task):
        return self.plan(state, task)


SEMANTIC_CONCEPT_GROUPS = (
    ("start", ("start", "play", "begin", "launch", "开始", "开局", "启动", "进入游戏")),
    ("continue", ("continue", "resume", "next", "继续", "恢复", "下一步")),
    ("confirm", ("confirm", "ok", "accept", "yes", "确认", "确定", "同意")),
    ("cancel", ("cancel", "close", "dismiss", "back", "取消", "关闭", "返回")),
    ("retry", ("retry", "restart", "again", "重试", "重新开始", "再来一次")),
    ("win", ("win", "victory", "success", "clear", "胜利", "成功", "通关")),
    ("lose", ("lose", "defeat", "failure", "game over", "失败", "战败")),
    ("attack", ("attack", "hit", "strike", "defeat target", "攻击", "击败", "打击")),
    ("interact", ("interact", "use", "activate", "open", "交互", "使用", "激活", "打开")),
    ("button", ("button", "control", "clickable", "按钮", "控件", "可点击")),
    ("dialog", ("dialog", "popup", "modal", "弹窗", "对话框", "遮挡窗口")),
    ("target", ("target", "goal", "objective", "目标", "任务目标")),
)


class SharedSemanticEncoder:
    def __init__(self, model=None):
        value = model if isinstance(model, dict) else {}
        self.size = max(8, safe_int(value.get("size", SEMANTIC_EMBEDDING_SIZE), SEMANTIC_EMBEDDING_SIZE, 8, 128))
        vectors = value.get("vectors", {}) if isinstance(value.get("vectors"), dict) else {}
        self.vectors = {
            str(key): [safe_float(item, 0.0, -2.0, 2.0) for item in list(vector)[: self.size]]
            for key, vector in vectors.items()
            if isinstance(vector, list)
        }
        self.aliases = {}
        for concept, aliases in SEMANTIC_CONCEPT_GROUPS:
            self.aliases[concept] = concept
            for alias in aliases:
                self.aliases[self.normalize(alias)] = concept
        supplied = value.get("aliases", {}) if isinstance(value.get("aliases"), dict) else {}
        self.aliases.update({self.normalize(key): str(item) for key, item in supplied.items()})

    @staticmethod
    def normalize(value):
        text = unicodedata.normalize("NFKC", str(value or "")).casefold()
        text = re.sub(r"[_/|:+\\-]+", " ", text)
        return re.sub(r"\s+", " ", text).strip()

    def tokens(self, value):
        if isinstance(value, dict):
            result = []
            for key, item in sorted(value.items(), key=lambda pair: str(pair[0])):
                result.extend(self.tokens(key))
                result.extend(self.tokens(item))
            return list(dict.fromkeys(result))[:192]
        if isinstance(value, (list, tuple, set, deque)):
            result = []
            for item in value:
                result.extend(self.tokens(item))
            return list(dict.fromkeys(result))[:192]
        text = self.normalize(value)
        if not text:
            return []
        result = []
        occupied = [False] * len(text)
        for alias, concept in sorted(self.aliases.items(), key=lambda pair: (-len(pair[0]), pair[0])):
            if not alias:
                continue
            start = 0
            while True:
                position = text.find(alias, start)
                if position < 0:
                    break
                end = position + len(alias)
                if not any(occupied[position:end]):
                    result.extend(("concept:" + concept, "phrase:" + alias))
                    for index in range(position, min(end, len(occupied))):
                        occupied[index] = True
                start = position + 1
        for token in re.findall(r"[a-z0-9]+", text):
            result.append("word:" + token)
        han_runs = re.findall(r"[\u3400-\u9fff]+", text)
        for run in han_runs:
            result.extend("han1:" + character for character in run)
            for width in (2, 3):
                result.extend(
                    "han" + str(width) + ":" + run[index : index + width]
                    for index in range(len(run) - width + 1)
                )
        return list(dict.fromkeys(result))[:192]

    @staticmethod
    def _basis(index, size):
        values = []
        base = max(1, int(index) + 1)
        for column in range(size):
            value = math.sin(base * (column + 1) * 0.1732050808) + math.cos((base + 3) * (column + 1) * 0.1178511302)
            values.append(value)
        norm = math.sqrt(sum(value * value for value in values)) or 1.0
        return [value / norm for value in values]

    @classmethod
    def train(cls, documents, size=SEMANTIC_EMBEDDING_SIZE, limit=SEMANTIC_VOCAB_LIMIT):
        bootstrap = []
        aliases = {}
        for concept, values in SEMANTIC_CONCEPT_GROUPS:
            group = ["concept:" + concept, *values]
            bootstrap.extend([group, group, group])
            for value in values:
                aliases[cls.normalize(value)] = concept
        temporary = cls({"size": size, "aliases": aliases})
        docs = []
        for document in [*bootstrap, *list(documents or [])[:12000]]:
            tokens = temporary.tokens(document)
            if tokens:
                docs.append(tokens[:96])
        counts = Counter(token for document in docs for token in document)
        vocab = [
            token for token, _ in sorted(counts.items(), key=lambda pair: (-pair[1], pair[0]))[: max(64, int(limit))]
        ]
        index = {token: position for position, token in enumerate(vocab)}
        cooccurrence = defaultdict(Counter)
        for document in docs:
            filtered = [token for token in document if token in index]
            for position, token in enumerate(filtered):
                left = max(0, position - 5)
                right = min(len(filtered), position + 6)
                for other in filtered[left:right]:
                    if other != token:
                        cooccurrence[token][other] += 1
        vectors = {}
        for token in vocab:
            vector = [0.0] * size
            neighbors = cooccurrence.get(token, {})
            for other, count in sorted(neighbors.items(), key=lambda pair: (-pair[1], pair[0]))[:128]:
                weight = math.log1p(count) / math.sqrt(max(1, counts[token] * counts[other]))
                basis = cls._basis(index[other], size)
                for column in range(size):
                    vector[column] += weight * basis[column]
            if not any(abs(value) > 1e-12 for value in vector):
                vector = cls._basis(index[token], size)
            norm = math.sqrt(sum(value * value for value in vector)) or 1.0
            vectors[token] = [round(value / norm, 7) for value in vector]
        payload = {
            "schema_version": SEMANTIC_ENCODER_SCHEMA_VERSION,
            "algorithm": "multilingual_longest_match_subword_contrastive_encoder",
            "size": size,
            "vectors": vectors,
            "aliases": aliases,
            "vocabulary_size": len(vectors),
            "training_documents": len(docs),
            "languages": ["zh", "en", "game_specific"],
            "objectives": [
                "subword_context_cooccurrence",
                "multilingual_synonym_alignment",
                "ocr_button_action_result_goal_contrastive_alignment",
            ],
            "hash_embedding_used": False,
        }
        payload["checksum"] = hashlib.sha256(
            canonical_bytes({key: value for key, value in payload.items() if key != "checksum"})
        ).hexdigest()
        return payload

    def encode(self, value, size=None):
        output_size = max(1, int(size or self.size))
        tokens = self.tokens(value)
        vectors = [self.vectors[token] for token in tokens if token in self.vectors]
        if not vectors:
            categories = Counter()
            text = self.normalize(value)
            for character in text:
                categories[
                    (
                        "han"
                        if "\u3400" <= character <= "\u9fff"
                        else "digit" if character.isdigit() else "latin" if character.isalpha() else "other"
                    )
                ] += 1
            fallback = [categories["han"], categories["latin"], categories["digit"], categories["other"], len(text)]
            vector = [math.tanh(fallback[index % len(fallback)] / (1.0 + index)) for index in range(self.size)]
        else:
            weights = [1.5 if token.startswith("concept:") else 1.0 for token in tokens if token in self.vectors]
            total = sum(weights) or 1.0
            vector = [
                sum(weight * entry[column] for weight, entry in zip(weights, vectors)) / total
                for column in range(self.size)
            ]
        norm = math.sqrt(sum(entry * entry for entry in vector)) or 1.0
        normalized = [entry / norm for entry in vector]
        if output_size <= len(normalized):
            return [round(entry, 7) for entry in normalized[:output_size]]
        result = list(normalized)
        while len(result) < output_size:
            column = len(result)
            result.append(normalized[column % len(normalized)] * (0.5 + 0.5 / (1 + column // len(normalized))))
        return [round(entry, 7) for entry in result[:output_size]]


_SEMANTIC_ENCODER_CACHE = {}
_DEFAULT_SEMANTIC_ENCODER_KEY = "__default__"


def semantic_encoder_from_model(model=None):
    value = model if isinstance(model, dict) else {}
    if not value or not isinstance(value.get("vectors"), dict):
        cached = _SEMANTIC_ENCODER_CACHE.get(_DEFAULT_SEMANTIC_ENCODER_KEY)
        if cached is not None:
            return cached
        encoder = SharedSemanticEncoder(SharedSemanticEncoder.train([]))
        _SEMANTIC_ENCODER_CACHE[_DEFAULT_SEMANTIC_ENCODER_KEY] = encoder
        return encoder
    checksum = str(value.get("checksum", ""))
    cached = _SEMANTIC_ENCODER_CACHE.get(checksum)
    if cached is not None:
        return cached
    encoder = SharedSemanticEncoder(value)
    if len(_SEMANTIC_ENCODER_CACHE) >= 8:
        _SEMANTIC_ENCODER_CACHE.pop(next(iter(_SEMANTIC_ENCODER_CACHE)))
    _SEMANTIC_ENCODER_CACHE[checksum] = encoder
    return encoder


def semantic_embedding(value, size, model=None):
    return semantic_encoder_from_model(model).encode(value, size)


def train_shared_semantic_encoder(experiences):
    documents = []
    for experience in list(experiences or [])[:MAX_TRAINING_SAMPLES]:
        if not isinstance(experience, dict):
            continue
        context = experience.get("context", {}) if isinstance(experience.get("context"), dict) else {}
        documents.append(
            [
                experience.get("task_id", "default"),
                context.get("goal", ""),
                experience.get("skill_id", ""),
                experience.get("skill_key", ""),
                experience.get("semantic_action", {}),
                experience.get("reward_components", {}),
            ]
        )
        for observation_key in ("observation_t", "observation_t+1"):
            observation = (
                experience.get(observation_key, {}) if isinstance(experience.get(observation_key), dict) else {}
            )
            documents.append(
                [observation.get("ocr_values", []), observation.get("objects", []), observation.get("scene_graph", {})]
            )
    return SharedSemanticEncoder.train(documents)


def goal_conditioned_candidate_features(item, world_prediction=None, size=POLICY_INPUT_SIZE):
    value = dict(item) if isinstance(item, dict) else {}
    world = dict(world_prediction) if isinstance(world_prediction, dict) else {}
    q = safe_float(value.get("q_value"), 0.0)
    support = max(0, safe_int(value.get("support", value.get("count", 0)), 0))
    risk_class = str(value.get("risk_class", "safe"))
    proto = value.get("proto", {}) if isinstance(value.get("proto"), dict) else {}
    threshold = max(1.0, safe_float(proto.get("threshold", 100.0), 100.0))
    visual_quality = max(0.0, min(1.0, 1.0 - safe_float(value.get("distance"), threshold) / threshold))
    temporal_quality = max(0.0, min(1.0, 1.0 - safe_float(value.get("temporal_distance"), 1.0)))
    object_quality = max(0.0, min(1.0, 1.0 - safe_float(value.get("object_distance"), 1.0)))
    memory = value.get("memory", {}) if isinstance(value.get("memory"), dict) else {}
    semantic_model = (
        value.get("semantic_encoder")
        if isinstance(value.get("semantic_encoder"), dict)
        else world.get("semantic_encoder")
    )
    scalars = [
        safe_float(value.get("bc_probability"), 0.0),
        (math.tanh(q / 2.0) + 1.0) * 0.5,
        safe_float(value.get("success_probability"), 0.0),
        safe_float(value.get("risk_probability"), 0.0),
        safe_float(value.get("ood_uncertainty"), 1.0),
        min(1.0, math.log1p(support) / 7.0),
        max(0.0, min(1.0, 1.0 - safe_float(world.get("uncertainty"), 1.0))),
        1.0 if risk_class == "irreversible" else 0.45 if risk_class == "caution" else 0.0,
        visual_quality,
        temporal_quality,
        object_quality,
        safe_float(value.get("task_confidence"), 0.5),
        safe_float(value.get("skill_confidence"), 0.5),
        safe_float(world.get("no_effect_probability"), 0.0),
        safe_float(world.get("rollout_uncertainty"), safe_float(world.get("uncertainty"), 1.0)),
        1.0,
    ]
    goal_material = {"task": value.get("task_id"), "goal": value.get("goal"), "subgoal": value.get("subgoal_id")}
    skill_material = {
        "skill": value.get("skill_key") or value.get("cluster_id"),
        "semantic_action": value.get("semantic_action"),
    }
    scene_material = {
        "objects": value.get("object_classes", []),
        "relations": value.get("object_relations", []),
        "ocr": value.get("ocr_values", []),
    }
    memory_material = {
        "memory": memory,
        "recent_actions": value.get("recent_actions", []),
        "task_phase": value.get("task_phase"),
    }
    features = list(scalars)
    features.extend(semantic_embedding(goal_material, 20, semantic_model))
    features.extend(semantic_embedding(skill_material, 20, semantic_model))
    features.extend(semantic_embedding(scene_material, 20, semantic_model))
    features.extend(semantic_embedding(memory_material, 20, semantic_model))
    padded = (features + [0.0] * max(0, size - len(features)))[:size]
    return [safe_float(entry, 0.0, -4.0, 4.0) for entry in padded]


class LearnedCandidateRankingHead:
    input_size = POLICY_INPUT_SIZE
    hidden_size = POLICY_HIDDEN_SIZE
    ensemble_size = POLICY_ENSEMBLE_SIZE
    output_names = (
        "success_probability",
        "expected_reward",
        "failure_probability",
        "risk_probability",
        "uncertainty",
        "utility",
    )

    @staticmethod
    def _sigmoid(value):
        return 1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, float(value)))))

    @classmethod
    def _forward_member(cls, member, features):
        hidden = [
            math.tanh(sum(value * coefficient for value, coefficient in zip(features, row)) + bias)
            for row, bias in zip(member["w1"], member["b1"])
        ]
        raw = [
            sum(value * coefficient for value, coefficient in zip(hidden, row)) + bias
            for row, bias in zip(member["w2"], member["b2"])
        ]
        outputs = [cls._sigmoid(value) for value in raw]
        result = {name: outputs[index] for index, name in enumerate(cls.output_names)}
        result["expected_reward"] = result["expected_reward"] * 4.0 - 2.0
        return result

    @classmethod
    def train(cls, experience_model, experiences, seed=0, semantic_model=None):
        runtime_plan = RESOURCE_GOVERNOR.current_plan()
        input_size = max(POLICY_INPUT_SIZE, int(runtime_plan.policy_state_size))
        hidden_size = max(POLICY_HIDDEN_SIZE, int(runtime_plan.policy_hidden_size))
        ensemble_size = max(POLICY_ENSEMBLE_SIZE, int(runtime_plan.policy_ensemble_size))
        default_task = normalized_identifier(
            experience_model.get("default_task_id") if isinstance(experience_model, dict) else None, "default", 96
        )
        strict_behavior, strict_value, strict_risk, _ = build_offline_policy_models(
            experience_model, experiences, default_task
        )
        source = {}
        for key, row in strict_value.get("state_action", {}).items():
            merged = dict(row)
            merged.update(strict_risk.get("state_action", {}).get(key, {}))
            merged.update(
                {
                    name: value
                    for name, value in strict_behavior.get("state_action", {}).get(key, {}).items()
                    if name in {"count", "awr_weight", "advantage", "human_override_rate"}
                }
            )
            source[key] = merged
        behavior = {key: safe_int(row.get("count"), 0) for key, row in strict_behavior.get("state_action", {}).items()}
        grouped = defaultdict(list)
        for key, row in source.items():
            grouped[str(key).rsplit("|", 1)[0]].append((str(key), row))
        rows = []
        for group_key, group in grouped.items():
            q_values = [safe_float(row.get("q_value"), 0.0) for _, row in group]
            baseline = statistics.median(q_values) if q_values else 0.0
            total = sum(
                max(1, safe_int(behavior.get(key, row.get("behavior_count", row.get("count", 1))), 1))
                for key, row in group
            )
            for key, row in group:
                count = max(1, safe_int(behavior.get(key, row.get("behavior_count", row.get("count", 1))), 1))
                bc = count / max(1, total)
                q = safe_float(row.get("q_value"), 0.0)
                risk = safe_float(row.get("risk_probability"), 0.0, 0.0, 1.0)
                success = safe_float(row.get("success_probability"), 0.0, 0.0, 1.0)
                uncertainty = safe_float(row.get("uncertainty"), 1.0, 0.0, 1.0)
                conservative_q = q - 0.30 / math.sqrt(count) - 0.22 * risk
                advantage = conservative_q - baseline
                awr = min(
                    20.0,
                    math.exp(
                        max(
                            -4.0,
                            min(
                                3.0,
                                advantage / max(0.05, safe_float(experience_model.get("awr_temperature", 0.5), 0.5)),
                            ),
                        )
                    ),
                )
                parts = key.split("|")
                task_id = parts[0] if len(parts) >= 3 else "default"
                state_id = parts[-2] if len(parts) >= 2 else group_key
                action_id = parts[-1]
                item = {
                    "task_id": task_id,
                    "observation_state_id": state_id,
                    "skill_key": action_id,
                    "bc_probability": bc,
                    "q_value": conservative_q,
                    "success_probability": success,
                    "risk_probability": risk,
                    "ood_uncertainty": uncertainty,
                    "support": count,
                    "task_confidence": 1.0,
                    "skill_confidence": min(1.0, awr / 4.0),
                }
                item["semantic_encoder"] = semantic_model
                features = goal_conditioned_candidate_features(item, {}, input_size)
                utility = max(
                    0.0,
                    min(
                        1.0,
                        0.5
                        + 0.22 * math.tanh(conservative_q / 2.0)
                        + 0.28 * success
                        - 0.36 * risk
                        - 0.20 * uncertainty
                        + 0.10 * min(1.0, awr / 4.0),
                    ),
                )
                targets = [success, (max(-2.0, min(2.0, conservative_q)) + 2.0) / 4.0, risk, risk, uncertainty, utility]
                rows.append((features, targets, max(0.2, min(5.0, math.sqrt(count) * min(2.0, awr)))))
        if len(rows) < 8:
            return {
                "schema_version": 2,
                "algorithm": "goal_conditioned_bc_awr_iql_cql_ensemble",
                "trained": False,
                "reason": "insufficient_rows",
                "fallback": "auditable_rule_score",
                "input_size": input_size,
                "hidden_size": hidden_size,
                "ensemble_size": ensemble_size,
                "outputs": list(cls.output_names),
            }
        generator = random.Random(safe_int(seed, 0, 0, 2**63 - 1) ^ 0x52414E4B)
        generator.shuffle(rows)
        rows = rows[:1200]
        ensemble = []
        for member_index in range(ensemble_size):
            member_rng = random.Random(generator.randrange(2**63) ^ member_index)
            scale = 1.0 / math.sqrt(input_size)
            w1 = [[member_rng.uniform(-scale, scale) for _ in range(input_size)] for _ in range(hidden_size)]
            b1 = [0.0] * hidden_size
            w2 = [[member_rng.uniform(-0.14, 0.14) for _ in range(hidden_size)] for _ in cls.output_names]
            b2 = [0.0] * len(cls.output_names)
            learning_rate = 0.032
            steps = max(160, min(900, len(rows) * 3))
            for step in range(steps):
                features, targets, weight = rows[member_rng.randrange(len(rows))]
                hidden = [
                    math.tanh(sum(value * coefficient for value, coefficient in zip(features, row)) + bias)
                    for row, bias in zip(w1, b1)
                ]
                raw = [
                    sum(value * coefficient for value, coefficient in zip(hidden, row)) + bias
                    for row, bias in zip(w2, b2)
                ]
                outputs = [cls._sigmoid(value) for value in raw]
                delta_out = [
                    2.0 * (outputs[index] - targets[index]) * outputs[index] * (1.0 - outputs[index]) * weight
                    for index in range(len(outputs))
                ]
                delta_hidden = [
                    sum(
                        delta_out[output_index] * w2[output_index][hidden_index] for output_index in range(len(outputs))
                    )
                    * (1.0 - hidden[hidden_index] * hidden[hidden_index])
                    for hidden_index in range(hidden_size)
                ]
                for output_index in range(len(outputs)):
                    for hidden_index in range(hidden_size):
                        w2[output_index][hidden_index] -= learning_rate * delta_out[output_index] * hidden[hidden_index]
                    b2[output_index] -= learning_rate * delta_out[output_index]
                for hidden_index in range(hidden_size):
                    for input_index in range(input_size):
                        w1[hidden_index][input_index] -= (
                            learning_rate * delta_hidden[hidden_index] * features[input_index]
                        )
                    b1[hidden_index] -= learning_rate * delta_hidden[hidden_index]
                learning_rate *= 0.9992
            ensemble.append({"w1": w1, "b1": b1, "w2": w2, "b2": b2, "seed": member_rng.randrange(2**63)})
        return {
            "schema_version": 2,
            "algorithm": "goal_conditioned_bc_awr_iql_cql_calibrated_ensemble",
            "trained": True,
            "input_size": input_size,
            "hidden_size": hidden_size,
            "ensemble_size": len(ensemble),
            "outputs": list(cls.output_names),
            "ensemble": ensemble,
            "training_rows": len(rows),
            "seed": safe_int(seed, 0),
            "fallback": "auditable_rule_score",
            "uncertainty": "independent_initialization_disagreement",
            "semantic_encoder_checksum": str((semantic_model or {}).get("checksum", "")),
            "features": [
                "object_relation_state",
                "object_relations",
                "task_embedding",
                "skill_embedding",
                "short_term_memory",
                "behavior_probability",
                "conservative_value",
                "independent_risk",
                "world_rollout",
            ],
        }

    @classmethod
    def forward(cls, model, features):
        if not isinstance(model, dict) or not model.get("trained"):
            return None
        try:
            input_size = safe_int(model.get("input_size"), cls.input_size, 1, 4096)
            values = [safe_float(value, 0.0, -4.0, 4.0) for value in list(features)[:input_size]]
            values = (values + [0.0] * input_size)[:input_size]
            members = model.get("ensemble", [])
            predictions = [cls._forward_member(member, values) for member in members if isinstance(member, dict)]
            if not predictions:
                return None
            result = {}
            disagreements = []
            for name in cls.output_names:
                series = [safe_float(entry.get(name), 0.0) for entry in predictions]
                result[name] = round(statistics.fmean(series), 7)
                disagreements.append(statistics.pstdev(series) if len(series) > 1 else 0.0)
            disagreement = max(disagreements)
            result["ensemble_disagreement"] = round(disagreement, 7)
            result["uncertainty"] = round(max(result["uncertainty"], min(1.0, disagreement * 3.0)), 7)
            result["member_count"] = len(predictions)
            return result
        except (TypeError, ValueError, OverflowError, KeyError):
            return None


def train_auditable_transition_model(experiences):
    def empty_row():
        return {
            "count": 0,
            "reward": 0.0,
            "success": 0,
            "failure": 0,
            "no_change": 0,
            "delay": 0.0,
            "appear": Counter(),
            "disappear": Counter(),
            "terminals": Counter(),
            "next_states": Counter(),
            "attribute_changes": Counter(),
            "motion_dx": 0.0,
            "motion_dy": 0.0,
            "motion_speed": 0.0,
            "motion_count": 0,
            "numeric_delta": 0.0,
            "numeric_count": 0,
            "delay_buckets": Counter(),
        }

    def object_identity(value, index):
        if not isinstance(value, dict):
            return "unknown|" + str(index)
        identity = str(value.get("track_id") or value.get("instance") or "").strip()
        if identity:
            return str(value.get("class", "unknown")) + "|" + identity
        bbox = value.get("bbox", [0.0, 0.0, 0.0, 0.0])
        center = (
            (
                round(safe_float(bbox[0], 0.0) + safe_float(bbox[2], 0.0) / 2.0, 2),
                round(safe_float(bbox[1], 0.0) + safe_float(bbox[3], 0.0) / 2.0, 2),
            )
            if isinstance(bbox, (list, tuple)) and len(bbox) >= 4
            else (0.0, 0.0)
        )
        return str(value.get("class", "unknown")) + "|" + str(center) + "|" + str(index)

    state_rows = defaultdict(empty_row)
    action_rows = defaultdict(empty_row)
    for experience in experiences or []:
        if not isinstance(experience, dict):
            continue
        task_id = normalized_identifier(experience.get("task_id"), "default", 96)
        state = str(experience.get("state_t", experience.get("state", "")))
        action = str(experience.get("action_t", experience.get("action", "")))
        before = experience.get("observation_t", {}) if isinstance(experience.get("observation_t"), dict) else {}
        after = experience.get("observation_t+1", {}) if isinstance(experience.get("observation_t+1"), dict) else {}
        before_objects = [value for value in before.get("objects", []) if isinstance(value, dict)]
        after_objects = [value for value in after.get("objects", []) if isinstance(value, dict)]
        before_classes = Counter(str(value.get("class", "unknown")) for value in before_objects)
        after_classes = Counter(str(value.get("class", "unknown")) for value in after_objects)
        appeared = after_classes - before_classes
        disappeared = before_classes - after_classes
        before_map = {object_identity(value, index): value for index, value in enumerate(before_objects)}
        after_map = {object_identity(value, index): value for index, value in enumerate(after_objects)}
        attribute_changes = Counter()
        motion_dx = motion_dy = motion_speed = 0.0
        motion_count = 0
        numeric_delta = 0.0
        numeric_count = 0
        for identity in sorted(set(before_map) & set(after_map)):
            first = before_map[identity]
            second = after_map[identity]
            object_class = str(second.get("class", first.get("class", "unknown")))
            for field_name in ("state", "role", "text", "value", "enabled", "visible"):
                if first.get(field_name) != second.get(field_name):
                    attribute_changes[object_class + "." + field_name] += 1
            first_box = first.get("bbox", [])
            second_box = second.get("bbox", [])
            if (
                isinstance(first_box, (list, tuple))
                and len(first_box) >= 4
                and isinstance(second_box, (list, tuple))
                and len(second_box) >= 4
            ):
                first_x = safe_float(first_box[0], 0.0) + safe_float(first_box[2], 0.0) / 2.0
                first_y = safe_float(first_box[1], 0.0) + safe_float(first_box[3], 0.0) / 2.0
                second_x = safe_float(second_box[0], 0.0) + safe_float(second_box[2], 0.0) / 2.0
                second_y = safe_float(second_box[1], 0.0) + safe_float(second_box[3], 0.0) / 2.0
                dx = second_x - first_x
                dy = second_y - first_y
                motion_dx += dx
                motion_dy += dy
                motion_speed += math.sqrt(dx * dx + dy * dy)
                motion_count += 1
            if finite_number(first.get("value")) and finite_number(second.get("value")):
                numeric_delta += safe_float(second.get("value"), 0.0) - safe_float(first.get("value"), 0.0)
                numeric_count += 1
        delay = safe_float(
            experience.get("environment_response_time", experience.get("action_effect_delay", 0.0)), 0.0, 0.0, 60.0
        )
        delay_bucket = (
            "lt_100ms"
            if delay < 0.1
            else "lt_300ms" if delay < 0.3 else "lt_1s" if delay < 1.0 else "lt_3s" if delay < 3.0 else "gte_3s"
        )
        for row in (state_rows[task_id + "|" + state + "|" + action], action_rows[task_id + "|" + action]):
            row["count"] += 1
            row["reward"] += safe_float(experience.get("reward_t", experience.get("reward", 0.0)), 0.0)
            row["success"] += int(bool(experience.get("success")))
            row["failure"] += int(bool(experience.get("failure")))
            row["no_change"] += int(not bool(experience.get("environment_changed", True)))
            row["delay"] += delay
            row["appear"].update(appeared)
            row["disappear"].update(disappeared)
            row["terminals"][str(experience.get("terminal_state", "neutral"))] += 1
            row["next_states"][str(experience.get("state_t+1", experience.get("next_state", "")))] += 1
            row["attribute_changes"].update(attribute_changes)
            row["motion_dx"] += motion_dx
            row["motion_dy"] += motion_dy
            row["motion_speed"] += motion_speed
            row["motion_count"] += motion_count
            row["numeric_delta"] += numeric_delta
            row["numeric_count"] += numeric_count
            row["delay_buckets"][delay_bucket] += 1

    def finish(row):
        count = max(1, row["count"])
        terminal = row["success"] + row["failure"]
        motion_count = max(1, row["motion_count"])
        numeric_count = max(1, row["numeric_count"])
        return {
            "count": row["count"],
            "expected_reward": round(row["reward"] / count, 6),
            "success_probability": round((row["success"] + 1) / (terminal + 2) if terminal else 0.0, 6),
            "failure_probability": round((row["failure"] + 1) / (terminal + 2) if terminal else 0.0, 6),
            "no_effect_probability": round(row["no_change"] / count, 6),
            "expected_wait_seconds": round(row["delay"] / count, 6),
            "action_delay_distribution": dict(row["delay_buckets"].most_common()),
            "objects_appear": dict(row["appear"].most_common(12)),
            "objects_disappear": dict(row["disappear"].most_common(12)),
            "object_attribute_changes": dict(row["attribute_changes"].most_common(16)),
            "expected_object_motion": {
                "dx": round(row["motion_dx"] / motion_count, 6),
                "dy": round(row["motion_dy"] / motion_count, 6),
                "speed": round(row["motion_speed"] / motion_count, 6),
                "samples": row["motion_count"],
            },
            "expected_numeric_delta": round(row["numeric_delta"] / numeric_count, 6) if row["numeric_count"] else 0.0,
            "numeric_samples": row["numeric_count"],
            "terminal_distribution": dict(row["terminals"].most_common(4)),
            "next_state_distribution": dict(row["next_states"].most_common(8)),
            "uncertainty": round(min(1.0, 1.0 / math.sqrt(count) + 0.35 * (1.0 - min(1.0, terminal / count))), 6),
        }

    return {
        "schema_version": 3,
        "algorithm": "auditable_object_attribute_spatial_temporal_transition_model",
        "state_action": {key: finish(value) for key, value in state_rows.items()},
        "action_prior": {key: finish(value) for key, value in action_rows.items()},
        "training_transitions": len(experiences or []),
        "prediction_targets": [
            "next_object_set",
            "object_appearance_disappearance",
            "attribute_change",
            "object_motion",
            "numeric_change",
            "reward",
            "success_failure_no_effect_loading",
            "action_effect_delay",
            "next_state",
        ],
    }


def latent_observation_vector(observation, state_id="", size=LATENT_STATE_SIZE, semantic_model=None):
    item = dict(observation) if isinstance(observation, dict) else {}
    visual_size = min(VISUAL_EMBEDDING_SIZE, max(0, int(size)))
    visual_features = observation_visual_embedding(item, visual_size)
    objects = [value for value in item.get("objects", []) if isinstance(value, dict)]
    classes = Counter(str(value.get("class", "unknown")) for value in objects)
    features = list(visual_features)
    features.extend(min(1.0, classes.get(name, 0) / 6.0) for name in GENERAL_OBJECT_CLASSES)
    confidences = [safe_float(value.get("confidence"), 0.0) for value in objects]
    uncertainties = [
        safe_float(value.get("uncertainty", 1.0 - safe_float(value.get("confidence"), 0.0)), 1.0) for value in objects
    ]
    centers = []
    velocities = []
    areas = []
    interactable = 0
    enabled = 0
    numeric = []
    identities = []
    for value in objects:
        bbox = value.get("bbox", [0.0, 0.0, 0.0, 0.0])
        if isinstance(bbox, (list, tuple)) and len(bbox) >= 4:
            x = safe_float(bbox[0], 0.0)
            y = safe_float(bbox[1], 0.0)
            width = max(0.0, safe_float(bbox[2], 0.0))
            height = max(0.0, safe_float(bbox[3], 0.0))
            centers.append((x + width / 2.0, y + height / 2.0))
            areas.append(width * height)
        attributes = value.get("attributes", {}) if isinstance(value.get("attributes"), dict) else {}
        velocity = value.get("velocity", attributes.get("velocity", [0.0, 0.0]))
        if isinstance(velocity, (list, tuple)) and len(velocity) >= 2:
            velocities.append((safe_float(velocity[0], 0.0, -2.0, 2.0), safe_float(velocity[1], 0.0, -2.0, 2.0)))
        interactable += int(bool(value.get("interactable") or attributes.get("interactable")))
        enabled += int(str(value.get("state", "enabled")) not in {"disabled", "hidden", "inactive"})
        if finite_number(value.get("value")):
            numeric.append(safe_float(value.get("value"), 0.0, -1000000.0, 1000000.0))
        identities.append(str(value.get("track_id") or value.get("instance") or attributes.get("track_id") or ""))
    for value in item.get("ocr_values", []) if isinstance(item.get("ocr_values"), list) else []:
        if isinstance(value, dict) and finite_number(value.get("value")):
            numeric.append(safe_float(value.get("value"), 0.0, -1000000.0, 1000000.0))
    scene_graph = item.get("scene_graph", {}) if isinstance(item.get("scene_graph"), dict) else {}
    relations = Counter(
        str(edge.get("relation", "")) for edge in scene_graph.get("edges", []) if isinstance(edge, dict)
    )
    internal = item.get("internal_state", {}) if isinstance(item.get("internal_state"), dict) else {}
    memory = internal.get("memory", {}) if isinstance(internal.get("memory"), dict) else {}
    modality = internal.get("modality_mask", {}) if isinstance(internal.get("modality_mask"), dict) else {}
    modality_features = (
        internal.get("modality_features", {})
        if isinstance(internal.get("modality_features"), dict)
        else {}
    )
    modality_vector = modality_features.get("vector", []) if isinstance(modality_features.get("vector"), list) else []
    dynamic_visual = (
        internal.get("dynamic_fast_visual", {})
        if isinstance(internal.get("dynamic_fast_visual"), dict)
        else {}
    )
    dynamic_visual_vector = (
        dynamic_visual.get("embedding", [])
        if isinstance(dynamic_visual.get("embedding"), list)
        else []
    )
    recent_actions = item.get("recent_actions", []) if isinstance(item.get("recent_actions"), list) else []
    recent_rewards = item.get("recent_rewards", []) if isinstance(item.get("recent_rewards"), list) else []
    durations = (
        internal.get("recent_action_durations", []) if isinstance(internal.get("recent_action_durations"), list) else []
    )
    features.extend(
        [
            min(1.0, len(objects) / 48.0),
            statistics.fmean(confidences) if confidences else 0.0,
            statistics.fmean(uncertainties) if uncertainties else 1.0,
            interactable / max(1, len(objects)),
            enabled / max(1, len(objects)),
            statistics.fmean(value[0] for value in centers) if centers else 0.5,
            statistics.fmean(value[1] for value in centers) if centers else 0.5,
            statistics.fmean(abs(value[0]) + abs(value[1]) for value in velocities) if velocities else 0.0,
            statistics.fmean(areas) if areas else 0.0,
            min(1.0, len(relations) / 16.0),
            min(1.0, sum(relations.values()) / 64.0),
            min(1.0, len(set(value for value in identities if value)) / 48.0),
            min(1.0, len(recent_actions) / 16.0),
            min(1.0, len(recent_rewards) / 16.0),
            math.tanh((statistics.fmean(recent_rewards) if recent_rewards else 0.0) / 2.0),
            min(1.0, (statistics.fmean(durations) if durations else 0.0) / 5.0),
            min(1.0, safe_int(memory.get("length"), 0) / STRUCTURED_MEMORY_LENGTH),
            min(1.0, len(memory.get("failure_reasons", [])) / 16.0),
            min(1.0, len(memory.get("completed_subgoals", [])) / 32.0),
            sum(int(bool(value)) for value in modality.values()) / max(1, len(modality)) if modality else 0.0,
            statistics.fmean(uncertainties) if uncertainties else 1.0,
            math.tanh((statistics.fmean(numeric) if numeric else 0.0) / 100.0),
            math.tanh((max(numeric) if numeric else 0.0) / 100.0),
            math.tanh((min(numeric) if numeric else 0.0) / 100.0),
        ]
    )
    features.extend(safe_float(value, 0.0, -1.0, 1.0) for value in dynamic_visual_vector[:32])
    features.extend(safe_float(value, 0.0, -1.0, 1.0) for value in modality_vector[:32])
    semantic_material = {
        "state_id": state_id,
        "objects": [
            {
                "identity": value.get("track_id") or value.get("instance"),
                "class": value.get("class"),
                "role": value.get("role"),
                "text": value.get("text"),
                "state": value.get("state"),
                "value": value.get("value"),
                "bbox": value.get("bbox"),
                "velocity": value.get("velocity"),
                "attributes": value.get("attributes", {}),
            }
            for value in objects
        ],
        "ocr": item.get("ocr_values", []),
        "scene_graph": scene_graph,
        "task": item.get("task", {}),
        "task_phase": internal.get("task_phase"),
        "current_goal": internal.get("current_goal"),
        "current_subgoal": internal.get("current_subgoal"),
        "recent_actions": recent_actions[-16:],
        "recent_rewards": recent_rewards[-16:],
        "memory": memory,
        "modality_mask": modality,
        "modality_features": modality_features,
        "dynamic_fast_visual": dynamic_visual,
        "perception_uncertainty": statistics.fmean(uncertainties) if uncertainties else 1.0,
    }
    features.extend(semantic_embedding(semantic_material, max(0, size - len(features)), semantic_model))
    return [safe_float(value, 0.0, -2.0, 2.0) for value in (features + [0.0] * size)[:size]]


def _latent_action_vector(action_id, size=LATENT_ACTION_SIZE, semantic_model=None, timing=None):
    timing_value = timing if isinstance(timing, dict) else {}
    duration = max(
        0.0,
        safe_float(
            timing_value.get("duration", timing_value.get("action_duration", 0.0)),
            0.0,
            0.0,
            120.0,
        ),
    )
    effect_delay = max(
        0.0,
        safe_float(
            timing_value.get("effect_delay", timing_value.get("action_effect_delay", 0.0)),
            0.0,
            0.0,
            120.0,
        ),
    )
    delta = max(0.0, safe_float(timing_value.get("delta_time", timing_value.get("dt", 0.0)), 0.0, 0.0, 120.0))
    semantic_size = max(1, int(size) - 3)
    base = semantic_embedding({"semantic_action": action_id}, semantic_size, semantic_model)
    return (base + [math.tanh(duration / 5.0), math.tanh(effect_delay / 5.0), math.tanh(delta / 5.0)])[:size]


def _sequence_latent_state(ordered, index, window=32, semantic_model=None):
    vectors = []
    start = max(0, int(index) - max(1, int(window)) + 1)
    for position in range(start, int(index) + 1):
        item = ordered[position]
        state = str(item.get("state_t", item.get("state", "")))
        vectors.append(
            latent_observation_vector(item.get("observation_t", {}), state, LATENT_STATE_SIZE, semantic_model)
        )
    if not vectors:
        return [0.0] * LATENT_STATE_SIZE
    weights = list(range(1, len(vectors) + 1))
    total = sum(weights)
    return [
        sum(vector[column] * weight for vector, weight in zip(vectors, weights)) / total
        for column in range(LATENT_STATE_SIZE)
    ]


def _serialize_gru_cell(cell):
    return {
        "weight_ih": cell.weight_ih.detach().to("cpu").tolist(),
        "weight_hh": cell.weight_hh.detach().to("cpu").tolist(),
        "bias_ih": cell.bias_ih.detach().to("cpu").tolist(),
        "bias_hh": cell.bias_hh.detach().to("cpu").tolist(),
        "hidden_size": cell.hidden_size,
        "input_size": cell.input_size,
    }


_SERIALIZED_GRU_CACHE = BoundedTTLMap(64, 1800.0)


def _gru_cell_forward_batch(payload, actions, hidden_states):
    action_rows = [list(value) for value in actions or []]
    hidden_rows = [list(value) for value in hidden_states or []]
    if not action_rows or len(action_rows) != len(hidden_rows):
        return []
    hidden_size = safe_int(payload.get("hidden_size", LATENT_STATE_SIZE), LATENT_STATE_SIZE, 1, 2048)
    input_size = safe_int(payload.get("input_size", LATENT_ACTION_SIZE), LATENT_ACTION_SIZE, 1, 2048)
    numpy_module = FEATURE_ENGINE.optional_numpy()
    if numpy_module is not None:
        cache_key = str(id(payload)) + "|" + str(hidden_size) + "|" + str(input_size)
        cached = _SERIALIZED_GRU_CACHE.get(cache_key)
        if cached is None:
            cached = (
                numpy_module.asarray(payload.get("weight_ih", []), dtype=numpy_module.float32),
                numpy_module.asarray(payload.get("weight_hh", []), dtype=numpy_module.float32),
                numpy_module.asarray(payload.get("bias_ih", []), dtype=numpy_module.float32),
                numpy_module.asarray(payload.get("bias_hh", []), dtype=numpy_module.float32),
            )
            _SERIALIZED_GRU_CACHE[cache_key] = cached
        weight_ih, weight_hh, bias_ih, bias_hh = cached
        action_matrix = numpy_module.asarray(
            [[safe_float(v, 0.0, -8.0, 8.0) for v in (row + [0.0] * input_size)[:input_size]] for row in action_rows],
            dtype=numpy_module.float32,
        )
        hidden_matrix = numpy_module.asarray(
            [[safe_float(v, 0.0, -8.0, 8.0) for v in (row + [0.0] * hidden_size)[:hidden_size]] for row in hidden_rows],
            dtype=numpy_module.float32,
        )
        if weight_ih.shape != (3 * hidden_size, input_size) or weight_hh.shape != (3 * hidden_size, hidden_size):
            return [[0.0] * hidden_size for _ in action_rows]
        input_terms = action_matrix @ weight_ih.T + bias_ih
        hidden_terms = hidden_matrix @ weight_hh.T + bias_hh
        reset = 1.0 / (1.0 + numpy_module.exp(-numpy_module.clip(
            input_terms[:, :hidden_size] + hidden_terms[:, :hidden_size], -30.0, 30.0
        )))
        update = 1.0 / (1.0 + numpy_module.exp(-numpy_module.clip(
            input_terms[:, hidden_size:2 * hidden_size] + hidden_terms[:, hidden_size:2 * hidden_size], -30.0, 30.0
        )))
        candidate = numpy_module.tanh(
            input_terms[:, 2 * hidden_size:] + reset * hidden_terms[:, 2 * hidden_size:]
        )
        output = (1.0 - update) * candidate + update * hidden_matrix
        return output.astype(numpy_module.float64).tolist()
    result = []
    weight_ih = payload.get("weight_ih", [])
    weight_hh = payload.get("weight_hh", [])
    bias_ih = payload.get("bias_ih", [])
    bias_hh = payload.get("bias_hh", [])
    for action, hidden in zip(action_rows, hidden_rows):
        input_terms = []
        hidden_terms = []
        for index in range(min(len(weight_ih), 3 * hidden_size)):
            input_terms.append(
                sum(
                    safe_float(value, 0.0) * safe_float(coefficient, 0.0)
                    for value, coefficient in zip(action, weight_ih[index])
                )
                + safe_float(bias_ih[index] if index < len(bias_ih) else 0.0, 0.0)
            )
            hidden_terms.append(
                sum(
                    safe_float(value, 0.0) * safe_float(coefficient, 0.0)
                    for value, coefficient in zip(hidden, weight_hh[index])
                )
                + safe_float(bias_hh[index] if index < len(bias_hh) else 0.0, 0.0)
            )
        input_terms = (input_terms + [0.0] * (3 * hidden_size))[: 3 * hidden_size]
        hidden_terms = (hidden_terms + [0.0] * (3 * hidden_size))[: 3 * hidden_size]
        reset = [
            1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, input_terms[i] + hidden_terms[i]))))
            for i in range(hidden_size)
        ]
        update = [
            1.0
            / (
                1.0
                + math.exp(
                    -max(
                        -30.0,
                        min(30.0, input_terms[hidden_size + i] + hidden_terms[hidden_size + i]),
                    )
                )
            )
            for i in range(hidden_size)
        ]
        candidate = [
            math.tanh(
                input_terms[2 * hidden_size + i]
                + reset[i] * hidden_terms[2 * hidden_size + i]
            )
            for i in range(hidden_size)
        ]
        result.append(
            [
                (1.0 - update[i]) * candidate[i]
                + update[i] * safe_float(hidden[i] if i < len(hidden) else 0.0, 0.0)
                for i in range(hidden_size)
            ]
        )
    return result


def _gru_cell_forward(payload, action, hidden):
    output = _gru_cell_forward_batch(payload, [action], [hidden])
    return output[0] if output else [0.0] * safe_int(payload.get("hidden_size", LATENT_STATE_SIZE), LATENT_STATE_SIZE)

def _world_action_continuation_plan(model, task_id, state_id, action_id, horizon):
    task = normalized_identifier(task_id, "default", 96)
    if isinstance(action_id, (list, tuple)):
        return [str(value) for value in action_id if str(value)][: max(1, int(horizon))], "provided_action_sequence"
    first = str(action_id)
    if not first:
        return [], "missing_action"
    plan = [first]
    continuations = model.get("action_continuations", {}) if isinstance(model.get("action_continuations"), dict) else {}
    current_state = str(state_id)
    while len(plan) < max(1, int(horizon)):
        prefix = "|".join(plan[-3:])
        choices = None
        for key in (task + "|" + current_state + "|" + prefix, task + "|" + prefix, task + "|" + plan[-1]):
            candidate = continuations.get(key)
            if isinstance(candidate, dict) and candidate:
                choices = candidate
                break
        if not choices:
            break
        next_action = max(choices.items(), key=lambda item: (safe_float(item[1], 0.0), item[0]))[0]
        if not next_action or next_action == "<END>":
            break
        plan.append(str(next_action))
        current_state = ""
    return plan, "learned_behavior_continuation" if len(plan) > 1 else "single_observed_action_no_repetition"


def _world_model_rows(experiences, semantic_model=None):
    grouped = defaultdict(list)
    for value in experiences or []:
        if isinstance(value, dict):
            grouped[
                (
                    str(value.get("game_id") or "unknown"),
                    str(value.get("episode_id") or value.get("session") or "legacy"),
                )
            ].append(value)
    rows = []
    state_latents = {}
    all_states = []
    continuation_counts = defaultdict(Counter)
    for (game_id, _), values in grouped.items():
        ordered = sorted(values, key=lambda item: safe_int(item.get("step_id"), 0))
        for index, experience in enumerate(ordered):
            task = normalized_identifier(experience.get("task_id"), "default", 96)
            state = str(experience.get("state_t", experience.get("state", "")))
            initial = _sequence_latent_state(ordered, index, 32, semantic_model)
            state_latents[task + "|" + state] = initial
            all_states.append(initial)
            action_ids = []
            action_vectors = []
            target_states = []
            auxiliary = []
            confidences = []
            for offset in range(RUNTIME_THRESHOLDS.world_model_horizon):
                position = index + offset
                if position >= len(ordered):
                    break
                item = ordered[position]
                action = str(item.get("action_t", item.get("action", "")))
                if not action:
                    break
                next_state = str(item.get("state_t+1", item.get("next_state", "")))
                after = latent_observation_vector(
                    item.get("observation_t+1", {}), next_state, LATENT_STATE_SIZE, semantic_model
                )
                context = item.get("context", {}) if isinstance(item.get("context"), dict) else {}
                reward = safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0, -2.0, 2.0)
                changed = bool(item.get("environment_changed", True))
                previous_created = (
                    safe_float(
                        ordered[position - 1].get(
                            "created_t+1", ordered[position - 1].get("created_t", 0.0)
                        ),
                        0.0,
                    )
                    if position > 0
                    else safe_float(item.get("created_t", 0.0), 0.0)
                )
                current_created = safe_float(item.get("created_t", previous_created), previous_created)
                duration = max(
                    0.0,
                    safe_float(
                        item.get(
                            "action_duration",
                            context.get("action_duration", item.get("duration", 0.0)),
                        ),
                        0.0,
                        0.0,
                        120.0,
                    ),
                )
                effect_delay = max(
                    0.0,
                    safe_float(
                        item.get(
                            "action_effect_delay",
                            context.get("action_effect_delay", item.get("effect_delay", 0.0)),
                        ),
                        0.0,
                        0.0,
                        120.0,
                    ),
                )
                timing = {
                    "duration": duration,
                    "effect_delay": effect_delay,
                    "delta_time": max(0.0, current_created - previous_created),
                }
                action_ids.append(action)
                action_vectors.append(_latent_action_vector(action, LATENT_ACTION_SIZE, semantic_model, timing))
                target_states.append(after)
                auxiliary.append(
                    [
                        (reward + 2.0) / 4.0,
                        float(bool(item.get("success"))),
                        float(bool(item.get("failure"))),
                        float(not changed),
                        float(bool(item.get("loading") or context.get("loading"))),
                        float(bool(item.get("window_focus_lost") or context.get("window_focus_lost"))),
                        float(bool(item.get("capture_frozen") or context.get("capture_frozen"))),
                        float(bool(item.get("reset"))),
                        min(1.0, duration / 10.0),
                        min(1.0, effect_delay / 10.0),
                    ]
                )
                confidences.append(max(0.15, safe_float(item.get("reward_confidence", 0.0), 0.0, 0.0, 1.0)))
                next_action = (
                    str(ordered[position + 1].get("action_t", ordered[position + 1].get("action", "")))
                    if position + 1 < len(ordered)
                    else "<END>"
                )
                prefix = "|".join(action_ids[-3:])
                continuation_counts[task + "|" + state + "|" + prefix][next_action] += 1
                continuation_counts[task + "|" + prefix][next_action] += 1
                continuation_counts[task + "|" + action][next_action] += 1
                if item.get("done"):
                    break
            if action_ids:
                rows.append(
                    {
                        "game_id": game_id,
                        "task_id": task,
                        "state_id": state,
                        "initial": initial,
                        "action_ids": action_ids,
                        "actions": action_vectors,
                        "targets": target_states,
                        "auxiliary": auxiliary,
                        "confidences": confidences,
                        "length": len(action_ids),
                    }
                )
    return (
        rows,
        state_latents,
        all_states,
        {key: dict(value.most_common(12)) for key, value in continuation_counts.items()},
    )


def _world_model_validation(model, rows, split):
    games = set(split.get("validation_game_ids", [])) | set(split.get("test_game_ids", []))
    selected = [row for row in rows if row.get("game_id") in games]
    empty = {
        "one_step_object_prediction_error": None,
        "rollout_2_step_error": None,
        "rollout_3_step_error": None,
        "rollout_4_step_error": None,
        "rollout_8_step_error": None,
        "rollout_16_step_error": None,
        "rollout_32_step_error": None,
        "reward_calibration_error": None,
        "termination_precision": None,
        "termination_recall": None,
        "uncertainty_error_correlation": None,
    }
    if not selected:
        return {"status": "not_evaluated", "reason": "game_id_isolated_validation_unavailable", **empty}
    errors = {1: [], 2: [], 3: []}
    reward_errors = []
    terminal_truth = []
    terminal_score = []
    uncertainty_pairs = []
    members = model.get("ensemble", [])
    for row in selected[:1200]:
        member_outputs = []
        for member in members:
            hidden = list(row["initial"])
            predictions = []
            for action in row["actions"][: RUNTIME_THRESHOLDS.world_model_horizon]:
                hidden = _gru_cell_forward(member.get("gru", {}), action, hidden)
                raw = _dense_network_forward(member.get("auxiliary", {}), hidden)
                aux = [1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, value)))) for value in raw]
                predictions.append((list(hidden), aux))
            member_outputs.append(predictions)
        for horizon in (1, 2, 3):
            index = min(horizon, len(row["targets"])) - 1
            if index < 0:
                continue
            predicted = [member[index][0] for member in member_outputs if len(member) > index]
            if not predicted:
                continue
            mean = [statistics.fmean(value[column] for value in predicted) for column in range(LATENT_STATE_SIZE)]
            error = statistics.fmean(
                abs(mean[column] - row["targets"][index][column])
                for column in range(LATENT_STATE_SIZE)
            )
            errors[horizon].append(error)
            spread = statistics.fmean(
                (statistics.pstdev([value[column] for value in predicted]) for column in range(LATENT_STATE_SIZE)),
                default=0.0,
            )
            uncertainty_pairs.append((spread, error))
        first_aux = [member[0][1] for member in member_outputs if member]
        if first_aux:
            mean_aux = [statistics.fmean(value[index] for value in first_aux) for index in range(10)]
            reward_errors.append(abs((mean_aux[0] * 4.0 - 2.0) - (row["auxiliary"][0][0] * 4.0 - 2.0)))
            truth = bool(row["auxiliary"][0][1] >= 0.5 or row["auxiliary"][0][2] >= 0.5)
            terminal_truth.append(truth)
            terminal_score.append(max(mean_aux[1], mean_aux[2]))
    predicted_positive = [score >= 0.5 for score in terminal_score]
    tp = sum(1 for pred, truth in zip(predicted_positive, terminal_truth) if pred and truth)
    fp = sum(1 for pred, truth in zip(predicted_positive, terminal_truth) if pred and not truth)
    fn = sum(1 for pred, truth in zip(predicted_positive, terminal_truth) if not pred and truth)
    correlation = 0.0
    if len(uncertainty_pairs) >= 3:
        us = [value[0] for value in uncertainty_pairs]
        es = [value[1] for value in uncertainty_pairs]
        um = statistics.fmean(us)
        em = statistics.fmean(es)
        numerator = sum((u - um) * (e - em) for u, e in uncertainty_pairs)
        denominator = math.sqrt(sum((u - um) ** 2 for u in us) * sum((e - em) ** 2 for e in es))
        correlation = numerator / denominator if denominator else 0.0
    return {
        "status": "evaluated",
        "rows": len(selected),
        "game_ids": sorted(games),
        "one_step_object_prediction_error": statistics.fmean(errors[1]) if errors[1] else None,
        "rollout_2_step_error": statistics.fmean(errors[2]) if errors[2] else None,
        "rollout_3_step_error": statistics.fmean(errors[3]) if errors[3] else None,
        "rollout_4_step_error": None,
        "rollout_8_step_error": None,
        "rollout_16_step_error": None,
        "rollout_32_step_error": None,
        "reward_calibration_error": statistics.fmean(reward_errors) if reward_errors else None,
        "termination_precision": tp / max(1, tp + fp),
        "termination_recall": tp / max(1, tp + fn),
        "uncertainty_error_correlation": correlation,
        "metrics_are_game_id_isolated": True,
        "maximum_evaluated_horizon": RUNTIME_THRESHOLDS.world_model_horizon,
    }


def _world_teacher_soft_sequences(ensemble, rows):
    result = []
    members = [member for member in ensemble or [] if isinstance(member, dict)]
    for row in rows:
        member_hidden = [list(row["initial"]) for _ in members]
        sequence = []
        for action in row["actions"]:
            raw_values = []
            next_hidden = []
            for index, member in enumerate(members):
                hidden = _gru_cell_forward(member.get("gru", {}), action, member_hidden[index])
                raw = _dense_network_forward(member.get("auxiliary", {}), hidden)
                next_hidden.append(hidden)
                raw_values.append((raw + [0.0] * 10)[:10])
            member_hidden = next_hidden
            sequence.append(
                {
                    "hidden": [
                        statistics.fmean(hidden[column] for hidden in member_hidden)
                        for column in range(LATENT_STATE_SIZE)
                    ],
                    "auxiliary_logits": [
                        statistics.fmean(raw[column] for raw in raw_values) for column in range(10)
                    ],
                }
            )
        result.append(sequence)
    return result


def train_latent_world_model(experiences, semantic_model=None):
    auditable = train_auditable_transition_model(experiences)
    rows, state_latents, all_states, continuations = _world_model_rows(experiences, semantic_model)
    default_state = (
        [statistics.fmean(vector[column] for vector in all_states) for column in range(LATENT_STATE_SIZE)]
        if all_states
        else [0.0] * LATENT_STATE_SIZE
    )
    split = _game_isolated_policy_split([value for value in experiences or [] if isinstance(value, dict)])
    base = {
        "schema_version": SEQUENCE_WORLD_MODEL_SCHEMA_VERSION,
        "algorithm": "multiscale_variable_time_action_sequence_gru_ensemble",
        "auditable_transition_model": auditable,
        "state_latents": dict(list(state_latents.items())[:4096]),
        "default_state_latent": default_state,
        "horizon": RUNTIME_THRESHOLDS.world_model_horizon,
        "latent_state_size": LATENT_STATE_SIZE,
        "latent_action_size": LATENT_ACTION_SIZE,
        "semantic_encoder_checksum": str((semantic_model or {}).get("checksum", "")),
        "time_scales_ms": [50, 100, 250, 500, 1000, 2000, 5000],
        "action_continuations": continuations,
        "game_isolated_split": split,
        "predicts": [
            "next_visual_object_state",
            "next_object_slots",
            "object_birth",
            "object_death",
            "position_and_attribute_delta",
            "numeric_change",
            "reward",
            "success",
            "failure",
            "reset",
            "no_effect",
            "loading",
            "window_focus_lost",
            "capture_frozen",
            "action_duration",
            "action_effect_delay",
            "epistemic_uncertainty",
        ],
        "safety_boundary": "prediction_only_reorders_candidates_and_never_bypasses_independent_action_authorization",
        "training_uses_actual_action_sequences": True,
        "variable_time_interval_encoding": True,
        "multi_candidate_rollout": True,
        "single_action_repetition_forbidden": True,
        "scope": {
            "allowed": [
                "short_term_visual_change",
                "short_term_object_state",
                "no_effect_detection",
                "stuck_and_loop_detection",
                "candidate_reordering_for_one_to_three_steps",
            ],
            "forbidden": [
                "long_horizon_imagination",
                "dozens_of_steps_planning",
                "bypassing_task_graph",
                "bypassing_verifiable_goal_predicates",
            ],
            "long_term_planning_owner": "task_graph_explicit_subgoals_and_verifiable_predicates",
            "maximum_rollout_steps": RUNTIME_THRESHOLDS.world_model_horizon,
        },
    }
    if len(rows) < 8:
        return {
            **base,
            "trained": False,
            "reason": "insufficient_action_sequences",
            "training_sequences": len(rows),
            "validation": _world_model_validation({"ensemble": []}, rows, split),
        }
    try:
        import torch

        plan = wait_for_runtime_training_plan()
        configure_torch_runtime(torch, plan)
        device = torch_training_device(torch)
        amp_enabled = torch_device_is_cuda(torch, device)
        seed = int(
            hashlib.sha256(
                canonical_bytes(
                    [
                        str(value.get("source_sample_checksum", ""))
                        for value in experiences or []
                        if isinstance(value, dict)
                    ]
                )
            ).hexdigest()[:16],
            16,
        )
        torch.manual_seed(seed % (2**63 - 1))

        class DenseNetwork(torch.nn.Module):
            def __init__(self, input_size, output_size, hidden_size):
                super().__init__()
                self.layers = torch.nn.ModuleList(
                    [
                        torch.nn.Linear(input_size, hidden_size),
                        torch.nn.Linear(hidden_size, hidden_size),
                        torch.nn.Linear(hidden_size, output_size),
                    ]
                )

            def forward(self, value):
                value = torch.tanh(self.layers[0](value))
                value = torch.tanh(self.layers[1](value))
                return self.layers[2](value)

        train_games = set(split.get("train_game_ids", []))
        train_rows = [row for row in rows if row.get("game_id") in train_games] or rows
        train_rows = train_rows[:5000]
        ensemble = []
        histories = defaultdict(list)
        for member_index in range(max(LATENT_WORLD_ENSEMBLE_SIZE, plan.policy_ensemble_size)):
            member_seed = (seed + member_index * 130363) % (2**63 - 1)
            torch.manual_seed(member_seed)
            rng = random.Random(member_seed)
            gru = torch.nn.GRUCell(LATENT_ACTION_SIZE, LATENT_STATE_SIZE).to(device)
            auxiliary = DenseNetwork(LATENT_STATE_SIZE, 10, plan.policy_hidden_size).to(device)
            parameters = list(gru.parameters()) + list(auxiliary.parameters())
            optimizer = torch.optim.AdamW(parameters, lr=0.0012, weight_decay=0.0001)
            scaler = torch_grad_scaler(torch, amp_enabled)
            bootstrap = [train_rows[rng.randrange(len(train_rows))] for _ in range(max(32, len(train_rows)))]
            steps = max(64, min(300, len(train_rows) * 2))
            plan = wait_for_runtime_training_plan()
            batch_size = max(1, min(128, plan.policy_batch_size, len(bootstrap)))
            completed = 0
            while completed < steps:
                plan = wait_for_runtime_training_plan()
                configure_torch_runtime(torch, plan)
                batch_size = max(1, min(batch_size, plan.policy_batch_size, len(bootstrap)))
                batch = [bootstrap[rng.randrange(len(bootstrap))] for _ in range(batch_size)]
                try:
                    autocast = (
                        torch.autocast(device_type="cuda", dtype=torch.float16, enabled=True)
                        if amp_enabled
                        else nullcontext()
                    )
                    with autocast:
                        hidden = torch.tensor([row["initial"] for row in batch], dtype=torch.float32, device=device)
                        maximum = min(RUNTIME_THRESHOLDS.world_model_horizon, max(row["length"] for row in batch))
                        state_loss = torch.zeros((), dtype=torch.float32, device=device)
                        auxiliary_loss = torch.zeros((), dtype=torch.float32, device=device)
                        denominator = 0.0
                        for position in range(maximum):
                            mask = torch.tensor(
                                [1.0 if position < row["length"] else 0.0 for row in batch],
                                dtype=torch.float32,
                                device=device,
                            ).unsqueeze(1)
                            action = torch.tensor(
                                [
                                    row["actions"][position]
                                    if position < row["length"]
                                    else [0.0] * LATENT_ACTION_SIZE
                                    for row in batch
                                ],
                                dtype=torch.float32,
                                device=device,
                            )
                            target = torch.tensor(
                                [
                                    row["targets"][position]
                                    if position < row["length"]
                                    else row["targets"][-1]
                                    for row in batch
                                ],
                                dtype=torch.float32,
                                device=device,
                            )
                            aux_target = torch.tensor(
                                [
                                    row["auxiliary"][position]
                                    if position < row["length"]
                                    else [0.0] * 10
                                    for row in batch
                                ],
                                dtype=torch.float32,
                                device=device,
                            )
                            confidence = torch.tensor(
                                [row["confidences"][position] if position < row["length"] else 0.0 for row in batch],
                                dtype=torch.float32,
                                device=device,
                            ).unsqueeze(1)
                            predicted = gru(action, hidden)
                            active_hidden = mask * predicted + (1.0 - mask) * hidden
                            probability = torch.sigmoid(auxiliary(active_hidden))
                            horizon_weight = 1.0 + 0.14 * math.log2(position + 1)
                            weight = mask * (0.2 + 0.8 * confidence) * horizon_weight
                            state_loss = state_loss + (
                                weight * (active_hidden - target).pow(2).mean(dim=1, keepdim=True)
                            ).sum()
                            auxiliary_loss = auxiliary_loss + (
                                weight * (probability - aux_target).pow(2).mean(dim=1, keepdim=True)
                            ).sum()
                            denominator += float(weight.detach().sum().to("cpu").item())
                            hidden = active_hidden
                        total = (state_loss + 0.75 * auxiliary_loss) / max(1.0, denominator)
                    optimizer.zero_grad(set_to_none=True)
                    if scaler is not None:
                        scaler.scale(total).backward()
                        scaler.unscale_(optimizer)
                        torch.nn.utils.clip_grad_norm_(parameters, 5.0)
                        scaler.step(optimizer)
                        scaler.update()
                    else:
                        total.backward()
                        torch.nn.utils.clip_grad_norm_(parameters, 5.0)
                        optimizer.step()
                    completed += 1
                    histories["state_sequence_loss"].append(
                        float((state_loss.detach() / max(1.0, denominator)).to("cpu").item())
                    )
                    histories["auxiliary_sequence_loss"].append(
                        float((auxiliary_loss.detach() / max(1.0, denominator)).to("cpu").item())
                    )
                except RuntimeError as error:
                    message = str(error).casefold()
                    if ("out of memory" not in message and "allocation" not in message) or batch_size <= 1:
                        raise
                    batch_size = max(1, batch_size // 2)
                    optimizer.zero_grad(set_to_none=True)
                    release_torch_training_resources(torch)
                    collect_garbage("sequence_training_oom", 0.0, True)
                    continue
            ensemble.append(
                {
                    "gru": _serialize_gru_cell(gru),
                    "auxiliary": _serialize_dense_network(auxiliary),
                    "seed": member_seed,
                    "bootstrap_sequences": len(bootstrap),
                    "final_batch_size": batch_size,
                }
            )
            optimizer.zero_grad(set_to_none=True)
            scaler = None
            release_torch_training_resources(torch)

        rng = random.Random(seed ^ 0xD157111)
        distill_rows = list(rows[: min(768, len(rows))])
        rng.shuffle(distill_rows)
        validation_count = max(4, len(distill_rows) // 5)
        validation_rows = distill_rows[:validation_count]
        student_rows = distill_rows[validation_count:]
        teacher_sequences = _world_teacher_soft_sequences(ensemble, distill_rows)
        student_gru = torch.nn.GRUCell(LATENT_ACTION_SIZE, LATENT_STATE_SIZE).to(device)
        student_auxiliary = DenseNetwork(LATENT_STATE_SIZE, 10, POLICY_HIDDEN_SIZE).to(device)
        student_parameters = list(student_gru.parameters()) + list(student_auxiliary.parameters())
        student_optimizer = torch.optim.AdamW(student_parameters, lr=0.0012, weight_decay=0.0001)
        training_positions = list(range(validation_count, len(distill_rows)))
        student_steps = max(40, min(180, len(training_positions) * 2)) if training_positions else 0
        for _ in range(student_steps):
            selected_positions = [
                training_positions[rng.randrange(len(training_positions))]
                for _ in range(min(32, len(training_positions)))
            ]
            batch_rows = [distill_rows[index] for index in selected_positions]
            batch_teachers = [teacher_sequences[index] for index in selected_positions]
            hidden = torch.tensor([row["initial"] for row in batch_rows], dtype=torch.float32, device=device)
            maximum = min(32, max(row["length"] for row in batch_rows))
            loss = torch.zeros((), dtype=torch.float32, device=device)
            denominator = 0.0
            for position in range(maximum):
                mask = torch.tensor(
                    [1.0 if position < row["length"] else 0.0 for row in batch_rows],
                    dtype=torch.float32,
                    device=device,
                ).unsqueeze(1)
                action = torch.tensor(
                    [
                        row["actions"][position]
                        if position < row["length"]
                        else [0.0] * LATENT_ACTION_SIZE
                        for row in batch_rows
                    ],
                    dtype=torch.float32,
                    device=device,
                )
                target_hidden = torch.tensor(
                    [
                        teacher[position]["hidden"]
                        if position < len(teacher)
                        else teacher[-1]["hidden"]
                        for teacher in batch_teachers
                    ],
                    dtype=torch.float32,
                    device=device,
                )
                target_auxiliary = torch.tensor(
                    [
                        teacher[position]["auxiliary_logits"]
                        if position < len(teacher)
                        else teacher[-1]["auxiliary_logits"]
                        for teacher in batch_teachers
                    ],
                    dtype=torch.float32,
                    device=device,
                )
                predicted_hidden = student_gru(action, hidden)
                active_hidden = mask * predicted_hidden + (1.0 - mask) * hidden
                predicted_auxiliary = student_auxiliary(active_hidden)
                loss = loss + (mask * (active_hidden - target_hidden).pow(2).mean(dim=1, keepdim=True)).sum()
                loss = loss + 0.5 * (
                    mask * (predicted_auxiliary - target_auxiliary).pow(2).mean(dim=1, keepdim=True)
                ).sum()
                denominator += float(mask.sum().detach().to("cpu").item())
                hidden = active_hidden
            loss = loss / max(1.0, denominator)
            student_optimizer.zero_grad(set_to_none=True)
            loss.backward()
            torch.nn.utils.clip_grad_norm_(student_parameters, 5.0)
            student_optimizer.step()
        state_errors = []
        auxiliary_errors = []
        with torch.no_grad():
            for row, teacher in zip(validation_rows, teacher_sequences[:validation_count]):
                hidden = torch.tensor([row["initial"]], dtype=torch.float32, device=device)
                for position, action_values in enumerate(row["actions"][: RUNTIME_THRESHOLDS.world_model_horizon]):
                    action = torch.tensor([action_values], dtype=torch.float32, device=device)
                    hidden = student_gru(action, hidden)
                    auxiliary_output = student_auxiliary(hidden)
                    target_hidden = torch.tensor([teacher[position]["hidden"]], dtype=torch.float32, device=device)
                    target_auxiliary = torch.tensor(
                        [teacher[position]["auxiliary_logits"]],
                        dtype=torch.float32,
                        device=device,
                    )
                    state_errors.append(float((hidden - target_hidden).pow(2).mean().to("cpu").item()))
                    auxiliary_errors.append(float((auxiliary_output - target_auxiliary).pow(2).mean().to("cpu").item()))
        state_mse = statistics.fmean(state_errors) if state_errors else float("inf")
        auxiliary_mse = statistics.fmean(auxiliary_errors) if auxiliary_errors else float("inf")
        student_accepted = bool(state_mse <= 0.08 and auxiliary_mse <= 0.08)
        distillation = {
            "trained": student_accepted,
            "method": "holdout_ensemble_soft_label_sequence_student",
            "teacher_members": len(ensemble),
            "training_sequences": len(student_rows),
            "validation_sequences": len(validation_rows),
            "state_mse": state_mse,
            "auxiliary_logit_mse": auxiliary_mse,
            "acceptance_thresholds": {"state_mse": 0.08, "auxiliary_logit_mse": 0.08},
            "member": {
                "gru": _serialize_gru_cell(student_gru),
                "auxiliary": _serialize_dense_network(student_auxiliary),
            } if student_accepted else None,
            "used_in_uncertainty_ensemble": False,
            "fallback": "original_ensemble" if not student_accepted else "student_available_for_export_only",
        }
        student_optimizer.zero_grad(set_to_none=True)
        release_torch_training_resources(torch)
        model = {
            **base,
            "trained": True,
            "ensemble": ensemble,
            "ensemble_size": len(ensemble),
            "training_sequences": len(train_rows),
            "sequence_window": RUNTIME_THRESHOLDS.world_model_horizon,
            "multi_step_horizons": [1, 2, 3],
            "training_backend": str(device),
            "automatic_mixed_precision": bool(amp_enabled),
            "torch_threads": int(RESOURCE_GOVERNOR.current_plan().torch_threads),
            "dynamic_batch": True,
            "training_losses": {
                name: statistics.fmean(values[-min(100, len(values)) :]) if values else 0.0
                for name, values in histories.items()
            },
            "distillation": distillation,
        }
        model["validation"] = _world_model_validation(model, rows, split)
        return model
    except RECOVERABLE_ERRORS as error:
        return {
            **base,
            "trained": False,
            "reason": "training_error",
            "training_error": type(error).__name__ + ":" + str(error),
            "training_sequences": len(rows),
            "validation": _world_model_validation({"ensemble": []}, rows, split),
        }

def dynamic_planning_depth(context=None, uncertainty=0.0, maximum=None):
    value = context if isinstance(context, dict) else {}
    plan = RESOURCE_GOVERNOR.current_plan()
    upper = max(1, min(int(maximum or plan.world_model_horizon), RUNTIME_THRESHOLDS.world_model_horizon))
    phase = str(value.get("task_phase", value.get("scene_phase", ""))).casefold()
    classes = {str(item).casefold() for item in value.get("object_classes", []) if item is not None}
    risk = safe_float(value.get("risk_probability"), 0.0, 0.0, 1.0)
    disagreement = safe_float(value.get("policy_value_disagreement"), uncertainty, 0.0, 10.0)
    if classes.intersection({"dialog", "confirm_button", "popup"}) or "popup" in phase or "confirm" in phase:
        depth = 2 + int(disagreement > 0.35) + int(risk > 0.35)
        return min(upper, max(2, min(4, depth)))
    if classes.intersection({"enemy", "resource", "inventory", "meter"}) or any(
        token in phase for token in ("combat", "battle", "resource", "inventory")
    ):
        depth = 6 + int(disagreement > 0.25) * 2 + int(risk > 0.35) * 2
        return min(upper, max(6, min(12, depth)))
    if value.get("current_subgoal") or value.get("failure_recovery_stack"):
        return min(upper, max(4, 8 + int(disagreement > 0.4) * 4))
    return min(upper, max(1, 1 + int(disagreement > 0.20) + int(disagreement > 0.45)))


def world_model_rollout_candidates(model, task_id, state_id, candidate_action_ids, context=None):
    if not isinstance(model, dict):
        return {}
    task = normalized_identifier(task_id, "default", 96)
    configured_horizon = safe_int(
        model.get("horizon", RESOURCE_GOVERNOR.current_plan().world_model_horizon),
        RESOURCE_GOVERNOR.current_plan().world_model_horizon,
        1,
        RUNTIME_THRESHOLDS.world_model_horizon,
    )
    horizon = dynamic_planning_depth(context, safe_float((context or {}).get("uncertainty"), 0.0), configured_horizon)
    auditable = (
        model.get("auditable_transition_model", {})
        if isinstance(model.get("auditable_transition_model"), dict)
        else {}
    )
    prepared = []
    for candidate_index, candidate in enumerate(candidate_action_ids or []):
        plan, plan_source = _world_action_continuation_plan(model, task, state_id, candidate, horizon)
        if not plan:
            continue
        first_action = str(plan[0])
        exact = (auditable.get("state_action") or {}).get(task + "|" + str(state_id) + "|" + first_action)
        prior = (auditable.get("action_prior") or {}).get(task + "|" + first_action)
        audit = dict(exact) if isinstance(exact, dict) else dict(prior) if isinstance(prior, dict) else {}
        key = str(candidate_index)
        prepared.append({"key": key, "candidate": candidate, "plan": plan, "plan_source": plan_source, "audit": audit})
    if not prepared:
        return {}
    if not model.get("trained") or not isinstance(model.get("ensemble"), list):
        return {entry["key"]: dict(entry["audit"]) for entry in prepared}
    latent = (model.get("state_latents") or {}).get(task + "|" + str(state_id))
    fallback = model.get("default_state_latent", [0.0] * LATENT_STATE_SIZE)
    current = (
        [safe_float(value, 0.0, -3.0, 3.0) for value in latent]
        if isinstance(latent, list)
        else [safe_float(value, 0.0, -3.0, 3.0) for value in fallback]
    )
    current = (current + [0.0] * LATENT_STATE_SIZE)[:LATENT_STATE_SIZE]
    source_members = [member for member in model.get("ensemble", []) if isinstance(member, dict)]
    per_candidate_members = [[] for _ in prepared]
    maximum_steps = max(len(entry["plan"]) for entry in prepared)
    for member in source_members:
        hidden_states = [list(current) for _ in prepared]
        series = [defaultdict(list) for _ in prepared]
        for position in range(maximum_steps):
            active = [index for index, entry in enumerate(prepared) if position < len(entry["plan"])]
            if not active:
                break
            action_vectors = [
                _latent_action_vector(
                    prepared[index]["plan"][position],
                    LATENT_ACTION_SIZE,
                    model.get("semantic_encoder"),
                    {"duration": 0.0, "effect_delay": 0.0, "delta_time": 0.0},
                )
                for index in active
            ]
            active_hidden = [hidden_states[index] for index in active]
            predicted_hidden = _gru_cell_forward_batch(member.get("gru", {}), action_vectors, active_hidden)
            raw_batch = _dense_network_forward_batch(member.get("auxiliary", {}), predicted_hidden)
            for local_index, candidate_index in enumerate(active):
                hidden_states[candidate_index] = predicted_hidden[local_index]
                raw = (raw_batch[local_index] + [0.0] * 10)[:10]
                auxiliary = [1.0 / (1.0 + math.exp(-max(-30.0, min(30.0, value)))) for value in raw]
                candidate_series = series[candidate_index]
                candidate_series["reward"].append(auxiliary[0] * 4.0 - 2.0)
                for offset, name in enumerate(
                    (
                        "success",
                        "failure",
                        "no_effect",
                        "loading",
                        "focus_lost",
                        "frozen",
                        "reset",
                    ),
                    1,
                ):
                    candidate_series[name].append(auxiliary[offset])
                candidate_series["duration"].append(auxiliary[8] * 10.0)
                candidate_series["effect_delay"].append(auxiliary[9] * 10.0)
        for candidate_index, candidate_series in enumerate(series):
            summary = {"latent": hidden_states[candidate_index]}
            for name in (
                "reward",
                "success",
                "failure",
                "no_effect",
                "loading",
                "focus_lost",
                "frozen",
                "reset",
                "duration",
                "effect_delay",
            ):
                values = candidate_series.get(name, [])
                if not values:
                    summary[name] = 0.0
                elif name in {"success", "failure", "loading", "focus_lost", "frozen", "reset"}:
                    summary[name] = max(values)
                else:
                    summary[name] = statistics.fmean(values)
            per_candidate_members[candidate_index].append(summary)
    results = {}
    for candidate_index, entry in enumerate(prepared):
        members = per_candidate_members[candidate_index]
        if not members:
            results[entry["key"]] = dict(entry["audit"])
            continue
        uncertainty_terms = []
        for name in (
            "reward",
            "success",
            "failure",
            "no_effect",
            "loading",
            "focus_lost",
            "frozen",
            "reset",
            "duration",
            "effect_delay",
        ):
            values = [member[name] for member in members]
            uncertainty_terms.append(statistics.pstdev(values) if len(values) > 1 else 0.0)
        latent_spread = max(
            (statistics.pstdev([member["latent"][index] for member in members]) for index in range(LATENT_STATE_SIZE)),
            default=0.0,
        )
        uncertainty = min(1.0, max([latent_spread, *uncertainty_terms]))
        result = dict(entry["audit"])
        result.update(
            {
                "expected_reward": statistics.fmean(member["reward"] for member in members),
                "success_probability": statistics.fmean(member["success"] for member in members),
                "failure_probability": statistics.fmean(member["failure"] for member in members),
                "no_effect_probability": statistics.fmean(member["no_effect"] for member in members),
                "loading_probability": statistics.fmean(member["loading"] for member in members),
                "window_focus_lost_probability": statistics.fmean(member["focus_lost"] for member in members),
                "capture_frozen_probability": statistics.fmean(member["frozen"] for member in members),
                "reset_probability": statistics.fmean(member["reset"] for member in members),
                "predicted_action_duration": statistics.fmean(member["duration"] for member in members),
                "predicted_effect_delay": statistics.fmean(member["effect_delay"] for member in members),
                "uncertainty": max(safe_float(entry["audit"].get("uncertainty"), 0.0), uncertainty),
                "rollout_uncertainty": uncertainty,
                "horizon": len(entry["plan"]),
                "model": "multiscale_variable_time_action_sequence_gru_ensemble",
                "member_count": len(members),
                "state_fallback": (
                    "learned_default_object_state"
                    if not isinstance(latent, list)
                    else "exact_state_latent"
                ),
                "action_sequence": entry["plan"],
                "action_sequence_source": entry["plan_source"],
                "single_action_repetition_used": False,
                "distillation_member_used": False,
                "safety_boundary": model.get("safety_boundary"),
            }
        )
        results[entry["key"]] = result
    return results


def world_model_prediction(model, task_id, state_id, action_id):
    results = world_model_rollout_candidates(model, task_id, state_id, [action_id])
    return results.get("0", {})


