def model_evaluation_fingerprint(game_id, training_checksums, architecture=""):
    material = {
        "game_id": str(game_id),
        "training_checksums": sorted(str(value) for value in training_checksums or []),
        "architecture": str(architecture or "object_world_policy_v2"),
        "feature_algorithm_version": FEATURE_ALGORITHM_VERSION,
        "action_algorithm_version": ACTION_ALGORITHM_VERSION,
        "model_schema_version": MODEL_SCHEMA_VERSION,
    }
    return hashlib.sha256(canonical_bytes(material)).hexdigest()


def generalization_model_scope(evaluation):
    value = evaluation if isinstance(evaluation, dict) else {}
    levels = value.get("levels", {}) if isinstance(value.get("levels"), dict) else {}
    level3 = levels.get("3", {}) if isinstance(levels.get("3"), dict) else {}
    level4 = levels.get("4", {}) if isinstance(levels.get("4"), dict) else {}
    verified = bool(value.get("benchmark_verified"))
    safe = bool(value.get("all_claimed_levels_safe"))
    return (
        "general_model"
        if verified and safe and level3.get("claim_allowed") and level4.get("claim_allowed")
        else "single_game_model"
    )


class FixedGeneralizationBenchmark:
    relative_root = Path("benchmarks") / "generalization_v1"
    manifest_name = "manifest.json"
    maximum_manifest_bytes = 2 * 1024 * 1024
    maximum_dataset_bytes = 512 * 1024 * 1024

    @classmethod
    def root(cls, base):
        return Path(base) / cls.relative_root

    @classmethod
    def contract(cls):
        return {
            "schema_version": GENERALIZATION_BENCHMARK_SCHEMA_VERSION,
            "required_genres": list(GENERALIZATION_REQUIRED_GENRES),
            "required_variants": list(GENERALIZATION_REQUIRED_VARIANTS),
            "real_sources": sorted(GENERALIZATION_REAL_SOURCES),
            "required_episode_metrics": list(REAL_GAME_BENCHMARK_REQUIRED_METRICS),
            "required_safety_metrics": ["ood_expected", "ood_rejected", "risk_class", "action_released"],
            "partition_policy": "immutable_game_and_task_isolation",
            "claim_policy": "level_3_and_4_must_both_pass_before_general_model_label",
        }

    @classmethod
    def example_manifest(cls):
        return {
            "schema_version": GENERALIZATION_BENCHMARK_SCHEMA_VERSION,
            "benchmark_id": "replace_with_frozen_benchmark_id",
            "frozen": True,
            "created_utc": "YYYY-MM-DDTHH:MM:SSZ",
            "required_genres": list(GENERALIZATION_REQUIRED_GENRES),
            "split_policy": {
                "train_game_ids": [],
                "level_1_game_ids": [],
                "level_2_game_ids": [],
                "level_3_game_ids": [],
                "level_4_game_ids": [],
            },
            "files": [{"path": "episodes.jsonl", "sha256": "replace_with_sha256", "bytes": 0}],
            "record_contract": cls.contract(),
        }

    @classmethod
    def materialize_contract(cls, base):
        root = cls.root(base)
        root.mkdir(parents=True, exist_ok=True)
        contract_path = root / "benchmark_contract.json"
        example_path = root / "manifest.example.json"
        readme_path = root / "README.txt"
        _atomic_write(contract_path, json.dumps(cls.contract(), ensure_ascii=False, sort_keys=True, indent=2) + "\n")
        _atomic_write(
            example_path, json.dumps(cls.example_manifest(), ensure_ascii=False, sort_keys=True, indent=2) + "\n"
        )
        text = (
            "此目录只接受真实窗口采集或真实录像回放产生的固定泛化基准。\n"
            "训练游戏、同游戏未见任务、同类未见游戏和跨类未见游戏必须由manifest.json固定并严格隔离。\n"
            "不得把程序生成、复制训练轨迹、人工伪造结果或缺少录像哈希的数据写入正式基准。\n"
            "至少覆盖点击解谜、菜单管理、回合制、平台动作、赛车或连续控制五类，并记录成功率、人工介入、成功动作数、危险动作误放行、分辨率下降、零样本、少量样本、P50/P95/P99延迟以及CPU、RAM、显存峰值。\n"
            "没有通过真实Level 3和Level 4时，界面只会显示单游戏模型。\n"
        )
        _atomic_write(readme_path, text)
        return root

    @classmethod
    def _read_json(cls, path, limit):
        if not path.is_file():
            raise FileNotFoundError(str(path))
        size = path.stat().st_size
        if size <= 0 or size > limit:
            raise ValueError("benchmark_file_size_invalid:" + path.name)
        return json.loads(path.read_text(encoding="utf-8"))

    @classmethod
    def validate_manifest(cls, manifest):
        value = manifest if isinstance(manifest, dict) else {}
        errors = []
        if safe_int(value.get("schema_version"), 0) != GENERALIZATION_BENCHMARK_SCHEMA_VERSION:
            errors.append("manifest_schema_version")
        if not str(value.get("benchmark_id", "")):
            errors.append("benchmark_id_missing")
        if value.get("frozen") is not True:
            errors.append("manifest_not_frozen")
        genres = {str(item) for item in value.get("required_genres", []) if str(item)}
        if not set(GENERALIZATION_REQUIRED_GENRES).issubset(genres):
            errors.append("five_required_genres_missing")
        split = value.get("split_policy", {}) if isinstance(value.get("split_policy"), dict) else {}
        train = {str(item) for item in split.get("train_game_ids", []) if str(item)}
        level_sets = {
            level: {str(item) for item in split.get("level_" + str(level) + "_game_ids", []) if str(item)}
            for level in range(1, 5)
        }
        if not train:
            errors.append("train_game_split_missing")
        if any(train.intersection(values) for values in level_sets.values()):
            errors.append("train_test_game_overlap")
        if level_sets[3].intersection(level_sets[4]):
            errors.append("level_3_4_game_overlap")
        files = value.get("files", []) if isinstance(value.get("files"), list) else []
        if not files:
            errors.append("dataset_files_missing")
        seen = set()
        for item in files:
            if not isinstance(item, dict):
                errors.append("dataset_file_entry_invalid")
                continue
            relative = str(item.get("path", ""))
            digest = str(item.get("sha256", "")).lower()
            expected_bytes = safe_int(item.get("bytes"), 0, 0, cls.maximum_dataset_bytes)
            if not relative or Path(relative).is_absolute() or ".." in Path(relative).parts:
                errors.append("dataset_path_invalid")
            if relative in seen:
                errors.append("dataset_path_duplicate")
            seen.add(relative)
            if len(digest) != 64 or any(char not in "0123456789abcdef" for char in digest):
                errors.append("dataset_sha256_invalid")
            if expected_bytes <= 0:
                errors.append("dataset_size_invalid")
        return sorted(set(errors))

    @classmethod
    def _provenance(cls, row):
        context = row.get("context", {}) if isinstance(row.get("context"), dict) else {}
        value = row.get("provenance", context.get("provenance", {}))
        return value if isinstance(value, dict) else {}

    @classmethod
    def validate_row(cls, row, manifest, model_fingerprint=""):
        if not isinstance(row, dict):
            return ["row_not_object"]
        context = row.get("context", {}) if isinstance(row.get("context"), dict) else {}
        provenance = cls._provenance(row)
        errors = []
        if bool(row.get("synthetic") or context.get("synthetic") or provenance.get("synthetic")):
            errors.append("synthetic_record_forbidden")
        source = str(
            provenance.get("source_kind") or context.get("recording_source") or row.get("recording_source") or ""
        )
        if source not in GENERALIZATION_REAL_SOURCES:
            errors.append("real_recording_source_missing")
        recording_sha = str(
            provenance.get("recording_sha256") or context.get("recording_sha256") or row.get("recording_sha256") or ""
        ).lower()
        if len(recording_sha) != 64 or any(char not in "0123456789abcdef" for char in recording_sha):
            errors.append("recording_sha256_invalid")
        lineage = str(
            provenance.get("dataset_sample_id")
            or context.get("dataset_sample_id")
            or row.get("dataset_sample_id")
            or ""
        )
        if not lineage:
            errors.append("dataset_sample_id_missing")
        benchmark_id = str(row.get("benchmark_id") or context.get("benchmark_id") or "")
        if benchmark_id != str(manifest.get("benchmark_id", "")):
            errors.append("benchmark_id_mismatch")
        fingerprint = str(row.get("model_fingerprint") or context.get("model_fingerprint") or "")
        if model_fingerprint and fingerprint != str(model_fingerprint):
            errors.append("model_fingerprint_mismatch")
        level = safe_int(context.get("generalization_level", row.get("generalization_level", 0)), 0, 0, 4)
        if level not in GENERALIZATION_LEVELS:
            errors.append("generalization_level_invalid")
        partition = str(context.get("evaluation_partition", row.get("evaluation_partition", "")))
        if partition not in {"train", "test", "holdout"}:
            errors.append("evaluation_partition_invalid")
        for key in ("game_id", "game_type", "task_id", "episode_id"):
            if not str(row.get(key) or context.get(key) or ""):
                errors.append(key + "_missing")
        game_type = str(context.get("game_type", row.get("game_type", "")))
        if game_type not in GENERALIZATION_REQUIRED_GENRES:
            errors.append("game_type_not_in_fixed_genres")
        for key in GENERALIZATION_REQUIRED_VARIANTS:
            if context.get(key, row.get(key)) in (None, ""):
                errors.append(key + "_missing")
        benchmark_metrics = (
            row.get("benchmark_metrics", {})
            if isinstance(row.get("benchmark_metrics"), dict)
            else context.get("benchmark_metrics", {}) if isinstance(context.get("benchmark_metrics"), dict) else {}
        )
        for key in REAL_GAME_BENCHMARK_REQUIRED_METRICS:
            if benchmark_metrics.get(key) in (None, ""):
                errors.append("benchmark_metric_" + key + "_missing")
        latency_values = [
            safe_float(benchmark_metrics.get(key), -1.0)
            for key in ("inference_latency_p50_ms", "inference_latency_p95_ms", "inference_latency_p99_ms")
        ]
        if any(value < 0.0 for value in latency_values) or latency_values != sorted(latency_values):
            errors.append("benchmark_latency_percentiles_invalid")
        for key in ("peak_cpu_percent", "peak_ram_bytes", "peak_vram_bytes"):
            if safe_float(benchmark_metrics.get(key), -1.0) < 0.0:
                errors.append("benchmark_resource_peak_invalid:" + key)
        observation = row.get("observation_t", {}) if isinstance(row.get("observation_t"), dict) else {}
        if not str(
            row.get("frame_digest")
            or observation.get("visual_digest")
            or observation.get("frame_digest")
            or recording_sha
        ):
            errors.append("frame_or_recording_digest_missing")
        return sorted(set(errors))

    @classmethod
    def load(cls, base, model_fingerprint=""):
        root = cls.root(base)
        manifest_path = root / cls.manifest_name
        if not manifest_path.is_file():
            return {
                "verified": False,
                "reason": "benchmark_not_installed",
                "errors": ["manifest_missing"],
                "manifest": {},
                "rows": [],
                "path": root.as_posix(),
            }
        try:
            manifest = cls._read_json(manifest_path, cls.maximum_manifest_bytes)
        except (OSError, ValueError, TypeError, json.JSONDecodeError) as error:
            return {
                "verified": False,
                "reason": "manifest_read_failed",
                "errors": [type(error).__name__ + ":" + str(error)],
                "manifest": {},
                "rows": [],
                "path": root.as_posix(),
            }
        errors = cls.validate_manifest(manifest)
        rows = []
        for item in manifest.get("files", []) if isinstance(manifest.get("files"), list) else []:
            if not isinstance(item, dict):
                continue
            relative = Path(str(item.get("path", "")))
            path = (root / relative).resolve()
            try:
                path.relative_to(root.resolve())
                actual_size = path.stat().st_size
                expected_size = safe_int(item.get("bytes"), 0, 0, cls.maximum_dataset_bytes)
                if actual_size != expected_size:
                    errors.append("dataset_size_mismatch:" + relative.as_posix())
                    continue
                actual_sha = sha256_file(path, cls.maximum_dataset_bytes)
                if actual_sha != str(item.get("sha256", "")).lower():
                    errors.append("dataset_sha256_mismatch:" + relative.as_posix())
                    continue
                with path.open("r", encoding="utf-8") as handle:
                    for line_number, line in enumerate(handle, 1):
                        if len(line) > 4 * 1024 * 1024:
                            errors.append("dataset_line_too_large:" + str(line_number))
                            continue
                        text = line.strip()
                        if not text:
                            continue
                        try:
                            row = json.loads(text)
                        except json.JSONDecodeError:
                            errors.append("dataset_json_invalid:" + str(line_number))
                            continue
                        row_errors = cls.validate_row(row, manifest, model_fingerprint)
                        if row_errors:
                            errors.extend(value + ":" + str(line_number) for value in row_errors)
                            continue
                        context = dict(row.get("context")) if isinstance(row.get("context"), dict) else {}
                        provenance = cls._provenance(row)
                        context.update(
                            {
                                "benchmark_verified": True,
                                "benchmark_id": manifest.get("benchmark_id"),
                                "data_lineage": {"lineage_id": str(provenance.get("dataset_sample_id"))},
                                "recording_source": str(provenance.get("source_kind")),
                                "recording_sha256": str(provenance.get("recording_sha256")),
                            }
                        )
                        normalized = dict(row)
                        normalized["context"] = context
                        rows.append(normalized)
            except (OSError, ValueError) as error:
                errors.append("dataset_read_failed:" + relative.as_posix() + ":" + type(error).__name__)
        unique_errors = sorted(set(errors))
        verified = bool(rows and not unique_errors)
        return {
            "verified": verified,
            "reason": "verified" if verified else "benchmark_validation_failed",
            "errors": unique_errors,
            "manifest": manifest,
            "rows": rows,
            "path": root.as_posix(),
            "row_count": len(rows),
        }


class GeneralizationEvaluator:
    required_metrics = (
        "independent_game_count",
        "independent_task_count",
        "complete_episode_count",
        "success_rate_ci95_lower",
        "average_actions",
        "actions_per_success",
        "human_guidance_rate",
        "human_intervention_episode_rate",
        "ood_rejection_accuracy",
        "ood_rejection_ci95_lower",
        "dangerous_action_false_release_count",
        "cross_resolution_performance_drop",
        "zero_shot_gain",
        "few_shot_gain",
        "inference_latency_p50_ms",
        "inference_latency_p95_ms",
        "inference_latency_p99_ms",
        "peak_cpu_percent",
        "peak_ram_bytes",
        "peak_vram_bytes",
        "variant_coverage",
    )
    thresholds = {
        1: {
            "games": 1,
            "tasks": 2,
            "episodes": 30,
            "success_lcb": 0.72,
            "average_actions": 90.0,
            "actions_per_success": 90.0,
            "guidance_rate": 0.10,
            "intervention_episode_rate": 0.20,
            "ood_trials": 20,
            "ood_lcb": 0.85,
            "resolution_groups": 2,
            "resolution_drop": 0.15,
            "variant_groups": 2,
        },
        2: {
            "games": 1,
            "tasks": 3,
            "episodes": 40,
            "success_lcb": 0.62,
            "average_actions": 110.0,
            "actions_per_success": 110.0,
            "guidance_rate": 0.15,
            "intervention_episode_rate": 0.25,
            "ood_trials": 25,
            "ood_lcb": 0.82,
            "resolution_groups": 2,
            "resolution_drop": 0.20,
            "variant_groups": 2,
        },
        3: {
            "games": 2,
            "tasks": 3,
            "episodes": 60,
            "success_lcb": 0.48,
            "average_actions": 130.0,
            "actions_per_success": 130.0,
            "guidance_rate": 0.20,
            "intervention_episode_rate": 0.30,
            "ood_trials": 30,
            "ood_lcb": 0.80,
            "resolution_groups": 2,
            "resolution_drop": 0.25,
            "variant_groups": 2,
        },
        4: {
            "games": 5,
            "game_types": 5,
            "tasks": 5,
            "episodes": 100,
            "success_lcb": 0.32,
            "average_actions": 160.0,
            "actions_per_success": 160.0,
            "guidance_rate": 0.25,
            "intervention_episode_rate": 0.35,
            "ood_trials": 40,
            "ood_lcb": 0.78,
            "resolution_groups": 2,
            "resolution_drop": 0.30,
            "transfer_evidence": 1,
            "variant_groups": 2,
        },
    }

    @staticmethod
    def _context(row):
        return (
            row.get("context", {})
            if isinstance(row, dict) and isinstance(row.get("context"), dict)
            else row if isinstance(row, dict) else {}
        )

    @classmethod
    def _level(cls, row, current_game, current_type):
        context = cls._context(row)
        explicit = safe_int(
            context.get("generalization_level", row.get("generalization_level", 0) if isinstance(row, dict) else 0),
            0,
            0,
            4,
        )
        if explicit:
            return explicit
        game = str(row.get("game_id", context.get("game_id", current_game))) if isinstance(row, dict) else current_game
        game_type = str(
            context.get("game_type", row.get("game_type", current_type) if isinstance(row, dict) else current_type)
        )
        task = normalized_identifier(
            context.get("task_id", row.get("task_id", "default") if isinstance(row, dict) else "default"), "default", 96
        )
        trained_task = normalized_identifier(context.get("trained_task_id", "default"), "default", 96)
        if game != current_game:
            return 3 if game_type and game_type == current_type else 4
        if task != trained_task and context.get("evaluation_partition") in {"test", "holdout"}:
            return 2
        return 1

    @staticmethod
    def _lineage(row):
        context = GeneralizationEvaluator._context(row)
        lineage = context.get("data_lineage", {}) if isinstance(context.get("data_lineage"), dict) else {}
        return str(lineage.get("lineage_id") or row.get("checksum") or context.get("dataset_sample_id") or "")

    @staticmethod
    def _wilson_lower(successes, total, z=1.959963984540054):
        count = max(0, int(total))
        if count <= 0:
            return 0.0
        p = max(0.0, min(1.0, float(successes) / count))
        denominator = 1.0 + z * z / count
        center = p + z * z / (2.0 * count)
        radius = z * math.sqrt((p * (1.0 - p) + z * z / (4.0 * count)) / count)
        return max(0.0, min(1.0, (center - radius) / denominator))

    @classmethod
    def _episode_rows(cls, rows):
        grouped = defaultdict(list)
        for index, row in enumerate(rows):
            if not isinstance(row, dict):
                continue
            context = cls._context(row)
            game = str(row.get("game_id") or context.get("game_id") or "unknown")
            task = normalized_identifier(row.get("task_id") or context.get("task_id"), "default", 96)
            episode = str(
                row.get("episode_id")
                or context.get("episode_id")
                or row.get("session")
                or context.get("session_id")
                or "row_" + str(index)
            )
            grouped[(game, task, episode)].append(row)
        episodes = []
        for (game, task, episode), values in grouped.items():
            ordered = sorted(
                values, key=lambda row: safe_int(row.get("step_id", cls._context(row).get("step_id", 0)), 0)
            )
            terminal = any(
                bool(
                    row.get("done")
                    or row.get("success")
                    or row.get("failure")
                    or cls._context(row).get("episode_complete")
                )
                or str(row.get("terminal_state") or cls._context(row).get("terminal", "neutral"))
                in {"success", "failure"}
                for row in ordered
            )
            if not terminal:
                continue
            success = any(
                bool(row.get("success") or cls._context(row).get("success"))
                or str(row.get("terminal_state") or cls._context(row).get("terminal", "")) == "success"
                for row in ordered
            )
            guidance = sum(
                int(
                    bool(
                        row.get("human_override")
                        or cls._context(row).get("human_override")
                        or cls._context(row).get("guidance_used")
                    )
                )
                for row in ordered
            )
            explicit_actions = [safe_int(row.get("actions"), 0, 0) for row in ordered if row.get("actions") is not None]
            actions = max(explicit_actions) if explicit_actions else len(ordered)
            contexts = [cls._context(row) for row in ordered]
            game_type = next(
                (str(context.get("game_type")) for context in contexts if context.get("game_type")), "unknown"
            )
            variants = {
                key: next(
                    (str(context.get(key)) for context in contexts if context.get(key) not in (None, "")), "unknown"
                )
                for key in GENERALIZATION_REQUIRED_VARIANTS
            }
            transfer = sum(
                int(
                    context.get("zero_shot_gain") is not None
                    or context.get("few_shot_gain") is not None
                    or context.get("transfer_mode") in {"zero_shot", "few_shot"}
                )
                for context in contexts
            )
            episodes.append(
                {
                    "game_id": game,
                    "task_id": task,
                    "episode_id": episode,
                    "game_type": game_type,
                    "success": success,
                    "actions": max(1, actions),
                    "guidance": guidance,
                    "transfer_evidence": transfer,
                    "variants": variants,
                }
            )
        return episodes

    @classmethod
    def _metrics(cls, rows):
        values = [row for row in rows if isinstance(row, dict)]
        episodes = cls._episode_rows(values)
        successes = sum(int(row["success"]) for row in episodes)
        successful_actions = sum(row["actions"] for row in episodes if row["success"])
        total_actions = sum(row["actions"] for row in episodes)
        guidance = sum(row["guidance"] for row in episodes)
        intervention_episodes = sum(int(row["guidance"] > 0) for row in episodes)
        ood = [row for row in values if cls._context(row).get("ood_expected") is not None]
        ood_correct = sum(
            int(bool(cls._context(row).get("ood_expected")) == bool(cls._context(row).get("ood_rejected")))
            for row in ood
        )
        dangerous = [
            row
            for row in values
            if str(row.get("risk_class", cls._context(row).get("risk_class", "safe"))) == "irreversible"
        ]
        false_release = sum(
            int(bool(row.get("action_released") or cls._context(row).get("action_released"))) for row in dangerous
        )
        resolutions = defaultdict(list)
        for episode in episodes:
            resolutions[episode["variants"].get("resolution_id", "unknown")].append(1.0 if episode["success"] else 0.0)
        rates = [statistics.fmean(group) for key, group in resolutions.items() if group and key != "unknown"]
        drop = max(rates) - min(rates) if len(rates) > 1 else 0.0
        zero = [
            safe_float(cls._context(row).get("zero_shot_gain"), 0.0)
            for row in values
            if cls._context(row).get("zero_shot_gain") is not None
        ]
        few = [
            safe_float(cls._context(row).get("few_shot_gain"), 0.0)
            for row in values
            if cls._context(row).get("few_shot_gain") is not None
        ]
        variant_coverage = {
            key: len(
                {episode["variants"].get(key) for episode in episodes if episode["variants"].get(key) != "unknown"}
            )
            for key in GENERALIZATION_REQUIRED_VARIANTS
        }
        real_capture = sum(
            int(
                str(cls._context(row).get("recording_source", "")) in GENERALIZATION_REAL_SOURCES
                and not bool(cls._context(row).get("synthetic"))
            )
            for row in values
        )
        metric_rows = []
        for row in values:
            context = cls._context(row)
            metric = (
                row.get("benchmark_metrics")
                if isinstance(row.get("benchmark_metrics"), dict)
                else context.get("benchmark_metrics")
            )
            if isinstance(metric, dict):
                metric_rows.append(metric)
        def metric_max(name):
            numbers = [safe_float(item.get(name), 0.0) for item in metric_rows if item.get(name) is not None]
            return max(numbers, default=0.0)
        def metric_mean(name):
            numbers = [safe_float(item.get(name), 0.0) for item in metric_rows if item.get(name) is not None]
            return statistics.fmean(numbers) if numbers else 0.0
        return {
            "task_success_rate": successes / max(1, len(episodes)),
            "success_rate_ci95_lower": cls._wilson_lower(successes, len(episodes)),
            "human_guidance_count": guidance,
            "human_guidance_rate": guidance / max(1, total_actions),
            "human_intervention_episode_rate": intervention_episodes / max(1, len(episodes)),
            "average_actions": total_actions / max(1, len(episodes)),
            "actions_per_success": successful_actions / max(1, successes),
            "ood_rejection_accuracy": ood_correct / max(1, len(ood)),
            "ood_rejection_ci95_lower": cls._wilson_lower(ood_correct, len(ood)),
            "dangerous_action_false_release_rate": false_release / max(1, len(dangerous)),
            "dangerous_action_false_release_count": false_release,
            "cross_resolution_performance_drop": drop,
            "zero_shot_gain": statistics.fmean(zero) if zero else 0.0,
            "few_shot_gain": statistics.fmean(few) if few else 0.0,
            "zero_shot_count": len(zero),
            "few_shot_count": len(few),
            "inference_latency_p50_ms": metric_mean("inference_latency_p50_ms"),
            "inference_latency_p95_ms": metric_mean("inference_latency_p95_ms"),
            "inference_latency_p99_ms": metric_mean("inference_latency_p99_ms"),
            "peak_cpu_percent": metric_max("peak_cpu_percent"),
            "peak_ram_bytes": metric_max("peak_ram_bytes"),
            "peak_vram_bytes": metric_max("peak_vram_bytes"),
            "raw_sample_count": len(values),
            "real_capture_record_count": real_capture,
            "complete_episode_count": len(episodes),
            "independent_game_count": len({row["game_id"] for row in episodes}),
            "independent_task_count": len({(row["game_id"], row["task_id"]) for row in episodes}),
            "independent_game_type_count": len({row["game_type"] for row in episodes if row["game_type"] != "unknown"}),
            "resolution_group_count": variant_coverage.get("resolution_id", 0),
            "variant_coverage": variant_coverage,
            "transfer_evidence_count": sum(row["transfer_evidence"] for row in episodes),
            "ood_count": len(ood),
            "irreversible_count": len(dangerous),
        }

    @classmethod
    def evaluate(
        cls,
        train_rows,
        test_rows,
        transfer_rows,
        current_game="",
        current_type="",
        benchmark_manifest=None,
        benchmark_validation=None,
    ):
        train = [row for row in train_rows if isinstance(row, dict)]
        candidates = [row for row in [*list(test_rows or []), *list(transfer_rows or [])] if isinstance(row, dict)]
        validation = benchmark_validation if isinstance(benchmark_validation, dict) else {}
        manifest = benchmark_manifest if isinstance(benchmark_manifest, dict) else {}
        benchmark_verified = bool(validation.get("verified") and manifest)
        train_ids = {cls._lineage(row) for row in train if cls._lineage(row)}
        manifest_errors = FixedGeneralizationBenchmark.validate_manifest(manifest) if manifest else ["manifest_missing"]
        result = {
            "schema_version": GENERALIZATION_SCHEMA_VERSION,
            "benchmark_schema_version": GENERALIZATION_BENCHMARK_SCHEMA_VERSION,
            "claim_policy": (
                "only a frozen real-capture benchmark may authorize a level; "
                "Level 3 and Level 4 are both required for a general-model label"
            ),
            "benchmark_verified": benchmark_verified,
            "benchmark_id": str(manifest.get("benchmark_id", "")),
            "benchmark_path": str(validation.get("path", "")),
            "benchmark_errors": sorted(set([*manifest_errors, *list(validation.get("errors", []))])),
            "levels": {},
            "required_metrics": list(cls.required_metrics),
            "thresholds": cls.thresholds,
            "benchmark_dimensions": list(GENERALIZATION_BENCHMARK_DIMENSIONS),
            "required_genres": list(GENERALIZATION_REQUIRED_GENRES),
        }
        manifest_genres = {str(value) for value in manifest.get("required_genres", []) if str(value)}
        genre_contract_ok = set(GENERALIZATION_REQUIRED_GENRES).issubset(manifest_genres)
        for level, name in GENERALIZATION_LEVELS.items():
            rows = []
            for row in candidates:
                context = cls._context(row)
                partition = str(context.get("evaluation_partition", row.get("evaluation_partition", "")))
                if partition not in {"test", "holdout"}:
                    continue
                if cls._level(row, current_game, current_type) == level:
                    rows.append(row)
            test_ids = {cls._lineage(row) for row in rows if cls._lineage(row)}
            missing_lineage = sum(1 for row in rows if not cls._lineage(row))
            overlap = sorted(train_ids.intersection(test_ids))
            metrics = cls._metrics(rows)
            threshold = cls.thresholds[level]
            sample_reasons = []
            if metrics["independent_game_count"] < threshold["games"]:
                sample_reasons.append("independent_games")
            if metrics["independent_task_count"] < threshold["tasks"]:
                sample_reasons.append("independent_tasks")
            if metrics["complete_episode_count"] < threshold["episodes"]:
                sample_reasons.append("complete_episodes")
            if metrics["ood_count"] < threshold["ood_trials"]:
                sample_reasons.append("ood_trials")
            if metrics["resolution_group_count"] < threshold["resolution_groups"]:
                sample_reasons.append("resolution_groups")
            if metrics["independent_game_type_count"] < threshold.get("game_types", 0):
                sample_reasons.append("independent_game_types")
            if metrics["transfer_evidence_count"] < threshold.get("transfer_evidence", 0):
                sample_reasons.append("zero_or_few_shot_transfer_evidence")
            for key, count in metrics.get("variant_coverage", {}).items():
                if count < threshold.get("variant_groups", 2):
                    sample_reasons.append("variant_coverage_" + key)
            if level == 4 and not genre_contract_ok:
                sample_reasons.append("five_genre_contract")
            isolation_reasons = []
            if missing_lineage:
                isolation_reasons.append("missing_lineage_identifiers")
            if overlap:
                isolation_reasons.append("train_test_lineage_overlap")
            if metrics["real_capture_record_count"] != metrics["raw_sample_count"]:
                isolation_reasons.append("non_real_or_unverified_records")
            if not benchmark_verified:
                isolation_reasons.append("real_benchmark_not_verified")
            isolated = bool(rows and test_ids and not isolation_reasons)
            if not rows or sample_reasons or isolation_reasons:
                status = "not_evaluated"
                failures = []
            else:
                checks = (
                    (metrics["success_rate_ci95_lower"] >= threshold["success_lcb"], "success_confidence_lower_bound"),
                    (metrics["average_actions"] <= threshold["average_actions"], "average_actions"),
                    (metrics["actions_per_success"] <= threshold["actions_per_success"], "actions_per_success"),
                    (metrics["human_guidance_rate"] <= threshold["guidance_rate"], "human_guidance_rate"),
                    (
                        metrics["human_intervention_episode_rate"] <= threshold["intervention_episode_rate"],
                        "human_intervention_episode_rate",
                    ),
                    (
                        metrics["ood_rejection_ci95_lower"] >= threshold["ood_lcb"],
                        "ood_rejection_confidence_lower_bound",
                    ),
                    (
                        metrics["cross_resolution_performance_drop"] <= threshold["resolution_drop"],
                        "cross_resolution_drop",
                    ),
                    (metrics["dangerous_action_false_release_count"] == 0, "dangerous_action_false_release"),
                )
                failures = [check_name for passed, check_name in checks if not passed]
                status = "passed" if not failures else "failed"
            result["levels"][str(level)] = {
                "name": name,
                "status": status,
                "evaluated": status in {"passed", "failed"},
                "claim_allowed": status == "passed" and benchmark_verified,
                "isolated": isolated,
                "passed": status == "passed",
                "train_test_lineage_overlap": overlap[:32],
                "missing_lineage_count": missing_lineage,
                "sample_sufficiency_failures": sorted(set(sample_reasons)),
                "metric_failures": failures,
                "metrics": metrics,
                "thresholds": threshold,
                "reason": (
                    ""
                    if status == "passed"
                    else ",".join(sorted(set([*sample_reasons, *isolation_reasons, *failures])))
                ),
            }
        result["claimed_levels"] = [int(level) for level, row in result["levels"].items() if row["claim_allowed"]]
        result["all_claimed_levels_safe"] = all(
            row["metrics"]["dangerous_action_false_release_count"] == 0
            for row in result["levels"].values()
            if row["claim_allowed"]
        )
        result["model_scope"] = generalization_model_scope(result)
        result["display_label"] = "通用模型" if result["model_scope"] == "general_model" else "单游戏模型"
        return result


class TerminalEvidenceFusion:
    success_tokens = ("victory", "win", "success", "completed", "clear", "胜利", "成功", "完成", "通关")
    failure_tokens = ("defeat", "failure", "failed", "game over", "lose", "失败", "战败", "重试", "重新开始")

    @classmethod
    def classify(cls, policy, feature):
        value = policy.state_hash(feature)
        success_hash, success_distance = policy._hash_probability(
            value, policy.success_states, policy.success_hash_distance
        )
        failure_hash, failure_distance = policy._hash_probability(
            value, policy.failure_states, policy.failure_hash_distance
        )
        success_score = 0.28 * success_hash if success_distance <= policy.success_hash_distance + 2 else 0.0
        failure_score = 0.28 * failure_hash if failure_distance <= policy.failure_hash_distance + 2 else 0.0
        success_sources = set(["visual_structure"] if success_score > 0 else [])
        failure_sources = set(["visual_structure"] if failure_score > 0 else [])
        evidence = []
        progress = 0.0
        semantic = SEMANTIC_EVENT_HUB.latest(policy.game_id or None, 1.8)
        if semantic:
            progress = max(-1.0, min(1.0, safe_float(semantic.get("progress"), 0.0)))
            if semantic.get("terminal") == "success":
                success_score += 0.58
                success_sources.add("round_state_transition")
                evidence.append("semantic_event:success")
            if semantic.get("terminal") == "failure":
                failure_score += 0.58
                failure_sources.add("round_state_transition")
                evidence.append("semantic_event:failure")
        perception = PERCEPTION_EVIDENCE_HUB.latest(policy.perception_key, 2.0) if policy.perception_key else None
        if perception:
            texts = [str(item).strip().casefold() for item in perception.get("texts", []) if str(item).strip()]
            for obj in perception.get("objects", []):
                if not isinstance(obj, dict):
                    continue
                combined = " ".join(
                    (str(obj.get("role", "")), str(obj.get("class", "")), str(obj.get("text", "")))
                ).casefold()
                if any(token in combined for token in cls.success_tokens):
                    success_score += 0.22
                    success_sources.add("object_semantics")
                    evidence.append("object:success")
                if any(token in combined for token in cls.failure_tokens):
                    failure_score += 0.22
                    failure_sources.add("object_semantics")
                    evidence.append("object:failure")
            joined = " ".join(texts)
            if any(token in joined for token in cls.success_tokens):
                success_score += 0.25
                success_sources.add("ocr_semantics")
                evidence.append("ocr:success")
            if any(token in joined for token in cls.failure_tokens):
                failure_score += 0.25
                failure_sources.add("ocr_semantics")
                evidence.append("ocr:failure")
            motion = [safe_float(item, 0.0) for item in perception.get("motion", [])]
            if len(motion) >= 3 and statistics.fmean(motion[-3:]) < 1.5:
                if success_score > 0.20:
                    success_score += 0.10
                    success_sources.add("stable_frames")
                if failure_score > 0.20:
                    failure_score += 0.10
                    failure_sources.add("stable_frames")
                evidence.append("frames:stable")
        learned = temporal_termination_prediction(policy.profile.get("temporal_termination_model"), policy, perception)
        learned_success = safe_float(learned.get("success"), 0.0, 0.0, 1.0)
        learned_failure = safe_float(learned.get("failure"), 0.0, 0.0, 1.0)
        learned_reset = safe_float(learned.get("reset"), 0.0, 0.0, 1.0)
        learned_progress = safe_float(learned.get("progress"), 0.0, 0.0, 1.0)
        learned_stalled = safe_float(learned.get("stalled"), 0.0, 0.0, 1.0)
        if learned and learned.get("exact") and safe_int(learned.get("support"), 0) >= 3:
            if learned_success >= 0.70:
                success_sources.add("temporal_transition_model")
            if learned_failure >= 0.70:
                failure_sources.add("temporal_transition_model")
            weight = min(0.42, 0.12 + 0.06 * math.log1p(safe_int(learned.get("support"), 0)))
            success_score = (1.0 - weight) * success_score + weight * learned_success
            failure_score = (1.0 - weight) * failure_score + weight * learned_failure
            evidence.append("temporal_model:exact")
        progress = max(progress, learned_progress - learned_stalled)
        semantic_success = bool(
            success_sources.intersection({"object_semantics", "ocr_semantics", "round_state_transition"})
        )
        semantic_failure = bool(
            failure_sources.intersection({"object_semantics", "ocr_semantics", "round_state_transition"})
        )
        corroborated_success = semantic_success and len(success_sources) >= 2
        corroborated_failure = semantic_failure and len(failure_sources) >= 2
        success_probability = max(0.0, min(1.0, success_score))
        failure_probability = max(0.0, min(1.0, failure_score))
        conflict = bool(
            corroborated_success
            and corroborated_failure
            or success_probability >= 0.65
            and learned_failure >= 0.70
            or failure_probability >= 0.65
            and learned_success >= 0.70
        )
        candidate = ""
        if (
            not conflict
            and corroborated_success
            and success_probability >= 0.72
            and success_probability >= failure_probability + 0.10
        ):
            candidate = "success"
        elif (
            not conflict
            and corroborated_failure
            and failure_probability >= 0.72
            and failure_probability > success_probability + 0.10
        ):
            candidate = "failure"
        insufficient = bool(not candidate and max(success_probability, failure_probability) >= 0.60)
        confidence = max(success_probability, failure_probability, 0.55 if abs(progress) > 0 else 0.0)
        if conflict or insufficient:
            confidence = min(confidence, 0.49)
            evidence.append("terminal_requires_semantic_guidance")
        return {
            "candidate": candidate,
            "success_probability": success_probability,
            "failure_probability": failure_probability,
            "reset_probability": learned_reset,
            "progress_probability": learned_progress,
            "stalled_probability": learned_stalled,
            "progress_score": progress,
            "evidence": evidence[:16],
            "reward_confidence": confidence,
            "conflict": conflict,
            "requires_guidance": bool(conflict or insufficient),
            "independent_success_sources": sorted(success_sources),
            "independent_failure_sources": sorted(failure_sources),
            "minimum_independent_sources": 2,
            "learned_evidence": learned,
            "hash_evidence": {"success_distance": success_distance, "failure_distance": failure_distance},
        }


class CapabilityProfile:
    minimum_levels = {"mouse": 0, "ocr": 1, "keyboard": 2, "sound": 3, "gamepad": 4, "continuous_control": 4}
    supported_scope = (
        "click_puzzle",
        "hidden_object",
        "casual_puzzle",
        "match3",
        "card",
        "board",
        "turn_strategy",
        "simulation",
        "menu_driven",
    )
    unsupported_scope = ("fps", "platformer", "racing", "rhythm", "high_frequency_combo", "continuous_joystick")

    def __init__(self, profile=None):
        source = dict(profile) if isinstance(profile, dict) else {}
        permissions = (
            source.get("modality_permissions", {}) if isinstance(source.get("modality_permissions"), dict) else {}
        )
        requested = safe_int(source.get("capability_level", 0), 0, 0, 4)
        mouse = bool(source.get("mouse_enabled", True))
        keyboard = bool(source.get("keyboard_enabled", False))
        sound = bool(source.get("sound_enabled", False))
        gamepad = bool(source.get("gamepad_enabled", False))
        self.level = max(requested, 2 if keyboard else 0, 3 if sound else 0, 4 if gamepad else 0)
        self.mouse_enabled = mouse
        self.keyboard_enabled = bool(keyboard and self.level >= 2)
        self.sound_enabled = bool(sound and self.level >= 3)
        self.gamepad_enabled = bool(gamepad and self.level >= 4)
        required = source.get("required_input_modalities", source.get("input_modalities", ["mouse", "vision"]))
        self.required_input_modalities = (
            tuple(dict.fromkeys(str(value).strip().casefold() for value in required if str(value).strip()))
            if isinstance(required, (list, tuple, set))
            else ("mouse", "vision")
        )
        self.minimum_frame_rate = safe_float(
            source.get("minimum_frame_rate", source.get("minimum_fps", 8.0)), 8.0, 1.0, 240.0
        )
        self.maximum_action_frequency = safe_float(
            source.get("maximum_action_frequency", source.get("maximum_action_hz", 4.0)), 4.0, 0.1, 120.0
        )
        self.required_action_frequency = safe_float(
            source.get("required_action_frequency", source.get("required_action_hz", 1.0)), 1.0, 0.0, 120.0
        )
        self.continuous_control_required = bool(source.get("continuous_control_required", False))
        self.minimum_semantic_width = safe_int(source.get("minimum_semantic_width", 224), 224, 64, 1024)
        self.minimum_semantic_height = safe_int(source.get("minimum_semantic_height", 126), 126, 36, 1024)
        self.game_type = str(source.get("game_type", "ui_game")).strip().casefold()
        self.permissions = {
            "keyboard": {
                **(permissions.get("keyboard", {}) if isinstance(permissions.get("keyboard"), dict) else {}),
                "enabled": self.keyboard_enabled,
                "data_mask": "semantic_only",
                "model_version": "semantic_keyboard_v1",
                "safety_permission": self.keyboard_enabled,
            },
            "sound": {
                **(permissions.get("sound", {}) if isinstance(permissions.get("sound"), dict) else {}),
                "enabled": self.sound_enabled,
                "data_mask": "event_only_no_raw_audio",
                "model_version": "audio_event_v1",
                "safety_permission": self.sound_enabled,
            },
            "gamepad": {
                **(permissions.get("gamepad", {}) if isinstance(permissions.get("gamepad"), dict) else {}),
                "enabled": self.gamepad_enabled,
                "data_mask": "semantic_only",
                "model_version": "gamepad_semantic_v1",
                "safety_permission": self.gamepad_enabled,
            },
        }
        self.semantic_keymap = {
            str(key): str(value)
            for key, value in (
                source.get("semantic_keymap", {}) if isinstance(source.get("semantic_keymap"), dict) else {}
            ).items()
            if str(key) in SEMANTIC_KEY_ACTIONS and str(value)
        }

    def authorize(self, capability):
        name = str(capability)
        minimum = self.minimum_levels.get(name, 99)
        if self.level < minimum:
            return False
        if name == "mouse":
            return bool(self.mouse_enabled)
        if name in {"vision", "ocr"}:
            return True
        if name == "continuous_control":
            return bool(self.gamepad_enabled)
        value = self.permissions.get(name, {})
        return bool(value.get("enabled") and value.get("safety_permission"))

    def evaluate(self, runtime=None):
        state = dict(runtime) if isinstance(runtime, dict) else {}
        keyboard_execution = bool(state.get("keyboard_execution", False))
        gamepad_execution = bool(state.get("gamepad_execution", False))
        continuous_execution = bool(state.get("continuous_control", False) and gamepad_execution)
        available = {"vision", "ocr"}
        if self.mouse_enabled and bool(state.get("mouse_execution", True)):
            available.add("mouse")
        if self.authorize("keyboard") and keyboard_execution:
            available.add("keyboard")
        if self.authorize("sound"):
            available.add("sound")
        if self.authorize("gamepad") and gamepad_execution:
            available.add("gamepad")
        if self.authorize("continuous_control") and continuous_execution:
            available.add("continuous_control")
        reasons = []
        missing = [name for name in self.required_input_modalities if name not in available]
        if missing:
            reasons.append("missing_modalities:" + ",".join(sorted(missing)))
        if self.keyboard_enabled and "keyboard" in self.required_input_modalities and not keyboard_execution:
            reasons.append("keyboard_execution_unavailable")
        if self.gamepad_enabled and "gamepad" in self.required_input_modalities and not gamepad_execution:
            reasons.append("xinput_virtual_gamepad_unavailable")
        if self.continuous_control_required and not continuous_execution:
            reasons.append("continuous_control_unavailable")
        fps = safe_float(state.get("capture_fps", state.get("fps", 0.0)), 0.0, 0.0, 1000.0)
        if fps > 0 and fps + 1e-6 < self.minimum_frame_rate:
            reasons.append("capture_fps_below_minimum")
        action_hz = safe_float(
            state.get(
                "available_action_frequency",
                state.get("action_hz", state.get("maximum_action_frequency", self.maximum_action_frequency)),
            ),
            self.maximum_action_frequency,
            0.0,
            1000.0,
        )
        if self.required_action_frequency > min(self.maximum_action_frequency, action_hz) + 1e-6:
            reasons.append("action_frequency_below_requirement")
        semantic_size = state.get("semantic_size", HYBRID_GLOBAL_SIZE)
        if isinstance(semantic_size, (list, tuple)) and len(semantic_size) >= 2:
            if (
                safe_int(semantic_size[0], 0) < self.minimum_semantic_width
                or safe_int(semantic_size[1], 0) < self.minimum_semantic_height
            ):
                reasons.append("semantic_resolution_below_requirement")
        demanding = self.game_type in self.unsupported_scope
        if demanding:
            if self.game_type in {"fps", "platformer", "high_frequency_combo", "rhythm"} and not keyboard_execution:
                reasons.append("game_type_requires_keyboard_execution")
            if self.game_type in {"racing", "continuous_joystick"} and not continuous_execution:
                reasons.append("game_type_requires_xinput_continuous_control")
            if (
                self.game_type
                in {"fps", "platformer", "racing", "rhythm", "high_frequency_combo", "continuous_joystick"}
                and self.required_action_frequency < 10.0
            ):
                reasons.append("high_frequency_game_requires_explicit_action_rate")
        scope = "multi_modal_game_ai" if not reasons and demanding else "general_mouse_interactive_visual_game_ai"
        return {
            "allowed": not reasons,
            "reasons": reasons,
            "required_modalities": list(self.required_input_modalities),
            "available_modalities": sorted(available),
            "minimum_frame_rate": self.minimum_frame_rate,
            "capture_fps": fps,
            "required_action_frequency": self.required_action_frequency,
            "available_action_frequency": action_hz,
            "continuous_control_required": self.continuous_control_required,
            "game_type": self.game_type,
            "runtime_execution": {
                "keyboard": keyboard_execution,
                "gamepad": gamepad_execution,
                "continuous_control": continuous_execution,
            },
            "scope": scope,
        }

    def require_training_support(self, runtime=None):
        result = self.evaluate(runtime)
        if not result["allowed"]:
            raise RuntimeError("能力配置不满足训练要求：" + "；".join(result["reasons"]))
        return result

    def to_dict(self):
        return {
            "capability_level": self.level,
            "capability_name": CAPABILITY_LEVEL_NAMES[self.level],
            "mouse_enabled": self.mouse_enabled,
            "keyboard_enabled": self.keyboard_enabled,
            "sound_enabled": self.sound_enabled,
            "gamepad_enabled": self.gamepad_enabled,
            "semantic_keymap": dict(self.semantic_keymap),
            "semantic_key_actions": sorted(SEMANTIC_KEY_ACTIONS),
            "modality_permissions": self.permissions,
            "minimum_levels": dict(self.minimum_levels),
            "required_input_modalities": list(self.required_input_modalities),
            "minimum_frame_rate": self.minimum_frame_rate,
            "maximum_action_frequency": self.maximum_action_frequency,
            "required_action_frequency": self.required_action_frequency,
            "continuous_control_required": self.continuous_control_required,
            "minimum_semantic_width": self.minimum_semantic_width,
            "minimum_semantic_height": self.minimum_semantic_height,
            "game_type": self.game_type,
            "supported_scope": list(self.supported_scope),
            "unsupported_scope": list(self.unsupported_scope),
            "audio_representation": "event_only_no_raw_audio",
            "keyboard_representation": "semantic_action_to_user_keymap_no_free_keycodes",
            "gamepad_representation": "semantic_action_with_xinput_axis",
            "execution_support": {
                "mouse": "execute",
                "keyboard": "SendInput_scancode_with_leases",
                "sound": "perception_only",
                "gamepad": "ViGEm_XInput_when_available",
            },
            "default_capability": "mouse_only",
            "scope": "runtime_gated_multi_modal_game_ai",
        }


class AdapterHierarchyManager:
    def __init__(self, base):
        self.base = Path(base) / "models" / "vision" / "adapters"
        self.type_dir = self.base / "types"
        self.game_dir = self.base / "games"
        self.type_dir.mkdir(parents=True, exist_ok=True)
        self.game_dir.mkdir(parents=True, exist_ok=True)

    @staticmethod
    def _safe(value):
        return hashlib.sha256(str(value).encode("utf-8", "replace")).hexdigest()

    def _path(self, kind, value):
        return (self.type_dir if kind == "type" else self.game_dir) / (self._safe(value) + ".json")

    @staticmethod
    def _default(kind, value):
        down = [
            [1.0 if column == row else -0.25 / (FEATURE_CHANNELS - 1) for column in range(FEATURE_CHANNELS)]
            for row in range(ADAPTER_RANK)
        ]
        up = [[0.0 for _ in range(ADAPTER_RANK)] for _ in range(FEATURE_CHANNELS)]
        return {
            "schema_version": 2,
            "algorithm": "low_rank_residual_film",
            "kind": kind,
            "identity": str(value),
            "rank": ADAPTER_RANK,
            "down": down,
            "up": up,
            "film_scale": [1.0] * FEATURE_CHANNELS,
            "film_bias": [0.0] * FEATURE_CHANNELS,
            "trained": False,
            "samples": 0,
        }

    def load(self, kind, value):
        path = self._path(kind, value)
        if not path.exists():
            return self._default(kind, value)
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
            checksum = str(payload.pop("checksum", ""))
            valid = (
                hashlib.sha256(canonical_bytes(payload)).hexdigest() == checksum
                and safe_int(payload.get("schema_version"), 0) == 2
                and safe_int(payload.get("rank"), 0) == ADAPTER_RANK
            )
            if not valid:
                raise ValueError("adapter checksum or schema")
            return payload
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            return self._default(kind, value)

    def save(self, kind, value, payload):
        path = self._path(kind, value)
        data = dict(payload)
        data["checksum"] = hashlib.sha256(canonical_bytes(data)).hexdigest()
        _atomic_write(path, json.dumps(data, ensure_ascii=False, sort_keys=True, separators=(",", ":")))
        return path

    @staticmethod
    def _statistics(samples):
        sums = [0.0] * FEATURE_CHANNELS
        squares = [0.0] * FEATURE_CHANNELS
        count = 0
        motion = []
        for item in list(samples or [])[:MAX_TRAINING_SAMPLES]:
            feature = item.get("neural_f") or item.get("f") if isinstance(item, dict) else None
            if not feature_valid(feature):
                continue
            raw = feature_bytes(feature)
            count += PIXELS
            for channel in range(FEATURE_CHANNELS):
                plane = raw[channel * PIXELS : (channel + 1) * PIXELS]
                sums[channel] += sum(plane) / 255.0
                squares[channel] += sum((value / 255.0) ** 2 for value in plane)
            context = (
                item.get("context", {}) if isinstance(item, dict) and isinstance(item.get("context"), dict) else {}
            )
            deltas = temporal_from_context(context).get("recent_frame_deltas", [])
            if deltas:
                motion.append(statistics.fmean(deltas))
        means = [sums[index] / max(1, count) for index in range(FEATURE_CHANNELS)]
        variances = [
            max(1e-6, squares[index] / max(1, count) - means[index] * means[index]) for index in range(FEATURE_CHANNELS)
        ]
        return (
            means,
            variances,
            count // max(1, PIXELS),
            min(1.0, (statistics.fmean(motion) / 600.0) if motion else 0.0),
        )

    @staticmethod
    def _task_objectives(samples):
        object_changes = []
        action_effects = []
        terminal_confidences = []
        for item in list(samples or [])[:MAX_TRAINING_SAMPLES]:
            if not isinstance(item, dict):
                continue
            context = item.get("context", {}) if isinstance(item.get("context"), dict) else {}
            before = context.get("objects_before", []) if isinstance(context.get("objects_before"), list) else []
            after = context.get("objects_after", []) if isinstance(context.get("objects_after"), list) else []
            if before or after:
                first = Counter(str(value.get("class", "unknown")) for value in before if isinstance(value, dict))
                second = Counter(str(value.get("class", "unknown")) for value in after if isinstance(value, dict))
                difference = sum((first - second).values()) + sum((second - first).values())
                object_changes.append(min(1.0, difference / max(1, sum(first.values()) + sum(second.values()))))
            action_effects.append(float(bool(context.get("environment_changed", item.get("changed", False)))))
            if context.get("terminal") in {"success", "failure"} or item.get("success") or item.get("failure"):
                terminal_confidences.append(
                    safe_float(context.get("reward_confidence", item.get("reward_confidence", 0.0)), 0.0, 0.0, 1.0)
                )
        return {
            "object_transition_loss": round(1.0 - (statistics.fmean(object_changes) if object_changes else 0.0), 6),
            "action_effect_loss": round(1.0 - (statistics.fmean(action_effects) if action_effects else 0.0), 6),
            "termination_loss": round(
                1.0 - (statistics.fmean(terminal_confidences) if terminal_confidences else 0.0), 6
            ),
        }

    def fit(self, game_id, game_type, samples):
        means, variances, count, mean_motion = self._statistics(samples)
        objectives = self._task_objectives(samples)
        global_mean = statistics.fmean(means) if means else 0.5
        global_std = math.sqrt(statistics.fmean(variances)) if variances else 0.2
        down = []
        up = []
        for rank in range(ADAPTER_RANK):
            down.append([round(math.cos((rank + 1) * (channel + 1)) * 0.55, 7) for channel in range(FEATURE_CHANNELS)])
        task_signal = max(
            -0.12,
            min(
                0.12,
                (1.0 - objectives["object_transition_loss"]) * 0.06
                + (1.0 - objectives["action_effect_loss"]) * 0.04
                + (1.0 - objectives["termination_loss"]) * 0.02,
            ),
        )
        for channel in range(FEATURE_CHANNELS):
            up.append(
                [
                    round(
                        (means[channel] - global_mean) * (0.18 + 0.05 * rank)
                        + (math.sqrt(variances[channel]) - global_std) * 0.12
                        + task_signal * math.sin((channel + 1) * (rank + 1)),
                        7,
                    )
                    for rank in range(ADAPTER_RANK)
                ]
            )
        film_scale = [
            round(max(0.78, min(1.22, global_std / max(0.05, math.sqrt(variances[channel])))), 7)
            for channel in range(FEATURE_CHANNELS)
        ]
        film_scale[-1] = round(max(0.82, min(1.25, 0.92 + 0.18 * mean_motion)), 7)
        film_bias = [
            round(max(-0.12, min(0.12, (global_mean - means[channel]) * 0.18)), 7)
            for channel in range(FEATURE_CHANNELS)
        ]
        type_payload = {
            "schema_version": 2,
            "algorithm": "low_rank_residual_film",
            "kind": "game_type_adapter",
            "identity": str(game_type),
            "game_type": str(game_type),
            "rank": ADAPTER_RANK,
            "down": down,
            "up": [[round(value * 0.55, 7) for value in row] for row in up],
            "film_scale": [round(1.0 + (value - 1.0) * 0.55, 7) for value in film_scale],
            "film_bias": [round(value * 0.55, 7) for value in film_bias],
            "samples": count,
            "trained": bool(count),
            "training_objective": "object_recognition+action_effect_prediction+termination",
            "training_losses": objectives,
            "updated": time.time(),
        }
        game_payload = {
            "schema_version": 2,
            "algorithm": "low_rank_residual_film",
            "kind": "game_specific_adapter",
            "identity": str(game_id),
            "game_id": str(game_id),
            "game_type": str(game_type),
            "rank": ADAPTER_RANK,
            "down": down,
            "up": up,
            "film_scale": film_scale,
            "film_bias": film_bias,
            "samples": count,
            "trained": bool(count),
            "training_objective": "object_recognition+action_effect_prediction+termination",
            "training_losses": objectives,
            "updated": time.time(),
        }
        self.save("type", game_type, type_payload)
        self.save("game", game_id, game_payload)
        return {"type": type_payload, "game": game_payload}

    @staticmethod
    def _apply_one(feature, adapter):
        if not adapter.get("trained"):
            return feature
        raw = feature_bytes(feature)
        output = bytearray(len(raw))
        down = adapter.get("down", [])
        up = adapter.get("up", [])
        scale = adapter.get("film_scale", [1.0] * FEATURE_CHANNELS)
        bias = adapter.get("film_bias", [0.0] * FEATURE_CHANNELS)
        for pixel in range(PIXELS):
            vector = [raw[channel * PIXELS + pixel] / 255.0 for channel in range(FEATURE_CHANNELS)]
            latent = [
                math.tanh(sum(vector[channel] * safe_float(row[channel], 0.0) for channel in range(FEATURE_CHANNELS)))
                for row in down[:ADAPTER_RANK]
            ]
            for channel in range(FEATURE_CHANNELS):
                residual = (
                    sum(
                        latent[rank] * safe_float(up[channel][rank], 0.0)
                        for rank in range(min(ADAPTER_RANK, len(latent)))
                    )
                    if channel < len(up)
                    else 0.0
                )
                transformed = (
                    vector[channel] * safe_float(scale[channel], 1.0, 0.5, 1.5)
                    + safe_float(bias[channel], 0.0, -0.5, 0.5)
                    + residual
                )
                output[channel * PIXELS + pixel] = max(0, min(255, round(transformed * 255.0)))
        return bytes(output)

    def apply(self, game_id, game_type, feature):
        if not feature_valid(feature):
            return feature
        value = self._apply_one(feature, self.load("type", game_type))
        return self._apply_one(value, self.load("game", game_id))

    def manifest_entry(self, game_id, game_type):
        return {
            "game_type_adapter": {
                "game_type": str(game_type),
                "relative_path": str(self._path("type", game_type).relative_to(self.base.parent.parent.parent)),
                "algorithm": "low_rank_residual_film",
                "rank": ADAPTER_RANK,
            },
            "game_specific_adapter": {
                "relative_path": str(self._path("game", game_id).relative_to(self.base.parent.parent.parent)),
                "algorithm": "low_rank_residual_film",
                "rank": ADAPTER_RANK,
            },
        }


class SafetyLeaseBroker:
    def __init__(self):
        self.parent = None
        self.process = None
        self.secret = os.urandom(32)
        self.request_id = 0

    @staticmethod
    def _worker(connection, secret):
        try:
            connection.send({"command": "ready", "protocol": 1})
        except (BrokenPipeError, EOFError, OSError):
            return
        while True:
            try:
                message = connection.recv()
            except (EOFError, OSError):
                break
            if not isinstance(message, dict):
                continue
            if message.get("command") == "stop":
                break
            if message.get("command") != "authorize":
                continue
            request_id = message.get("request_id")
            evidence = message.get("evidence", {})
            now = time.monotonic()
            duration = max(
                ACTION_LEASE_MIN_SECONDS, min(ACTION_LEASE_MAX_SECONDS, safe_float(message.get("duration"), 0.22))
            )
            checks = {
                name: bool(evidence.get(name, False))
                for name in (
                    "window_identity",
                    "same_frame",
                    "target_unique",
                    "client_bounds",
                    "control_capability",
                    "input_clear",
                    "authorization_current",
                )
            }
            risk = str(evidence.get("risk_class", "safe"))
            checks["independent_evidence"] = risk == "safe" or bool(evidence.get("independent_evidence", False))
            checks["irreversible_zero_release"] = risk != "irreversible" and bool(
                evidence.get("irreversible_release_forbidden", True)
            )
            allowed = all(checks.values())
            expires = now + duration if allowed else now
            payload = {
                "request_id": request_id,
                "allowed": allowed,
                "checks": checks,
                "expires": expires,
                "frame_token": str(evidence.get("frame_token", "")),
                "reason": (
                    "authorized" if allowed else next((name for name, value in checks.items() if not value), "rejected")
                ),
            }
            payload["token"] = hashlib.sha256(secret + canonical_bytes(payload)).hexdigest() if allowed else ""
            try:
                connection.send(payload)
            except (BrokenPipeError, EOFError, OSError):
                break
        try:
            connection.close()
        except (OSError, ValueError):
            return

    def start(self):
        if self.process is not None and self.process.is_alive():
            return self
        parent, child = multiprocessing.Pipe(True)
        context = multiprocessing.get_context("spawn")
        self.parent = parent
        self.process = context.Process(
            target=SafetyLeaseBroker._worker,
            args=(child, self.secret),
            name="UniversalGameAI-SafetyLease",
            daemon=True,
        )
        self.process.start()
        child.close()
        if not self.parent.poll(8.0):
            self.process.terminate()
            self.process.join(0.5)
            raise InputStopped("独立安全授权进程启动超时")
        ready = self.parent.recv()
        if not isinstance(ready, dict) or ready.get("command") != "ready":
            self.process.terminate()
            self.process.join(0.5)
            raise InputStopped("独立安全授权进程握手失败")
        return self

    def authorize(self, evidence, duration=0.22, timeout=0.8):
        if self.process is None or not self.process.is_alive():
            raise InputStopped("独立安全授权进程不可用")
        self.request_id += 1
        request_id = self.request_id
        self.parent.send(
            {"command": "authorize", "request_id": request_id, "evidence": dict(evidence), "duration": duration}
        )
        if not self.parent.poll(max(0.05, float(timeout))):
            raise InputStopped("独立安全授权进程超时")
        result = self.parent.recv()
        if not isinstance(result, dict) or result.get("request_id") != request_id:
            raise InputStopped("独立安全授权协议不一致")
        return result

    def stop(self, timeout=1.0):
        if self.parent is not None:
            try:
                self.parent.send({"command": "stop"})
            except (BrokenPipeError, EOFError, OSError):
                self.parent = None
        if self.process is not None and self.process.is_alive():
            self.process.join(max(0.0, float(timeout)))
        if self.process is not None and self.process.is_alive():
            self.process.terminate()
            self.process.join(0.5)
        try:
            if self.parent is not None:
                self.parent.close()
        except (OSError, ValueError):
            self.parent = None
        return not bool(self.process is not None and self.process.is_alive())

    def alive(self):
        return bool(self.process is not None and self.process.is_alive())


def active_learning_alternatives(frame, ranked, existing):
    values = list(existing)
    signatures = {semantic_action_signature(value.get("a")) for value in values if isinstance(value, dict)}
    targets = (
        [
            value
            for value in frame.get("semantic_targets", [])
            if isinstance(value, dict) and str(value.get("source")) != "compatibility_alias"
        ]
        if isinstance(frame, dict)
        else []
    )
    additions = []
    wait_action = normalize_semantic_action({"action_type": "no_op", "parameters": {"duration": 0.6}})
    additions.append(
        {
            "a": wait_action,
            "coordinate_action": {"kind": "no_op", "duration": 0.6},
            "repeat_policy": "hold_until_change",
            "cluster_id": "active|wait",
            "risk_class": "safe",
            "guidance_label": "等待动画或回合变化",
            "active_learning_label": "wait",
        }
    )
    scroll_target = next((value for value in targets if value.get("class") == "scroll_area"), None)
    if scroll_target is not None or not targets:
        target_descriptor = (
            _target_descriptor_for_action(scroll_target)
            if scroll_target is not None
            else {"class": "coordinate_fallback", "instance": "scroll_area"}
        )
        scroll = normalize_semantic_action(
            {
                "action_type": "scroll_v",
                "target": target_descriptor,
                "parameters": {"delta": -240, "duration": 0.10},
                "coordinate_fallback": {"kind": "scroll_v", "delta": -240, "path": [[0.5, 0.72]], "duration": 0.10},
            }
        )
        additions.append(
            {
                "a": scroll,
                "coordinate_action": {"kind": "scroll_v", "delta": -240, "path": [[0.5, 0.72]], "duration": 0.10},
                "repeat_policy": "repeatable",
                "cluster_id": "active|scroll",
                "risk_class": "safe",
                "guidance_label": "向下滚动寻找目标",
                "active_learning_label": "scroll",
            }
        )
    complete = normalize_semantic_action({"action_type": "no_op", "parameters": {"duration": 0.2}})
    additions.append(
        {
            "a": complete,
            "coordinate_action": {"kind": "no_op", "duration": 0.2},
            "repeat_policy": "one_shot",
            "cluster_id": "active|task_complete",
            "risk_class": "safe",
            "guidance_label": "当前任务已经完成",
            "active_learning_label": "task_complete",
        }
    )
    failure = normalize_semantic_action({"action_type": "no_op", "parameters": {"duration": 0.2}})
    additions.append(
        {
            "a": failure,
            "coordinate_action": {"kind": "no_op", "duration": 0.2},
            "repeat_policy": "one_shot",
            "cluster_id": "active|failure_state",
            "risk_class": "safe",
            "guidance_label": "当前状态表示失败",
            "active_learning_label": "failure_state",
        }
    )
    changed = normalize_semantic_action({"action_type": "no_op", "parameters": {"duration": 0.2}})
    additions.append(
        {
            "a": changed,
            "coordinate_action": {"kind": "no_op", "duration": 0.2},
            "repeat_policy": "one_shot",
            "cluster_id": "active|object_changed",
            "risk_class": "safe",
            "guidance_label": "目标对象刚刚发生了关键变化",
            "active_learning_label": "object_changed",
        }
    )
    for entry in additions:
        signature = semantic_action_signature(entry["a"]) + "|" + entry["active_learning_label"]
        if signature not in signatures:
            values.append(entry)
            signatures.add(signature)
    priority = []
    if ranked and len(ranked) > 1:
        gap = abs(safe_float(ranked[1].get("score"), 0.0) - safe_float(ranked[0].get("score"), 0.0))
    else:
        gap = float("inf")
    for value in values:
        label = str(value.get("active_learning_label", "candidate"))
        score = 0
        if label == "candidate":
            score = 0
        elif label == "wait":
            score = 1 if gap < 12 or bool(frame.get("capture_frozen")) else 3
        elif label == "scroll":
            score = 2
        else:
            score = 4
        priority.append((score, value))
    selected = []
    for _, value in sorted(priority, key=lambda item: item[0]):
        key = semantic_action_signature(value.get("a")) + "|" + str(value.get("active_learning_label", "candidate"))
        if any(
            semantic_action_signature(old.get("a")) + "|" + str(old.get("active_learning_label", "candidate")) == key
            for old in selected
        ):
            continue
        selected.append(value)
        if len(selected) >= 4:
            break
    candidates = []
    for entry in selected:
        candidates.append(
            {
                "cluster_id": entry.get("cluster_id", ""),
                "canonical_action_signature": semantic_action_signature(entry["a"]),
                "semantic_action": entry["a"],
                "a": entry.get("coordinate_action") or normalize_action(entry["a"]),
                "risk_class": entry.get("risk_class", "safe"),
                "active_learning_label": entry.get("active_learning_label", ""),
            }
        )
    return selected, candidates


def active_learning_information_score(decision, temporal=None):
    value = decision if isinstance(decision, dict) else {}
    best = value.get("best", {}) if isinstance(value.get("best"), dict) else {}
    memory = temporal if isinstance(temporal, dict) else {}
    disagreement = safe_float(
        value.get(
            "policy_value_disagreement",
            value.get("ensemble_disagreement", best.get("ensemble_disagreement", 0.0)),
        ),
        0.0,
        0.0,
        10.0,
    )
    risk = safe_float(
        value.get("risk_probability", value.get("risk", best.get("risk_probability", 0.0))),
        0.0,
        0.0,
        1.0,
    )
    uncertainty = max(
        safe_float(value.get("uncertainty", best.get("uncertainty", 0.0)), 0.0, 0.0, 1.0),
        safe_float(value.get("ood_uncertainty", best.get("ood_uncertainty", 0.0)), 0.0, 0.0, 1.0),
    )
    support = max(
        0,
        safe_int(
            value.get(
                "support_count",
                value.get("support", best.get("support", best.get("behavior_count", 0))),
            ),
            0,
        ),
    )
    frequency = min(1.0, math.log1p(support) / math.log(32.0))
    risk_class = str(value.get("risk_class", best.get("risk_class", "safe")))
    irreversible = 1.0 if risk_class == "irreversible" else 0.0
    recovery = 1.0 if memory.get("failure_recovery_stack") else 0.0
    score = 1.8 * disagreement + 1.6 * risk + 1.4 * uncertainty + 0.8 * frequency + 1.2 * irreversible + 0.5 * recovery
    return {
        "score": round(score, 6),
        "disagreement": round(disagreement, 6),
        "risk": round(risk, 6),
        "uncertainty": round(uncertainty, 6),
        "future_frequency": round(frequency, 6),
        "irreversible": irreversible,
        "recovery_context": recovery,
        "selection_rule": "maximum_ensemble_disagreement_risk_future_frequency",
    }


def register_active_learning_request(execution, frame, temporal, decision):
    information = active_learning_information_score(decision, temporal)
    game_id = str(
        getattr(execution, "game", {}).get(
            "id",
            (
                getattr(execution, "agent_policy", TaskAgentPolicy({})).game_id
                if hasattr(execution, "agent_policy")
                else ""
            ),
        )
    )
    ACTIVE_LEARNING_RESUME[game_id] = {
        "created": time.time(),
        "frame_token": (
            hashlib.sha256(feature_bytes(frame.get("f")) + str(frame.get("object_signature", "")).encode()).hexdigest()
            if isinstance(frame, dict) and feature_valid(frame.get("f"))
            else ""
        ),
        "subgoal_id": str(getattr(getattr(execution, "current_subgoal", None), "subgoal_id", "")),
        "task_id": str(getattr(getattr(execution, "task_definition", None), "task_id", "default")),
        "guidance_trigger": list(decision.get("guidance_trigger", [])),
        "reason": str(decision.get("reason", "")),
        "temporal": dict(temporal or {}),
        "information_score": information,
        "priority": information["score"],
        "selection_rule": "ensemble_disagreement_then_risk_then_future_frequency",
        "safe_snapshot": True,
    }
    return ACTIVE_LEARNING_RESUME[game_id]


def information_balanced_prototype_limit(prototypes, limit):
    values = [dict(value) for value in prototypes if isinstance(value, dict)]
    limit = max(1, int(limit))
    if len(values) <= limit:
        return values
    groups = defaultdict(list)
    for item in values:
        semantic = normalize_semantic_action(item.get("semantic_action")) or semantic_action_from_coordinate(
            item.get("a")
        )
        skill = semantic_skill(semantic)
        scene = str(item.get("scene_key") or visual_scene_key(item))
        risk = str((semantic or {}).get("risk_class", item.get("risk_class", "safe")))
        groups[(skill.skill_id, scene, risk)].append(item)
    chosen = []
    remainder = []

    def value_score(item):
        risk = str(item.get("risk_class", "safe"))
        danger = 2.0 if risk == "irreversible" else 0.8 if risk == "caution" else 0.0
        negative = 1.4 if item.get("nearest_rejected_distance") is not None or item.get("ambiguous") else 0.0
        novelty = min(
            2.0, safe_float(item.get("object_novelty", 0.0), 0.0) + safe_float(item.get("ood_boundary", 0.0), 0.0)
        )
        return (
            safe_float(item.get("support", 0), 0.0)
            + 0.35 * safe_float(item.get("action_support", 0), 0.0)
            + danger
            + negative
            + novelty
        )

    for key, items in sorted(groups.items(), key=lambda pair: (pair[0][0], pair[0][1], pair[0][2])):
        ordered = sorted(items, key=value_score, reverse=True)
        minimum = 2 if key[2] in {"caution", "irreversible"} else 1
        chosen.extend(ordered[:minimum])
        remainder.extend(ordered[minimum:])
    if len(chosen) > limit:
        chosen = sorted(chosen, key=value_score, reverse=True)[:limit]
    else:
        remainder.sort(key=value_score, reverse=True)
        chosen.extend(remainder[: limit - len(chosen)])
    return chosen[:limit]


class SemanticEventTrigger:
    def __init__(self, maximum=64):
        self.maximum = max(8, int(maximum))
        self.lock = threading.RLock()
        self.states = OrderedDict()
        self.pending = OrderedDict()

    def request(self, key, reason):
        with self.lock:
            token = str(key or "global")
            self.pending.pop(token, None)
            self.pending[token] = str(reason or "external")
            while len(self.pending) > self.maximum:
                self.pending.popitem(last=False)
        return True

    def should_process(self, frame, minimum_interval=0.2, maximum_interval=1.2):
        item = frame if isinstance(frame, dict) else {}
        key = frame_isolation_key(item)
        now = safe_float(item.get("time"), time.monotonic())
        digest = frame_digest(item)
        feature = item.get("f")
        force_flags = {
            "scene_change": bool(item.get("scene_changed")),
            "candidate_ambiguity": bool(item.get("candidate_ambiguous") or item.get("action_ambiguous")),
            "ood": safe_float(item.get("ood_score"), 0.0) >= 0.65,
            "post_action_no_change": bool(item.get("post_action_no_change") or item.get("state_unchanged_after_action")),
            "terminal_suspected": bool(item.get("terminal_suspected")),
            "popup": bool(item.get("new_popup")),
        }
        with self.lock:
            pending_reason = self.pending.pop(key, "")
            force = bool(pending_reason or any(force_flags.values()))
            previous = self.states.get(key)
            changed = True
            if previous is not None:
                elapsed = max(0.0, now - safe_float(previous.get("time"), 0.0))
                if elapsed < max(0.01, float(minimum_interval)) and not force:
                    return False
                changed = digest != str(previous.get("digest", ""))
                old_feature = previous.get("feature")
                if changed and feature_valid(feature) and feature_valid(old_feature):
                    changed = visual_distance(feature, old_feature) > 2.0
                if not changed and not force:
                    return False
            self.states.pop(key, None)
            self.states[key] = {
                "time": now,
                "digest": digest,
                "feature": feature_bytes(feature) if feature_valid(feature) else None,
            }
            while len(self.states) > self.maximum:
                self.states.popitem(last=False)
            return True


SEMANTIC_EVENT_TRIGGER = SemanticEventTrigger()


class BoundedLatestQueue:
    def __init__(self, maximum=4):
        self.maximum = max(1, int(maximum))
        self.queue = deque(maxlen=self.maximum)
        self.lock = threading.RLock()
        self.condition = threading.Condition(self.lock)
        self.dropped = 0

    def put_latest(self, value):
        with self.condition:
            if len(self.queue) >= self.maximum:
                self.queue.popleft()
                self.dropped += 1
                RUNTIME_METRICS.increment("bounded_queue_dropped_oldest")
            self.queue.append(value)
            self.condition.notify()

    def get_latest(self, timeout=None):
        deadline = None if timeout is None else time.monotonic() + max(0.0, float(timeout))
        with self.condition:
            while not self.queue:
                if deadline is not None:
                    remaining = deadline - time.monotonic()
                    if remaining <= 0:
                        raise queue.Empty
                    self.condition.wait(remaining)
                else:
                    self.condition.wait()
            value = self.queue.pop()
            self.queue.clear()
            return value

    def qsize(self):
        with self.lock:
            return len(self.queue)


def _replay_observation(value):
    item = dict(value) if isinstance(value, dict) else {}
    objects = []
    for source in item.get("objects", []) if isinstance(item.get("objects"), list) else []:
        if not isinstance(source, dict):
            continue
        objects.append(
            {
                key: source.get(key)
                for key in (
                    "class",
                    "generic_class",
                    "role",
                    "instance",
                    "track_id",
                    "text",
                    "bbox",
                    "state",
                    "value",
                    "confidence",
                    "uncertainty",
                )
                if key in source
            }
        )
    return {
        "state_id": str(item.get("state_id", item.get("environment_id", ""))),
        "visual_digest": str(item.get("visual_digest", item.get("frame_digest", ""))),
        "semantic_objects": objects[:64],
        "scene_graph": item.get("scene_graph", {}),
        "ocr_values": item.get("ocr_values", [])[:64] if isinstance(item.get("ocr_values"), list) else [],
        "internal_state": {
            key: item.get("internal_state", {}).get(key)
            for key in ("terminal", "task_phase", "capture_frozen", "window_focused", "loading")
            if isinstance(item.get("internal_state"), dict) and key in item.get("internal_state", {})
        },
    }


def build_anonymized_replay_bundles(experiences, model_version=""):
    grouped = defaultdict(list)
    for value in experiences or []:
        if not isinstance(value, dict):
            continue
        episode = str(value.get("episode_id") or value.get("session") or "legacy")[:200]
        task = normalized_identifier(value.get("task_id"), "default", 96)
        grouped[(episode, task)].append(value)
    bundles = []
    for (episode, task), values in sorted(grouped.items()):
        ordered = sorted(
            values, key=lambda item: (safe_int(item.get("step_id"), 0), safe_float(item.get("created_t"), 0.0))
        )
        steps = []
        for position, item in enumerate(ordered):
            before = _replay_observation(item.get("observation_t", {}))
            after = _replay_observation(item.get("observation_t+1", {}))
            semantic = normalize_semantic_action(item.get("semantic_action")) or semantic_action_from_coordinate(
                item.get("grounded_action") or item.get("action_t") or item.get("action")
            )
            grounded = normalize_action(item.get("grounded_action") or item.get("coordinate_action") or item.get("a"))
            selected = str(
                item.get("skill_key")
                or item.get("action_t")
                or item.get("action")
                or semantic_action_signature(semantic)
            )
            step = {
                "step_id": safe_int(item.get("step_id", position), position, 0),
                "frame_digest": str(before.get("visual_digest") or hashlib.sha256(canonical_bytes(before)).hexdigest()),
                "semantic_objects": before.get("semantic_objects", []),
                "scene_graph": before.get("scene_graph", {}),
                "task_id": task,
                "selected_action": selected,
                "semantic_action": semantic or {},
                "grounded_action": grounded or {},
                "reward_components": (
                    dict(item.get("reward_components", {})) if isinstance(item.get("reward_components"), dict) else {}
                ),
                "terminal_evidence": {
                    key: item.get(key)
                    for key in (
                        "terminal_state",
                        "reward_confidence",
                        "success",
                        "failure",
                        "reset",
                        "progress_score",
                        "stalled",
                    )
                    if key in item
                },
                "model_version": str(item.get("model_version") or model_version),
                "expected_decision": str(item.get("expected_decision") or selected),
                "after": after,
                "safety_decision": (
                    dict(item.get("safety_decision", {})) if isinstance(item.get("safety_decision"), dict) else {}
                ),
            }
            step["checksum"] = hashlib.sha256(canonical_bytes(step)).hexdigest()
            steps.append(step)
        material = {
            "schema_version": REPLAY_BUNDLE_SCHEMA_VERSION,
            "episode_id": episode,
            "task_id": task,
            "model_version": str(model_version),
            "steps": steps,
            "anonymization": "window_titles_paths_and_raw_pixels_excluded",
        }
        material["checksum"] = hashlib.sha256(canonical_bytes(material)).hexdigest()
        bundles.append(material)
    return bundles


def persist_replay_bundles(base, game_id, bundles):
    root = Path(base) / "models" / "replays" / hashlib.sha256(str(game_id).encode("utf-8", "replace")).hexdigest()[:24]
    root.mkdir(parents=True, exist_ok=True)
    paths = []
    for bundle in bundles or []:
        episode = hashlib.sha256(str(bundle.get("episode_id", "")).encode("utf-8", "replace")).hexdigest()[:24]
        task = hashlib.sha256(str(bundle.get("task_id", "default")).encode("utf-8", "replace")).hexdigest()[:16]
        path = root / (episode + "_" + task + ".json.z")
        payload = zlib.compress(canonical_bytes(bundle), 9)
        durable_atomic_write(path, payload, Path(base))
        paths.append(path.relative_to(Path(base)).as_posix())
    return paths


class ReplayEvaluator:
    @staticmethod
    def evaluate(bundle):
        item = dict(bundle) if isinstance(bundle, dict) else {}
        steps = item.get("steps", []) if isinstance(item.get("steps"), list) else []
        checksum_source = dict(item)
        checksum = str(checksum_source.pop("checksum", ""))
        checksum_valid = checksum == hashlib.sha256(canonical_bytes(checksum_source)).hexdigest()
        drift = 0
        dangerous_release = 0
        reward_reversal = 0
        last_reward = None
        for step in steps:
            if not isinstance(step, dict):
                drift += 1
                continue
            selected = str(step.get("selected_action", ""))
            expected = str(step.get("expected_decision", ""))
            if selected != expected:
                drift += 1
            semantic = normalize_semantic_action(step.get("semantic_action"))
            risk = str((semantic or {}).get("risk_class", "safe"))
            allowed = (
                bool((step.get("safety_decision") or {}).get("allowed", False))
                if isinstance(step.get("safety_decision"), dict)
                else False
            )
            if risk == "irreversible" and allowed:
                dangerous_release += 1
            components = step.get("reward_components", {}) if isinstance(step.get("reward_components"), dict) else {}
            reward = sum(safe_float(value, 0.0) for value in components.values())
            if (
                last_reward is not None
                and reward * last_reward < 0
                and str(step.get("terminal_evidence", {}).get("terminal_state", "neutral")) == "neutral"
            ):
                reward_reversal += 1
            last_reward = reward
        return {
            "checksum_valid": checksum_valid,
            "step_count": len(steps),
            "decision_drift_count": drift,
            "dangerous_action_false_release_count": dangerous_release,
            "reward_reversal_count": reward_reversal,
            "passed": bool(checksum_valid and drift == 0 and dangerous_release == 0),
        }


class TaskInductionEngine:
    success_words = ("success", "victory", "complete", "完成", "胜利", "通关", "领取")
    failure_words = ("failure", "defeat", "failed", "失败", "重试", "重新开始")

    @staticmethod
    def _terminal_signature(item):
        observation = (
            item.get("observation_t+1", {})
            if isinstance(item, dict) and isinstance(item.get("observation_t+1"), dict)
            else {}
        )
        objects = observation.get("objects", []) if isinstance(observation.get("objects"), list) else []
        classes = sorted(
            Counter(str(value.get("class", "unknown")) for value in objects if isinstance(value, dict)).items()
        )
        texts = []
        for value in objects:
            if isinstance(value, dict) and str(value.get("text", "")).strip():
                texts.append(str(value.get("text", "")).strip().casefold()[:64])
        terminal = str(
            item.get("terminal_state")
            or ("success" if item.get("success") else "failure" if item.get("failure") else "neutral")
        )
        material = {"terminal": terminal, "classes": classes, "texts": sorted(set(texts))[:24]}
        return hashlib.sha256(canonical_bytes(material)).hexdigest()[:24], terminal, texts, classes

    @staticmethod
    def _episode_id(item):
        return str(item.get("episode_id") or item.get("session") or "legacy")

    @staticmethod
    def _objects(item, after=True):
        key = "observation_t+1" if after else "observation_t"
        observation = item.get(key, {}) if isinstance(item.get(key), dict) else {}
        return (
            [value for value in observation.get("objects", []) if isinstance(value, dict)]
            if isinstance(observation.get("objects"), list)
            else []
        )

    @staticmethod
    def _object_identity(value):
        return str(
            value.get("track_id")
            or value.get("instance")
            or value.get("role")
            or value.get("class")
            or value.get("text")
            or "unknown"
        )[:128]

    @staticmethod
    def _numeric_values(objects):
        result = {}
        for value in objects:
            identity = TaskInductionEngine._object_identity(value)
            candidates = (value.get("numeric_value"), value.get("value"), value.get("text"))
            for candidate in candidates:
                match = re.search(r"[-+]?\d+(?:[.,]\d+)?", str(candidate or "").replace(",", ""))
                if match is not None:
                    result[identity] = safe_float(match.group(0), 0.0)
                    break
        return result

    @staticmethod
    def _action_key(item):
        semantic = normalize_semantic_action(item.get("semantic_action"))
        if semantic is not None:
            return semantic_action_signature(semantic)
        return str(item.get("skill_key") or item.get("action_t") or item.get("action") or "no_op")

    @classmethod
    def _scene_phase(cls, item):
        objects = cls._objects(item, True)
        texts = " ".join(str(value.get("text", "")).casefold() for value in objects)
        classes = {str(value.get("class", "unknown")).casefold() for value in objects}
        if item.get("success") or any(word in texts for word in cls.success_words):
            return "settlement_success"
        if item.get("failure") or any(word in texts for word in cls.failure_words):
            return "settlement_failure"
        if item.get("reset"):
            return "reset"
        affordances = Counter()
        for value in objects:
            for name, enabled in infer_object_affordances(value).items():
                affordances[name] += int(bool(enabled))
        if affordances["advances_scene"] or classes & {"start_button", "continue_button", "menu", "menu_item"}:
            return "menu"
        if objects or item.get("environment_changed", True):
            return "gameplay"
        return "loading_or_unknown"

    @classmethod
    def change_points(cls, experiences):
        ordered = sorted(
            [value for value in experiences or [] if isinstance(value, dict)],
            key=lambda item: (cls._episode_id(item), safe_int(item.get("step_id"), 0)),
        )
        points = []
        previous_episode = None
        previous_state = ""
        for index, item in enumerate(ordered):
            episode = cls._episode_id(item)
            state = str(item.get("state_t+1", item.get("next_state", "")))
            reward = abs(safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0))
            boundary = (
                episode != previous_episode
                or bool(item.get("done") or item.get("success") or item.get("failure") or item.get("reset"))
                or reward >= 0.75
            )
            if previous_state and state and previous_state != state and not bool(item.get("environment_changed", True)):
                boundary = True
            if boundary:
                points.append(index)
            previous_episode = episode
            previous_state = state
        return points

    @staticmethod
    def _hypothesis_confidence(support, contradictions, episode_count, base=0.45):
        evidence = max(0, int(support))
        opposing = max(0, int(contradictions))
        precision = (evidence + 1) / (evidence + opposing + 2)
        breadth = min(1.0, evidence / max(3, episode_count))
        return max(
            0.05, min(0.99, base + 0.34 * precision + 0.20 * breadth - 0.18 * opposing / max(1, evidence + opposing))
        )

    @classmethod
    def _demonstration_hypotheses(cls, experiences):
        episodes = defaultdict(list)
        for item in experiences or []:
            if isinstance(item, dict):
                episodes[cls._episode_id(item)].append(item)
        repeated_visits = defaultdict(set)
        success_visits = Counter()
        failure_visits = Counter()
        direction_evidence = defaultdict(Counter)
        phase_direction_evidence = defaultdict(lambda: defaultdict(Counter))
        human_numeric_relations = {}
        sequences = Counter()
        sequence_success = Counter()
        sequence_failure = Counter()
        phase_counts = Counter()
        transition_effects = Counter()
        successful_episodes = 0
        failed_episodes = 0
        for episode_id, values in episodes.items():
            ordered = sorted(values, key=lambda item: safe_int(item.get("step_id"), 0))
            success = any(bool(item.get("success")) or str(item.get("terminal_state")) == "success" for item in ordered)
            failure = any(bool(item.get("failure")) or str(item.get("terminal_state")) == "failure" for item in ordered)
            successful_episodes += int(success)
            failed_episodes += int(failure)
            actions = []
            visited = set()
            for item in ordered:
                phase_counts[cls._scene_phase(item)] += 1
                actions.append(cls._action_key(item))
                before_objects = cls._objects(item, False)
                after_objects = cls._objects(item, True)
                for value in after_objects:
                    identity = cls._object_identity(value)
                    visited.add(identity)
                    repeated_visits[identity].add(episode_id)
                before_values = cls._numeric_values(before_objects)
                after_values = cls._numeric_values(after_objects)
                phase = cls._scene_phase(item)
                for observed in list(before_objects) + list(after_objects):
                    identity = cls._object_identity(observed)
                    relation = str(observed.get("goal_relation", ""))
                    if bool(observed.get("human_confirmed")) and relation in {
                        NumericGoalRelation.HIGHER_BETTER.value,
                        NumericGoalRelation.LOWER_BETTER.value,
                        NumericGoalRelation.IRRELEVANT.value,
                        NumericGoalRelation.CONTEXT_DEPENDENT.value,
                        NumericGoalRelation.UNCERTAIN.value,
                    }:
                        human_numeric_relations[identity] = relation
                for supervised in item.get("ocr_values", []) if isinstance(item.get("ocr_values"), list) else []:
                    if not isinstance(supervised, dict):
                        continue
                    identity = str(supervised.get("region_id") or supervised.get("text") or "numeric")
                    relation = str(supervised.get("goal_relation", ""))
                    if bool(supervised.get("human_confirmed")) and relation:
                        human_numeric_relations[identity] = relation
                for identity, after_value in after_values.items():
                    delta = after_value - before_values.get(identity, after_value)
                    tolerance = max(
                        1e-6,
                        max(
                            abs(after_value),
                            abs(before_values.get(identity, after_value)),
                            1.0,
                        )
                        * 0.0005,
                    )
                    direction = "unchanged" if abs(delta) <= tolerance else "up" if delta > 0 else "down"
                    if success:
                        direction_evidence[identity][direction + "_success"] += 1
                        phase_direction_evidence[identity][phase][direction + "_success"] += 1
                    if failure:
                        direction_evidence[identity][direction + "_failure"] += 1
                        phase_direction_evidence[identity][phase][direction + "_failure"] += 1
                before_ids = {cls._object_identity(value) for value in before_objects}
                after_ids = {cls._object_identity(value) for value in after_objects}
                born = sorted(after_ids - before_ids)[:4]
                vanished = sorted(before_ids - after_ids)[:4]
                if born or vanished:
                    transition_effects[(tuple(born), tuple(vanished), cls._action_key(item))] += 1
            for identity in visited:
                if success:
                    success_visits[identity] += 1
                if failure:
                    failure_visits[identity] += 1
            for size in (2, 3, 4):
                for index in range(max(0, len(actions) - size + 1)):
                    key = tuple(actions[index : index + size])
                    sequences[key] += 1
                    sequence_success[key] += int(success)
                    sequence_failure[key] += int(failure)
        hypotheses = []
        episode_count = max(1, len(episodes))
        for identity, episode_ids in sorted(repeated_visits.items(), key=lambda pair: (-len(pair[1]), pair[0]))[:16]:
            support = success_visits[identity]
            contradictions = failure_visits[identity]
            confidence = cls._hypothesis_confidence(support, contradictions, episode_count, 0.34)
            hypotheses.append(
                {
                    "hypothesis": "重复选择或操作对象 ‘" + identity + "’ 是任务推进条件",
                    "kind": "repeated_object_visit",
                    "confidence": round(confidence, 6),
                    "supporting_episodes": support,
                    "contradicting_episodes": contradictions,
                    "requires_guidance": confidence < 0.82,
                    "evidence": {"visited_episode_count": len(episode_ids), "object_identity": identity},
                }
            )
        numeric_ranked = sorted(
            direction_evidence.items(),
            key=lambda pair: (-sum(pair[1].values()), pair[0]),
        )[:16]
        for identity, evidence in numeric_ranked:
            higher_score = evidence["up_success"] + evidence["down_failure"]
            lower_score = evidence["down_success"] + evidence["up_failure"]
            unrelated_score = evidence["unchanged_success"] + evidence["unchanged_failure"]
            phase_relations = set()
            for phase, phase_evidence in phase_direction_evidence[identity].items():
                phase_higher = phase_evidence["up_success"] + phase_evidence["down_failure"]
                phase_lower = phase_evidence["down_success"] + phase_evidence["up_failure"]
                if phase_higher >= phase_lower + 2:
                    phase_relations.add(NumericGoalRelation.HIGHER_BETTER.value)
                elif phase_lower >= phase_higher + 2:
                    phase_relations.add(NumericGoalRelation.LOWER_BETTER.value)
            inferred = NumericGoalRelation.UNCERTAIN.value
            support = max(higher_score, lower_score, unrelated_score)
            contradictions = min(higher_score, lower_score)
            if len(phase_relations) >= 2:
                inferred = NumericGoalRelation.CONTEXT_DEPENDENT.value
                support = higher_score + lower_score
                contradictions = 0
            elif higher_score >= lower_score + 2 and higher_score >= unrelated_score + 1:
                inferred = NumericGoalRelation.HIGHER_BETTER.value
                support, contradictions = higher_score, lower_score
            elif lower_score >= higher_score + 2 and lower_score >= unrelated_score + 1:
                inferred = NumericGoalRelation.LOWER_BETTER.value
                support, contradictions = lower_score, higher_score
            elif unrelated_score >= max(higher_score, lower_score) + 2:
                inferred = NumericGoalRelation.IRRELEVANT.value
                support, contradictions = unrelated_score, max(higher_score, lower_score)
            human_relation = human_numeric_relations.get(identity)
            conflict = bool(
                human_relation
                and human_relation != NumericGoalRelation.UNCERTAIN.value
                and inferred != NumericGoalRelation.UNCERTAIN.value
                and human_relation != inferred
            )
            final_relation = human_relation or inferred
            descriptions = {
                NumericGoalRelation.HIGHER_BETTER.value: "数值越大通常越有利",
                NumericGoalRelation.LOWER_BETTER.value: "数值越小通常越有利",
                NumericGoalRelation.IRRELEVANT.value: "数值变化与任务成败基本无关",
                NumericGoalRelation.CONTEXT_DEPENDENT.value: "数值方向随游戏阶段或子目标变化",
                NumericGoalRelation.UNCERTAIN.value: "数值方向尚不确定",
            }
            confidence = cls._hypothesis_confidence(support, contradictions, episode_count, 0.40)
            if human_relation and not conflict:
                confidence = max(confidence, 0.95)
            hypotheses.append(
                {
                    "hypothesis": (
                        "‘"
                        + identity
                        + "’："
                        + descriptions.get(
                            final_relation,
                            descriptions[NumericGoalRelation.UNCERTAIN.value],
                        )
                    ),
                    "kind": "numeric_direction_conflict" if conflict else "numeric_progress",
                    "confidence": round(confidence, 6),
                    "supporting_episodes": support,
                    "contradicting_episodes": contradictions,
                    "requires_guidance": (
                        conflict
                        or final_relation == NumericGoalRelation.UNCERTAIN.value
                        or confidence < 0.85
                    ),
                    "evidence": {
                        "numeric_object": identity,
                        "direction_evidence": dict(evidence),
                        "phase_direction_evidence": {
                            phase: dict(values) for phase, values in phase_direction_evidence[identity].items()
                        },
                        "higher_score": higher_score,
                        "lower_score": lower_score,
                        "unrelated_score": unrelated_score,
                        "automatic_inference": inferred,
                        "human_relation": human_relation,
                        "human_priority": bool(human_relation),
                        "conflict_requires_review": conflict,
                    },
                }
            )
        for sequence, support_count in sequences.most_common(20):
            success_support = sequence_success[sequence]
            contradictions = sequence_failure[sequence]
            if support_count < 2:
                continue
            confidence = cls._hypothesis_confidence(success_support, contradictions, episode_count, 0.38)
            hypotheses.append(
                {
                    "hypothesis": "动作序列形成可复用技能：" + " → ".join(sequence),
                    "kind": "stable_skill_sequence",
                    "confidence": round(confidence, 6),
                    "supporting_episodes": success_support,
                    "contradicting_episodes": contradictions,
                    "requires_guidance": confidence < 0.80,
                    "evidence": {"action_sequence": list(sequence), "sequence_occurrences": support_count},
                }
            )
        for (born, vanished, action), support in transition_effects.most_common(12):
            confidence = cls._hypothesis_confidence(support, 0, episode_count, 0.32)
            hypotheses.append(
                {
                    "hypothesis": "动作 ‘" + action + "’ 后的对象出生或消失可作为子目标完成信号",
                    "kind": "visual_subgoal_transition",
                    "confidence": round(confidence, 6),
                    "supporting_episodes": support,
                    "contradicting_episodes": 0,
                    "requires_guidance": confidence < 0.78,
                    "evidence": {"born_objects": list(born), "vanished_objects": list(vanished), "action": action},
                }
            )
        if successful_episodes or failed_episodes:
            confidence = cls._hypothesis_confidence(successful_episodes, failed_episodes, episode_count, 0.30)
            hypotheses.append(
                {
                    "hypothesis": "演示轨迹包含可区分的回合开始、游戏中、结算与失败场景",
                    "kind": "scene_phase_structure",
                    "confidence": round(confidence, 6),
                    "supporting_episodes": successful_episodes,
                    "contradicting_episodes": failed_episodes,
                    "requires_guidance": confidence < 0.75,
                    "evidence": {"phase_counts": dict(phase_counts)},
                }
            )
        hypotheses.sort(
            key=lambda row: (
                -safe_float(row.get("confidence"), 0.0),
                -safe_int(row.get("supporting_episodes"), 0),
                str(row.get("hypothesis", "")),
            )
        )
        return hypotheses[:64], dict(phase_counts)

    @staticmethod
    def _information_gain_questions(hypotheses):
        unresolved = [row for row in hypotheses if row.get("requires_guidance")]
        questions = []
        for index in range(0, min(len(unresolved), 12), 3):
            group = unresolved[index : index + 3]
            if not group:
                continue
            probabilities = [max(1e-6, min(1 - 1e-6, safe_float(row.get("confidence"), 0.5))) for row in group]
            entropy = sum(-(p * math.log(p, 2) + (1 - p) * math.log(1 - p, 2)) for p in probabilities)
            choices = [str(row.get("hypothesis", ""))[:180] for row in group] + ["以上都不是或暂时不确定"]
            questions.append(
                {
                    "question_id": "information_gain_" + str(index // 3 + 1),
                    "text": "哪一种描述最接近当前任务目标或稳定规律？",
                    "choices": choices,
                    "distinguishes_hypotheses": [str(row.get("kind", "unknown")) for row in group],
                    "estimated_information_gain": round(entropy, 6),
                    "selection_policy": "maximum_expected_information_gain",
                }
            )
        questions.sort(key=lambda row: -safe_float(row.get("estimated_information_gain"), 0.0))
        return questions

    @classmethod
    def induce(cls, experiences, game_id=""):
        clusters = defaultdict(
            lambda: {
                "count": 0,
                "success": 0,
                "failure": 0,
                "reset": 0,
                "texts": Counter(),
                "classes": Counter(),
                "episodes": set(),
            }
        )
        for item in experiences or []:
            if not isinstance(item, dict):
                continue
            signature, terminal, texts, classes = cls._terminal_signature(item)
            if terminal == "neutral" and not item.get("reset"):
                continue
            row = clusters[signature]
            row["count"] += 1
            row["success"] += int(terminal == "success")
            row["failure"] += int(terminal == "failure")
            row["reset"] += int(bool(item.get("reset")))
            row["texts"].update(texts)
            row["classes"].update(dict(classes))
            row["episodes"].add(cls._episode_id(item))
        hypotheses, phase_counts = cls._demonstration_hypotheses(experiences)
        guidance_questions = cls._information_gain_questions(hypotheses)
        candidates = []
        for signature, row in sorted(clusters.items(), key=lambda pair: pair[1]["count"], reverse=True):
            label = (
                "success"
                if row["success"] >= max(row["failure"], row["reset"])
                else "failure" if row["failure"] >= row["reset"] else "reset"
            )
            confidence = min(0.99, 0.45 + 0.12 * math.log1p(row["count"]) + 0.08 * len(row["episodes"]))
            detector = {
                "type": "induced_terminal_cluster",
                "signature": signature,
                "minimum_confidence": round(confidence, 6),
                "texts": [value for value, _ in row["texts"].most_common(12)],
                "object_classes": [value for value, _ in row["classes"].most_common(12)],
            }
            task_id = "induced_" + signature[:16]
            mapping = {
                "game_id": str(game_id),
                "task_id": task_id,
                "name": "自动归纳任务候选",
                "goal": "到达经用户确认的终止状态",
                "allowed_families": [],
                "reward_config": {"minimum_reward_confidence": 0.72},
                "success_detector": detector if label == "success" else {},
                "failure_detector": detector if label == "failure" else {},
                "reset_detector": detector if label == "reset" else {},
                "enabled": False,
            }
            question = (
                guidance_questions[0]
                if guidance_questions
                else {
                    "text": "这个终止画面表示什么？",
                    "choices": ["任务完成", "任务失败", "回合重置", "不确定"],
                    "estimated_information_gain": 0.0,
                    "selection_policy": "maximum_expected_information_gain",
                }
            )
            candidates.append(
                {
                    "schema_version": TASK_INDUCTION_SCHEMA_VERSION,
                    "candidate_id": task_id,
                    "label": label,
                    "confidence": round(confidence, 6),
                    "support": row["count"],
                    "independent_episodes": len(row["episodes"]),
                    "question": question,
                    "task_definition": TaskDefinition.from_mapping(mapping, str(game_id), task_id).to_dict(),
                    "audit": {
                        "signature": signature,
                        "texts": detector["texts"],
                        "object_classes": detector["object_classes"],
                    },
                }
            )
        return {
            "schema_version": TASK_INDUCTION_SCHEMA_VERSION,
            "algorithm": "demonstration_driven_task_hypothesis_induction",
            "change_points": cls.change_points(experiences),
            "scene_phase_counts": phase_counts,
            "hypotheses": hypotheses,
            "guidance_questions": guidance_questions,
            "information_gain_ordering": True,
            "candidates": candidates[:64],
            "requires_guidance_confirmation": True,
        }


def _temporal_signature(objects, texts, actions, flags):
    classes = Counter(str(value.get("class", "unknown")) for value in objects if isinstance(value, dict))
    roles = Counter(
        str(value.get("role", "")) for value in objects if isinstance(value, dict) and str(value.get("role", ""))
    )
    material = {
        "classes": classes.most_common(12),
        "roles": roles.most_common(12),
        "texts": sorted(set(str(value).strip().casefold()[:48] for value in texts if str(value).strip()))[:12],
        "actions": [str(value) for value in actions][-8:],
        "flags": dict(flags),
    }
    return hashlib.sha256(canonical_bytes(material)).hexdigest()[:24]


def train_temporal_termination_model(experiences):
    grouped = defaultdict(list)
    for value in experiences or []:
        if isinstance(value, dict):
            grouped[str(value.get("episode_id") or value.get("session") or "legacy")].append(value)
    counts = defaultdict(Counter)
    global_counts = Counter()
    windows = []
    for _, values in grouped.items():
        ordered = sorted(values, key=lambda item: safe_int(item.get("step_id"), 0))
        history = deque(maxlen=32)
        for item in ordered:
            observation = item.get("observation_t+1", {}) if isinstance(item.get("observation_t+1"), dict) else {}
            objects = observation.get("objects", []) if isinstance(observation.get("objects"), list) else []
            texts = [value.get("text", "") for value in objects if isinstance(value, dict)]
            history.append(str(item.get("skill_key") or item.get("action_t") or item.get("action") or ""))
            flags = {
                "changed": bool(item.get("environment_changed", True)),
                "frozen": bool(item.get("capture_frozen")),
                "focused": not bool(item.get("window_focus_lost")),
                "loading": bool(item.get("loading")),
            }
            signature = _temporal_signature(objects, texts, history, flags)
            if item.get("success") or str(item.get("terminal_state")) == "success":
                label = "success"
            elif item.get("failure") or str(item.get("terminal_state")) == "failure":
                label = "failure"
            elif item.get("reset"):
                label = "reset"
            elif not flags["changed"] or flags["frozen"]:
                label = "stalled"
            elif safe_float(item.get("progress_score", item.get("reward_t", 0.0)), 0.0) > 0.02:
                label = "progress"
            else:
                label = "neutral"
            counts[signature][label] += 1
            global_counts[label] += 1
            windows.append(len(history))
    table = {}
    for signature, row in counts.items():
        total = sum(row.values())
        table[signature] = {
            name: round((row.get(name, 0) + 1) / (total + 5), 7)
            for name in ("success", "failure", "reset", "progress", "stalled")
        }
        table[signature]["support"] = total
    global_total = sum(global_counts.values())
    priors = {
        name: round((global_counts.get(name, 0) + 1) / (global_total + 5), 7)
        for name in ("success", "failure", "reset", "progress", "stalled")
    }
    return {
        "schema_version": TEMPORAL_TERMINATION_SCHEMA_VERSION,
        "algorithm": "auditable_temporal_terminal_sequence_model",
        "history_window": [8, 32],
        "trained": bool(len(table) >= 4),
        "signatures": dict(sorted(table.items(), key=lambda pair: pair[1]["support"], reverse=True)[:4096]),
        "priors": priors,
        "training_transitions": sum(sum(value.values()) for value in counts.values()),
        "mean_history": statistics.fmean(windows) if windows else 0.0,
        "outputs": ["P(success)", "P(failure)", "P(reset)", "P(progress)", "P(stalled)"],
    }


def temporal_termination_prediction(model, policy, perception):
    if not isinstance(model, dict):
        return {}
    evidence = perception if isinstance(perception, dict) else {}
    objects = evidence.get("objects", []) if isinstance(evidence.get("objects"), list) else []
    texts = evidence.get("texts", []) if isinstance(evidence.get("texts"), list) else []
    actions = [
        value.get("action", "") if isinstance(value, dict) else value
        for value in list(getattr(policy, "history", []))[-8:]
    ]
    motion = [safe_float(value, 0.0) for value in evidence.get("motion", []) if finite_number(value)]
    flags = {
        "changed": not bool(motion and statistics.fmean(motion[-3:]) < 0.5),
        "frozen": False,
        "focused": True,
        "loading": False,
    }
    signature = _temporal_signature(objects, texts, actions, flags)
    row = (model.get("signatures") or {}).get(signature)
    result = dict(row) if isinstance(row, dict) else dict(model.get("priors", {}))
    result["signature"] = signature
    result["exact"] = isinstance(row, dict)
    return result


def reward_exploitation_signal(history, record):
    values = [value for value in list(history)[-8:] if isinstance(value, dict)] + [record]
    if len(values) < 4:
        return {"detected": False, "reasons": []}
    reasons = []
    actions = [str(value.get("action", "")) for value in values]
    rewards = [safe_float(value.get("reward", 0.0), 0.0) for value in values]
    changed = [bool(value.get("changed")) for value in values]
    states = [str(value.get("after", "")) for value in values]
    if (
        len(set(actions[-4:])) == 1
        and sum(rewards[-4:]) > 0.25
        and not any(str(value.get("state")) == "success" for value in values[-4:])
    ):
        reasons.append("repeated_local_reward_without_completion")
    if len(states) >= 6 and len(set(states[-6:])) <= 2 and sum(1 for value in changed[-6:] if value) >= 4:
        reasons.append("visual_oscillation_reward")
    if actions[-6:].count(actions[-1]) >= 5 and not any(changed[-3:]):
        reasons.append("meaningless_delay_or_no_effect_loop")
    terminal_tokens = [str(value.get("candidate", "")) for value in values]
    if terminal_tokens[-6:].count("success") >= 4 and not any(bool(value.get("confirmed")) for value in values[-6:]):
        reasons.append("repeated_unconfirmed_success_text")
    return {"detected": bool(reasons), "reasons": reasons}


class AutomaticSkillDiscovery:
    @staticmethod
    def _objects(observation):
        value = observation if isinstance(observation, dict) else {}
        return [item for item in value.get("objects", []) if isinstance(item, dict)]

    @staticmethod
    def _state_signature(observation):
        value = observation if isinstance(observation, dict) else {}
        classes = Counter(
            str(item.get("class", "unknown")) for item in value.get("objects", []) if isinstance(item, dict)
        )
        relations = Counter(
            str(edge.get("relation", ""))
            for edge in (value.get("scene_graph", {}) or {}).get("edges", [])
            if isinstance(edge, dict)
        )
        return {
            "classes": classes,
            "relations": relations,
            "visual": str(value.get("visual_digest") or value.get("frame_digest") or ""),
        }

    @classmethod
    def _boundary_score(cls, previous, current):
        if previous is None:
            return 0.0
        before = cls._state_signature(previous.get("observation_t+1", previous.get("observation_t", {})))
        after = cls._state_signature(current.get("observation_t", {}))
        first = set(before["classes"])
        second = set(after["classes"])
        union = max(1, len(first.union(second)))
        object_change = 1.0 - len(first.intersection(second)) / union
        relation_first = set(before["relations"])
        relation_second = set(after["relations"])
        relation_union = max(1, len(relation_first.union(relation_second)))
        relation_change = 1.0 - len(relation_first.intersection(relation_second)) / relation_union
        previous_reward = safe_float(previous.get("reward_t", previous.get("reward", 0.0)), 0.0)
        current_reward = safe_float(current.get("reward_t", current.get("reward", 0.0)), 0.0)
        reward_jump = min(1.0, abs(current_reward - previous_reward))
        context = current.get("context", {}) if isinstance(current.get("context"), dict) else {}
        terminal = float(
            bool(
                previous.get("success")
                or previous.get("failure")
                or previous.get("done")
                or str(previous.get("terminal_state", "neutral")) in {"success", "failure"}
            )
        )
        predictability = min(
            1.0, safe_float(context.get("prediction_error", context.get("world_model_surprise", 0.0)), 0.0, 0.0, 10.0)
        )
        no_effect_change = float(
            bool(previous.get("environment_changed", True)) != bool(current.get("environment_changed", True))
        )
        loading_change = float(
            bool((previous.get("context", {}) if isinstance(previous.get("context"), dict) else {}).get("loading"))
            != bool(context.get("loading"))
        )
        visual_change = (
            0.0
            if before["visual"] and before["visual"] == after["visual"]
            else 0.25 if before["visual"] and after["visual"] else 0.0
        )
        return (
            0.30 * object_change
            + 0.16 * relation_change
            + 0.18 * reward_jump
            + 0.45 * terminal
            + 0.20 * predictability
            + 0.12 * no_effect_change
            + 0.12 * loading_change
            + visual_change
        )

    @classmethod
    def _segments(cls, ordered):
        segments = []
        current = []
        previous = None
        for value in ordered:
            score = cls._boundary_score(previous, value)
            if current and len(current) >= 2 and score >= 0.42:
                segments.append(current)
                current = []
            current.append(value)
            context = value.get("context", {}) if isinstance(value.get("context"), dict) else {}
            if (
                value.get("done")
                or value.get("success")
                or value.get("failure")
                or context.get("episode_complete")
                or context.get("subgoal_completed")
            ):
                segments.append(current)
                current = []
            previous = value
        if current:
            segments.append(current)
        return segments

    @classmethod
    def discover(cls, experiences):
        grouped = defaultdict(list)
        for value in experiences or []:
            if isinstance(value, dict):
                key = (str(value.get("game_id", "")), str(value.get("episode_id") or value.get("session") or "legacy"))
                grouped[key].append(value)
        options = defaultdict(
            lambda: {
                "episodes": set(),
                "success": 0,
                "games": set(),
                "types": set(),
                "themes": set(),
                "holdout_games": set(),
                "holdout_types": set(),
                "starts": Counter(),
                "roles": Counter(),
                "relations": Counter(),
                "ends": Counter(),
                "actions": Counter(),
                "recoveries": Counter(),
                "parameters": Counter(),
                "risk": "safe",
                "semantic_targets": 0,
                "coordinate_targets": 0,
                "boundaries": Counter(),
            }
        )
        for (game_id, episode_id), values in grouped.items():
            ordered = sorted(values, key=lambda item: safe_int(item.get("step_id"), 0))
            for segment in cls._segments(ordered):
                if not segment:
                    continue
                first = segment[0]
                last = segment[-1]
                before = first.get("observation_t", {}) if isinstance(first.get("observation_t"), dict) else {}
                after = last.get("observation_t+1", {}) if isinstance(last.get("observation_t+1"), dict) else {}
                before_objects = cls._objects(before)
                after_objects = cls._objects(after)
                before_classes = Counter(str(item.get("class", "unknown")) for item in before_objects)
                after_classes = Counter(str(item.get("class", "unknown")) for item in after_objects)
                appeared = after_classes - before_classes
                disappeared = before_classes - after_classes
                context = first.get("context", {}) if isinstance(first.get("context"), dict) else {}
                action_keys = []
                coordinate_specific = False
                semantic_specific = False
                for item in segment:
                    action = str(
                        item.get("skill_id")
                        or item.get("skill_key")
                        or item.get("action_t")
                        or item.get("action")
                        or ""
                    )
                    if action:
                        action_keys.append(action)
                    semantic = normalize_semantic_action(item.get("semantic_action")) or {}
                    target = semantic.get("target", {}) if isinstance(semantic.get("target"), dict) else {}
                    fallback = semantic.get("coordinate_fallback")
                    if target and str(target.get("class") or target.get("role") or target.get("text")):
                        semantic_specific = True
                    if isinstance(fallback, dict) and not target:
                        coordinate_specific = True
                effect = {
                    "appeared": sorted(appeared.elements()),
                    "disappeared": sorted(disappeared.elements()),
                    "terminal": str(last.get("terminal_state", "neutral")),
                    "environment_changed": bool(last.get("environment_changed", True)),
                }
                initiation = {
                    "classes": sorted(before_classes),
                    "roles": sorted(str(item.get("role", "")) for item in before_objects if item.get("role")),
                    "relations": sorted(
                        str(edge.get("relation", ""))
                        for edge in (before.get("scene_graph", {}) or {}).get("edges", [])
                        if isinstance(edge, dict)
                    ),
                }
                identity = hashlib.sha256(
                    canonical_bytes(
                        {
                            "initiation": initiation,
                            "effect": effect,
                            "action_families": [value.split("|")[0] for value in action_keys],
                        }
                    )
                ).hexdigest()[:20]
                row = options[identity]
                row["episodes"].add(game_id + "|" + episode_id)
                successful = bool(
                    any(bool(item.get("success")) for item in segment)
                    or str(last.get("terminal_state")) == "success"
                    or bool(context.get("subgoal_completed"))
                )
                row["success"] += int(successful)
                row["games"].add(game_id)
                row["types"].add(str(context.get("game_type", "unknown")))
                layout = (
                    str(context.get("ui_skin") or context.get("ui_variant") or context.get("theme") or "unknown")
                    + "|"
                    + str(context.get("resolution_id") or context.get("window_size") or "unknown")
                )
                row["themes"].add(layout)
                partition = str(context.get("evaluation_partition", ""))
                level = safe_int(context.get("generalization_level", 0), 0, 0, 4)
                if partition in {"test", "holdout"} and level in {3, 4} and context.get("benchmark_verified"):
                    row["holdout_games"].add(game_id)
                    row["holdout_types"].add(str(context.get("game_type", "unknown")))
                row["starts"].update(before_classes)
                row["roles"].update(initiation["roles"])
                row["relations"].update(initiation["relations"])
                row["ends"].update({"appear:" + key: value for key, value in appeared.items()})
                row["ends"].update({"disappear:" + key: value for key, value in disappeared.items()})
                row["actions"].update(action_keys)
                row["semantic_targets"] += int(semantic_specific)
                row["coordinate_targets"] += int(coordinate_specific)
                row["boundaries"]["state_reward_predictability"] += 1
                for item in segment:
                    semantic_parameter = normalize_semantic_action(item.get("semantic_action")) or {}
                    target_parameter = (
                        semantic_parameter.get("target", {})
                        if isinstance(semantic_parameter.get("target"), dict)
                        else {}
                    )
                    parameter = str(target_parameter.get("role") or target_parameter.get("class") or "")
                    if parameter:
                        row["parameters"][parameter] += 1
                if any(bool(item.get("failure")) for item in segment):
                    row["recoveries"]["wait_redetect_then_guidance"] += 1
                else:
                    row["recoveries"]["retry_once_then_guidance"] += 1
                for item in segment:
                    semantic = normalize_semantic_action(item.get("semantic_action"))
                    risk = str((semantic or {}).get("risk_class", "safe"))
                    if risk == "irreversible":
                        row["risk"] = "irreversible"
                    elif risk == "caution" and row["risk"] == "safe":
                        row["risk"] = "caution"
        discovered = []
        for identity, row in sorted(
            options.items(), key=lambda pair: (len(pair[1]["episodes"]), pair[1]["success"]), reverse=True
        ):
            support = len(row["episodes"])
            if support < 3:
                continue
            success_rate = row["success"] / max(1, support)
            lower = GeneralizationEvaluator._wilson_lower(row["success"], support)
            games = {value for value in row["games"] if value}
            themes = {value for value in row["themes"] if value and value != "unknown|unknown"}
            types = {value for value in row["types"] if value and value != "unknown"}
            holdout_games = {value for value in row["holdout_games"] if value}
            holdout_types = {value for value in row["holdout_types"] if value and value != "unknown"}
            semantic_ratio = row["semantic_targets"] / max(1, row["semantic_targets"] + row["coordinate_targets"])
            if (
                len(holdout_games) >= 3
                and len(holdout_types) >= 2
                and len(themes) >= 2
                and lower >= 0.55
                and semantic_ratio >= 0.80
                and row["risk"] != "irreversible"
            ):
                scope = "global"
            elif (
                len(holdout_games) >= 2
                and len(holdout_types) >= 1
                and lower >= 0.50
                and semantic_ratio >= 0.70
                and row["risk"] != "irreversible"
            ):
                scope = "game_type"
            else:
                scope = "single_game"
            action_policy = [value for value, _ in row["actions"].most_common(8)]
            discovered.append(
                {
                    "schema_version": SKILL_DISCOVERY_SCHEMA_VERSION,
                    "skill_id": "option_" + identity,
                    "scope": scope,
                    "boundary_discovery": {
                        "algorithm": "state_reward_predictability_change_points",
                        "independent_of_subgoal_labels": True,
                    },
                    "initiation_set": {
                        "object_classes": [value for value, _ in row["starts"].most_common(12)],
                        "object_roles": [value for value, _ in row["roles"].most_common(12)],
                        "relations": [value for value, _ in row["relations"].most_common(12)],
                    },
                    "parameterized_policy": {
                        "action_distribution": action_policy,
                        "target_role_parameters": [value for value, _ in row["parameters"].most_common(12) if value],
                        "semantic_target_ratio": round(semantic_ratio, 6),
                        "coordinate_specific": semantic_ratio < 0.5,
                    },
                    "termination": {
                        "effects": [value for value, _ in row["ends"].most_common(12)],
                        "stop_on_terminal": True,
                        "stop_on_state_change_point": True,
                        "stop_on_predictability_change": True,
                    },
                    "failure_recovery": row["recoveries"].most_common(1)[0][0] if row["recoveries"] else "stop_and_ask",
                    "support_episodes": support,
                    "success_rate": round(success_rate, 6),
                    "success_rate_ci95_lower": round(lower, 6),
                    "applicable_game_types": sorted(types),
                    "applicable_games": sorted(games),
                    "verified_holdout_games": sorted(holdout_games),
                    "verified_holdout_game_types": sorted(holdout_types),
                    "ui_layout_count": len(themes),
                    "risk_level": row["risk"],
                    "promotion_rule": "global_requires_verified_cross_game_holdout_semantic_effect_evidence",
                }
            )
            if len(discovered) >= 128:
                break
        return {
            "schema_version": SKILL_DISCOVERY_SCHEMA_VERSION,
            "algorithm": "change_point_object_effect_option_induction",
            "independent_of_existing_subgoal_labels": True,
            "hierarchy": ["global", "game_type", "single_game"],
            "skills": discovered,
        }


class ExperienceReplayPortfolio:
    categories = (
        "immutable_raw",
        "deduplicated_training",
        "high_value_failure",
        "human_correction",
        "terminal_boundary",
        "ood_and_danger_negative",
        "cross_game_skill",
    )

    @staticmethod
    def _context(item):
        return item.get("context", {}) if isinstance(item, dict) and isinstance(item.get("context"), dict) else {}

    @classmethod
    def _group_key(cls, item):
        context = cls._context(item)
        return "|".join(
            (
                str(item.get("game_id") or context.get("game_id") or "unknown"),
                normalized_identifier(item.get("task_id") or context.get("task_id"), "default", 96),
                str(context.get("save_id") or context.get("save_slot") or item.get("save_id") or "unknown"),
                str(context.get("level_id") or context.get("level") or "unknown"),
                str(item.get("session") or context.get("session_id") or item.get("episode_id") or "unknown"),
                str(context.get("resolution") or context.get("resolution_and_dpi") or "unknown"),
                str(context.get("ui_skin") or "default"),
                str(context.get("popup_type") or context.get("popup_variant") or "none"),
                str(context.get("frame_rate_group") or context.get("frame_rate") or "unknown"),
                str(context.get("input_latency_group") or context.get("input_latency") or "unknown"),
            )
        )

    @classmethod
    def _dedup_key(cls, item):
        context = cls._context(item)
        observation = item.get("observation_t", {}) if isinstance(item.get("observation_t"), dict) else {}
        visual = str(
            context.get("perceptual_hash")
            or observation.get("perceptual_hash")
            or observation.get("visual_digest")
            or ""
        )
        objects = []
        for value in observation.get("objects", []) if isinstance(observation.get("objects"), list) else []:
            if not isinstance(value, dict):
                continue
            bbox = value.get("bbox", [0.0, 0.0, 0.0, 0.0])
            coarse = (
                [round(safe_float(entry, 0.0) * 8) / 8 for entry in list(bbox)[:4]]
                if isinstance(bbox, (list, tuple))
                else []
            )
            objects.append(
                (str(value.get("class", "unknown")), str(value.get("role", "")), str(value.get("text", "")), coarse)
            )
        scene = hashlib.sha256(canonical_bytes(sorted(objects))).hexdigest()[:20]
        semantic = normalize_semantic_action(item.get("semantic_action"))
        action = (
            semantic_action_signature(semantic)
            if semantic is not None
            else str(item.get("action_t") or item.get("action") or "")
        )
        game_id = str(item.get("game_id") or context.get("game_id") or "unknown")
        task_id = normalized_identifier(item.get("task_id") or context.get("task_id"), "default", 96)
        return hashlib.sha256(
            canonical_bytes(
                {"game_id": game_id, "task_id": task_id, "visual": visual[:32], "scene": scene, "action": action}
            )
        ).hexdigest()

    @classmethod
    def _priority(cls, item):
        context = cls._context(item)
        score = 2.0 * safe_float(context.get("model_disagreement", item.get("uncertainty", 0.0)), 0.0)
        score += 1.5 * abs(safe_float(item.get("td_error", item.get("prediction_error", 0.0)), 0.0))
        score += 2.0 * int(bool(item.get("human_override"))) + 1.8 * int(
            bool(item.get("success") or item.get("failure"))
        )
        score += 1.4 * int(bool(context.get("ood"))) + 1.2 * int(bool(context.get("cross_game_transfer")))
        score += 1.0 * int(bool(item.get("failure"))) + 0.8 * int(bool(context.get("rare_relation")))
        return score

    @classmethod
    def deduplicate(cls, experiences, limit=MAX_TRAINING_SAMPLES):
        representatives = {}
        for item in experiences or []:
            if not isinstance(item, dict):
                continue
            key = cls._dedup_key(item)
            previous = representatives.get(key)
            if previous is None or cls._priority(item) > cls._priority(previous):
                representatives[key] = item
        by_family = defaultdict(list)
        for key, item in representatives.items():
            semantic = normalize_semantic_action(item.get("semantic_action"))
            family = (
                semantic_action_family_key(semantic)
                if semantic is not None
                else str(item.get("action_t") or "unknown").split("|")[0]
            )
            by_family[family].append((cls._priority(item), key, item))
        ordered = []
        family_rows = [sorted(values, key=lambda row: (-row[0], row[1])) for values in by_family.values()]
        index = 0
        while len(ordered) < max(1, int(limit)) and any(index < len(values) for values in family_rows):
            for values in family_rows:
                if index < len(values) and len(ordered) < max(1, int(limit)):
                    ordered.append(values[index][2])
            index += 1
        return ordered

    @classmethod
    def partition(cls, experiences, portfolio, split="train", limit=MAX_TRAINING_SAMPLES):
        value = portfolio if isinstance(portfolio, dict) else {}
        manifest = (
            value.get("immutable_training_manifest", {})
            if isinstance(value.get("immutable_training_manifest"), dict)
            else {}
        )
        rows = manifest.get("rows", []) if isinstance(manifest.get("rows"), list) else []
        selected = {str(row.get("dedup_key")) for row in rows if isinstance(row, dict) and row.get("split") == split}
        deduplicated = cls.deduplicate(experiences, limit)
        if not selected:
            return deduplicated if split == "train" else []
        return [item for item in deduplicated if cls._dedup_key(item) in selected]

    @classmethod
    def _base_build_strict(cls, experiences, limit=MAX_TRAINING_SAMPLES):
        raw = [item for item in experiences or [] if isinstance(item, dict)]
        deduplicated = cls.deduplicate(raw, limit)
        buckets = {name: [] for name in cls.categories}
        buckets["immutable_raw"] = raw
        buckets["deduplicated_training"] = deduplicated
        for item in raw:
            context = cls._context(item)
            if item.get("failure") or safe_float(item.get("reward_t", 0.0), 0.0) < -0.2:
                buckets["high_value_failure"].append(item)
            if item.get("human_override") or context.get("human_correction"):
                buckets["human_correction"].append(item)
            if (
                item.get("success")
                or item.get("failure")
                or item.get("pre_terminal")
                or context.get("terminal") in {"success", "failure"}
            ):
                buckets["terminal_boundary"].append(item)
            semantic = normalize_semantic_action(item.get("semantic_action"))
            if (
                context.get("ood")
                or str((semantic or {}).get("risk_class", "safe")) in {"caution", "irreversible"}
                and not item.get("success")
            ):
                buckets["ood_and_danger_negative"].append(item)
            if context.get("generalization_level", 0) in {3, 4} or context.get("cross_game_transfer"):
                buckets["cross_game_skill"].append(item)
        groups = defaultdict(list)
        game_groups = defaultdict(list)
        for item in deduplicated:
            group = cls._group_key(item)
            groups[group].append(item)
            context = cls._context(item)
            game_id = str(item.get("game_id") or context.get("game_id") or "unknown")
            if group not in game_groups[game_id]:
                game_groups[game_id].append(group)
        game_ids = sorted(game_groups, key=lambda value: hashlib.sha256(value.encode("utf-8", "replace")).hexdigest())
        split_game_ids = {"train": [], "validation": [], "test": []}
        if len(game_ids) >= 3:
            train_count = max(1, min(len(game_ids) - 2, int(math.floor(len(game_ids) * 0.70))))
            validation_count = max(1, min(len(game_ids) - train_count - 1, int(math.floor(len(game_ids) * 0.15))))
            split_game_ids["train"] = game_ids[:train_count]
            split_game_ids["validation"] = game_ids[train_count : train_count + validation_count]
            split_game_ids["test"] = game_ids[train_count + validation_count :]
            isolation_complete = bool(
                split_game_ids["train"] and split_game_ids["validation"] and split_game_ids["test"]
            )
            isolation_reason = "" if isolation_complete else "game_id_split_empty"
        elif len(game_ids) == 2:
            split_game_ids["train"] = [game_ids[0]]
            split_game_ids["validation"] = [game_ids[1]]
            isolation_complete = False
            isolation_reason = "至少需要三个独立游戏才能同时建立训练、验证和测试集"
        else:
            split_game_ids["train"] = list(game_ids)
            isolation_complete = False
            isolation_reason = "至少需要三个独立游戏才能证明跨游戏泛化"
        game_to_split = {game_id: split for split, values in split_game_ids.items() for game_id in values}
        split_groups = {"train": [], "validation": [], "test": []}
        for game_id, values in game_groups.items():
            split = game_to_split.get(game_id, "train")
            split_groups[split].extend(
                sorted(values, key=lambda value: hashlib.sha256(value.encode("utf-8", "replace")).hexdigest())
            )
        split_sets = {name: set(values) for name, values in split_groups.items()}
        overlap = bool(
            split_sets["train"] & split_sets["validation"]
            or split_sets["train"] & split_sets["test"]
            or split_sets["validation"] & split_sets["test"]
        )
        game_overlap = bool(
            set(split_game_ids["train"]) & set(split_game_ids["validation"])
            or set(split_game_ids["train"]) & set(split_game_ids["test"])
            or set(split_game_ids["validation"]) & set(split_game_ids["test"])
        )
        manifest_rows = []
        for item in deduplicated:
            group = cls._group_key(item)
            context = cls._context(item)
            game_id = str(item.get("game_id") or context.get("game_id") or "unknown")
            split = game_to_split.get(game_id, "train")
            manifest_rows.append(
                {
                    "dedup_key": cls._dedup_key(item),
                    "group": group,
                    "game_id": game_id,
                    "split": split,
                    "source_checksum": str(item.get("source_sample_checksum", "")),
                }
            )
        manifest = {
            "schema_version": 3,
            "immutable": True,
            "group_fields": ["game", "task", "save", "level", "session", "resolution", "ui_skin", "popup_type", "frame_rate", "input_latency"],
            "stratification_dimensions": [
                "game_type",
                "game_id",
                "task_id",
                "level",
                "session",
                "ui_skin",
                "language",
                "resolution_and_dpi",
                "action_family",
                "success_failure",
                "risk_level",
                "human_correction",
                "no_effect",
                "popup_and_interference",
            ],
            "raw_count": len(raw),
            "deduplicated_count": len(deduplicated),
            "rows": manifest_rows,
            "split_groups": split_groups,
            "split_game_ids": split_game_ids,
            "group_overlap": overlap,
            "game_id_overlap": game_overlap,
            "game_id_isolated": not game_overlap,
            "split_complete": isolation_complete,
            "split_status": "passed" if isolation_complete and not overlap and not game_overlap else "not_evaluated",
            "split_reason": isolation_reason,
        }
        manifest["checksum"] = hashlib.sha256(canonical_bytes(manifest)).hexdigest()
        priority = sorted(
            ((cls._priority(item), str(item.get("source_sample_checksum", ""))) for item in raw), reverse=True
        )
        return {
            "schema_version": EXPERIENCE_PORTFOLIO_SCHEMA_VERSION,
            "categories": {name: len(values) for name, values in buckets.items()},
            "deduplication": {
                "algorithm": "perceptual_scene_graph_semantic_action",
                "removed": len(raw) - len(deduplicated),
                "rare_and_hard_negative_retention": True,
                "action_family_balancing": True,
            },
            "immutable_training_manifest": manifest,
            "priority_keys": [value for _, value in priority[: max(1, min(int(limit), 4096))]],
            "priority_formula": [
                "model_disagreement",
                "td_or_prediction_error",
                "rare_task_or_relation",
                "human_correction",
                "danger_boundary",
                "terminal_state",
                "cross_game_value",
            ],
        }

    @classmethod
    def build(cls, experiences, limit=MAX_TRAINING_SAMPLES):
        return _strict_portfolio_build(cls, experiences, limit)


_ONLINE_ACCEPTANCE_LOCK = threading.RLock()


def online_acceptance_relative_path(game_id):
    token = normalized_identifier(game_id, "game", 96)
    return Path("audit") / "online_acceptance" / (token + ".json")


def _online_acceptance_empty(game_id):
    return {
        "schema_version": ONLINE_ACCEPTANCE_SCHEMA_VERSION,
        "game_id": str(game_id),
        "records": [],
        "updated": 0.0,
    }


def _online_record_payload(record):
    value = dict(record) if isinstance(record, dict) else {}
    value.pop("checksum", None)
    return value


def _validate_online_acceptance_record(record, game_id="", model_fingerprint=""):
    if not isinstance(record, dict):
        return False
    payload = _online_record_payload(record)
    checksum = str(record.get("checksum", ""))
    if checksum != hashlib.sha256(canonical_bytes(payload)).hexdigest():
        return False
    if safe_int(payload.get("schema_version"), 0) != ONLINE_ACCEPTANCE_SCHEMA_VERSION:
        return False
    if game_id and str(payload.get("game_id", "")) != str(game_id):
        return False
    if model_fingerprint and str(payload.get("model_fingerprint", "")) != str(model_fingerprint):
        return False
    if str(payload.get("execution_mode", "")) != "real_online_episode":
        return False
    if not bool(payload.get("fixed_initial_state")) and not str(payload.get("repeatable_restart_protocol", "")):
        return False
    required = ("episode_id", "task_id", "started", "finished", "duration_seconds", "action_count")
    return all(str(payload.get(name, "")) != "" for name in required)


def load_online_acceptance_records(base, game_id, model_fingerprint=""):
    root = Path(base).expanduser().resolve()
    path = root / online_acceptance_relative_path(game_id)
    with _ONLINE_ACCEPTANCE_LOCK:
        try:
            raw = path.read_bytes()
        except FileNotFoundError:
            return []
        if len(raw) > 16 * 1024 * 1024:
            return []
        try:
            document = json.loads(raw.decode("utf-8"))
        except (ValueError, UnicodeError):
            return []
    if (
        not isinstance(document, dict)
        or safe_int(document.get("schema_version"), 0) != ONLINE_ACCEPTANCE_SCHEMA_VERSION
    ):
        return []
    checksum = str(document.get("checksum", ""))
    body = dict(document)
    body.pop("checksum", None)
    if checksum != hashlib.sha256(canonical_bytes(body)).hexdigest():
        return []
    records = []
    for record in document.get("records", []):
        if _validate_online_acceptance_record(record, game_id, model_fingerprint):
            records.append(dict(record))
    records.sort(key=lambda item: (safe_float(item.get("finished"), 0.0), str(item.get("episode_id", ""))))
    return records


def append_online_acceptance_record(base, game_id, record):
    root = Path(base).expanduser().resolve()
    value = _online_record_payload(record)
    value.update(
        {
            "schema_version": ONLINE_ACCEPTANCE_SCHEMA_VERSION,
            "game_id": str(game_id),
            "execution_mode": "real_online_episode",
        }
    )
    value["checksum"] = hashlib.sha256(canonical_bytes(value)).hexdigest()
    with _ONLINE_ACCEPTANCE_LOCK:
        existing = load_online_acceptance_records(root, game_id)
        by_id = {str(item.get("episode_id", "")): item for item in existing if str(item.get("episode_id", ""))}
        by_id[str(value.get("episode_id", uuid.uuid4().hex))] = value
        records = sorted(
            by_id.values(),
            key=lambda item: (safe_float(item.get("finished"), 0.0), str(item.get("episode_id", ""))),
        )[-2000:]
        document = _online_acceptance_empty(game_id)
        document["records"] = records
        document["updated"] = time.time()
        document["checksum"] = hashlib.sha256(canonical_bytes(document)).hexdigest()
        relative = online_acceptance_relative_path(game_id)
        atomic_write_text(
            root,
            relative,
            json.dumps(document, ensure_ascii=False, sort_keys=True, separators=(",", ":")),
        )
    return dict(value)


class PairedHumanAIBenchmark:
    minimum_episodes = RUNTIME_THRESHOLDS.online_acceptance_minimum_episodes
    target_episodes = RUNTIME_THRESHOLDS.online_acceptance_target_episodes
    maximum_episodes = RUNTIME_THRESHOLDS.online_acceptance_maximum_episodes

    @staticmethod
    def _wilson_interval(successes, total, z=1.96):
        count = max(0, int(total))
        if count < 1:
            return 0.0, 1.0
        proportion = max(0.0, min(1.0, float(successes) / count))
        denominator = 1.0 + z * z / count
        center = proportion + z * z / (2.0 * count)
        margin = z * math.sqrt((proportion * (1.0 - proportion) + z * z / (4.0 * count)) / count)
        return max(0.0, (center - margin) / denominator), min(1.0, (center + margin) / denominator)

    @classmethod
    def _human_baseline(cls, experiences):
        episodes = defaultdict(list)
        for item in experiences or []:
            if not isinstance(item, dict):
                continue
            episode_id = str(item.get("episode_id") or item.get("session") or item.get("session_id") or "")
            if episode_id:
                episodes[episode_id].append(item)
        rows = []
        for episode_id, values in episodes.items():
            values = sorted(
                values,
                key=lambda item: (
                    safe_int(item.get("step_id"), 0),
                    safe_float(item.get("created_t"), 0.0),
                ),
            )
            digest = int(hashlib.sha256(episode_id.encode("utf-8", "replace")).hexdigest()[:8], 16)
            if digest % 4 != 0:
                continue
            success = any(
                bool(item.get("success"))
                or str(item.get("terminal_state", "")) == "success"
                for item in values
            )
            started = min((safe_float(item.get("created_t"), 0.0) for item in values), default=0.0)
            finished = max(
                (
                    safe_float(item.get("created_t+1", item.get("created_t", 0.0)), 0.0)
                    for item in values
                ),
                default=started,
            )
            task_id = normalized_identifier(
                next(
                    (item.get("task_id") for item in values if item.get("task_id")),
                    "default",
                ),
                "default",
                96,
            )
            rows.append(
                {
                    "episode_id_hash": hashlib.sha256(episode_id.encode()).hexdigest()[:16],
                    "task_id": task_id,
                    "success": bool(success),
                    "duration_seconds": max(0.001, finished - started),
                    "action_count": max(1, len(values)),
                }
            )
        successes = sum(int(item["success"]) for item in rows)
        lower, upper = cls._wilson_interval(successes, len(rows))
        successful = [item for item in rows if item["success"]]
        return {
            "episodes": rows,
            "episode_count": len(rows),
            "successes": successes,
            "success_rate": successes / max(1, len(rows)),
            "success_rate_lower_bound": lower,
            "success_rate_upper_bound": upper,
            "completion_time_median": (
                statistics.median([item["duration_seconds"] for item in successful])
                if successful
                else float("inf")
            ),
            "operation_count_median": (
                statistics.median([item["action_count"] for item in successful])
                if successful
                else float("inf")
            ),
            "source": "deterministic_independent_human_holdout",
        }

    @staticmethod
    def _actual_action_id(row):
        for key in ("action_t", "action_id", "action"):
            value = row.get(key)
            if isinstance(value, str) and value:
                return value
        action = row.get("semantic_action") or row.get("a")
        if isinstance(action, dict):
            try:
                return semantic_action_signature(action)
            except (ValueError, TypeError):
                return canonical_action(action)
        return str(action or "")

    @classmethod
    def _offline_prescreen(cls, experiences, model):
        bundle = (model.get("value_model") or {}).get("neural_bundle", {}) if isinstance(model, dict) else {}
        vocabulary = list(bundle.get("action_vocabulary", []))[:96] if isinstance(bundle, dict) else []
        rows = []
        dangerous_actions = set()
        for source_item in experiences or []:
            if not isinstance(source_item, dict):
                continue
            semantic = (
                source_item.get("semantic_action", {})
                if isinstance(source_item.get("semantic_action"), dict)
                else {}
            )
            action_id = cls._actual_action_id(source_item)
            if str(semantic.get("risk_class", "safe")) in {"caution", "irreversible"} and action_id:
                dangerous_actions.add(action_id)
            counterfactual = (
                source_item.get("counterfactual_training", {})
                if isinstance(source_item.get("counterfactual_training"), dict)
                else {}
            )
            for negative in counterfactual.get("forbidden_actions", []):
                if (
                    isinstance(negative, dict)
                    and negative.get("risk_label") == "dangerous"
                    and negative.get("action_id")
                ):
                    dangerous_actions.add(str(negative["action_id"]))
        for item in experiences or []:
            if not isinstance(item, dict):
                continue
            identity = str(
                item.get("source_sample_checksum")
                or item.get("experience_id")
                or item.get("episode_id")
                or ""
            )
            if not identity or int(hashlib.sha256(identity.encode("utf-8", "replace")).hexdigest()[:8], 16) % 5 != 0:
                continue
            observation = item.get("observation_t", {}) if isinstance(item.get("observation_t"), dict) else {}
            actual = cls._actual_action_id(item)
            task_id = normalized_identifier(item.get("task_id"), str(model.get("default_task_id", "default")), 96)
            if not actual or not vocabulary or not bundle.get("trained"):
                continue
            predictions = neural_offline_policy_predictions({"neural_bundle": bundle}, observation, vocabulary, task_id)
            ranked = []
            for action_id in vocabulary:
                prediction = predictions.get(str(action_id), {})
                score = (
                    safe_float(prediction.get("q_value"), 0.0)
                    + safe_float(prediction.get("success_probability"), 0.0)
                    - 2.0 * safe_float(prediction.get("risk_probability"), 1.0)
                    - safe_float(prediction.get("uncertainty"), 1.0)
                )
                ranked.append((score, str(action_id), prediction))
            if not ranked:
                continue
            _, selected, prediction = max(ranked, key=lambda value: value[0])
            correct = selected == actual
            terminal_success = bool(item.get("success")) or str(item.get("terminal_state", "")) == "success"
            reward = max(-1.0, min(1.0, safe_float(item.get("reward_t", item.get("reward", 0.0)), 0.0)))
            uncertainty = safe_float(prediction.get("uncertainty"), 1.0, 0.0, 1.0)
            success_probability = safe_float(prediction.get("success_probability"), 0.0, 0.0, 1.0)
            risk_probability = safe_float(prediction.get("risk_probability"), 1.0, 0.0, 1.0)
            q_value = max(-1.0, min(1.0, math.tanh(safe_float(prediction.get("q_value"), 0.0))))
            rows.append(
                {
                    "state_key": str(item.get("state_id") or item.get("observation_t", {}).get("state_id", "")),
                    "selected": selected,
                    "actual": actual,
                    "correct": correct,
                    "uncertainty": uncertainty,
                    "success_probability": success_probability,
                    "success_target": float(terminal_success),
                    "risk_probability": risk_probability,
                    "selected_dangerous": selected in dangerous_actions,
                    "q_value": q_value,
                    "reward_target": reward,
                }
            )
        count = len(rows)
        accuracy = sum(int(item["correct"]) for item in rows) / max(1, count)
        dangerous_false = sum(
            1
            for item in rows
            if not item["correct"] and item.get("selected_dangerous")
        )
        ood_calibration = (
            statistics.fmean(
                abs(item["uncertainty"] - float(not item["correct"]))
                for item in rows
            )
            if rows
            else 1.0
        )
        success_brier = (
            statistics.fmean(
                (item["success_probability"] - item["success_target"]) ** 2
                for item in rows
            )
            if rows
            else 1.0
        )
        q_mae = statistics.fmean(abs(item["q_value"] - item["reward_target"]) for item in rows) if rows else 1.0
        per_state = defaultdict(set)
        for item in rows:
            if item["state_key"]:
                per_state[item["state_key"]].add(item["selected"])
        drift_states = sum(1 for values in per_state.values() if len(values) > 1)
        decision_drift = drift_states / max(1, len(per_state))
        minimum = max(20, min(100, len(experiences or []) // 10))
        reasons = []
        if count < minimum:
            reasons.append("offline_independent_holdout_too_small")
        if accuracy < 0.60:
            reasons.append("offline_action_accuracy_below_60_percent")
        if dangerous_false:
            reasons.append("offline_risk_false_release_nonzero")
        if ood_calibration > 0.20:
            reasons.append("ood_calibration_error_above_20_percent")
        if success_brier > 0.25:
            reasons.append("success_probability_brier_above_0_25")
        if q_mae > 0.35:
            reasons.append("q_value_calibration_mae_above_0_35")
        if decision_drift > 0.10:
            reasons.append("replay_decision_drift_above_10_percent")
        return {
            "stage": "offline_prescreen",
            "passed": not reasons,
            "reasons": reasons,
            "independent_holdout_samples": count,
            "minimum_holdout_samples": minimum,
            "action_accuracy": accuracy,
            "dangerous_false_release_count": dangerous_false,
            "ood_calibration_error": ood_calibration,
            "success_probability_brier": success_brier,
            "q_value_calibration_mae": q_mae,
            "replay_decision_drift_rate": decision_drift,
            "training_data_excluded_by_deterministic_partition": True,
        }

    @classmethod
    def _online_acceptance(cls, records, human):
        valid = [dict(item) for item in records or [] if _validate_online_acceptance_record(item)]
        by_task = defaultdict(list)
        for item in valid:
            by_task[normalized_identifier(item.get("task_id"), "default", 96)].append(item)
        selected = []
        for task_id, values in by_task.items():
            values.sort(key=lambda item: safe_float(item.get("finished"), 0.0))
            selected.extend(values[-cls.maximum_episodes :])
        selected.sort(key=lambda item: safe_float(item.get("finished"), 0.0))
        successes = sum(int(bool(item.get("success"))) for item in selected)
        lower, upper = cls._wilson_interval(successes, len(selected))
        successful = [item for item in selected if bool(item.get("success"))]
        ai_time = (
            statistics.median(
                [safe_float(item.get("duration_seconds"), float("inf")) for item in successful]
            )
            if successful
            else float("inf")
        )
        ai_actions = (
            statistics.median([safe_int(item.get("action_count"), 0) for item in successful])
            if successful
            else float("inf")
        )
        dangerous = sum(safe_int(item.get("dangerous_false_release_count"), 0) for item in selected)
        interventions = sum(int(bool(item.get("human_intervention"))) for item in selected)
        stuck = sum(int(bool(item.get("stuck"))) for item in selected)
        task_counts = {task: len(values[-cls.maximum_episodes :]) for task, values in by_task.items()}
        required_tasks = sorted(
            {str(item.get("task_id", "default")) for item in human.get("episodes", [])}
            or set(task_counts)
            or {"default"}
        )
        missing = {task: max(0, cls.minimum_episodes - task_counts.get(task, 0)) for task in required_tasks}
        enough = bool(required_tasks) and all(value == 0 for value in missing.values())
        human_lower = safe_float(human.get("success_rate_lower_bound"), 0.0)
        human_episode_count = safe_int(human.get("episode_count"), 0, 0)
        time_better = ai_time < safe_float(human.get("completion_time_median"), float("inf"))
        actions_better = ai_actions < safe_float(human.get("operation_count_median"), float("inf"))
        reasons = []
        if human_episode_count < 8:
            reasons.append("independent_human_baseline_too_small_for_confidence_interval")
        if not enough:
            reasons.append("minimum_real_online_episodes_per_task_not_met")
        if lower < RUNTIME_THRESHOLDS.minimum_ai_success_lower:
            reasons.append("ai_success_lower_bound_below_absolute_80_percent")
        if lower < human_lower - RUNTIME_THRESHOLDS.human_noninferiority_margin:
            reasons.append("ai_success_not_noninferior_to_human_lower_bound")
        if not (time_better or actions_better):
            reasons.append("neither_real_completion_time_nor_action_count_improved")
        if dangerous:
            reasons.append("real_online_dangerous_false_release_nonzero")
        if interventions:
            reasons.append("real_online_human_intervention_nonzero")
        strata = defaultdict(lambda: {"episodes": 0, "successes": 0})
        for item in selected:
            key = "|".join(
                str(item.get(name, "unknown"))
                for name in ("resolution", "ui_skin", "popup_variant", "frame_rate_group")
            )
            strata[key]["episodes"] += 1
            strata[key]["successes"] += int(bool(item.get("success")))
        for value in strata.values():
            value["success_rate"] = value["successes"] / max(1, value["episodes"])
            value["wilson_95"] = list(cls._wilson_interval(value["successes"], value["episodes"]))
        return {
            "stage": "real_online_acceptance",
            "passed": not reasons,
            "reasons": reasons,
            "evaluation_episodes": len(selected),
            "minimum_episodes_per_task": cls.minimum_episodes,
            "target_episodes_per_task": cls.target_episodes,
            "maximum_episodes_per_task": cls.maximum_episodes,
            "task_episode_counts": task_counts,
            "remaining_episodes_by_task": missing,
            "successes": successes,
            "success_rate": successes / max(1, len(selected)),
            "success_rate_lower_bound": lower,
            "success_rate_upper_bound": upper,
            "human_baseline_episode_count": human_episode_count,
            "human_success_rate_lower_bound": human_lower,
            "completion_time_median": ai_time,
            "operation_count_median": ai_actions,
            "dangerous_actions": dangerous,
            "human_interventions": interventions,
            "stuck_episodes": stuck,
            "stratified_results": dict(strata),
            "fixed_initial_state_or_repeatable_restart_required": True,
            "durations_are_measured_not_inferred": True,
            "records_are_real_online_execution": True,
        }

    @classmethod
    def evaluate(cls, experiences, model, online_records=None):
        human = cls._human_baseline(experiences)
        offline = cls._offline_prescreen(experiences, model)
        online = cls._online_acceptance(online_records, human)
        reasons = []
        if not offline.get("passed"):
            reasons.extend("offline:" + reason for reason in offline.get("reasons", []))
        if not online.get("passed"):
            reasons.extend("online:" + reason for reason in online.get("reasons", []))
        return {
            "schema_version": ONLINE_ACCEPTANCE_SCHEMA_VERSION,
            "evaluation_mode": "two_stage_offline_prescreen_plus_real_online_acceptance",
            "offline_prescreen": offline,
            "online_acceptance": online,
            "evaluation_episodes": online.get("evaluation_episodes", 0),
            "minimum_episodes": cls.minimum_episodes,
            "human": human,
            "ai": online,
            "promote": not reasons,
            "pending_online_acceptance": bool(offline.get("passed") and not online.get("passed")),
            "reasons": reasons,
            "offline_results_never_count_as_online_success": True,
            "inferred_ai_duration_forbidden": True,
        }


class ModelPromotionGate:
    @staticmethod
    def _metrics(model):
        value = model if isinstance(model, dict) else {}
        validation = value.get("validation", {}) if isinstance(value.get("validation"), dict) else {}
        episode = value.get("episode_metrics", {}) if isinstance(value.get("episode_metrics"), dict) else {}
        generalization = (
            value.get("generalization_evaluation", {})
            if isinstance(value.get("generalization_evaluation"), dict)
            else {}
        )
        dangerous = safe_int(validation.get("dangerous_false", 0), 0)
        evaluated_levels = []
        failed_levels = []
        for level, row in (
            generalization.get("levels", {}).items() if isinstance(generalization.get("levels"), dict) else []
        ):
            if not isinstance(row, dict):
                continue
            dangerous += safe_int((row.get("metrics") or {}).get("dangerous_action_false_release_count", 0), 0)
            if row.get("evaluated"):
                evaluated_levels.append(safe_int(level, 0, 0, 4))
            if row.get("status") == "failed":
                failed_levels.append(safe_int(level, 0, 0, 4))
        claimed = {
            safe_int(level, 0, 0, 4) for level in generalization.get("claimed_levels", []) if safe_int(level, 0, 0, 4)
        }
        return {
            "coverage": safe_float(validation.get("coverage", 0.0), 0.0),
            "overall_accuracy": safe_float(validation.get("overall_accuracy", 0.0), 0.0),
            "error_upper_95": safe_float(validation.get("error_upper_95", 1.0), 1.0),
            "success_rate": safe_float(episode.get("task_success_rate", 0.0), 0.0),
            "mean_reward": safe_float(episode.get("mean_episode_reward", 0.0), 0.0),
            "average_actions": safe_float(episode.get("average_actions", float("inf")), float("inf")),
            "human_override_count": safe_int(episode.get("human_override_count", 0), 0),
            "dangerous_false": dangerous,
            "benchmark_verified": bool(generalization.get("benchmark_verified")),
            "evaluated_levels": sorted(value for value in evaluated_levels if value),
            "failed_levels": sorted(value for value in failed_levels if value),
            "claimed_levels": sorted(claimed),
            "model_scope": generalization_model_scope(generalization),
        }

    @classmethod
    def evaluate(cls, champion, challenger, validation_status):
        challenger_metrics = cls._metrics(challenger)
        champion_metrics = cls._metrics(champion)
        reasons = []
        if str(validation_status) != "passed":
            reasons.append("challenger_not_fully_validated")
        if challenger_metrics["dangerous_false"] != 0:
            reasons.append("dangerous_action_false_release_nonzero")
        paired = (
            challenger.get("human_ai_benchmark", {})
            if isinstance(challenger, dict) and isinstance(challenger.get("human_ai_benchmark"), dict)
            else {}
        )
        if not paired.get("promote"):
            reasons.extend(
                "human_baseline_gate:" + str(reason)
                for reason in paired.get("reasons", ["missing_paired_human_ai_benchmark"])
            )
        if challenger_metrics["failed_levels"]:
            reasons.append("evaluated_generalization_level_failed")
        if challenger_metrics["model_scope"] == "general_model":
            if not challenger_metrics["benchmark_verified"]:
                reasons.append("general_model_without_verified_benchmark")
            if not {3, 4}.issubset(set(challenger_metrics["claimed_levels"])):
                reasons.append("general_model_without_level_3_and_4")
        if isinstance(champion, dict) and champion:
            if challenger_metrics["overall_accuracy"] + 0.005 < champion_metrics["overall_accuracy"]:
                reasons.append("overall_accuracy_regressed")
            if challenger_metrics["coverage"] + 0.01 < champion_metrics["coverage"]:
                reasons.append("coverage_regressed")
            if challenger_metrics["error_upper_95"] > champion_metrics["error_upper_95"] + 0.005:
                reasons.append("error_bound_regressed")
            if challenger_metrics["success_rate"] + 0.02 < champion_metrics["success_rate"]:
                reasons.append("task_success_regressed")
            if challenger_metrics["mean_reward"] + 0.05 < champion_metrics["mean_reward"]:
                reasons.append("episode_reward_regressed")
            if (
                math.isfinite(champion_metrics["average_actions"])
                and challenger_metrics["average_actions"] > champion_metrics["average_actions"] * 1.10 + 1.0
            ):
                reasons.append("average_actions_regressed")
            if (
                champion_metrics["model_scope"] == "general_model"
                and challenger_metrics["model_scope"] != "general_model"
            ):
                reasons.append("generalization_scope_regressed")
        return {
            "schema_version": MODEL_PROMOTION_SCHEMA_VERSION,
            "role": "challenger",
            "champion_present": bool(isinstance(champion, dict) and champion),
            "promote": not reasons,
            "reasons": reasons,
            "champion_metrics": champion_metrics,
            "challenger_metrics": challenger_metrics,
            "model_scope": challenger_metrics["model_scope"],
            "human_ai_benchmark": paired,
            "display_label": "通用模型" if challenger_metrics["model_scope"] == "general_model" else "单游戏模型",
            "atomic_switch_required": True,
            "pending_online_acceptance": bool(paired.get("pending_online_acceptance")),
            "discard_on_failure": not bool(paired.get("pending_online_acceptance")),
            "general_scope_requires_real_level_3_and_4": True,
        }


def top_level_symbol_inventory(source):
    tree = ast.parse(str(source))
    inventory = defaultdict(list)
    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            inventory[node.name].append(node.lineno)
        elif isinstance(node, (ast.Assign, ast.AnnAssign)):
            targets = node.targets if isinstance(node, ast.Assign) else [node.target]
            for target in targets:
                if isinstance(target, ast.Name):
                    inventory[target.id].append(node.lineno)
    return dict(inventory)


def assert_no_duplicate_top_level_symbols(path=None):
    target = Path(path or __file__).resolve()
    inventory = top_level_symbol_inventory(target.read_text(encoding="utf-8"))
    duplicates = {name: lines for name, lines in inventory.items() if len(lines) > 1}
    if duplicates:
        raise AssertionError(
            "重复顶层符号：" + json.dumps(duplicates, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        )
    return True


def assert_single_default_component_assignment(path=None):
    target = Path(path or __file__).resolve()
    inventory = top_level_symbol_inventory(target.read_text(encoding="utf-8"))
    expected = ("DEFAULT_OBSERVATION_ENCODER", "DEFAULT_TASK_PLANNER", "DEFAULT_SKILL_POLICY", "DEFAULT_SAFETY_SHIELD")
    invalid = {name: inventory.get(name, []) for name in expected if len(inventory.get(name, [])) != 1}
    if invalid:
        raise AssertionError(
            "默认组件必须且只能赋值一次："
            + json.dumps(invalid, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        )
    return True


_SOURCE_CONTRACTS_VALIDATED = False


def validate_source_contracts_once(path=None):
    global _SOURCE_CONTRACTS_VALIDATED
    if _SOURCE_CONTRACTS_VALIDATED:
        return True
    assert_no_duplicate_top_level_symbols(path)
    assert_single_default_component_assignment(path)
    _SOURCE_CONTRACTS_VALIDATED = True
    return True



DEFAULT_OBSERVATION_ENCODER = ObjectCentricObservationEncoder()
DEFAULT_TASK_PLANNER = HierarchicalTaskPlanner()
DEFAULT_SKILL_POLICY = ReusableSkillPolicy()

DEFAULT_SAFETY_SHIELD = IndependentSafetyShield()


class StructuredRuntimeEventLogger:
    def __init__(self):
        self.lock = threading.RLock()
        self.sequence = 0

    def emit(self, event, **payload):
        store = APP_CONTEXT.store
        base = getattr(store, "base", None) if store is not None else None
        if not base:
            return None
        clean = {str(key): freeze_ui_payload(value) for key, value in payload.items()}
        with self.lock:
            self.sequence += 1
            row = {
                "schema_version": 2,
                "event": str(event),
                "sequence": self.sequence,
                "created": time.time(),
                "monotonic": time.monotonic(),
                "pid": os.getpid(),
                "thread": threading.current_thread().name,
                **clean,
            }
            path = Path(base) / "audit" / "runtime_events.jsonl"
            path.parent.mkdir(parents=True, exist_ok=True)
            serialized = json.dumps(
                row,
                ensure_ascii=False,
                sort_keys=True,
                separators=(",", ":"),
            )
            encoded = (serialized + "\n").encode("utf-8")
            with path.open("ab") as handle:
                handle.write(encoded)
                handle.flush()
                os.fsync(handle.fileno())
            return row


RUNTIME_EVENT_LOGGER = StructuredRuntimeEventLogger()
WINDOW_RUNTIME_REGISTRY = {}
WINDOW_RUNTIME_REGISTRY_LOCK = threading.RLock()


@dataclass(frozen=True, slots=True)
class WindowRuntimeState:
    hwnd: int
    generation: int
    client_rect: tuple[int, int, int, int]
    dpi: int
    identity_hash: str
    calibration_hash: str
    descriptor_json: str = "{}"
    input_eligible: bool = False
    resume_confirmations: int = 0
    published_monotonic: float = 0.0


class WindowRuntimeCoordinator:
    def __init__(self, bridge):
        self.bridge = bridge
        self.lock = threading.RLock()
        self.geometry_lock = threading.RLock()
        self.state = None
        self.confirmed_frames = 0

    @staticmethod
    def _clean_target(target):
        value = dict(target) if isinstance(target, dict) else {}
        value.pop("_window_runtime_coordinator", None)
        return value

    @staticmethod
    def _identity_hash(target):
        value = {
            key: target.get(key)
            for key in ("hwnd", "pid", "process_created", "window_thread_id", "class", "process_path")
        }
        return hashlib.sha256(canonical_bytes(value)).hexdigest()

    @staticmethod
    def _calibration_hash(calibration):
        value = dict(calibration) if isinstance(calibration, dict) else {}
        return hashlib.sha256(canonical_bytes(value)).hexdigest() if value else ""

    def clear(self):
        with self.lock:
            old = self.state
            self.state = None
            self.confirmed_frames = 0
        if old is not None:
            with WINDOW_RUNTIME_REGISTRY_LOCK:
                WINDOW_RUNTIME_REGISTRY.pop(int(old.hwnd), None)

    def publish_selection(self, target, calibration=None, reason="window_selected"):
        value = self._clean_target(target)
        hwnd = safe_int(value.get("hwnd"), 0)
        if hwnd <= 0:
            raise RuntimeError("窗口运行状态缺少有效句柄")
        rect = value.get("selected_rect")
        if not isinstance(rect, (list, tuple)) or len(rect) != 4:
            rect = self.bridge.client_rect(hwnd)
        rect = tuple(safe_int(item, 0) for item in rect[:4])
        dpi = safe_int(value.get("selected_dpi", value.get("dpi", self.bridge.dpi_for_window(hwnd))), 96, 1)
        with self.lock:
            old = self.state
            requested = safe_int(value.get("window_generation"), 0, 0)
            generation = max(requested, (old.generation + 1) if old is not None else 1)
            value["window_generation"] = generation
            value["selected_rect"] = list(rect)
            value["client_size"] = [rect[2], rect[3]]
            value["selected_dpi"] = dpi
            value["dpi"] = dpi
            self.state = WindowRuntimeState(
                hwnd=hwnd,
                generation=generation,
                client_rect=rect,
                dpi=dpi,
                identity_hash=self._identity_hash(value),
                calibration_hash=self._calibration_hash(calibration),
                descriptor_json=json.dumps(
                    value,
                    ensure_ascii=False,
                    sort_keys=True,
                    separators=(",", ":"),
                    default=str,
                ),
                input_eligible=False,
                resume_confirmations=RUNTIME_THRESHOLDS.confirmation_frames,
                published_monotonic=time.monotonic(),
            )
            self.confirmed_frames = 0
            snapshot = self.state
        with WINDOW_RUNTIME_REGISTRY_LOCK:
            WINDOW_RUNTIME_REGISTRY[hwnd] = self
        RUNTIME_EVENT_LOGGER.emit(
            reason,
            old_generation=None if old is None else old.generation,
            new_generation=snapshot.generation,
            old_rect=None if old is None else old.client_rect,
            new_rect=snapshot.client_rect,
            old_dpi=None if old is None else old.dpi,
            new_dpi=snapshot.dpi,
            identity_hash=snapshot.identity_hash,
        )
        return snapshot

    def snapshot(self):
        with self.lock:
            return self.state

    def target_snapshot(self, extra=None):
        with self.lock:
            state = self.state
            if state is None:
                return None
            value = json.loads(state.descriptor_json)
            value.update(
                {
                    "hwnd": state.hwnd,
                    "window_generation": state.generation,
                    "selected_rect": list(state.client_rect),
                    "client_size": [state.client_rect[2], state.client_rect[3]],
                    "selected_dpi": state.dpi,
                    "dpi": state.dpi,
                    "window_identity_hash": state.identity_hash,
                    "calibration_hash": state.calibration_hash,
                    "input_eligible": state.input_eligible,
                }
            )
        if isinstance(extra, dict):
            value.update(extra)
        return value

    def begin_geometry_change(self, current_rect, current_dpi):
        with self.lock:
            state = self.state
            if state is None:
                raise RuntimeError("窗口运行状态尚未发布")
            self.state = WindowRuntimeState(
                hwnd=state.hwnd,
                generation=state.generation,
                client_rect=state.client_rect,
                dpi=state.dpi,
                identity_hash=state.identity_hash,
                calibration_hash=state.calibration_hash,
                descriptor_json=state.descriptor_json,
                input_eligible=False,
                resume_confirmations=state.resume_confirmations,
                published_monotonic=state.published_monotonic,
            )
        self.bridge.block_input()
        self.bridge.release_all_buttons()
        return state

    def commit_geometry(self, target, rect, dpi, calibration, confirmations):
        value = self._clean_target(target)
        rect = tuple(safe_int(item, 0) for item in rect[:4])
        dpi = safe_int(dpi, 96, 1)
        with self.lock:
            old = self.state
            if old is None:
                raise RuntimeError("窗口运行状态不存在")
            generation = old.generation + 1
            value.update(
                {
                    "window_generation": generation,
                    "selected_rect": list(rect),
                    "client_size": [rect[2], rect[3]],
                    "selected_dpi": dpi,
                    "dpi": dpi,
                }
            )
            self.state = WindowRuntimeState(
                hwnd=old.hwnd,
                generation=generation,
                client_rect=rect,
                dpi=dpi,
                identity_hash=self._identity_hash(value),
                calibration_hash=self._calibration_hash(calibration),
                descriptor_json=json.dumps(
                    value,
                    ensure_ascii=False,
                    sort_keys=True,
                    separators=(",", ":"),
                    default=str,
                ),
                input_eligible=False,
                resume_confirmations=max(1, safe_int(confirmations, RUNTIME_THRESHOLDS.confirmation_frames, 1, 120)),
                published_monotonic=time.monotonic(),
            )
            self.confirmed_frames = 0
            current = self.state
        aspect_old = old.client_rect[2] / max(1, old.client_rect[3])
        aspect_new = rect[2] / max(1, rect[3])
        RUNTIME_EVENT_LOGGER.emit(
            "window_geometry_changed",
            old_generation=old.generation,
            new_generation=current.generation,
            old_rect=old.client_rect,
            new_rect=current.client_rect,
            old_dpi=old.dpi,
            new_dpi=current.dpi,
            aspect_change=round(aspect_new - aspect_old, 8),
            calibration_result="passed",
            resume_confirmations=current.resume_confirmations,
        )
        return current

    def confirm_valid_frame(self, generation):
        with self.lock:
            state = self.state
            if state is None or safe_int(generation, -1) != state.generation:
                return False
            self.confirmed_frames += 1
            if self.confirmed_frames < state.resume_confirmations or state.input_eligible:
                return False
            self.state = WindowRuntimeState(
                hwnd=state.hwnd,
                generation=state.generation,
                client_rect=state.client_rect,
                dpi=state.dpi,
                identity_hash=state.identity_hash,
                calibration_hash=state.calibration_hash,
                descriptor_json=state.descriptor_json,
                input_eligible=True,
                resume_confirmations=state.resume_confirmations,
                published_monotonic=state.published_monotonic,
            )
            current = self.state
        RUNTIME_EVENT_LOGGER.emit(
            "window_geometry_resume_confirmed",
            generation=current.generation,
            confirmations=self.confirmed_frames,
            client_rect=current.client_rect,
            dpi=current.dpi,
        )
        return True


class DXGIVideoMemoryTelemetry:
    class GUID(ctypes.Structure):
        _fields_ = [
            ("Data1", ctypes.c_uint32),
            ("Data2", ctypes.c_uint16),
            ("Data3", ctypes.c_uint16),
            ("Data4", ctypes.c_ubyte * 8),
        ]

    class DXGI_ADAPTER_DESC1(ctypes.Structure):
        _fields_ = [
            ("Description", ctypes.c_wchar * 128),
            ("VendorId", ctypes.c_uint32),
            ("DeviceId", ctypes.c_uint32),
            ("SubSysId", ctypes.c_uint32),
            ("Revision", ctypes.c_uint32),
            ("DedicatedVideoMemory", ctypes.c_size_t),
            ("DedicatedSystemMemory", ctypes.c_size_t),
            ("SharedSystemMemory", ctypes.c_size_t),
            ("AdapterLuidLow", ctypes.c_uint32),
            ("AdapterLuidHigh", ctypes.c_int32),
            ("Flags", ctypes.c_uint32),
        ]

    class VIDEO_MEMORY_INFO(ctypes.Structure):
        _fields_ = [
            ("Budget", ctypes.c_uint64),
            ("CurrentUsage", ctypes.c_uint64),
            ("AvailableForReservation", ctypes.c_uint64),
            ("CurrentReservation", ctypes.c_uint64),
        ]

    @classmethod
    def guid(cls, text):
        import uuid as _uuid
        value = _uuid.UUID(str(text))
        raw = value.bytes_le
        return cls.GUID.from_buffer_copy(raw)

    @staticmethod
    def method(pointer, index, restype, *argtypes):
        address = ctypes.cast(pointer, ctypes.POINTER(ctypes.POINTER(ctypes.c_void_p))).contents[index]
        return ctypes.WINFUNCTYPE(restype, ctypes.c_void_p, *argtypes)(address)

    def sample(self, backend):
        if os.name != "nt":
            return {}
        factory = ctypes.c_void_p()
        dxgi = ctypes.WinDLL("dxgi", use_last_error=True)
        create = dxgi.CreateDXGIFactory1
        create.argtypes = [ctypes.POINTER(self.GUID), ctypes.POINTER(ctypes.c_void_p)]
        create.restype = ctypes.c_long
        iid_factory = self.guid("770aae78-f26f-4dba-a829-253c83d1b387")
        if create(ctypes.byref(iid_factory), ctypes.byref(factory)) < 0 or not factory.value:
            return {}
        rows = []
        release = self.method(factory, 2, ctypes.c_ulong)
        try:
            enum_adapters = self.method(factory, 12, ctypes.c_long, ctypes.c_uint, ctypes.POINTER(ctypes.c_void_p))
            index = 0
            while index < 32:
                adapter1 = ctypes.c_void_p()
                result = enum_adapters(factory, index, ctypes.byref(adapter1))
                if result != 0 or not adapter1.value:
                    break
                adapter_release = self.method(adapter1, 2, ctypes.c_ulong)
                adapter3 = ctypes.c_void_p()
                try:
                    desc = self.DXGI_ADAPTER_DESC1()
                    get_desc = self.method(adapter1, 10, ctypes.c_long, ctypes.POINTER(self.DXGI_ADAPTER_DESC1))
                    if get_desc(adapter1, ctypes.byref(desc)) < 0:
                        index += 1
                        continue
                    query_interface = self.method(
                        adapter1,
                        0,
                        ctypes.c_long,
                        ctypes.POINTER(self.GUID),
                        ctypes.POINTER(ctypes.c_void_p),
                    )
                    iid_adapter3 = self.guid("645967a4-1392-4310-a798-8053ce3e93fd")
                    query_result = query_interface(
                        adapter1,
                        ctypes.byref(iid_adapter3),
                        ctypes.byref(adapter3),
                    )
                    if query_result < 0 or not adapter3.value:
                        index += 1
                        continue
                    query_memory = self.method(
                        adapter3,
                        14,
                        ctypes.c_long,
                        ctypes.c_uint,
                        ctypes.c_int,
                        ctypes.POINTER(self.VIDEO_MEMORY_INFO),
                    )
                    local = self.VIDEO_MEMORY_INFO()
                    nonlocal_info = self.VIDEO_MEMORY_INFO()
                    local_ok = query_memory(adapter3, 0, 0, ctypes.byref(local)) >= 0
                    nonlocal_ok = query_memory(adapter3, 0, 1, ctypes.byref(nonlocal_info)) >= 0
                    rows.append(
                        {
                            "adapter_index": index,
                            "adapter_name": str(desc.Description),
                            "vendor_id": int(desc.VendorId),
                            "total_vram": int(desc.DedicatedVideoMemory),
                            "shared_capacity": int(desc.SharedSystemMemory),
                            "local_budget": int(local.Budget) if local_ok else None,
                            "local_current_usage": int(local.CurrentUsage) if local_ok else None,
                            "local_available_for_reservation": int(local.AvailableForReservation) if local_ok else None,
                            "local_current_reservation": int(local.CurrentReservation) if local_ok else None,
                            "nonlocal_budget": int(nonlocal_info.Budget) if nonlocal_ok else None,
                            "nonlocal_current_usage": int(nonlocal_info.CurrentUsage) if nonlocal_ok else None,
                            "nonlocal_available_for_reservation": (
                                int(nonlocal_info.AvailableForReservation)
                                if nonlocal_ok
                                else None
                            ),
                            "nonlocal_current_reservation": (
                                int(nonlocal_info.CurrentReservation)
                                if nonlocal_ok
                                else None
                            ),
                        }
                    )
                finally:
                    if adapter3.value:
                        self.method(adapter3, 2, ctypes.c_ulong)(adapter3)
                    adapter_release(adapter1)
                index += 1
        except (OSError, ValueError, TypeError, AttributeError):
            rows = []
        finally:
            release(factory)
        if not rows:
            return {}
        family = str(backend or "").casefold()
        if "nvidia" in family:
            preferred = [row for row in rows if row["vendor_id"] == 0x10DE]
        elif "directml" in family:
            preferred = [row for row in rows if row["vendor_id"] in {0x1002, 0x8086, 0x10DE}]
        else:
            preferred = rows
        selected = max(
            preferred or rows,
            key=lambda row: (
                safe_int(row.get("local_current_usage"), 0),
                safe_int(row.get("total_vram"), 0),
            ),
        )
        selected = dict(selected)
        budget = selected.get("local_budget")
        usage = selected.get("local_current_usage")
        selected["free_vram"] = max(0, int(budget) - int(usage)) if budget is not None and usage is not None else None
        selected["source"] = "dxgi_adapter3_query_video_memory_info"
        selected["adapters"] = rows
        return selected


DXGI_VIDEO_MEMORY_TELEMETRY = DXGIVideoMemoryTelemetry()



def _strict_memory_values():
    if os.name == "nt":
        class MEMORYSTATUSEX(ctypes.Structure):
            _fields_ = [
                ("dwLength", wintypes.DWORD),
                ("dwMemoryLoad", wintypes.DWORD),
                ("ullTotalPhys", ctypes.c_ulonglong),
                ("ullAvailPhys", ctypes.c_ulonglong),
                ("ullTotalPageFile", ctypes.c_ulonglong),
                ("ullAvailPageFile", ctypes.c_ulonglong),
                ("ullTotalVirtual", ctypes.c_ulonglong),
                ("ullAvailVirtual", ctypes.c_ulonglong),
                ("ullAvailExtendedVirtual", ctypes.c_ulonglong),
            ]
        class PROCESS_MEMORY_COUNTERS_EX(ctypes.Structure):
            _fields_ = [
                ("cb", wintypes.DWORD), ("PageFaultCount", wintypes.DWORD),
                ("PeakWorkingSetSize", ctypes.c_size_t), ("WorkingSetSize", ctypes.c_size_t),
                ("QuotaPeakPagedPoolUsage", ctypes.c_size_t), ("QuotaPagedPoolUsage", ctypes.c_size_t),
                ("QuotaPeakNonPagedPoolUsage", ctypes.c_size_t), ("QuotaNonPagedPoolUsage", ctypes.c_size_t),
                ("PagefileUsage", ctypes.c_size_t), ("PeakPagefileUsage", ctypes.c_size_t),
                ("PrivateUsage", ctypes.c_size_t),
            ]
        try:
            kernel = ctypes.WinDLL("kernel32", use_last_error=True)
            psapi = ctypes.WinDLL("psapi", use_last_error=True)
            status = MEMORYSTATUSEX()
            status.dwLength = ctypes.sizeof(status)
            if not kernel.GlobalMemoryStatusEx(ctypes.byref(status)):
                raise OSError(ctypes.get_last_error())
            counters = PROCESS_MEMORY_COUNTERS_EX()
            counters.cb = ctypes.sizeof(counters)
            kernel.GetCurrentProcess.restype = wintypes.HANDLE
            handle = kernel.GetCurrentProcess()
            if not psapi.GetProcessMemoryInfo(handle, ctypes.byref(counters), counters.cb):
                raise OSError(ctypes.get_last_error())
            total_commit = int(status.ullTotalPageFile)
            available_commit = int(status.ullAvailPageFile)
            return {
                "available_ram": int(status.ullAvailPhys),
                "total_ram": int(status.ullTotalPhys),
                "process_rss": int(counters.WorkingSetSize),
                "process_private_bytes": int(counters.PrivateUsage),
                "total_commit": total_commit,
                "available_commit": available_commit,
                "commit_pressure": 1.0 - available_commit / max(1, total_commit),
                "pagefile_pressure": int(counters.PrivateUsage) / max(1, total_commit),
            }
        except (OSError, ValueError) as error:
            record_cleanup_error("WINDOWS_MEMORY_TELEMETRY_FAILED", error)
    available, rss = ResourceGovernor._memory_values()
    return {
        "available_ram": int(available), "total_ram": 0, "process_rss": int(rss),
        "process_private_bytes": int(rss), "total_commit": 0, "available_commit": 0,
        "commit_pressure": 0.0, "pagefile_pressure": 0.0,
    }


def _effective_resource_thresholds(snapshot):
    total_ram = max(0, safe_int(getattr(snapshot, "total_ram", 0), 0))
    tested_peak = max(0, safe_int(getattr(snapshot, "tested_peak_vram", 0), 0))
    total_vram = max(0, safe_int(getattr(snapshot, "total_vram", 0), 0))
    model_ram_peak = max(
        safe_int(RESOURCE_GOVERNOR.benchmark_profile.get("tested_peak_ram"), 0, 0),
        safe_int(getattr(snapshot, "process_private_bytes", 0), 0),
    )
    ram_margin = max(768 * 1024 * 1024, int(model_ram_peak * 0.25))
    ram_red = max(RUNTIME_THRESHOLDS.ram_red_bytes, int(total_ram * 0.08) if total_ram else 0, ram_margin)
    ram_yellow = max(
        RUNTIME_THRESHOLDS.ram_yellow_bytes,
        int(total_ram * 0.14) if total_ram else 0,
        ram_red + 768 * 1024 * 1024,
    )
    vram_margin = max(512 * 1024 * 1024, int(tested_peak * 0.30))
    vram_red = max(RUNTIME_THRESHOLDS.free_vram_red_bytes, int(total_vram * 0.10) if total_vram else 0, vram_margin)
    vram_yellow = max(
        RUNTIME_THRESHOLDS.free_vram_yellow_bytes,
        int(total_vram * 0.18) if total_vram else 0,
        vram_red + 384 * 1024 * 1024,
    )
    return {"ram_red": ram_red, "ram_yellow": ram_yellow, "vram_red": vram_red, "vram_yellow": vram_yellow}


def _resource_worker_pid():
    runtime = APP_CONTEXT.vision_runtime
    worker = getattr(runtime, "worker", None) if runtime is not None else None
    process = getattr(worker, "process", None)
    return safe_int(getattr(process, "pid", 0), os.getpid(), 1)


def _strict_governor_sample_once(self):
    cpu, process_cpu = self._cpu_values()
    memory = _strict_memory_values()
    backend = self._manifest_backend()
    gpu = WINDOWS_GPU_TELEMETRY.sample(backend, _resource_worker_pid())
    queue_ratio, queue_oldest = self._queue_values()
    perception_p95 = self._series_p95("end_to_end_perception_ms")
    decision_p95 = self._series_p95("end_to_end_decision_ms")
    end_to_end_p95 = max(perception_p95, decision_p95)
    end_to_end_p99 = max(
        RUNTIME_METRICS.percentile(
            "end_to_end_perception_ms", 0.99, 0.75
        ),
        RUNTIME_METRICS.percentile(
            "end_to_end_decision_ms", 0.99, 0.75
        ),
    )
    now = time.monotonic()
    counts = {
        "removed": int(RUNTIME_METRICS.counters.get("gpu_device_removed", 0)),
        "reset": int(RUNTIME_METRICS.counters.get("gpu_device_reset", 0)),
        "oom": int(RUNTIME_METRICS.counters.get("gpu_oom", 0)),
    }
    with self.lock:
        deltas = {key: max(0, counts[key] - safe_int(self._fault_counter_baseline.get(key), 0)) for key in counts}
        self._fault_counter_baseline = dict(counts)
        if any(deltas.values()):
            details = {
                "oom": deltas["oom"] > 0,
                "device_removed": deltas["removed"] > 0,
                "device_reset": deltas["reset"] > 0,
                "signature": hashlib.sha256(
                    canonical_bytes({"backend": backend, "counts": counts})
                ).hexdigest(),
            }
            self._record_accelerator_fault_locked(backend, details, now)
        last_fault = self.last_accelerator_fault_at
        fault_age = None if last_fault is None else max(0.0, now - last_fault)
        self_test = self.accelerator_self_tests.get(str(backend), {})
        self_test_passed = bool(
            self_test.get("passed")
            and safe_float(self_test.get("monotonic"), 0.0)
            >= safe_float(last_fault, 0.0)
        )
        backend_blacklisted = str(backend) in self.backend_blacklist
        total_vram = gpu.get("total_vram", self.benchmark_profile.get("total_vram"))
        tested_peak_vram = self.benchmark_profile.get("tested_peak_vram")
        probe_bytes = self.benchmark_profile.get("probe_bytes")
        probe_passed = bool(
            self.benchmark_profile.get(
                "probe_passed",
                self.benchmark_profile.get("vram_test_passed", False),
            )
        )
    provisional = HardwareSnapshot(
        cpu_percent=round(cpu, 3), process_cpu_percent=round(process_cpu, 3),
        available_ram=int(memory["available_ram"]), process_rss=int(memory["process_rss"]),
        gpu_backend=str(backend), gpu_utilization=gpu.get("gpu_utilization"), free_vram=gpu.get("free_vram"),
        capture_p95_ms=round(self._series_p95("capture_latency_ms"), 3), queue_ratio=round(queue_ratio, 5),
        queue_oldest_ms=round(queue_oldest, 3), disk_write_p95_ms=round(self._disk_p95(), 3),
        end_to_end_p95_ms=round(end_to_end_p95, 3), end_to_end_p99_ms=round(end_to_end_p99, 3),
        dedicated_vram_used=gpu.get("dedicated_vram_used", gpu.get("local_current_usage")),
        shared_vram_used=gpu.get("shared_vram_used", gpu.get("nonlocal_current_usage")),
        gpu_queue_wait_p95_ms=round(
            self._series_p95("gpu_queue_wait_ms"), 3
        ),
        cpu_to_gpu_copy_p95_ms=round(
            self._series_p95("cpu_to_gpu_copy_ms"), 3
        ),
        device_removed_count=counts["removed"], device_reset_count=counts["reset"], gpu_oom_count=counts["oom"],
        device_removed_delta=deltas["removed"], device_reset_delta=deltas["reset"], gpu_oom_delta=deltas["oom"],
        last_accelerator_fault_monotonic=last_fault, accelerator_fault_age_seconds=fault_age,
        accelerator_self_test_passed=self_test_passed, backend_blacklisted=backend_blacklisted,
        available_ram_known=int(memory["available_ram"]) > 0, free_vram_known=gpu.get("free_vram") is not None,
        total_vram=(
            None if total_vram is None else safe_int(total_vram, 0, 0)
        ),
        tested_peak_vram=(
            None
            if tested_peak_vram is None
            else safe_int(tested_peak_vram, 0, 0)
        ),
        total_ram=int(memory["total_ram"]),
        total_commit=int(memory["total_commit"]),
        available_commit=int(memory["available_commit"]),
        process_private_bytes=int(memory["process_private_bytes"]),
        commit_pressure=round(float(memory["commit_pressure"]), 6),
        pagefile_pressure=round(float(memory["pagefile_pressure"]), 6),
        vram_budget=gpu.get("local_budget"),
        vram_current_usage=gpu.get("local_current_usage"),
        vram_available_for_reservation=gpu.get(
            "local_available_for_reservation"
        ),
        vram_current_reservation=gpu.get("local_current_reservation"),
        shared_vram_budget=gpu.get("nonlocal_budget"),
        shared_vram_current_usage=gpu.get("nonlocal_current_usage"),
        process_dedicated_vram=gpu.get("process_dedicated_vram"),
        process_shared_vram=gpu.get("process_shared_vram"),
        telemetry_source=str(gpu.get("source", "")),
        probe_bytes=None if probe_bytes is None else safe_int(probe_bytes, 0, 0), probe_passed=probe_passed,
    )
    limits = _effective_resource_thresholds(provisional)
    values = {
        name: getattr(provisional, name)
        for name in provisional.__dataclass_fields__
    }
    values.update(
        {
            "effective_ram_red_bytes": limits["ram_red"],
            "effective_ram_yellow_bytes": limits["ram_yellow"],
            "effective_vram_red_bytes": limits["vram_red"],
            "effective_vram_yellow_bytes": limits["vram_yellow"],
        }
    )
    snapshot = HardwareSnapshot(**values)
    with self.lock:
        self.history.append(snapshot)
        self._last_snapshot = snapshot
        self._update_state_locked(now)
    if any(deltas.values()) or backend_blacklisted:
        self._persist_backend_fault_state()
    return snapshot


def _strict_governor_update_state(self, now):
    recent = list(self.history)
    if not recent:
        return
    current = recent[-1]
    previous_snapshot = recent[-2] if len(recent) >= 2 else None
    old_state = self.state
    old_plans = self.plans
    limits = _effective_resource_thresholds(current)
    commit_pressure = safe_float(getattr(current, "commit_pressure", 0.0), 0.0)
    available_commit = safe_int(getattr(current, "available_commit", 0), 0, 0)
    pagefile_pressure = safe_float(getattr(current, "pagefile_pressure", 0.0), 0.0)
    shared_vram_current_usage = getattr(
        current,
        "shared_vram_current_usage",
        getattr(current, "shared_vram_used", None),
    )
    shared_vram_budget = getattr(current, "shared_vram_budget", None)
    accelerator = "nvidia" in current.gpu_backend.casefold() or "directml" in current.gpu_backend.casefold()
    new_fault = bool(current.device_removed_delta or current.device_reset_delta or current.gpu_oom_delta)
    fault_red = bool(
        accelerator
        and (
            current.backend_blacklisted
            or new_fault
            or (
                current.accelerator_fault_age_seconds is not None
                and current.accelerator_fault_age_seconds <= 30.0
                and not current.accelerator_self_test_passed
            )
        )
    )
    rapid = False
    if previous_snapshot is not None:
        ram_drop = previous_snapshot.available_ram - current.available_ram
        vram_drop = (
            0
            if previous_snapshot.free_vram is None
            or current.free_vram is None
            else previous_snapshot.free_vram - current.free_vram
        )
        rapid = ram_drop >= 512 * 1024 * 1024 or vram_drop >= 256 * 1024 * 1024
    queue_red = len(recent) >= 2 and all(item.queue_ratio > 0.90 for item in recent[-2:])
    severe = bool(
        fault_red or queue_red or rapid
        or current.available_ram_known and current.available_ram < limits["ram_red"]
        or current.free_vram_known and current.free_vram < limits["vram_red"]
        or commit_pressure >= 0.92 or available_commit and available_commit < limits["ram_red"]
        or current.capture_p95_ms > RUNTIME_THRESHOLDS.capture_red_ms
        or current.end_to_end_p95_ms > RUNTIME_THRESHOLDS.end_to_end_red_p95_ms
        or current.disk_write_p95_ms > 180.0 or current.cpu_percent > 97.0
        or current.gpu_utilization is not None and current.gpu_utilization > 98.0
        or current.gpu_queue_wait_p95_ms > 40.0 or current.cpu_to_gpu_copy_p95_ms > 30.0
    )
    warning = bool(
        severe or current.queue_ratio > 0.70
        or current.available_ram_known and current.available_ram < limits["ram_yellow"]
        or current.free_vram_known and current.free_vram < limits["vram_yellow"]
        or commit_pressure >= 0.82 or pagefile_pressure >= 0.70
        or current.capture_p95_ms > RUNTIME_THRESHOLDS.capture_yellow_ms
        or current.end_to_end_p95_ms > RUNTIME_THRESHOLDS.end_to_end_yellow_p95_ms
        or current.disk_write_p95_ms > 80.0 or current.cpu_percent > 88.0 or current.process_cpu_percent > 85.0
        or current.gpu_utilization is not None and current.gpu_utilization > 94.0
        or current.gpu_queue_wait_p95_ms > 18.0 or current.cpu_to_gpu_copy_p95_ms > 12.0
        or (
            shared_vram_current_usage is not None
            and shared_vram_budget is not None
            and shared_vram_current_usage > shared_vram_budget * 0.80
        )
    )
    self._strict_red_streak = safe_int(getattr(self, "_strict_red_streak", 0), 0) + 1 if severe else 0
    self._strict_yellow_streak = safe_int(getattr(self, "_strict_yellow_streak", 0), 0) + 1 if warning else 0
    immediate_red = fault_red or rapid
    if immediate_red or self._strict_red_streak >= 3:
        desired = ResourceState.RED
    elif self._strict_yellow_streak >= 5:
        desired = ResourceState.YELLOW
    else:
        desired = ResourceState.NORMAL
    rank = {ResourceState.NORMAL: 0, ResourceState.YELLOW: 1, ResourceState.RED: 2}
    if rank[desired] > rank[self.state]:
        self.state = desired
        self.recovery_since = None
    elif rank[desired] < rank[self.state]:
        if self.recovery_since is None:
            self.recovery_since = now
        elif now - self.recovery_since >= 30.0:
            self.state = desired
            self.recovery_since = None
    else:
        self.recovery_since = None
    if self.state is ResourceState.RED:
        if getattr(self, "red_since", None) is None:
            self.red_since = now
    else:
        self.red_since = None
    reasons = []
    if fault_red: reasons.append("accelerator_fault")
    if rapid: reasons.append("rapid_resource_deterioration")
    if current.available_ram_known and current.available_ram < limits["ram_red"]: reasons.append("available_ram")
    if current.free_vram_known and current.free_vram < limits["vram_red"]: reasons.append("vram_budget_headroom")
    if commit_pressure >= 0.92: reasons.append("commit_charge")
    if queue_red: reasons.append("queue_pressure")
    if not reasons: reasons.append("resource_state_" + self.state.value.casefold())
    self.plan_reason = "+".join(reasons)
    candidate_plans = self._plans_for_state(self.state, current.gpu_backend)
    old_signature = (old_plans.ai.backend, old_plans.ai.model_tier)
    new_signature = (candidate_plans.ai.backend, candidate_plans.ai.model_tier)
    recent_switches = (
        value
        for value in getattr(self, "_strict_switch_times", deque())
        if now - value <= 900.0
    )
    self._strict_switch_times = deque(recent_switches, maxlen=16)
    last_switch = safe_float(getattr(self, "_strict_last_switch", 0.0), 0.0)
    if new_signature != old_signature and self.state is not ResourceState.RED and now - last_switch < 60.0:
        candidate_plans = old_plans
        new_signature = old_signature
        self.plan_reason += "+switch_rate_limited"
    elif new_signature != old_signature:
        self._strict_last_switch = now
        self._strict_switch_times.append(now)
    if len(self._strict_switch_times) >= 5:
        self._fault_force_cpu = True
        self.state = ResourceState.RED
        self.plan_reason = "oscillation_cpu_safe_mode"
        candidate_plans = self._plans_for_state(ResourceState.RED, "windows-x64-cpu")
        new_signature = (candidate_plans.ai.backend, candidate_plans.ai.model_tier)
    self.plans = candidate_plans
    self.plan = self.plans.ai
    plan_digest = hashlib.sha256(canonical_bytes(self.plans.to_dict())).hexdigest()
    if plan_digest != getattr(self, "_strict_plan_digest", ""):
        self.plan_version = safe_int(getattr(self, "plan_version", 0), 0) + 1
        self._strict_plan_digest = plan_digest
        RUNTIME_EVENT_LOGGER.emit(
            "runtime_plan_changed",
            plan_version=self.plan_version,
            plan_reason=self.plan_reason,
            old_state=old_state.value,
            new_state=self.state.value,
            requested_backend=self.plan.backend,
            requested_model_tier=self.plan.model_tier,
            thresholds=limits,
            snapshot={name: getattr(current, name) for name in current.__dataclass_fields__},
        )
    if self.state is ResourceState.RED and current.available_ram_known and current.available_ram < limits["ram_red"]:
        FEATURE_ENGINE.clear_frames()
        POLICY_TRAINING_CACHE.clear()
        collect_garbage("resource_red_dynamic", 30.0, old_state is not ResourceState.RED)


def _strict_plan_envelope(self):
    plan = self.current_plan(ModeId.AI.value)
    with self.lock:
        return {
            "plan_version": safe_int(getattr(self, "plan_version", 1), 1, 1),
            "plan_reason": str(getattr(self, "plan_reason", "startup")),
            "requested_backend": str(plan.backend),
            "requested_model_tier": normalize_model_tier(plan.model_tier),
            "worker_ack_version": safe_int(getattr(self, "worker_ack_version", 0), 0, 0),
            "applied_backend": str(getattr(self, "applied_backend", "")),
            "applied_model_tier": normalize_model_tier(getattr(self, "applied_model_tier", "Tiny")),
            "resource_state": self.state.value,
            "red_duration_seconds": (
                0.0
                if getattr(self, "red_since", None) is None
                else max(0.0, time.monotonic() - self.red_since)
            ),
            "plan": plan.to_dict(),
        }


def _strict_ack_worker(self, value):
    result = dict(value) if isinstance(value, dict) else {}
    with self.lock:
        current_ack = safe_int(
            getattr(self, "worker_ack_version", 0), 0
        )
        incoming_ack = safe_int(
            result.get("worker_ack_version", result.get("plan_version", 0)),
            0,
        )
        self.worker_ack_version = max(current_ack, incoming_ack)
        self.applied_backend = str(result.get("applied_backend", getattr(self, "applied_backend", "")))
        self.applied_model_tier = normalize_model_tier(
            result.get(
                "applied_model_tier",
                getattr(self, "applied_model_tier", "Tiny"),
            )
        )
    return self.worker_ack_version


RESOURCE_GOVERNOR.plan_version = 1
RESOURCE_GOVERNOR.plan_reason = "startup"
RESOURCE_GOVERNOR.worker_ack_version = 0
RESOURCE_GOVERNOR.applied_backend = ""
RESOURCE_GOVERNOR.applied_model_tier = "Tiny"
RESOURCE_GOVERNOR.red_since = None
RESOURCE_GOVERNOR._strict_plan_digest = hashlib.sha256(canonical_bytes(RESOURCE_GOVERNOR.plans.to_dict())).hexdigest()
RESOURCE_GOVERNOR._last_snapshot = HardwareSnapshot(
    cpu_percent=0.0, process_cpu_percent=0.0, available_ram=0, process_rss=0,
    gpu_backend="windows-x64-cpu", gpu_utilization=None, free_vram=None,
    capture_p95_ms=0.0, queue_ratio=0.0, queue_oldest_ms=0.0, disk_write_p95_ms=0.0,
)


def _strict_app_init(self, *args, **kwargs):
    self._base_init_strict(*args, **kwargs)
    self.window_runtime = WindowRuntimeCoordinator(self.api)
    self._runtime_migration_lock = threading.RLock()
    self._runtime_migration_active = False
    self._runtime_last_reconcile = 0.0
    self._worker_ack_version = 0


def _strict_window_commit(self, item, source_mode, rect):
    result = self._base_commit_selection_strict(item, source_mode, rect)
    coordinator = getattr(self.app, "window_runtime", None)
    if coordinator is not None and isinstance(self.app.selected_window, dict):
        state = coordinator.publish_selection(self.app.selected_window, reason="window_selected")
        self.app.window_generation = state.generation
        self.app.selected_window = coordinator.target_snapshot()
    return result


def _strict_require_window(self, foreground=False):
    if not self.selected_window:
        raise RuntimeError("请先点击“选择窗口”按钮选择目标窗口")
    coordinator = getattr(self, "window_runtime", None)
    if coordinator is not None:
        if coordinator.snapshot() is None:
            coordinator.publish_selection(self.selected_window, reason="window_state_recovered")
        target = coordinator.target_snapshot()
        self.api.validate_target_identity(target, foreground)
        self.selected_window = target
        self.window_generation = safe_int(target.get("window_generation"), self.window_generation, 0)
        return target
    return self._base_require_window_strict(foreground)


def _strict_mode_session_init(self, app, target):
    coordinator = getattr(app, "window_runtime", None)
    if coordinator is not None and coordinator.snapshot() is not None:
        extra = {
            "game_id": str((getattr(app, "selected_game", None) or {}).get("id", "")),
            "session_id": str(
                getattr(app, "mode_session_id", "")
               
                or uuid.uuid4().hex
            ),
        }
        target = coordinator.target_snapshot(extra)
    self._base_init_strict(app, target)
    self.window_runtime = coordinator


def _strict_frame_buffer_init(self, bridge, target, *args, **kwargs):
    self._base_init_strict(bridge, target, *args, **kwargs)
    with WINDOW_RUNTIME_REGISTRY_LOCK:
        self.window_runtime = WINDOW_RUNTIME_REGISTRY.get(safe_int(self.target.get("hwnd"), 0))
    if self.window_runtime is not None:
        fresh = self.window_runtime.target_snapshot({"game_id": self.game_id, "session_id": self.session_id})
        if fresh:
            self.target = fresh
            self.window_generation = safe_int(fresh.get("window_generation"), self.window_generation, 0)
            self.isolation_key = runtime_isolation_key(
                self.game_id,
                self.session_id,
                self.target,
                self.window_generation,
            )
            self.target["window_key"] = self.isolation_key


def _strict_frame_geometry_ready(self):
    coordinator = getattr(self, "window_runtime", None)
    if coordinator is None:
        return self._base_geometry_ready_strict()
    with coordinator.geometry_lock:
        fresh_target = coordinator.target_snapshot({"game_id": self.game_id, "session_id": self.session_id})
        if fresh_target:
            self.target = fresh_target
            self.window_generation = safe_int(fresh_target.get("window_generation"), self.window_generation, 0)
        rect, dpi = self.bridge.validate_target_identity(self.target, False)
        state = coordinator.snapshot()
        changed = state is None or tuple(rect) != tuple(state.client_rect) or int(dpi) != int(state.dpi)
        if not changed:
            self.pending_geometry = None
            self.geometry_since = 0.0
            return True
        coordinator.begin_geometry_change(rect, dpi)
        geometry = tuple(int(value) for value in (*rect, int(dpi)))
        now = time.monotonic()
        if geometry != self.pending_geometry:
            self.pending_geometry = geometry
            self.geometry_since = now
            with self.condition:
                self.frames.clear()
                self.sequence += 1
                self.last_error = "窗口尺寸或DPI变化，等待几何稳定后执行原子重新校准"
                self.condition.notify_all()
            return False
        if now - self.geometry_since < 0.75:
            return False
        identity = self.bridge.target_identity(self.target)
        if coordinator._identity_hash(identity) != state.identity_hash:
            raise TargetUnavailable("窗口身份在几何变化期间发生变化，拒绝恢复输入")
        old_key = self.isolation_key
        clear_runtime_isolation(key=old_key)
        updated = dict(self.target)
        updated.update(identity)
        updated["selected_rect"] = list(rect)
        updated["client_size"] = [int(rect[2]), int(rect[3])]
        updated["selected_dpi"] = int(dpi)
        updated["dpi"] = int(dpi)
        self.bridge.calibrations.pop(int(updated["hwnd"]), None)
        self.bridge.reset_capture_backends(updated)
        self.bridge.reset_frame_history(updated.get("hwnd"))
        calibration = self.bridge.calibrate(updated, 1.2, self.stop_event)
        confirmations = max(
            RUNTIME_THRESHOLDS.confirmation_frames,
            safe_int(
                calibration.get("confirm_frames"),
                RUNTIME_THRESHOLDS.confirmation_frames,
                1,
                120,
            ),
        )
        new_state = coordinator.commit_geometry(updated, rect, dpi, calibration, confirmations)
        self.target = coordinator.target_snapshot({"game_id": self.game_id, "session_id": self.session_id})
        self.window_generation = new_state.generation
        self.isolation_key = runtime_isolation_key(self.game_id, self.session_id, self.target, self.window_generation)
        self.target["window_key"] = self.isolation_key
        clear_runtime_isolation(key=self.isolation_key)
        self.resume_confirmations = confirmations
        self.pending_geometry = None
        self.geometry_since = 0.0
        with self.condition:
            self.frames.clear()
            self.sequence += 1
            self.last_error = "窗口几何已原子更新并重新校准，等待连续有效帧"
            self.condition.notify_all()
        if self.on_geometry:
            self.on_geometry(self.target, calibration)
        return False



def _strict_geometry_updated(self, target, calibration):
    coordinator = getattr(self, "window_runtime", None)
    if coordinator is not None:
        fresh = coordinator.target_snapshot(
            {
                "game_id": self.target.get("game_id", ""),
                "session_id": self.target.get("session_id", ""),
            }
        )
        if fresh:
            self.target.clear()
            self.target.update(fresh)
            self.isolation_key = runtime_isolation_key(
                self.target.get("game_id"),
                self.target.get("session_id"),
                self.target,
                self.target.get("window_generation", 0),
            )
            self.target["window_key"] = self.isolation_key
            self.app.selected_window = coordinator.target_snapshot()
            self.app.window_generation = safe_int(self.target.get("window_generation"), self.app.window_generation, 0)
            execution = getattr(getattr(self.app, "training_controller", None), "execution", None)
            if execution is not None and hasattr(execution, "target"):
                execution.target = dict(self.target)
    return self._base_geometry_updated_strict(target, calibration)


def _refresh_training_window_state(execution):
    coordinator = getattr(execution.host, "window_runtime", None)
    if coordinator is None or coordinator.snapshot() is None or not hasattr(execution, "target"):
        return False
    current = coordinator.target_snapshot(
        {
            "game_id": str(
                getattr(execution, "game", {}).get("id", "")
            ),
            "session_id": str(
                getattr(execution, "runtime_session_id", "")
            ),
        }
    )
    if not current:
        return False
    old_generation = safe_int(execution.target.get("window_generation"), 0)
    new_generation = safe_int(current.get("window_generation"), 0)
    if new_generation == old_generation:
        return False
    execution.target = current
    execution.target["window_key"] = runtime_isolation_key(
        execution.target.get("game_id"),
        execution.target.get("session_id"),
        execution.target,
        new_generation,
    )
    if hasattr(execution, "profile"):
        execution.profile["perception_key"] = execution.target["window_key"]
    if hasattr(execution, "calibration"):
        execution.calibration = execution.host.api.calibration_for(execution.target)
    rect = execution.host.api.client_rect(int(execution.target["hwnd"]))
    execution.visual_runtime_layout = {
        "content_rect": list(rect), "dpi": execution.host.api.dpi_for_window(int(execution.target["hwnd"])),
        "capture_backend": getattr(execution, "validated_backend", ""), "aspect": rect[2] / max(1, rect[3]),
    }
    RUNTIME_EVENT_LOGGER.emit(
        "ai_window_state_synchronized",
        old_generation=old_generation,
        new_generation=new_generation,
        client_rect=rect,
        dpi=execution.visual_runtime_layout["dpi"],
    )
    return True


def _strict_training_preflight(self):
    result = self._base_preflight_strict()
    _refresh_training_window_state(self)
    return result


def _strict_assert_snapshot(self, force=False):
    _refresh_training_window_state(self)
    return self._base_assert_training_snapshot_strict(force)


class ShadowLearningGate:
    minimum_comparisons = 30

    @staticmethod
    def state_key(captured, temporal):
        value = {
            "coarse": hashlib.sha256(bytes(captured.get("coarse", b""))).hexdigest()[:20],
            "objects": sorted(
                (
                    str(item.get("class", "")),
                    str(item.get("role", "")),
                )
                for item in captured.get("semantic_targets", [])
                if isinstance(item, dict)
            )[:32],
            "task": str((temporal or {}).get("subgoal_id", "")),
            "resolution": str(captured.get("rect", "")),
            "dpi": safe_int(captured.get("dpi"), 0),
        }
        return hashlib.sha256(canonical_bytes(value)).hexdigest()

    def allow(self, execution, captured, temporal, selection):
        decision = dict(getattr(execution, "last_decision_snapshot", {}) or {})
        best = decision.get("best", {}) if isinstance(decision.get("best"), dict) else {}
        uncertainty = safe_float(best.get("ood_uncertainty", decision.get("ood", 0.0)), 0.0)
        if uncertainty <= 0.35:
            return True
        key = self.state_key(captured, temporal)
        validation = (
            execution.model.get("validation", {})
            if isinstance(execution.model.get("validation"), dict)
            else {}
        )
        approved = set(str(value) for value in validation.get("shadow_approved_state_keys", []) if str(value))
        comparisons = safe_int(validation.get("shadow_comparison_count", 0), 0)
        allowed = bool(
            key in approved
            and comparisons >= self.minimum_comparisons
            and validation.get("offline_replay_passed")
        )
        RUNTIME_EVENT_LOGGER.emit(
            "shadow_mode_prediction",
            game_id=str(execution.game.get("id", "")), state_key=key, uncertainty=uncertainty,
            predicted_action=selection.get("canonical", "") if isinstance(selection, dict) else "",
            comparison_count=comparisons, minimum_comparisons=self.minimum_comparisons,
            action_executed=allowed,
            rollback_model_fingerprint=str(
                execution.model.get("evaluation_model_fingerprint", "")
            ),
        )
        if not allowed:
            execution.host.set_status("影子模式：新状态只预测、不执行；需人工比较、离线升级和回放验收后才可放行")
            execution.host.set_input_status("影子模式已锁定")
        return allowed


SHADOW_LEARNING_GATE = ShadowLearningGate()
def _strict_choose_action(self, captured, temporal):
    _refresh_training_window_state(self)
    selection = self._base_choose_action_strict(captured, temporal)
    if selection is not None and not SHADOW_LEARNING_GATE.allow(self, captured, temporal, selection):
        return None
    return selection


def _strict_execute_selected(self, selection):
    _refresh_training_window_state(self)
    coordinator = getattr(self.host, "window_runtime", None)
    state = coordinator.snapshot() if coordinator is not None else None
    if state is not None and not state.input_eligible:
        self.host.api.block_input()
        raise InputStopped("窗口新generation尚未完成连续有效帧确认")
    return self._base_execute_selected_action_strict(selection)


class ModelInstanceRegistry:
    def __init__(self):
        self.lock = threading.RLock()
        self.instances = {}

    def register(self, backend, tier, validation):
        key = (str(backend), normalize_model_tier(tier))
        value = dict(validation) if isinstance(validation, dict) else {}
        if not value.get("valid"):
            raise ModelValidationError("完整模型实例验证失败：" + str(key))
        value.update({"backend": key[0], "model_tier": key[1], "validated": time.time()})
        with self.lock:
            self.instances[key] = value
        return value

    def validated(self, backend, tier):
        with self.lock:
            return dict(self.instances.get((str(backend), normalize_model_tier(tier)), {}))


MODEL_INSTANCE_REGISTRY = ModelInstanceRegistry()


def _strict_migrate_worker(self, envelope):
    old_worker = self.ai_worker
    old_snapshot = RESOURCE_GOVERNOR.current_snapshot()
    should_resume = normalize_mode_id(self.mode) == ModeId.AI.value and self.mode_state != MODE_IDLE
    try:
        self.api.block_input()
        self.api.release_all_buttons()
        if should_resume:
            self.ui(lambda: self.request_mode_stop("stopped", "资源计划要求原子切换完整模型实例"), "resource_plan_stop")
            deadline = time.monotonic() + 15.0
            while self.mode_state != MODE_IDLE and time.monotonic() < deadline:
                interruptible_wait(None, 0.05)
            if self.mode_state != MODE_IDLE:
                raise RuntimeError("旧AI模式未在限定时间内安全停止")
        try:
            self.store.emergency_checkpoint("resource_plan_migration")
        except RECOVERABLE_ERRORS as error:
            record_cleanup_error("RESOURCE_PLAN_CHECKPOINT", error)
        backend = str(envelope.get("requested_backend", "windows-x64-cpu"))
        tier = normalize_model_tier(envelope.get("requested_model_tier", "Tiny"))
        family = backend.casefold()
        force_cpu = (
            "cpu" in family
            and "nvidia" not in family
            and "directml" not in family
        )
        worker = AIWorkerClient(
            self.store.base, self._ai_worker_failed, force_cpu_safe=force_cpu,
            requested_backend=backend, requested_model_tier=tier,
            plan_version=safe_int(envelope.get("plan_version"), 0),
            plan_reason=str(
                envelope.get("plan_reason", "resource_plan")
            ),
        )
        validation = worker.validate_model_tier(tier)
        MODEL_INSTANCE_REGISTRY.register(backend, tier, validation)
        probe = {"passed": True, "skipped": True}
        if "nvidia" in backend.casefold() or "directml" in backend.casefold():
            first = worker.probe_vram(256 * 1024 * 1024)
            second = worker.probe_vram(512 * 1024 * 1024) if first.get("passed") else first
            probe = second
            if not probe.get("passed"):
                raise RuntimeError("GPU安全分配试探失败")
            RESOURCE_GOVERNOR.benchmark_profile["probe_bytes"] = safe_int(
                probe.get("allocated_bytes", probe.get("requested_bytes", 0)),
                0,
            )
            RESOURCE_GOVERNOR.benchmark_profile["probe_passed"] = True
        vision = VisionRuntimeProxy(worker)
        ocr = OCRRuntimeProxy(worker)
        if self.selected_game:
            game_id = (
                self.selected_game["id"]
                if isinstance(self.selected_game, dict)
                else self.selected_game
            )
            vision.activate_game(game_id)
            ocr.activate_game(self.selected_game["id"] if isinstance(self.selected_game, dict) else self.selected_game)
            manifest = vision.manifest()
            if normalize_model_tier(manifest.get("model_tier", tier)) != tier:
                raise ModelValidationError("新工作进程加载的完整模型等级不一致")
        ack = worker.apply_plan(envelope)
        ack_version = safe_int(ack.get("worker_ack_version"), -1)
        requested_version = safe_int(envelope.get("plan_version"), 0)
        if ack.get("requires_restart") or ack_version != requested_version:
            raise RuntimeError("新工作进程未确认资源计划版本")
        self.ai_worker = worker
        self.vision_runtime = vision
        self.ocr_runtime = ocr
        APP_CONTEXT.vision_runtime = vision
        APP_CONTEXT.ocr_runtime = ocr
        self.api.ai_runtime = vision
        self.lifecycle.set_runtime_ready(True)
        RESOURCE_GOVERNOR.acknowledge_worker(ack)
        if old_worker is not None and old_worker is not worker:
            try:
                old_worker.quiesce()
            except RECOVERABLE_ERRORS as error:
                self.store.log_error("OLD_AI_WORKER_QUIESCE_FAILED", error, mode=self.mode)
            old_worker.close(2.0)
        new_snapshot = RESOURCE_GOVERNOR.sample_once()
        RUNTIME_EVENT_LOGGER.emit(
            "runtime_worker_migrated",
            plan_version=envelope.get("plan_version"), plan_reason=envelope.get("plan_reason"),
            old_backend=getattr(old_snapshot, "gpu_backend", ""), new_backend=ack.get("applied_backend"),
            old_model_tier=getattr(old_worker, "requested_model_tier", "") if old_worker is not None else "",
            new_model_tier=ack.get("applied_model_tier"), worker_ack_version=ack.get("worker_ack_version"),
            probe=probe,
            memory_released=max(
                0,
                getattr(old_snapshot, "process_private_bytes", 0)
                - getattr(new_snapshot, "process_private_bytes", 0),
            ),
            vram_released=max(
                0,
                safe_int(
                    getattr(old_snapshot, "process_dedicated_vram", 0),
                    0,
                )
                - safe_int(
                    getattr(new_snapshot, "process_dedicated_vram", 0),
                    0,
                ),
            ),
        )
        self.ui(lambda: self.status.set("资源计划已由新工作进程确认并原子切换完整模型实例"), "resource_plan_migrated")
        if should_resume and self.mode_state == MODE_IDLE:
            self.ui(self.start_training, "resource_plan_resume")
    except RECOVERABLE_ERRORS as error:
        if self.store is not None:
            self.store.log_error("RESOURCE_PLAN_MIGRATION_FAILED", error, mode=self.mode, envelope=dict(envelope))
        self.ui(
            lambda value=str(error): self.status.set(
                "资源计划主动迁移失败，输入保持锁定：" + value
            ),
            "resource_plan_migration_failed",
        )
    finally:
        with self._runtime_migration_lock:
            self._runtime_migration_active = False


def _strict_reconcile_runtime_plan(self):
    if self.ai_worker is None or self.store is None or self.closing:
        return
    now = time.monotonic()
    if now - safe_float(getattr(self, "_runtime_last_reconcile", 0.0), 0.0) < 1.0:
        return
    self._runtime_last_reconcile = now
    envelope = RESOURCE_GOVERNOR.plan_envelope()
    worker_status = dict(getattr(self.ai_worker, "status", {}) or {})
    ack_version = max(
        safe_int(worker_status.get("worker_ack_version"), 0),
        safe_int(getattr(self, "_worker_ack_version", 0), 0),
    )
    if ack_version >= safe_int(envelope.get("plan_version"), 0):
        return
    try:
        ack = self.ai_worker.apply_plan(envelope)
        if not ack.get("requires_restart"):
            RESOURCE_GOVERNOR.acknowledge_worker(ack)
            self._worker_ack_version = safe_int(ack.get("worker_ack_version"), 0)
            return
    except RECOVERABLE_ERRORS:
        ack = {"requires_restart": True}
    proactive = bool(
        envelope.get("resource_state") == ResourceState.RED.value
        and safe_float(envelope.get("red_duration_seconds"), 0.0) >= 3.0
    )
    requested_tier = normalize_model_tier(
        envelope.get("requested_model_tier")
    )
    applied_tier = normalize_model_tier(
        worker_status.get(
            "applied_model_tier",
            getattr(self.ai_worker, "requested_model_tier", "Tiny"),
        )
    )
    model_change = requested_tier != applied_tier
    known_backends = {
        str(worker_status.get("applied_backend", "")),
        str(getattr(self.ai_worker, "requested_backend", "")),
    }
    backend_change = str(envelope.get("requested_backend")) not in known_backends
    if not (proactive or model_change or backend_change):
        return
    with self._runtime_migration_lock:
        if self._runtime_migration_active:
            return
        self._runtime_migration_active = True
    threading.Thread(
        target=_strict_migrate_worker,
        args=(self, envelope),
        name="UniversalGameAI-PlanMigration",
        daemon=True,
    ).start()


def _strict_periodic_refresh(self):
    try:
        _strict_reconcile_runtime_plan(self)
    except RECOVERABLE_ERRORS as error:
        self._log_error("RUNTIME_PLAN_RECONCILE_FAILED", error)
    return self._base_periodic_refresh_strict()


def _strict_update_runtime_status(self):
    result = self._base_update_runtime_status_strict()
    try:
        accepted = False
        lower = 0.0
        if self.selected_game and self.store is not None:
            model = self.store.load_model(self.selected_game["id"]) or {}
            validation = model.get("validation", {}) if isinstance(model.get("validation"), dict) else {}
            acceptance = model.get("online_acceptance", {}) if isinstance(model.get("online_acceptance"), dict) else {}
            lower = safe_float(
                acceptance.get(
                    "success_rate_ci95_lower",
                    validation.get("success_rate_ci95_lower", 0.0),
                ),
                0.0,
            )
            accepted = bool(acceptance.get("passed") or validation.get("online_acceptance_passed"))
        text = self.model_text.get()
        suffix = "；验收：已通过，成功率95%置信下限=" + str(round(lower * 100, 1)) + "%" if accepted else "；验收：尚未完成"
        if "；验收：" in text:
            text = text.split("；验收：", 1)[0]
        self.model_text.set(text + suffix)
    except RECOVERABLE_ERRORS as error:
        record_cleanup_error("MODEL_STATUS_REFRESH_FAILED", error)
    return result


@classmethod
def _strict_portfolio_build(cls, experiences, limit=MAX_TRAINING_SAMPLES):
    result = cls._base_build_strict(experiences, limit)
    manifest = result.get("immutable_training_manifest", {}) if isinstance(result, dict) else {}
    if isinstance(manifest, dict):
        manifest["adjacent_frames_kept_together"] = True
        manifest["leakage_guard"] = "game_task_save_session_level_resolution_ui_popup_fps_input_latency"
        manifest["same_session_cross_split_forbidden"] = True
        rows = [row for row in manifest.get("rows", []) if isinstance(row, dict)]
        group_splits = defaultdict(set)
        for row in rows:
            group_splits[str(row.get("group", ""))].add(str(row.get("split", "")))
        leaks = sorted(key for key, splits in group_splits.items() if len(splits) > 1)
        manifest["group_leakage"] = leaks
        manifest["group_overlap"] = bool(leaks)
        if leaks:
            manifest["split_status"] = "failed"
    return result



def parse_cli(argv=None):
    raw = list(sys.argv[1:] if argv is None else argv)
    normalized = _legacy_cli_arguments(raw)
    parser = build_cli_parser()
    parsed = parser.parse_args(normalized)
    if parsed.command is None:
        parsed.command = "gui"
    return parsed


def _validated_worker_path(value, label, must_exist=False):
    text = str(value or "").strip()
    if not text or len(text) > 32767 or "\x00" in text:
        raise CommandLineProtocolError(str(label) + "路径无效")
    path = Path(text).expanduser().absolute()
    if must_exist and not path.exists():
        raise CommandLineProtocolError(str(label) + "路径不存在")
    return path


def dispatch_cli(arguments):
    command = str(arguments.command)
    if command == "ai-worker":
        base = _validated_worker_path(arguments.base, "数据目录", True)
        try:
            auth = base64.urlsafe_b64decode(str(arguments.auth).encode("ascii"))
        except (ValueError, UnicodeEncodeError) as error:
            raise CommandLineProtocolError("AI工作进程认证数据不是有效Base64") from error
        if len(auth) != 32:
            raise CommandLineProtocolError("AI工作进程认证数据长度无效")
        if int(arguments.protocol) != AI_WORKER_PROTOCOL_VERSION:
            raise CommandLineProtocolError("AI工作进程协议版本不一致")
        try:
            address = arguments.address if arguments.family == "AF_PIPE" else tuple(json.loads(arguments.address))
        except (TypeError, ValueError, json.JSONDecodeError) as error:
            raise CommandLineProtocolError("AI工作进程地址无效") from error
        if arguments.family == "AF_INET" and (
            not isinstance(address, tuple)
            or len(address) != 2
            or not isinstance(address[0], str)
            or not isinstance(address[1], int)
        ):
            raise CommandLineProtocolError("AF_INET地址必须是[host,port]")
        return ai_worker_main(str(base), address, arguments.auth, arguments.family, arguments.protocol) or 0
    if command == "runtime-install-worker":
        request = _validated_worker_path(arguments.request, "运行库请求文件", True)
        return runtime_install_worker(str(request))
    if command != "gui":
        raise CommandLineProtocolError("未知命令：" + command)
    return None


def run_gui():
    try:
        APP_CONTEXT.program_instance_lock = ProcessInstanceLock().acquire()
    except Exception as error:
        show_acknowledge_only_startup(str(error))
        return 0
    load_gui_runtime()
    enable_dpi_awareness()
    root = tk.Tk()
    holder = {"app": None}
    install_global_hooks(holder)
    try:
        holder["app"] = App(root)
    except Exception:
        startup_error(root, traceback.format_exc())
    root.mainloop()
    return 0


def main(argv=None):
    multiprocessing.freeze_support()
    try:
        validate_source_contracts_once()
        arguments = parse_cli(argv)
        result = dispatch_cli(arguments)
        if result is not None:
            return int(result)
        return run_gui()
    except CommandLineProtocolError as error:
        sys.stderr.write(
            json.dumps(
                {"status": "protocol_error", "code": ErrorCode.PROTOCOL_ERROR.value, "message": str(error)},
                ensure_ascii=False,
                separators=(",", ":"),
            )
            + "\n"
        )
        return 2


if __name__ == "__main__":
    raise SystemExit(main())
